// ═══════════════════════════════════════════════════════════════
// 🆕 v6.15.1: AUTO-ZUWEISUNG FÜR TELEGRAM-SOFORTFAHRTEN
// Läuft server-seitig → funktioniert 24/7 ohne Browser!
// ═══════════════════════════════════════════════════════════════

function gpsDistanceKm(lat1, lon1, lat2, lon2) {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon/2) * Math.sin(dLon/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

// 🆕 v6.62.542: Chain-Leerfahrt — schnelle Haversine-Schaetzung der Leerfahrt
// vom ZIEL der einen Fahrt zum ABHOLORT der naechsten.
// v6.63.171: Faktor 1.3 → 1.4 fuer realistischere Strassen-Schaetzung.
// Bleibt als synchroner FALLBACK fuer chainLeerfahrtMinAsync wenn OSRM down.
function chainLeerfahrtMin(fromLat, fromLon, toLat, toLon) {
    const _f1 = parseFloat(fromLat), _f2 = parseFloat(fromLon);
    const _t1 = parseFloat(toLat),   _t2 = parseFloat(toLon);
    if (!Number.isFinite(_f1) || !Number.isFinite(_f2) ||
        !Number.isFinite(_t1) || !Number.isFinite(_t2)) return null;
    const distKm = gpsDistanceKm(_f1, _f2, _t1, _t2);
    return Math.max(2, Math.round(distKm * 1.4 / 40 * 60));
}

// v6.63.171: OSRM-Cache fuer Chain-Leerfahrt + Rueckfahrt (Patrick 05.06.07:21)
// Patrick: 'Wenn der Abholort der naechsten Fahrt geaendert wird, berechnet ihr
// verkehrt — das ist Quatsch'. Vorher Luftlinie x 1.3 + Cap 30 Min, jetzt echte
// OSRM-Routing-Berechnung mit 24h-Cache. Bei OSRM-Fail Fallback auf chainLeerfahrtMin.
const _osrmCache = new Map(); // key 'lat1,lon1>lat2,lon2' (gerundet 4 Dezimalstellen) → { min, t }
const _OSRM_CACHE_TTL_MS = 24 * 3600 * 1000;

// 🆕 v6.63.363 (Patrick 16.06. 13:19 Bridge: "Warum nimmst du nicht Google-Distance?
//   Das steht schon wieder irgendwas von OSRM."): Google Routes API (TRAFFIC_AWARE)
//   als primäre Quelle für Anfahrt-/Routing-Zeiten im Hot-Path (autoResolveConflicts,
//   scheduledAutoAssign). OSRM bleibt als Fallback nur wenn Google streikt.
//   API-Key gecached um db.once-Roundtrip pro Call zu vermeiden.
let _googleApiKeyCache = null;
let _googleApiKeyCachedAt = 0;
async function getGoogleApiKey() {
    const _ageMs = Date.now() - _googleApiKeyCachedAt;
    if (_googleApiKeyCache !== null && _ageMs < 5 * 60 * 1000) return _googleApiKeyCache;
    try {
        const snap = await db.ref('settings/googleMapsApiKey').once('value');
        _googleApiKeyCache = snap.val() || null;
        _googleApiKeyCachedAt = Date.now();
    } catch (_) { _googleApiKeyCache = null; }
    return _googleApiKeyCache;
}

async function googleRoutesDrivingMin(fromLat, fromLon, toLat, toLon) {
    try {
        const apiKey = await getGoogleApiKey();
        if (!apiKey) return null;
        const resp = await fetch('https://routes.googleapis.com/directions/v2:computeRoutes', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-Goog-Api-Key': apiKey,
                'X-Goog-FieldMask': 'routes.duration'
            },
            body: JSON.stringify({
                origin: { location: { latLng: { latitude: fromLat, longitude: fromLon } } },
                destination: { location: { latLng: { latitude: toLat, longitude: toLon } } },
                travelMode: 'DRIVE',
                routingPreference: 'TRAFFIC_AWARE'
            }),
            signal: AbortSignal.timeout(6000)
        });
        if (!resp.ok) return null;
        const data = await resp.json();
        const sec = parseInt(String(data?.routes?.[0]?.duration || '0').replace('s', ''));
        if (!sec) return null;
        return Math.max(2, Math.round(sec / 60));
    } catch (_) { return null; }
}

async function osrmDrivingMin(fromLat, fromLon, toLat, toLon) {
    const _f1 = parseFloat(fromLat), _f2 = parseFloat(fromLon);
    const _t1 = parseFloat(toLat),   _t2 = parseFloat(toLon);
    if (!Number.isFinite(_f1) || !Number.isFinite(_f2) ||
        !Number.isFinite(_t1) || !Number.isFinite(_t2)) return null;
    const key = `${_f1.toFixed(4)},${_f2.toFixed(4)}>${_t1.toFixed(4)},${_t2.toFixed(4)}`;
    const cached = _osrmCache.get(key);
    if (cached && (Date.now() - cached.t) < _OSRM_CACHE_TTL_MS) return cached.min;
    // 🆕 v6.63.447: Firebase /routeCache lookup VOR jedem Google-Call
    //   In-Memory _osrmCache überlebt nur einen Cloud-Function-Instance-Lifecycle;
    //   /routeCache überlebt Cold-Starts → spart bei estimateVehicleLeerfahrt
    //   und autoResolveConflicts-Crons den Großteil der Calls.
    const _from = { lat: _f1, lon: _f2 }, _to = { lat: _t1, lon: _t2 };
    const _fbCached = await _readRouteCache(_from, _to, [], 'driving-min', true);
    if (_fbCached && typeof _fbCached.duration === 'number') {
        const _min = Math.max(2, _fbCached.duration);
        _osrmCache.set(key, { min: _min, t: Date.now(), src: 'fb-cache' });
        return _min;
    }
    // 🆕 v6.63.363: Google Routes zuerst (TRAFFIC_AWARE), dann OSRM-Fallback
    const _googleMin = await googleRoutesDrivingMin(_f1, _f2, _t1, _t2);
    if (_googleMin != null) {
        _osrmCache.set(key, { min: _googleMin, t: Date.now(), src: 'google' });
        _writeRouteCache(_from, _to, [], 'driving-min', { duration: _googleMin, distance: null, source: 'google-routes-driving-min' }).catch(() => {});
        return _googleMin;
    }
    try {
        const url = `https://router.project-osrm.org/route/v1/driving/${_f2},${_f1};${_t2},${_t1}?overview=false`;
        const resp = await fetch(url, { signal: AbortSignal.timeout(6000) });
        if (!resp.ok) throw new Error('OSRM HTTP ' + resp.status);
        const data = await resp.json();
        const sec = data?.routes?.[0]?.duration;
        if (typeof sec !== 'number') throw new Error('OSRM kein Route-Ergebnis');
        const min = Math.max(2, Math.round(sec / 60));
        _osrmCache.set(key, { min, t: Date.now(), src: 'osrm' });
        _writeRouteCache(_from, _to, [], 'driving-min', { duration: min, distance: null, source: 'osrm-driving-min' }).catch(() => {});
        return min;
    } catch (e) {
        console.warn('⚠️ Google+OSRM-Routing fehlgeschlagen, Fallback Luftlinie x 1.4:', e.message);
        return chainLeerfahrtMin(_f1, _f2, _t1, _t2);
    }
}

// v6.63.646: ETA-Routing für scheduledReachabilityCheck — OSRM only (kein Google).
// Grund: calculateRoute() ruft Google Routes + OSRM parallel auf. Da Fahrzeug-GPS
// sich jede Minute ändert, gibt es keine Cache-Hits → jede Minute Google API-Call
// pro aktiver Fahrt → bis zu 500€/Monat Hochsaison. OSRM ist kostenlos + ausreichend
// für "Fahrer kommt in X Minuten"-Anzeige. Google Routes bleibt für Preisberechnung
// und Konflikt-Auflösung (selten, Cache-fähig) erhalten.
const _etaRouteMem = new Map(); // key → { duration, distance, t }
const _ETA_ROUTE_TTL = 60 * 1000; // 60s — Fahrzeug bewegt sich, längeres Cache sinnlos
async function _osrmEtaRoute(fromLat, fromLon, tgtLat, tgtLon) {
    // Cache-Key: 3 Dezimalstellen (~100m Raster) — spart Calls wenn Fahrzeug kurz steht
    const _r = v => parseFloat(v).toFixed(3);
    const _key = `${_r(fromLat)},${_r(fromLon)}>${_r(tgtLat)},${_r(tgtLon)}`;
    const _mem = _etaRouteMem.get(_key);
    if (_mem && (Date.now() - _mem.t) < _ETA_ROUTE_TTL) return _mem;
    try {
        const url = `https://router.project-osrm.org/route/v1/driving/${fromLon},${fromLat};${tgtLon},${tgtLat}?overview=false&alternatives=2`;
        const resp = await fetch(url, { signal: AbortSignal.timeout(6000) });
        if (!resp.ok) return null;
        const data = await resp.json();
        const routes = (data.routes || []).filter(r => r.distance > 0);
        if (!routes.length) return null;
        routes.sort((a, b) => a.distance - b.distance);
        const best = routes[0];
        const result = { duration: Math.max(1, Math.round(best.duration / 60)), distance: +(best.distance / 1000).toFixed(1), t: Date.now() };
        _etaRouteMem.set(_key, result);
        return result;
    } catch (_) { return null; }
}

// 🆕 v6.38.27: Unabhängige Kontroll-Prüfung — Vier-Augen-Prinzip
// Prüft DIREKT die Rohdaten in Firebase, NICHT über isVehicleInShift()
function verifyVehicleShiftIndependent(vehicleId, shiftsData, dateStr, timeStr) {
    const shifts = shiftsData[vehicleId];
    const d = new Date(dateStr + 'T00:00:00');
    const dow = d.getDay();
    const dayNames = ['So','Mo','Di','Mi','Do','Fr','Sa'];

    if (!shifts) {
        const hasAny = Object.keys(shiftsData).length > 0;
        if (hasAny) return { ok: false, reason: `${vehicleId} hat keinen Eintrag in vehicleShifts` };
        return { ok: true, reason: 'Kein Schichtsystem aktiv' };
    }

    const defaults = shifts.defaults || {};
    const dayActive = defaults[dow] === true;
    const dateEntry = shifts[dateStr];
    const dateExplicitInactive = dateEntry && dateEntry.active === false;
    const dateExplicitActive = dateEntry && dateEntry.active === true;
    const dateHasTimes = dateEntry && (dateEntry.startTime || dateEntry.endTime || (dateEntry.timeRanges && dateEntry.timeRanges.length > 0));
    const defTimesEntry = (shifts.defaultTimes || {})[dow];
    const hasDefaultTimes = defTimesEntry && (defTimesEntry.startTime || (defTimesEntry.timeRanges && defTimesEntry.timeRanges.length > 0));

    if (dateExplicitInactive) return { ok: false, reason: `${dateStr} explizit inaktiv` };
    if (dateExplicitActive && dateHasTimes) {
        if (timeStr) {
            const ranges = (dateEntry.timeRanges && dateEntry.timeRanges.length > 0)
                ? dateEntry.timeRanges : [{ startTime: dateEntry.startTime || '00:00', endTime: dateEntry.endTime || '23:59' }];
            const inRange = ranges.some(r => timeStr >= r.startTime && timeStr <= r.endTime);
            if (!inRange) return { ok: false, reason: `${timeStr} außerhalb Datums-Schicht` };
        }
        return { ok: true, reason: `Datums-Ausnahme ${dateStr} aktiv` };
    }
    if (!dayActive) return { ok: false, reason: `${dayNames[dow]} nicht aktiv in defaults` };
    if (!hasDefaultTimes) return { ok: false, reason: `${dayNames[dow]} aktiv aber keine defaultTimes` };
    if (timeStr) {
        const ranges = (defTimesEntry.timeRanges && defTimesEntry.timeRanges.length > 0)
            ? defTimesEntry.timeRanges : [{ startTime: defTimesEntry.startTime || '00:00', endTime: defTimesEntry.endTime || '23:59' }];
        const inRange = ranges.some(r => timeStr >= r.startTime && timeStr <= r.endTime);
        if (!inRange) return { ok: false, reason: `${timeStr} außerhalb Wochenplan-Schicht` };
    }
    return { ok: true, reason: `${dayNames[dow]} aktiv, Zeiten ok` };
}

function isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr) {
    // v6.63.473 (Patrick 22.06. 21:00 Cost-Cut): Schicht-Check-Logs entfernt.
    // Hatten ~40-60 Eintraege pro scheduledAutoAssign-Lauf = massives Logging-Volumen.
    // Bei Bedarf temporaer via /settings/debug/shiftCheck=true einschaltbar (TODO Helper).
    const shifts = shiftsData[vehicleId];
    if (!shifts) {
        const hasAnyShifts = Object.keys(shiftsData).length > 0;
        return !hasAnyShifts;
    }

    // Tag aktiv?
    const d = new Date(dateStr + 'T00:00:00');
    const dow = d.getDay();
    const dayNames = ['So','Mo','Di','Mi','Do','Fr','Sa'];
    if (shifts[dateStr] !== undefined) {
        if (shifts[dateStr].active === false) return false;
        if (!(shifts[dateStr].startTime || shifts[dateStr].endTime || (shifts[dateStr].timeRanges && shifts[dateStr].timeRanges.length > 0))) {
            const _dtEntry = (shifts.defaultTimes || {})[dow];
            if (!_dtEntry || !(_dtEntry.startTime || (_dtEntry.timeRanges && _dtEntry.timeRanges.length > 0))) return false;
        }
    } else {
        const defaults = shifts.defaults || {};
        if (defaults[dow] !== true) return false;
        const _defTimesEntry = (shifts.defaultTimes || {})[dow];
        if (!_defTimesEntry || !(_defTimesEntry.startTime || (_defTimesEntry.timeRanges && _defTimesEntry.timeRanges.length > 0))) return false;
    }

    // Schichtzeiten ermitteln
    let times = null;
    const dayEntry = shifts[dateStr];
    if (dayEntry && (dayEntry.startTime || dayEntry.endTime)) {
        const defaultEntry = (shifts.defaultTimes || {})[dow] || null;
        if (dayEntry.additiveException) {
            // 🔧 v6.15.10: KEIN Fallback auf 06:00-22:00!
            // Wochenplan (defaultTimes) ist Gesetz – ohne eingetragene Zeiten = kein Standard-Block
            // 🔧 v6.25.5: Default-Zeiten NUR wenn Tag im Wochenplan aktiv ist!
            // 🔧 v6.38.24: Kein Mo-Fr Fallback
            const _defaults = shifts.defaults || {};
            const _isDayActiveByDefault = _defaults[dow] === true;
            const _effDefault = (_isDayActiveByDefault && defaultEntry) ? defaultEntry : null;
            if (_effDefault) {
                const defRanges = (_effDefault.timeRanges && _effDefault.timeRanges.length > 1)
                    ? _effDefault.timeRanges
                    : [{ startTime: _effDefault.startTime, endTime: _effDefault.endTime }];
                const exRanges = (dayEntry.timeRanges && dayEntry.timeRanges.length >= 1)
                    ? dayEntry.timeRanges
                    : [{ startTime: dayEntry.startTime, endTime: dayEntry.endTime }];
                times = { timeRanges: [...defRanges, ...exRanges] };
            } else {
                // Kein Standard und kein aktiver Wochentag → nur Exception-Zeiten
                times = { startTime: dayEntry.startTime || '00:00', endTime: dayEntry.endTime || '23:59' };
                if (dayEntry.timeRanges && dayEntry.timeRanges.length > 1) times.timeRanges = dayEntry.timeRanges;
            }
        } else {
            times = { startTime: dayEntry.startTime || '00:00', endTime: dayEntry.endTime || '23:59' };
            if (dayEntry.timeRanges && dayEntry.timeRanges.length > 1) times.timeRanges = dayEntry.timeRanges;
        }
    } else {
        const defaultEntry = (shifts.defaultTimes || {})[dow];
        // 🔧 v6.31.0: Nur wenn ECHTE Zeiten konfiguriert sind — sonst = kein Dienst!
        // Verhindert dass Fahrzeuge mit leerem defaultTimes-Eintrag als 24h-Schicht gelten
        if (defaultEntry && (defaultEntry.startTime || (defaultEntry.timeRanges && defaultEntry.timeRanges.length > 0))) {
            times = { startTime: defaultEntry.startTime || '00:00', endTime: defaultEntry.endTime || '23:59' };
            if (defaultEntry.timeRanges && defaultEntry.timeRanges.length > 1) times.timeRanges = defaultEntry.timeRanges;
        }
    }

    if (!times) return false;
    if (!timeStr) return true;
    if (times.timeRanges && times.timeRanges.length > 1) {
        // 🔧 v6.63.569: startTime als äußere Untergrenze VOR timeRanges prüfen.
        // Schicht-Editor schreibt nur startTime wenn Zeiten geändert werden,
        // aber timeRanges bleiben auf alten Werten → Beispiel: startTime=18:30 aber
        // timeRanges hat 09:00-17:00 → 15:00 würde fälschlicherweise "in Dienst" gelten.
        // 🔧 v6.63.572: endTime-Gate entfernt — timeRanges[] hat eigene Obergrenzen
        // und endTime kann veraltet/inkonsistent sein wenn timeRanges direkt im Web-Editor
        // gesetzt wurden (z.B. VGLK Fr: endTime=14:00 aber timeRanges bis 18:00).
        if (times.startTime && timeStr < times.startTime) return false;
        return times.timeRanges.some(r => timeStr >= r.startTime && timeStr <= r.endTime);
    }
    return timeStr >= times.startTime && timeStr <= times.endTime;
}

// 🆕 v6.63.124 (Patrick 03.06. 15:34): isVehicleInShift + Live-Override.
//   Bug: pw-ik-222 ohne Wochenplan, ABER live aktiv eingeloggt + online.
//   isVehicleInShift returnt false → Phase 5 verwirft als Tausch-Kandidat.
//   Fix: wenn vData.online===true UND vData.shift.status==='active' → akzeptiere
//   fuer HEUTE (sonst nicht — Live-Status morgen weg, nicht voraussagbar).
// v6.63.176: Patrick 05.06. 12:40+12:42 — Vorbestellung NUR an Fahrzeuge im
// Schichtplan; Live-Override (online+active ohne Plan) nur fuer Sofortfahrten.
// Bug: cloud-prio-time-resort hat Nicole Schindel 13:40 auf Toyota Prius IK
// gemappt obwohl Kulpa (IK 222) Freitags FREI hat — App lief seit gestern
// weil vergessen auszustempeln, Live-Override hat das als 'verfuegbar' gewertet.
function isVehicleAvailableForRide(vehicleId, vehiclesData, shiftsData, dateStr, timeStr, opts) {
    if (isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr)) return true;
    // Live-Override nur erlaubt wenn explizit zugelassen (Sofortfahrten).
    // Standard: zugelassen — Aufrufer fuer Vorbestellungen muss { allowLiveOverride: false } setzen.
    const allowLiveOverride = !opts || opts.allowLiveOverride !== false;
    if (!allowLiveOverride) {
        return false;
    }
    // 🔧 v6.63.548: Live-Override NICHT fuer Fahrzeuge die einen Wochenplan-Eintrag
    // fuer den betreffenden Tag haben aber ausserhalb des Schichtfensters liegen.
    // Beispiel: IK hat Mo 15:30-19:30, Danilo startet Schicht um 08:36 → Live-Override
    // wuerde IK fuer 14:05-Pickup freischalten obwohl Plan sagt erst 15:30.
    // Wochenplan hat Vorrang vor Live-Status (Patrick 29.06.2026 Gruntz-Vorfall).
    const _liveShifts = shiftsData[vehicleId];
    if (_liveShifts) {
        const _liveDow = new Date(dateStr + 'T00:00:00').getDay();
        if ((_liveShifts.defaults || {})[_liveDow] === true) {
            // Fahrzeug hat aktiven Wochentag im Plan aber liegt ausserhalb des Fensters
            // → kein Live-Override, Wochenplan ist massgeblich
            return false;
        }
    }
    const vData = (vehiclesData || {})[vehicleId];
    if (!vData) return false;
    if (vData.online !== true) return false;
    if (!vData.shift || vData.shift.status !== 'active') return false;
    // Nur fuer heute akzeptieren (Berlin-TZ)
    const todayBerlin = new Date().toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' });
    if (dateStr !== todayBerlin) return false;
    console.log(`   🟢 Live-Override ${vehicleId}: kein Wochenplan fuer ${dateStr}, aber online+active → verfuegbar`);
    return true;
}

// 🆕 v6.26.0: Schichtende ermitteln für den Zeitblock der die gegebene Uhrzeit enthält
function getShiftEndTime(vehicleId, shiftsData, dateStr, timeStr) {
    const shifts = shiftsData[vehicleId];
    if (!shifts) return null;

    // Schichtzeiten ermitteln (gleiche Logik wie isVehicleInShift)
    let times = null;
    const d = new Date(dateStr + 'T00:00:00');
    const dow = d.getDay();
    const dayEntry = shifts[dateStr];
    if (dayEntry && (dayEntry.startTime || dayEntry.endTime)) {
        if (dayEntry.additiveException) {
            const defaultEntry = (shifts.defaultTimes || {})[dow] || null;
            if (defaultEntry) {
                const defRanges = (defaultEntry.timeRanges && defaultEntry.timeRanges.length > 1)
                    ? defaultEntry.timeRanges
                    : [{ startTime: defaultEntry.startTime, endTime: defaultEntry.endTime }];
                const exRanges = (dayEntry.timeRanges && dayEntry.timeRanges.length >= 1)
                    ? dayEntry.timeRanges
                    : [{ startTime: dayEntry.startTime, endTime: dayEntry.endTime }];
                times = { timeRanges: [...defRanges, ...exRanges] };
            } else {
                times = { startTime: dayEntry.startTime || '00:00', endTime: dayEntry.endTime || '23:59' };
                if (dayEntry.timeRanges && dayEntry.timeRanges.length > 1) times.timeRanges = dayEntry.timeRanges;
            }
        } else {
            times = { startTime: dayEntry.startTime || '00:00', endTime: dayEntry.endTime || '23:59' };
            if (dayEntry.timeRanges && dayEntry.timeRanges.length > 1) times.timeRanges = dayEntry.timeRanges;
        }
    } else {
        const defaultEntry = (shifts.defaultTimes || {})[dow];
        if (defaultEntry && (defaultEntry.startTime || (defaultEntry.timeRanges && defaultEntry.timeRanges.length > 0))) {
            times = { startTime: defaultEntry.startTime || '00:00', endTime: defaultEntry.endTime || '23:59' };
            if (defaultEntry.timeRanges && defaultEntry.timeRanges.length > 1) times.timeRanges = defaultEntry.timeRanges;
        }
    }

    if (!times) return null;

    // Split-Shift: Finde den Block der die Uhrzeit enthält
    if (times.timeRanges && times.timeRanges.length > 1) {
        for (const r of times.timeRanges) {
            if (timeStr >= r.startTime && timeStr <= r.endTime) {
                return r.endTime;
            }
        }
        // Fallback: letztes endTime
        const sorted = [...times.timeRanges].sort((a, b) => a.endTime.localeCompare(b.endTime));
        return sorted[sorted.length - 1].endTime;
    }
    return times.endTime;
}

// 🆕 v6.25.6: Detaillierte Schicht-Info für Prüfprotokoll in der App
function getShiftInfoDetailed(vehicleId, shiftsData, dateStr, timeStr) {
    const shifts = shiftsData[vehicleId];
    const dayNames = ['So','Mo','Di','Mi','Do','Fr','Sa'];
    const d = new Date(dateStr + 'T00:00:00');
    const dow = d.getDay();
    if (!shifts) {
        const hasAny = Object.keys(shiftsData).length > 0;
        return { hasShiftEntry: false, reason: hasAny ? 'Kein Schichtplan-Eintrag vorhanden' : 'Kein Schichtsystem aktiv', dayActive: false, shiftTimes: null };
    }
    let dayActive = false;
    let daySource = '';
    if (shifts[dateStr] !== undefined) {
        dayActive = shifts[dateStr].active !== false;
        daySource = dayActive ? `${dateStr} explizit aktiv` : `${dateStr} explizit INAKTIV`;
    } else {
        // 🔧 v6.38.24: Kein Mo-Fr Fallback
        const defaults = shifts.defaults || {};
        dayActive = defaults[dow] === true;
        daySource = dayActive ? `${dayNames[dow]} im Wochenplan aktiv` : `${dayNames[dow]} nicht im Wochenplan`;
    }
    if (!dayActive) return { hasShiftEntry: true, reason: daySource, dayActive: false, shiftTimes: null };
    // Zeiten ermitteln
    const dayEntry = shifts[dateStr];
    const defaultEntry = (shifts.defaultTimes || {})[dow];
    let shiftTimes = null;
    if (dayEntry && (dayEntry.startTime || dayEntry.endTime)) {
        shiftTimes = dayEntry.startTime + '-' + dayEntry.endTime;
        if (dayEntry.timeRanges && dayEntry.timeRanges.length > 1) {
            shiftTimes = dayEntry.timeRanges.map(r => r.startTime + '-' + r.endTime).join(', ');
        }
    } else if (defaultEntry && (defaultEntry.startTime || (defaultEntry.timeRanges && defaultEntry.timeRanges.length > 0))) {
        shiftTimes = defaultEntry.startTime + '-' + defaultEntry.endTime;
        if (defaultEntry.timeRanges && defaultEntry.timeRanges.length > 1) {
            shiftTimes = defaultEntry.timeRanges.map(r => r.startTime + '-' + r.endTime).join(', ');
        }
    }
    if (!shiftTimes) return { hasShiftEntry: true, reason: 'Tag aktiv aber keine Schichtzeiten konfiguriert', dayActive: true, shiftTimes: null };
    const inShift = isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr);
    return { hasShiftEntry: true, reason: inShift ? `Im Dienst (${shiftTimes})` : `Außerhalb Schicht (${shiftTimes})`, dayActive: true, daySource, shiftTimes, inShift };
}

// 🆕 v6.41.96: FCM-Push an einen Fahrer/Fahrzeug. Liest fcmToken aus
// /vehicles/{vid}/fcmToken/token, sendet hochpriore Native-Notification.
// Wird auch dann zugestellt wenn die WebView tot ist — über Android FCM-Service.
// 🆕 v6.62.667: sendFCMToAdmins — sendet Push an alle registrierten Admin-Geraete
//   (/adminFcmTokens/{deviceId}/token). Verwendet von onRideCreated wenn eine
//   Web-Buchung (source=web-booking/qr-aufsteller) reinkommt.
//   Patrick (13.05. 08:56): "Web-Anfragen muss man in der Native-App bestaetigen
//   koennen — kann nicht immer in die Web-App gehen."
async function sendFCMToAdmins(payload) {
    try {
        const snap = await db.ref('adminFcmTokens').once('value');
        // 🆕 v6.62.908 (Patrick 24.05. 09:13): 'Stille Admins' — User die als Fahrer aktiv
        //   sind wollen KEINE Admin-Pushes mehr (kein new_anfrage, kein new_web_booking).
        //   /settings/silentAdminTokens[] enthaelt deviceIds die ausgenommen werden.
        let silentDeviceIds = [];
        try {
            const _silentSnap = await db.ref('settings/silentAdminTokens').once('value');
            const _v = _silentSnap.val();
            if (Array.isArray(_v)) silentDeviceIds = _v;
            else if (_v && typeof _v === 'object') silentDeviceIds = Object.values(_v);
        } catch (_) {}
        const tokens = [];
        snap.forEach(c => {
            const t = c.val();
            if (t && t.token && !silentDeviceIds.includes(c.key)) {
                tokens.push({ deviceId: c.key, token: t.token, label: t.label || '?' });
            }
        });
        if (tokens.length === 0) {
            console.log('📵 sendFCMToAdmins: Keine Admin-Tokens registriert (oder alle silent)');
            return 0;
        }
        const data = Object.fromEntries(Object.entries(payload || {}).map(([k, v]) => [k, String(v == null ? '' : v)]));
        let sent = 0;
        for (const t of tokens) {
            try {
                await admin.messaging().send({
                    token: t.token,
                    data,
                    android: { priority: 'high', ttl: 60_000 }
                });
                sent++;
                console.log(`✅ Admin-FCM an ${t.label} (${t.deviceId}) gesendet`);
            } catch (e) {
                console.warn(`❌ Admin-FCM an ${t.label} fehlgeschlagen: ${e.code || e.message}`);
                if (e.code === 'messaging/registration-token-not-registered' || e.code === 'messaging/invalid-registration-token') {
                    try { await db.ref('adminFcmTokens/' + t.deviceId).remove(); } catch (_) {}
                }
            }
        }
        if (payload && payload.rideId) {
            try { await addRideLog(payload.rideId, '📲', `Admin-FCM-Push gesendet an ${sent}/${tokens.length} Admin(s)`, { quelle: 'sendFCMToAdmins v6.62.667', type: payload.type || '?' }); } catch (_) {}
        }
        return sent;
    } catch (e) {
        console.error('sendFCMToAdmins Fehler:', e.message);
        return 0;
    }
}

async function sendFCMToVehicle(vehicleId, payload) {
    if (!vehicleId) return false;
    try {
        const tokenSnap = await db.ref(`vehicles/${vehicleId}/fcmToken/token`).once('value');
        const token = tokenSnap.val();
        if (!token) {
            console.log(`📵 sendFCMToVehicle: Kein FCM-Token für ${vehicleId} (App nicht geöffnet seit Update?)`);
            return false;
        }
        const message = {
            token,
            // KEIN notification-Block — wir bauen die Notification nativ in TaxiFCMService damit
            // Sound/Vibration/FullScreenIntent kontrollierbar sind. Nur Daten schicken.
            data: Object.fromEntries(Object.entries(payload || {}).map(([k, v]) => [k, String(v == null ? '' : v)])),
            android: {
                priority: 'high',
                ttl: 60_000 // 60 Sek — wenn nicht zugestellt verfällt der Push
            }
        };
        const result = await admin.messaging().send(message);
        console.log(`✅ FCM gesendet an ${vehicleId}: ${result}`);
        // 🆕 v6.62.69: Audit-Trail im lifecycleLog der Ride — Patrick will sehen wann Push raus ging
        if (payload && payload.rideId) {
            try {
                await addRideLog(payload.rideId, '📲', `FCM-Push gesendet an ${vehicleId}`, {
                    vehicleId,
                    type: payload.type || 'unknown',
                    isReminder: payload.isReminder || 'false',
                    quelle: 'sendFCMToVehicle'
                });
            } catch (_logErr) { /* Log-Fehler nicht eskalieren */ }
        }
        // 🆕 v6.63.159 (Patrick 04.06. 12:04 "die push verfolgung wer welche pusher
        //   bekommt und welche alarme und was das für ein geräusch macht"):
        //   Pro-Fahrzeug Push-Audit in /pushAudit/{vehicleId}/{ts}. Admin kann
        //   im Web-Tab "Push-Verlauf" sehen welcher Fahrer wann was bekommen hat.
        //   Kategorie ('alarm' = Vollton/Full-Screen, 'reminder' = Standard,
        //   'silent' = Hintergrund-Update). Native TaxiFCMService entscheidet
        //   anhand des type was abgespielt wird.
        try {
            const _ts = Date.now();
            const _t = payload?.type || 'unknown';
            // Severity-Mapping fuer Web-Filter
            let _severity = 'silent';
            if (_t === 'new_ride' || _t === 'new_ride_immediate') _severity = 'alarm';
            else if (_t === 'losfahren_reminder' || _t === 'replan_notification' || _t === 'new_ride_reminder') _severity = 'reminder';
            else if (_t === 'cancel_notification') _severity = 'reminder';
            // 🆕 v6.63.162 (Patrick 04.06. 12:37 "ich sehe nicht das Datum,
            //   sehe ich auch nicht im Push"): pickupTimestamp + Adressen direkt
            //   aus der Ride nachholen — damit Web-UI volles Datum + Pickup/Ziel
            //   anzeigen kann.
            const _extras = {};
            if (payload?.rideId) {
                try {
                    const _rSnap = await db.ref(`rides/${payload.rideId}`).once('value');
                    const _r = _rSnap.val();
                    if (_r) {
                        _extras.pickupTimestamp = _r.pickupTimestamp || null;
                        _extras.pickup = (_r.pickup || '').substring(0, 80) || null;
                        _extras.destination = (_r.destination || '').substring(0, 80) || null;
                        _extras.passengers = _r.passengers || null;
                        _extras.rideStatus = _r.status || null;
                    }
                } catch (_e) { /* non-critical */ }
            }
            await db.ref(`pushAudit/${vehicleId}/${_ts}`).set({
                ts: _ts,
                type: _t,
                severity: _severity,
                rideId: payload?.rideId || null,
                customerName: payload?.customerName || null,
                pickupTime: payload?.pickupTime || null,
                ..._extras,
                isReminder: payload?.isReminder === 'true' || payload?.isReminder === true,
                success: true,
                quelle: 'sendFCMToVehicle v6.63.162'
            });
        } catch (_auditErr) { /* non-critical */ }
        return true;
    } catch (e) {
        console.error(`❌ sendFCMToVehicle ${vehicleId} fehlgeschlagen:`, e.message);
        // v6.62.69: Auch Fehlschlaege loggen
        if (payload && payload.rideId) {
            try { await addRideLog(payload.rideId, '⚠️', `FCM-Push FEHLGESCHLAGEN an ${vehicleId}`, { vehicleId, fehler: e.message }); } catch(_) {}
        }
        // 🆕 v6.63.159: Audit-Trail auch bei Fail (zeigt Connection-Probleme)
        try {
            const _ts = Date.now();
            await db.ref(`pushAudit/${vehicleId}/${_ts}`).set({
                ts: _ts,
                type: payload?.type || 'unknown',
                rideId: payload?.rideId || null,
                success: false,
                error: e.message || 'unknown',
                errorCode: e.code || null,
                quelle: 'sendFCMToVehicle v6.63.159'
            });
        } catch (_auditErr) { /* non-critical */ }
        // Wenn Token ungültig (UNREGISTERED/INVALID_ARGUMENT) → entfernen
        if (e.code === 'messaging/registration-token-not-registered' || e.code === 'messaging/invalid-registration-token') {
            try { await db.ref(`vehicles/${vehicleId}/fcmToken`).remove(); } catch (_) {}
        }
        return false;
    }
}

// v6.61.2: Wartezeit-Schätzung für warteschlange-Fahrten.
// Patrick: 'der Kunde müsste doch jetzt gleich eine Info kriegen das es ca 30 Minuten dauert
// weil ich ja mit der Fahrt beschäftigt bin'.
// Liefert die Minuten bis das nächste Fahrzeug frei wird, basierend auf:
// - Aktive Fahrten (on_way/picked_up/accepted/assigned innerhalb 30 Min)
// - Pickup + Duration + Boarding + Alighting Buffer
async function estimateNextAvailableMinutes(allRides, vehiclesData, pricingSettings) {
    const now = Date.now();
    // v6.63.188 (Patrick 06.06. 07:44): boarding/alighting/buffer aus settings.timeslotSettings
    //   ziehen (vorher pricingSettings.boardingTime + hardcoded +5). Defaults 1/1/3 statt 2/2/5.
    //   Marion-Analyse 06.06.: System rechnet 9 Min Polster zwischen Fahrten — gefuehlt zu lang.
    const _tss = (await db.ref('settings/timeslotSettings').once('value')).val() || {};
    const boardingMin = _tss.boardingTime != null ? _tss.boardingTime : ((pricingSettings && pricingSettings.boardingTime) || 1);
    const alightingMin = _tss.alightingTime != null ? _tss.alightingTime : ((pricingSettings && pricingSettings.alightingTime) || 1);
    const _bufMin = _tss.bufferTime != null ? _tss.bufferTime : 3;
    const bufferMs = (boardingMin + alightingMin + _bufMin) * 60000;
    const candidates = [];
    for (const [vid, vData] of Object.entries(vehiclesData || {})) {
        if (!vData || !vData.online) continue;
        // Welche Fahrten halten dieses Fahrzeug noch beschäftigt?
        const vehicleRides = (allRides || []).filter(r =>
            (r.vehicleId === vid || r.assignedVehicle === vid) &&
            ['on_way', 'picked_up', 'assigned', 'accepted'].includes(r.status)
        );
        if (vehicleRides.length === 0) {
            // Fahrzeug ist FREI → würde von autoAssignRide gefunden — also schnell wieder probieren
            return 0;
        }
        // Spätestes Frei-Werden = max über alle aktiven Fahrten + Buffer
        let freeAtMs = now;
        for (const r of vehicleRides) {
            const start = r.pickupTimestamp || r.acceptedAt || now;
            const dur = ((r.duration || r.estimatedDuration || 20) * 60000);
            const end = start + dur + bufferMs;
            if (end > freeAtMs) freeAtMs = end;
        }
        candidates.push(freeAtMs);
    }
    if (candidates.length === 0) {
        // Kein Fahrer online → großzügige Schätzung
        return 30;
    }
    const earliestMs = Math.min(...candidates);
    const minUntil = Math.round((earliestMs - now) / 60000);
    return Math.max(1, minUntil);
}

// 🆕 v6.63.291 (Patrick 11.06. 17:51): Wartepool-Resolver Helper.
//   Patrick's Algorithmus:
//   fuer jede Wartepool-Ride W:
//     fuer jede assigned Ride R in 30-Min-Naehe (gleiche Vehicles)
//       versuche R -5 / R -10 / W +5 Min
//   Returns: Optionen-Array [{key, label, action, shiftMin, ...}]
// 🆕 v6.63.380 (Patrick 17.06. 11:52-11:53 Bridge: "erstelle prüfung warum
//   fahrten im wartepool landen und nicht aufgelöst werden / du ein auge drauf
//   selber umweisen und beobachten und dem system das beibringen"):
//   Audit-Log Helper — pro Wartepool-Lifecycle alle Events tracken in
//   /wartepoolAudit/{rideId}/{push} mit ts + stage + reason + suggestion.
//   Patrick + Claude sehen Verlauf jeder hängenden Ride.
async function wartepoolAuditPush(rideId, stage, details) {
    if (!rideId) return;
    try {
        await db.ref('wartepoolAudit/' + rideId).push({
            ts: Date.now(),
            stage,
            ...(details || {})
        });
    } catch (e) {
        console.warn('wartepoolAuditPush err:', e.message);
    }
}

async function buildWartepoolOptions(wpRide, allRides, vehicles, shiftsData) {
    const _options = [];
    const _key = (n) => String.fromCharCode(64 + n); // 1->A, 2->B, ...
    let _n = 1;
    if (!wpRide.pickupTimestamp) {
        _options.push({ key: _key(_n++), label: 'Manuell loesen', action: 'manual' });
        return _options;
    }
    const _wpTs = wpRide.pickupTimestamp;
    const _wpPax = parseInt(wpRide.passengers || 1);
    // 🆕 v6.63.330 (Patrick 14.06.2026 09:34): Bahnhof-Tabu fuer WARTEPOOL-Fahrt selbst.
    //   Wenn Pickup ODER Drop Bahnhof/Flughafen → wartepool-Fahrt darf NICHT +5 Min spaeter
    //   (Kunde verpasst Zug/Flug). Nur OTHER-Verschiebung zulaessig.
    const _wpIsTrainOrAirport = (() => {
        const _p = (wpRide.pickup || '').toLowerCase();
        const _d = (wpRide.destination || '').toLowerCase();
        const _hit = s => s.includes('bahnhof') || s.includes('hbf') || s.includes('flughafen');
        return _hit(_p) || _hit(_d);
    })();
    // Naheliegende assigned Rides (30 Min Window davor)
    const _candidates = allRides.filter(r => {
        if (!r || !r.assignedVehicle || !r.pickupTimestamp) return false;
        if (r.firebaseId === wpRide.firebaseId) return false;
        if (['accepted','picked_up','on_way','completed','cancelled','deleted','storniert'].includes(r.status)) return false;
        if (r.assignmentLocked === true) return false;
        if ((r.assignedBy || '').startsWith('claude-manual-')) return false;
        if ((r.assignedBy || '').startsWith('manual-admin')) return false;
        const _gap = _wpTs - r.pickupTimestamp;
        if (_gap < 0 || _gap > 30 * 60000) return false;
        // Kapazitaet pruefen — Vehicle muss W passen
        const _vCap = (OFFICIAL_VEHICLES[r.assignedVehicle] || {}).capacity || 4;
        if (_vCap < _wpPax) return false;
        // Bahnhof-Tabu: wenn R Pickup ODER Drop Bahnhof/Flughafen, nicht verschieben (Patrick 09:34)
        const _puStr = (r.pickup || '').toLowerCase();
        const _dStr = (r.destination || '').toLowerCase();
        const _hit = s => s.includes('bahnhof') || s.includes('hbf') || s.includes('flughafen');
        if (_hit(_puStr) || _hit(_dStr)) return false;
        return true;
    });
    // Patrick-Regel: -5, -10 versuchen
    for (const r of _candidates.slice(0, 2)) {
        const _vName = (OFFICIAL_VEHICLES[r.assignedVehicle] || {}).name || r.assignedVehicle;
        const _rTime = berlinTimeGlobal(r.pickupTimestamp);
        // 🆕 v6.63.330: zusaetzliche Detail-Felder fuer Push-Nachricht
        const _rFrom = (r.pickup || '').slice(0, 40);
        const _rTo = (r.destination || '').slice(0, 40);
        const _rPax = r.passengers || 1;
        _options.push({
            key: _key(_n++),
            label: (r.customerName || '?') + ' ' + _rTime + ' -5 Min auf ' + _vName,
            action: 'shift-other-assign-to-wp',
            otherRideId: r.firebaseId,
            otherCustomerName: r.customerName || '?',
            otherTime: _rTime,
            otherFrom: _rFrom,
            otherTo: _rTo,
            otherPax: _rPax,
            otherVehicleName: _vName,
            shiftMin: -5,
            targetVehicleForWp: r.assignedVehicle
        });
        if (_n > 4) break;
        _options.push({
            key: _key(_n++),
            label: (r.customerName || '?') + ' ' + _rTime + ' -10 Min auf ' + _vName,
            action: 'shift-other-assign-to-wp',
            otherRideId: r.firebaseId,
            otherCustomerName: r.customerName || '?',
            otherTime: _rTime,
            otherFrom: _rFrom,
            otherTo: _rTo,
            otherPax: _rPax,
            otherVehicleName: _vName,
            shiftMin: -10,
            targetVehicleForWp: r.assignedVehicle
        });
        if (_n > 4) break;
    }
    // 🆕 v6.63.330: W +5 Min NUR wenn Bahnhof-Tabu nicht greift
    if (!_wpIsTrainOrAirport) {
        _options.push({
            key: _key(_n++),
            label: 'Diese Fahrt +5 Min spaeter ' + berlinTimeGlobal(_wpTs + 5*60000),
            action: 'shift-wartepool',
            shiftMin: 5
        });
    }
    // Manuell-Option als Fallback
    _options.push({ key: _key(_n++), label: 'Manuell loesen', action: 'manual' });
    return _options;
}

// v6.63.648: In-Memory-Cache für autoAssignRide — verhindert N×7 Firebase-Reads pro Cron-Lauf
// v6.63.649: Settings ebenfalls gecacht (5 Min TTL — ändern sich selten)
const _aarCache = { vehicles: null, shifts: null, rides: null, ts: 0, priorities: null, pricing: null, prioMalus: null, optByDay: null, settingsTs: 0 };
const _AAR_CACHE_TTL = 30 * 1000;
const _AAR_SETTINGS_TTL = 5 * 60 * 1000;
async function autoAssignRide(rideId, rideData, _excludeVehicleIds = []) {
    console.log(`🎯 v6.25.4: Cloud-AutoAssign für Fahrt: ${rideId}${_excludeVehicleIds.length ? ' (exclude: ' + _excludeVehicleIds.join(',') + ')' : ''}`);

    // 🆕 v6.63.454 (Patrick 21.06. 09:00 Bridge: "warum funktioniert Krause nicht"):
    //   Helper damit JEDE return-null-Stelle vor dem Z.1809-Persist trotzdem einen
    //   sichtbaren autoAssignLastReason in die DB schreibt. Sonst sehen wir im
    //   Wartepool-Detective + Native-Dispo NICHTS bei Krause-ähnlichen Fällen,
    //   wo die Function vor dem Score-Persist-Block aussteigt (Safety-Check,
    //   Locked, Route-Fail etc.).
    const _persistEarlyReturn = async (stage, reason) => {
        try {
            await db.ref(`rides/${rideId}`).update({
                autoAssignLastReason: `early-return:${stage} ${reason || ''}`.slice(0, 200),
                autoAssignLastEarlyStage: stage,
                autoAssignLastFailAtV454: Date.now()
            });
        } catch (_) { /* defensive */ }
    };

    // 🛡️ v6.63.378: Recursion-Guard — Patrick will dass System nicht endlos ausschließt
    if (_excludeVehicleIds.length > 10) {
        console.warn(`   ⚠️ v6.63.378: Recursion-Guard erreicht (10 Vehicles excluded) — gebe auf`);
        await _persistEarlyReturn('recursion-guard', `${_excludeVehicleIds.length} Vehicles excluded`);
        return null;
    }

    // 🆕 v6.63.491 (Patrick 23.06. 15:51 'warum werde ich zugespammt'):
    //   EINSTEIGER-Fahrten (vom Fahrer-Dashboard "Einsteiger" Button) haben PER DEFINITION
    //   kein Ziel. Auto-Assign macht keinen Sinn — der Fahrer hat den Einsteiger schon
    //   eingeladen, das Ziel wird erst waehrend der Fahrt klar. Frueher Bail-out
    //   verhindert Watchdog-Spam ("Auto-Zuweisung FEHLGESCHLAGEN ... weder Routendaten
    //   noch Koordinaten") bei jedem Cron-Lauf.
    if (rideData.isInsteiger === true || rideData.source === 'native_einsteiger') {
        console.log(`   ℹ️ v6.63.491: Einsteiger-Fahrt ${rideId} — KEIN Auto-Assign noetig (Fahrer hat schon)`);
        await _persistEarlyReturn('einsteiger-skip', 'Einsteiger-Fahrt vom Fahrer-Dashboard');
        return null;
    }
    // 🆕 v6.63.377 (Patrick 17.06. 09:10 Bridge "ja" zu Komplett-Diagnose):
    //   Helper für return-null-Trace. Jede return-null-Stelle pusht ein
    //   debugLogs/autoassign Event mit stage-Marker damit Patrick endlich
    //   sieht WARUM eine Ride im Wartepool bleibt (Polina/Tegge undefined).
    // v6.63.463 (Patrick 21.06. 20:22 Bridge "Funktioniert trotzdem nicht"): Hasbargen-Test
    //   crashte mit "value argument contains undefined in property 'debugLogs.autoassign.estimatedDuration'".
    //   Firebase RTDB lehnt undefined ab. Native-Buchungen setzen estimatedDuration nicht
    //   (nur drivingTimeToDestination). Sanitizer entfernt undefined-Felder vor push.
    const _sanitizeForFB = (obj) => {
        const out = {};
        for (const k of Object.keys(obj || {})) {
            const v = obj[k];
            if (v !== undefined) out[k] = v;
        }
        return out;
    };
    const _trace377 = (stage, details) => db.ref('debugLogs/autoassign').push(_sanitizeForFB({
        ts: Date.now(),
        rideId,
        customer: rideData?.customerName || '?',
        pickupTime: rideData?.pickupTime || '?',
        pickup: (rideData?.pickup || '').slice(0,60),
        stage,
        ...(details || {})
    })).catch(()=>{});
    // Entry-Trace: was reinkommt
    _trace377('entry-v6.63.377', {
        status: rideData?.status,
        hasCoords: !!(rideData?.pickupCoords?.lat && rideData?.destCoords?.lat),
        estimatedDuration: rideData?.estimatedDuration ?? null,
        source: rideData?.source
    });
    try {
        // 🛡️ v6.62.663: Patrick (13.05. 10:04): Watchdog hat Tesla unterwegs (status=on_way)
        // gewaltsam an Toyota Prius IK umgeleitet, weil das Fahrzeug noch in rejectedVehicles
        // stand. Defensive Sicherung: vor JEDER Zuweisung den aktuellen Status pruefen —
        // wenn die Fahrt schon accepted/on_way/picked_up/arrived/completed ist, brich ab.
        // Eine laufende Fahrt darf NIEMALS durch Auto-Assign aus den Haenden des Fahrers
        // gerissen werden.
        try {
            const _curSnap = await db.ref('rides/' + rideId).once('value');
            const _cur = _curSnap.val();
            if (_cur) {
                const _protected = ['accepted', 'on_way', 'picked_up', 'arrived', 'completed', 'cancelled', 'storniert', 'deleted'];
                if (_protected.includes(_cur.status)) {
                    console.warn(`🛡️ autoAssignRide ABORT: ${rideId} hat status='${_cur.status}' (geschuetzt, Fahrer laeuft schon)`);
                    try { await addRideLog(rideId, '🛡️', `autoAssignRide blockiert: status=${_cur.status}`, {
                        quelle: 'autoAssignRide v6.62.663 Safety',
                        grund: `Aktive Fahrt darf nicht ueberschrieben werden`,
                        aktuelleFahrzeug: _cur.assignedVehicleName || _cur.assignedVehicle || '?'
                    }); } catch (_) {}
                    await _trace377('exit-protected-status', { status: _cur.status });
                    await _persistEarlyReturn('protected-status', `status='${_cur.status}'`);
                    return null;
                }
                // 🆕 v6.63.159 (Patrick 04.06. 12:14 Tesla-Sperre): assignmentLocked
                //   ist HARTER Schutz. Wenn Admin/Disponent ein Fahrzeug zur Fahrt
                //   gesperrt hat, darf autoAssignRide das Fahrzeug NIE austauschen —
                //   auch nicht wenn das Fahrzeug keinen Wochenplan-Eintrag hat.
                //   Patrick entscheidet manuell, das System respektiert das Lock.
                if (_cur.assignmentLocked === true && (_cur.assignedVehicle || _cur.vehicleId)) {
                    console.warn(`🔒 autoAssignRide ABORT: ${rideId} assignmentLocked=true (Fahrzeug ${_cur.assignedVehicleName || _cur.assignedVehicle || _cur.vehicleId} fest gesperrt)`);
                    try { await addRideLog(rideId, '🔒', `autoAssignRide blockiert: assignmentLocked=true`, {
                        quelle: 'autoAssignRide v6.63.159 Lock-Guard',
                        grund: `Admin/Disponent hat Fahrzeug fest gesperrt — kein Auto-Reassign`,
                        aktuelleFahrzeug: _cur.assignedVehicleName || _cur.assignedVehicle || _cur.vehicleId || '?'
                    }); } catch (_) {}
                    await _persistEarlyReturn('assignment-locked', `Vehicle ${_cur.assignedVehicleName || _cur.assignedVehicle || _cur.vehicleId || '?'} gesperrt`);
                    return null;
                }
            }
        } catch (_safetyErr) {
            console.warn('autoAssignRide Safety-Check Fehler (ignored):', _safetyErr.message);
        }
        // 🔧 v6.63.217 (Cost-Detox Phase X): rides nur Fenster -2h..+24h statt ALLES.
        //   Vorher 5-15 MB pro Call × 100ks Calls/Tag = ~16 GB/Tag Hauptkostenfresser.
        // v6.63.648: 30s Cache — scheduledAutoAssign ruft autoAssignRide N-mal auf (1/Fahrt),
        //   vorher N×3 Reads (vehicles+shifts+rides). Mit Cache: 3 Reads pro Cron-Lauf.
        const _now648 = Date.now();
        const _rWS = _now648 - 2 * 60 * 60 * 1000;
        const _rWE = _now648 + 24 * 60 * 60 * 1000;
        const _cacheHit = (_aarCache.ts && (_now648 - _aarCache.ts) < _AAR_CACHE_TTL);
        if (!_cacheHit) {
            const [_vSnap, _sSnap, _rSnap] = await Promise.all([
                db.ref('vehicles').once('value'),
                db.ref('vehicleShifts').once('value'),
                db.ref('rides').orderByChild('pickupTimestamp').startAt(_rWS).endAt(_rWE).once('value')
            ]);
            _aarCache.vehicles = _vSnap.val() || {};
            _aarCache.shifts = _sSnap.val() || {};
            _aarCache.rides = [];
            _rSnap.forEach(c => { _aarCache.rides.push({ ...c.val(), firebaseId: c.key }); });
            _aarCache.ts = _now648;
            console.log(`📦 v6.63.648: autoAssignRide Cache-Miss — ${_aarCache.rides.length} Rides, ${Object.keys(_aarCache.vehicles).length} Fahrzeuge geladen`);
        } else {
            console.log(`⚡ v6.63.648: autoAssignRide Cache-Hit (${Math.round((_now648 - _aarCache.ts)/1000)}s alt)`);
        }
        // v6.63.649: Settings-Cache (5 Min TTL)
        const _settingsCacheHit = (_aarCache.settingsTs && (_now648 - _aarCache.settingsTs) < _AAR_SETTINGS_TTL);
        if (!_settingsCacheHit) {
            const [_pSnap, _prSnap, _pmSnap, _obdSnap] = await Promise.all([
                db.ref('settings/vehiclePriorities').once('value'),
                db.ref('settings/pricing').once('value'),
                db.ref('settings/vehiclePrioMalus').once('value'),
                db.ref('settings/optimizationByDay').once('value')
            ]);
            _aarCache.priorities = _pSnap.val() || {};
            _aarCache.pricing = _prSnap.val() || {};
            _aarCache.prioMalus = _pmSnap.val() || {};
            _aarCache.optByDay = _obdSnap.val() || {};
            _aarCache.settingsTs = _now648;
        }
        const vehicles = _aarCache.vehicles;
        const shiftsData = _aarCache.shifts;
        const vehiclePriorities = _aarCache.priorities;
        const vehiclePrioMalus = _aarCache.prioMalus;
        const optimizationByDay = _aarCache.optByDay;
        const pricingSettings = _aarCache.pricing;
        const allRides = _aarCache.rides;

        // 🔧 v6.38.34: PFLICHT — Duration muss vorhanden sein! Kein Fallback auf 20 Min!
        if (!rideData.duration && !rideData.estimatedDuration) {
            console.warn(`⚠️ autoAssignRide: Fahrt ${rideId} hat KEINE Duration! Versuche Neuberechnung...`);
            if (rideData.pickupLat && rideData.destinationLat) {
                try {
                    const _routeResult = await calculateTelegramRoutePrice({
                        pickupLat: rideData.pickupLat, pickupLon: rideData.pickupLon,
                        destinationLat: rideData.destinationLat, destinationLon: rideData.destinationLon,
                        datetime: rideData.pickupTimestamp ? new Date(rideData.pickupTimestamp).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' }) : null
                    });
                    if (_routeResult && _routeResult.duration) {
                        console.log(`✅ Route nachberechnet: ${_routeResult.distance} km, ${_routeResult.duration} min, ${_routeResult.price}€`);
                        rideData.duration = _routeResult.duration;
                        rideData.estimatedDuration = _routeResult.duration;
                        rideData.distance = _routeResult.distance;
                        rideData.estimatedDistance = _routeResult.distance;
                        rideData.price = _routeResult.price;
                        rideData.estimatedPrice = _routeResult.price;
                        // In Firebase speichern damit die Daten nicht nochmal fehlen
                        await db.ref(`rides/${rideId}`).update({
                            duration: _routeResult.duration, estimatedDuration: _routeResult.duration,
                            distance: _routeResult.distance, estimatedDistance: _routeResult.distance,
                            price: _routeResult.price, estimatedPrice: _routeResult.price
                        });
                    } else {
                        console.error(`❌ autoAssignRide: Route konnte NICHT berechnet werden für ${rideId} — KEINE ZUWEISUNG!`);
                        // 🆕 v6.63.491: Throttle — nur 1x pro Stunde pro Ride pushen
                        const _lastFail = rideData.autoAssignLastFailAtV454 || 0;
                        if (Date.now() - _lastFail > 3600000) {
                            await sendToAllAdmins(`⚠️ <b>Auto-Zuweisung FEHLGESCHLAGEN</b>\n\nFahrt ${rideId} hat keine Routendaten (Dauer/Entfernung) und OSRM-Berechnung ist fehlgeschlagen.\n\n❌ <b>Fahrt wird NICHT automatisch zugewiesen!</b>\nBitte manuell prüfen und zuweisen.`);
                        }
                        await _persistEarlyReturn('route-fail', 'OSRM/Google liefert keine Route');
                        return null;
                    }
                } catch (e) {
                    console.error(`❌ autoAssignRide: Route-Berechnung Fehler für ${rideId}:`, e.message);
                    const _lastFail = rideData.autoAssignLastFailAtV454 || 0;
                    if (Date.now() - _lastFail > 3600000) {
                        await sendToAllAdmins(`⚠️ <b>Auto-Zuweisung FEHLGESCHLAGEN</b>\n\nFahrt ${rideId}: Route-Berechnung Fehler: ${e.message}\n\n❌ <b>Fahrt wird NICHT automatisch zugewiesen!</b>\nBitte manuell prüfen und zuweisen.`);
                    }
                    await _persistEarlyReturn('route-exception', e.message);
                    return null;
                }
            } else {
                console.error(`❌ autoAssignRide: Fahrt ${rideId} hat KEINE Koordinaten UND keine Duration — KEINE ZUWEISUNG!`);
                const _lastFail = rideData.autoAssignLastFailAtV454 || 0;
                if (Date.now() - _lastFail > 3600000) {
                    await sendToAllAdmins(`⚠️ <b>Auto-Zuweisung FEHLGESCHLAGEN</b>\n\nFahrt ${rideId} hat weder Routendaten noch Koordinaten.\n\n❌ <b>Fahrt wird NICHT automatisch zugewiesen!</b>\nBitte manuell prüfen und zuweisen.`);
                }
                await _persistEarlyReturn('no-coords-no-duration', 'pickupLat/destLat fehlen');
                return null;
            }
        }

        // 🔧 v6.25.4: Firebase-Prioritäten nutzen (wie Browser), Fallback auf OFFICIAL_VEHICLES
        const getVehiclePrio = (vid) => {
            if (vehiclePriorities[vid] !== undefined) return vehiclePriorities[vid];
            return (OFFICIAL_VEHICLES[vid] || {}).priority || 99;
        };
        const priorityAdvantageMin = pricingSettings.priorityAdvantageMinutes || 0;
        // 🆕 v6.62.520: Pro-Wochentag Resolver — nimmt Pickup-Timestamp, liefert Settings
        // mit Tag-Override > globaler Override > globaler Default.
        const _IDX_TO_DAY_DE = ['So','Mo','Di','Mi','Do','Fr','Sa'];
        const getOptForTimestamp = (ts) => {
            const safeTs = Number(ts) || Date.now();
            const berlin = new Date(new Date(safeTs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
            const dayKey = _IDX_TO_DAY_DE[berlin.getDay()];
            const dayOv = (optimizationByDay || {})[dayKey] || {};
            const dayVehicleMalus = (dayOv.vehicleMalus && typeof dayOv.vehicleMalus === 'object') ? dayOv.vehicleMalus : {};
            return {
                day: dayKey,
                prioVorteil: Number.isFinite(dayOv.prioVorteil) ? dayOv.prioVorteil : priorityAdvantageMin,
                lastenmalus: Number.isFinite(dayOv.lastenmalus) ? dayOv.lastenmalus : (pricingSettings.lastverteilungMalusMinuten || 0),
                vehicleMalus: { ...vehiclePrioMalus, ...dayVehicleMalus }
            };
        };
        // 🆕 v6.62.518: Pro-Fahrzeug Malus-Override hat Vorrang vor (Prio-1) × prioVorteil
        // 🆕 v6.62.520: Wenn Pickup-Timestamp gegeben → Tag-Override beachten
        const getEffectivePrioMalus = (vid, pickupTs) => {
            const opt = pickupTs ? getOptForTimestamp(pickupTs) : null;
            const dayOv = opt ? opt.vehicleMalus[vid] : vehiclePrioMalus[vid];
            const ov = Number(dayOv);
            if (Number.isFinite(ov)) return ov;
            const pv = opt ? opt.prioVorteil : priorityAdvantageMin;
            return (getVehiclePrio(vid) - 1) * pv;
        };

        // 🔧 v6.15.10: Zwei Modi — Sofortfahrt (GPS first) vs. Vorbestellung (Schichtplan/Priorität)
        const now = new Date();
        const berlin = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
        const minutesUntilPickup = rideData.pickupTimestamp ? (rideData.pickupTimestamp - Date.now()) / 60000 : 0;
        // v6.62.222: Vorbestellungs-Schwelle = 15 + Anfahrt (nicht mehr pauschal 60).
        // Patrick (03.05. 18:04 zu Hasbargen): Buchung 18:01 fuer 19:00 (59 Min vor Pickup)
        // wurde sofort als 'assigned' gesetzt + FCM-Push. Soll: erst 15+Anfahrt vor Pickup
        // pushen — wie der onRideCreated-Pfad das schon macht (Zeile 18685).
        const _anfahrtMin = (rideData.drivingTimeToPickup && rideData.drivingTimeToPickup > 0) ? rideData.drivingTimeToPickup : 10;
        const isSofort = !rideData.pickupTimestamp || rideData.isJetzt === true || minutesUntilPickup <= (15 + _anfahrtMin);

        // 🔧 v6.25.4: Schicht-Check IMMER gegen Abholzeit prüfen, nicht aktuelle Uhrzeit!
        // Vorher: Sofortfahrten nutzten berlin (aktuelle Uhrzeit) → Fahrzeug bekam Fahrt außerhalb seiner Schicht
        const pickupDate = rideData.pickupTimestamp
            ? new Date(new Date(rideData.pickupTimestamp).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }))
            : berlin;
        const dateStr = pickupDate.getFullYear() + '-' + String(pickupDate.getMonth()+1).padStart(2,'0') + '-' + String(pickupDate.getDate()).padStart(2,'0');
        const timeStr = String(pickupDate.getHours()).padStart(2,'0') + ':' + String(pickupDate.getMinutes()).padStart(2,'0');
        const MAX_GPS_AGE = 10 * 60 * 1000;
        const dow = pickupDate.getDay();
        const passengers = rideData.passengers || 1;
        const candidates = [];

        // 🆕 v6.63.021 (Patrick 29.05. 20:42 "das System muss das erkennen"):
        //   Großraum-Reserve. Wenn am gleichen Tag noch eine andere Vorbestellung
        //   mit passengers >= 5 existiert (also nur die 8-Pax-Fahrzeuge können sie
        //   bedienen) UND das aktuell zu verteilende Ride passt in ein kleines
        //   Fahrzeug, kriegt ein 8-Pax-Fahrzeug einen Bias-Malus, damit es für die
        //   Großgruppen frei bleibt.
        const _LARGE_PAX_THRESHOLD = 5;
        const _LARGE_VEHICLE_CAPACITY = 8;
        // 🆕 v6.63.425 (Patrick 19.06. 16:34 Bridge "schau ob 'sofort' überall berücksichtigt wird"):
        //   'sofort' war hier nicht drin → Sitzplatz-Reservierungs-Check übersah Sofort-Rides.
        //   Nach v6.63.424 (Status-Normalisierung) bleibt 'sofort' u.U. länger stehen.
        const _activeStatusesForPaxReserve = ['new','sofort','vorbestellt','assigned','accepted','warteschlange','wartepool'];
        const _largeUnassignedSameDay = allRides.filter(r => {
            if (!r || !r.pickupTimestamp) return false;
            if (r.firebaseId === rideId) return false;
            if (!_activeStatusesForPaxReserve.includes(r.status)) return false;
            if ((r.passengers || 1) < _LARGE_PAX_THRESHOLD) return false;
            return berlinDateGlobal(r.pickupTimestamp) === dateStr;
        });
        const _largeReserveActive = _largeUnassignedSameDay.length > 0 && passengers < _LARGE_PAX_THRESHOLD;
        if (_largeReserveActive) {
            const _names = _largeUnassignedSameDay.slice(0, 3).map(r => `${r.customerName || '?'} (${r.passengers}P)`).join(', ');
            console.log(`   🚐 GROSSRAUM-RESERVE aktiv: ${_largeUnassignedSameDay.length} Großgruppen am ${dateStr} — Klein-Pax-Bias für 8-Pax-Fahrzeuge (${_names})`);
        }

        console.log(`🎯 Modus: ${isSofort ? 'SOFORTFAHRT (GPS schlägt alles)' : 'VORBESTELLUNG (Schichtplan + Priorität)'} | Abholzeit: ${dateStr} ${timeStr}`);
        console.log(`📋 PRÜFPROTOKOLL Auto-Zuweisung für Ride ${rideId}:`);
        console.log(`   📅 Datum: ${dateStr} | ⏰ Uhrzeit: ${timeStr} | 👥 Personen: ${passengers}`);
        console.log(`   🔧 Schichtpläne in DB: ${Object.keys(shiftsData).join(', ') || 'KEINE'}`);

        // 🆕 v6.25.6: vehicleScores für ALLE Fahrzeuge (auch abgelehnte) — für Prüfprotokoll in App
        const vehicleScores = {};

        for (const [vehicleId, info] of Object.entries(OFFICIAL_VEHICLES)) {
            console.log(`\n   ═══ Prüfe ${info.name} (${vehicleId}) ═══`);

            // 🆕 v6.63.378: Anschluss-Ziel/Delay-Fallback hat dieses Vehicle ausgeschlossen
            if (_excludeVehicleIds.includes(vehicleId)) {
                console.log(`   ⏭️ v6.63.378: ${info.name} excluded (Fallback aus voherigem Aufruf)`);
                vehicleScores[vehicleId] = { status: 'rejected', reason: 'Vorheriger Versuch fehlgeschlagen (Konflikt/Anschluss)', check: 'fallback-excluded' };
                continue;
            }

            // 🆕 v6.38.45: Fahrzeug-Level Deaktivierung prüfen
            // Admin kann in Firebase /vehicles/{id}/active = false setzen → komplett von Auto-Zuweisung ausgeschlossen
            const _vData = vehicles[vehicleId] || {};
            if (_vData.active === false || _vData.deactivated === true) {
                console.log(`   ❌ ${info.name}: Fahrzeug DEAKTIVIERT (active=${_vData.active}, deactivated=${_vData.deactivated})`);
                vehicleScores[vehicleId] = { status: 'rejected', reason: 'Fahrzeug deaktiviert', check: 'deactivated' };
                continue;
            }

            // 🆕 v6.38.97: Abgelehnte Fahrzeuge überspringen (Fahrer hat nicht bestätigt / abgelehnt)
            // 🔧 v6.62.771 (Patrick 16.05. 09:54): "Wie soll er die Fahrt bestaetigen?
            //   Er braucht doch gar keine Fahrt bestaetigen! Er wird doch gar nicht
            //   erst gefragt." — Bei VORBESTELLUNGEN wird der Fahrer erst kurz vor
            //   Losfahren per Push gefragt. Wenn rejectedVehicles aus einer frueheren
            //   Sofort-Iteration noch dranhaengt, blockiert es das Fahrzeug komplett —
            //   obwohl der Fahrer fuer die jetzt-anstehende Vorbestellung gar nicht
            //   gefragt wurde. Fix: rejectedVehicles-Filter NUR bei Sofortfahrten
            //   anwenden. Bei Vorbestellungen ignorieren.
            const _rejectedList = rideData._rejectedVehicles || rideData.rejectedVehicles || [];
            if (isSofort && _rejectedList.includes(vehicleId)) {
                console.log(`   ❌ ${info.name}: Vom Fahrer abgelehnt/nicht bestätigt (Sofort)`);
                vehicleScores[vehicleId] = { status: 'rejected', reason: 'Fahrer hat nicht bestätigt', check: 'driver_rejected' };
                continue;
            }

            if (info.capacity < passengers) {
                console.log(`   ❌ ${info.name}: Kapazität ${info.capacity} < ${passengers} Personen`);
                vehicleScores[vehicleId] = { status: 'rejected', reason: `Kapazität ${info.capacity} < ${passengers} Personen`, check: 'capacity' };
                continue;
            }

            // 🔧 v6.38.45: Sofortfahrt → nur PAUSE blockiert (Schichtplan entscheidet, nicht GPS!)
            if (isSofort) {
                const _isPaused = _vData.shift && _vData.shift.status === 'paused';
                if (_isPaused) {
                    console.log(`   ❌ ${info.name}: Fahrer in Pause — Sofortfahrt nicht möglich`);
                    vehicleScores[vehicleId] = { status: 'rejected', reason: 'Fahrer in Pause', check: 'paused' };
                    continue;
                }
            }

            // 🆕 v6.63.437 (Patrick 20.06. 10:50 + 11:18 Bridge: "LK ist offline, GPS
            //   1015 Min alt, trotzdem wurde Nicole Schindel zugewiesen — Shift status
            //   muss berücksichtigt werden"):
            //   Wenn Vehicle Shift heute 'ended' / 'auto-ended' UND Pickup <4h weg
            //   → Vehicle kommt nicht mehr in Zeit. Wochenplan-Eintrag ist statisch,
            //   aber wenn der Fahrer schon abgemeldet ist, ist die Wochenplan-Schicht
            //   für heute beendet. Auto-Assign skipped.
            try {
                const _shiftStatus = _vData.shift && _vData.shift.status;
                const _isEnded = _shiftStatus === 'ended' || _shiftStatus === 'auto-ended' || _shiftStatus === 'force-ended';
                const _endedAt = _vData.shift && (_vData.shift.endedAt || _vData.shift.autoEndedAt);
                const _todayBerlin = new Date().toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' });
                const _endedDateBerlin = _endedAt ? new Date(_endedAt).toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' }) : null;
                const _endedToday = _endedDateBerlin === _todayBerlin;
                const _pickupSoon = rideData.pickupTimestamp && (rideData.pickupTimestamp - Date.now()) < 4 * 60 * 60 * 1000;

                if (_isEnded && _endedToday && _pickupSoon) {
                    console.log(`   ❌ ${info.name}: Schicht heute ${_shiftStatus} (${new Date(_endedAt).toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin' })}), Pickup <4h → skip`);
                    vehicleScores[vehicleId] = {
                        status: 'rejected',
                        reason: `Schicht heute ${_shiftStatus} um ${new Date(_endedAt).toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' })} — Fahrer kommt nicht mehr in Zeit`,
                        check: 'shift-ended-today'
                    };
                    continue;
                }
            } catch (_endedErr) {
                console.warn('v6.63.437 Shift-Ended-Check Fehler:', _endedErr.message);
            }

            // 🆕 v6.63.439 (Patrick 20.06. 11:40 Bridge: "Rückfahrt zum Standort muss
            //   eigentlich auch noch als Punkt mit aufgenommen werden und nicht als
            //   freie Zeit"): RÜCKFAHRT-ZUR-BASIS BUSY-UNTIL.
            //   Wenn die letzte Ride auf diesem Vehicle einen Long-Distance-Drop hatte
            //   (z.B. Züssow), ist der Fahrer noch auf der Rückfahrt zur Heimbasis und
            //   NICHT verfügbar. Aktuell sah System nur 'Anfahrt zur nächsten' — wenn
            //   keine Folgefahrt existiert, war Vehicle scheinbar 'sofort frei nach Drop'.
            //   Bug-Fall LK Züssow heute: 09:00 Pickup → 09:50 Drop → 50 Min Rückfahrt
            //   nach Bahnhof Ahlbeck → erst 10:40 verfügbar, nicht 09:50.
            try {
                // Finde letzte aktive Ride auf diesem Vehicle (pickupTs <= now + 24h)
                let _lastRide = null;
                for (const r of allRides) {
                    if (r.firebaseId === rideId) continue;
                    if (r.assignedVehicle !== vehicleId && r.vehicleId !== vehicleId) continue;
                    if (['cancelled','deleted','storniert'].includes(r.status)) continue;
                    if (!r.pickupTimestamp) continue;
                    // Nur Rides VOR newPickup
                    if (r.pickupTimestamp >= rideData.pickupTimestamp) continue;
                    if (!_lastRide || r.pickupTimestamp > _lastRide.pickupTimestamp) {
                        _lastRide = r;
                    }
                }
                if (_lastRide && homeCoords && homeCoords.lat && homeCoords.lon) {
                    const _lastDestLat = _lastRide.destCoords?.lat || _lastRide.destinationLat;
                    const _lastDestLon = _lastRide.destCoords?.lon || _lastRide.destinationLon;
                    const _lastDurMs = ((_lastRide.duration || _lastRide.estimatedDuration || 20)) * 60000;
                    let _lastEndMs;
                    if (_lastRide.completedAt) {
                        _lastEndMs = _lastRide.completedAt;
                    } else {
                        _lastEndMs = _lastRide.pickupTimestamp + _lastDurMs + bufferMs;
                    }
                    // Rückfahrt zum Standort
                    let _returnMin = null;
                    if (_lastDestLat && _lastDestLon) {
                        _returnMin = await osrmDrivingMin(_lastDestLat, _lastDestLon, homeCoords.lat, homeCoords.lon);
                    }
                    const _returnMs = (_returnMin !== null) ? (_returnMin * 60000) : _rueckfahrtMinMs;
                    const _busyUntil = _lastEndMs + _returnMs;
                    if (rideData.pickupTimestamp < _busyUntil) {
                        const _busyTimeStr = new Date(_busyUntil).toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });
                        const _lastCity = (_lastRide.destination || '').split(',').pop()?.trim() || (_lastRide.destination || '?').slice(0, 30);
                        console.log(`   ❌ ${info.name}: noch auf Rückfahrt von ${_lastCity}, frei ab ${_busyTimeStr}`);
                        vehicleScores[vehicleId] = {
                            status: 'rejected',
                            reason: `Rückfahrt von ${_lastCity} bis ${_busyTimeStr} (${_returnMin || '?'} Min)`,
                            check: 'busy-back-to-base',
                            busyUntil: _busyUntil,
                            returnFromCity: _lastCity,
                            returnMin: _returnMin
                        };
                        continue;
                    }
                }
            } catch (_returnErr) {
                console.warn('v6.63.439 Rückfahrt-zur-Basis-Check Fehler:', _returnErr.message);
            }

            // 🔧 v6.38.27: Vier-Augen-Prinzip bei Zuweisung
            const _shiftInfo = getShiftInfoDetailed(vehicleId, shiftsData, dateStr, timeStr);
            const _shiftOk = isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr);
            const _verifyOk = verifyVehicleShiftIndependent(vehicleId, shiftsData, dateStr, timeStr);

            // v6.62.249: live shift.status='active' = Pflicht bei Sofortfahrten,
            // Wochenplan wird dann IGNORIERT. Patrick (10:42): "wer JETZT online ist
            // soll fahren — Wochenplan egal bei Sofortfahrten".
            //
            // 🔧 v6.62.723 (Patrick 17.05. 07:38): Vorbestellungen sind STRIKT Wochenplan-Pflicht.
            // KEIN Live-Override mehr. Wenn das Fahrzeug am Pickup-Datum/Zeit nicht im
            // Wochenplan steht, darf es KEINE Vorbestellung uebernehmen — auch wenn der
            // Fahrer JETZT live online ist (live-Status sagt nichts ueber Verfuegbarkeit
            // am zukuenftigen Pickup-Zeitpunkt; Stale 'status=active' aus alter Schicht
            // hat sonst die Johannknecht-Vorbestellung an pw-sk-222 ohne Sonntag-Dienst
            // gegeben — siehe Ghost-Fall 17.05.).
            const _isShiftActive = _vData.shift && _vData.shift.status === 'active';

            // 🆕 v6.62.897 (Patrick 23.05. 15:07): forceEnded ist HARD BLOCK.
            // 🔧 v6.63.592 (Patrick 03.07. 19:22): forceEnded gilt nur HEUTE, nicht für Zukunft.
            // 🔧 v6.63.605 (Patrick 04.07. 12:00): forceEnded gilt nur wenn es AM GLEICHEN TAG
            //   passiert ist (forceEndedAt == heute). Ein forceEnded vom 02.07. darf den 04.07.
            //   NICHT blockieren — der Wochenplan entscheidet für neue Tage.
            //   forceEndedAt: 2.7.2026 08:25 blockierte Samstag 4.7.2026 → Bug.
            if (_vData.shift && _vData.shift.forceEnded === true) {
                const _todayBerlin = new Date().toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' });
                const _feAt = _vData.shift.forceEndedAt || _vData.shift.endedAt || 0;
                const _feDateBerlin = _feAt
                    ? new Date(_feAt).toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' })
                    : _todayBerlin;
                const _feToday = _feDateBerlin === _todayBerlin;
                if (!_feToday) {
                    // forceEnded von anderem Tag → ignorieren, Wochenplan entscheidet
                    console.log(`   ⚠️ v6.63.605 ${info.name}: forceEnded vom ${_feDateBerlin} ignoriert (nicht heute ${_todayBerlin}) — Wochenplan entscheidet`);
                } else {
                    const _isTodayRide = dateStr === _todayBerlin;
                    if (isSofort || _isTodayRide) {
                        console.log(`   ❌ ${info.name}: Schicht heute force-beendet (${new Date(_feAt).toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' })}) — ${isSofort ? 'Sofort' : 'Heute'}`);
                        vehicleScores[vehicleId] = { status: 'rejected', reason: 'Schicht heute durch Admin beendet (forceEnded)', check: 'forceEnded' };
                        continue;
                    }
                    // Anderer Tag → forceEnded ignorieren, Wochenplan entscheidet
                    console.log(`   ⚠️ v6.63.605 ${info.name}: forceEnded heute, aber Vorbestellung am ${dateStr} → Wochenplan entscheidet`);
                }
            }

            if (isSofort) {
                // Sofortfahrt — nur live aktive Schicht zählt
                if (!_isShiftActive) {
                    console.log(`   ❌ ${info.name}: Sofortfahrt — Schicht nicht live aktiv (status=${_vData.shift?.status || 'kein shift'})`);
                    vehicleScores[vehicleId] = { status: 'rejected', reason: 'Sofortfahrt: Schicht nicht live aktiv', check: 'live-shift-required', shiftStatus: _vData.shift?.status || null };
                    continue;
                }
                // 🔧 v6.63.549: "Nur dieser Tag"-Override gilt auch fuer Sofortfahrten.
                // Patrick 29.06. "Nur dieser Tag wird gar nicht akzeptiert": live-aktive
                // Fahrzeuge haben ihr Schicht-Fenster per Tag-Override eingeschraenkt →
                // das muss auch bei Sofortfahrten respektiert werden.
                const _todayShiftEntry = (shiftsData[vehicleId] || {})[dateStr];
                if (_todayShiftEntry) {
                    if (_todayShiftEntry.active === false) {
                        console.log(`   ❌ ${info.name}: Sofortfahrt — Nur-Heute-Override: OFFLINE fuer ${dateStr}`);
                        vehicleScores[vehicleId] = { status: 'rejected', reason: 'Nur-Heute-Override: offline', check: 'today-override-inactive' };
                        continue;
                    }
                    if (!isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr)) {
                        const _tWindow = `${_todayShiftEntry.startTime || '?'}–${_todayShiftEntry.endTime || '?'}`;
                        console.log(`   ❌ ${info.name}: Sofortfahrt — Nur-Heute-Override ${_tWindow}, ${timeStr} ausserhalb Fenster`);
                        vehicleScores[vehicleId] = { status: 'rejected', reason: `Nur-Heute-Override: ${timeStr} ausserhalb ${_tWindow}`, check: 'today-override-time' };
                        continue;
                    }
                }
                console.log(`   ✅ ${info.name}: Sofortfahrt — Schicht live aktiv`);
            } else {
                // Vorbestellung — Wochenplan ist PFLICHT, kein Override mehr.
                if (!_shiftOk || !_verifyOk.ok) {
                    if (_shiftOk !== _verifyOk.ok) console.warn(`   ⚠️ DISKREPANZ ${info.name}: isVehicleInShift=${_shiftOk}, verify=${_verifyOk.ok} (${_verifyOk.reason})`);
                    console.log(`   ❌ ${info.name}: Vorbestellung — Kein Dienst am ${dateStr} um ${timeStr} (${_verifyOk.reason})`);
                    vehicleScores[vehicleId] = { status: 'rejected', reason: _verifyOk.reason || _shiftInfo.reason || 'Kein Dienst', check: 'shift', shiftDetails: _shiftInfo };
                    continue;
                }
                // 🔧 v6.63.568 (01.07. IK-222/MY-222-Bug): Wenn Vorbestellung HEUTE innerhalb
                // 4h Vorlauf ist UND das Fahrzeug shift.status='auto-ended' hat (Heartbeat-Timeout),
                // dann blockieren. Ein auto-ended Fahrzeug hat keinen aktiven Fahrer — auch wenn
                // der Wochenplan es erlaubt. Fahrzeuge mit live-aktiver Schicht bekommen Vorrang.
                // Hintergrund: Patrick in MY-222 eingeloggt, IK-222 per Heartbeat-Timeout auto-ended
                // → scheduledAutoAssign weist Fahrten trotzdem IK-222 zu → Patrick sieht sie nicht.
                //
                // 🆕 v6.63.672 (Patrick 10.07. 11:27 Koch-Fall): 'ended' + 'force-ended'
                //   sollten geblockt werden. Aber v6.63.677 (Patrick 10.07. 15:48 Bridge:
                //   "MY ist eingeteilt ab 5.45, warum kein Fahrzeug"): HART geblockt war
                //   ZU STRENG. Patrick hatte heute Nachmittag seine MY-Schicht ended, das
                //   auto-assign für morgen 07:50 lief danach → MY komplett aus dem Pool.
                //   Aber morgen früh startet er ja wieder Schicht (steht im Wochenplan).
                //
                //   Neue Regel:
                //   - 'force-ended' → HART blocken (bewusst gesetzt, kein Fahrer geplant)
                //   - 'ended' / 'auto-ended' + Pickup <4h → blocken (unmittelbar → sonst hängt)
                //   - 'ended' / 'auto-ended' + Pickup >=4h → durchlassen (Fahrer kann morgen
                //     wieder in Schicht, Wochenplan ist Autorität für Vorbestellungen)
                const _msUntilPickup = rideData.pickupTimestamp - Date.now();
                const _shiftStatus = _vData.shift && _vData.shift.status;
                if (_shiftStatus === 'force-ended') {
                    console.log(`   ❌ ${info.name}: Schicht 'force-ended' — hart blockiert`);
                    vehicleScores[vehicleId] = { status: 'rejected', reason: 'Schicht force-ended, kein Fahrer aktiv', check: 'shift-force-ended' };
                    continue;
                }
                const _shiftInactive = _shiftStatus === 'ended' || _shiftStatus === 'auto-ended';
                if (_shiftInactive && _msUntilPickup < 4 * 60 * 60 * 1000 && _msUntilPickup > -30 * 60 * 1000) {
                    console.log(`   ❌ ${info.name}: Vorbestellung in <4h — shift.status=${_shiftStatus}, kein aktiver Fahrer`);
                    vehicleScores[vehicleId] = { status: 'rejected', reason: `Schicht ${_shiftStatus}, kein Fahrer aktiv`, check: 'shift-inactive-near-pickup' };
                    continue;
                }
            }

            // 🆕 v6.26.0: Schichtende-Prüfung — Fahrtende darf Schicht nicht überschreiten
            // 🔧 v6.41.78: Bei manuell gestarteter Schicht (shift.status='active') überspringen.
            // Sonst blockiert der Wochenplan-Schichtende eine aktive Überstunden-Schicht:
            // Fahrer arbeitet länger als geplant → Fahrtende > Plan-Ende → trotz aktiver Schicht
            // "übersprungen". Der manuelle Schichtstart override'd oben bereits den Plan-Schicht-
            // Check; ohne denselben Override hier bleibt das Fahrzeug unerreichbar.
            const _rideDurMin = rideData.duration || rideData.estimatedDuration || 20;
            const _rideEndMs = rideData.pickupTimestamp + _rideDurMin * 60000;
            const _rideEndBerlin = new Date(new Date(_rideEndMs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
            const _rideEndTimeStr = String(_rideEndBerlin.getHours()).padStart(2,'0') + ':' + String(_rideEndBerlin.getMinutes()).padStart(2,'0');
            const _shiftEnd = getShiftEndTime(vehicleId, shiftsData, dateStr, timeStr);
            if (_shiftEnd && _rideEndTimeStr > _shiftEnd && !_isShiftActive) {
                console.log(`   ❌ ${info.name}: Fahrtende ${_rideEndTimeStr} > Schichtende ${_shiftEnd} → übersprungen`);
                vehicleScores[vehicleId] = { status: 'shift-end', reason: `Fahrtende ${_rideEndTimeStr} > Schichtende ${_shiftEnd}`, check: 'shift-end', shiftEnd: _shiftEnd, rideEndTime: _rideEndTimeStr, overMinutes: Math.round((_rideEndMs - new Date(dateStr + 'T' + _shiftEnd + ':00').getTime()) / 60000) };
                continue;
            }
            if (_shiftEnd && _rideEndTimeStr > _shiftEnd && _isShiftActive) {
                console.log(`   ⚠️ ${info.name}: Fahrtende ${_rideEndTimeStr} > Plan-Schichtende ${_shiftEnd}, aber Fahrer hat Schicht aktiv → erlaubt`);
            }

            // 🔧 v6.38.50 BUG-05 FIX: accepted + on_way + picked_up blockieren!
            // Fahrer der gerade zum Kunden fährt (accepted) darf keine zweite Fahrt bekommen
            // v6.62.43: + arrived als busy — Fahrer wartet vor Ort auf Kunde
            // 🆕 v6.62.319: Patrick (06.05. 07:00 Hasbargen 22:00): Tesla=Patrick war aktuell
            // besetzt → wurde fuer Vorbestellung um 22:00 NICHT als Kandidat eingeplant,
            // obwohl er bis 22:00 laengst fertig waere. Bug: pauschaler busyRide-Filter
            // blockierte das Fahrzeug komplett. Fix: bei VORBESTELLUNGEN den Filter NICHT
            // anwenden — der Zeitkonflikt-Check unten (Z.808+) prueft sauber ob die
            // bestehende Fahrt vor dem neuen Pickup endet.
            // 🆕 v6.62.362: Phase-1-3-Zonen-Modell (Patrick: 'wenn ich ne Stunde vorher
            // einen Termin annehme bin ich eine Stunde lang blockiert, das ist Quatsch').
            // accepted-Vorbestellung blockiert nur wenn now in der Losfahr-Zone ist:
            //   blockiertAb = pickup - max(15 Min, drivingTimeToPickup + 3 Min Boarding)
            // Vorher: Fahrzeug bleibt FREI fuer Sofort-Anfragen, der Zeitkonflikt-Check
            // unten (Z.819+) prueft sauber ob Sofort + Rueckfahrt vor blockiertAb fertig wird.
            const _nowMs = Date.now();
            const _isInLosfahrZone = (r) => {
                if (!r || !r.pickupTimestamp) return true; // ohne Timestamp lieber blockieren (sicher)
                const _anfahrtMin = (typeof r.drivingTimeToPickup === 'number' && r.drivingTimeToPickup > 0)
                    ? r.drivingTimeToPickup : 10;
                const _blockBufMin = Math.max(15, _anfahrtMin + 3);
                return (r.pickupTimestamp - _nowMs) <= (_blockBufMin * 60 * 1000);
            };
            const busyRide = allRides.find(r =>
                (r.vehicleId === vehicleId || r.assignedTo === vehicleId || r.assignedVehicle === vehicleId) &&
                (r.status === 'on_way' || r.status === 'picked_up' || r.status === 'arrived'
                  || (isSofort && r.status === 'accepted' && _isInLosfahrZone(r))
                  || (isSofort && r.status === 'assigned' && _isInLosfahrZone(r)))
            );
            if (busyRide && isSofort) {
                // 🆕 v6.63.401 (Patrick 17.06. 15:47-15:48 Bridge: "Fahrer kann Fahrten
                //   sammeln, GPS-mäßig nah ist → Angebot bekommen, selber sortieren
                //   ob er 2 Min länger braucht"):
                //   Statt komplett rejecten: prüfen ob Vehicle GPS-nah und aktuelle
                //   Fahrt fast fertig (status=picked_up = bald aussteigen).
                //   Wenn ja → als 'soon-available' Kandidat aufnehmen mit Hinweis im Push.
                //   Fahrer entscheidet selber per Accept/Reject.
                const _hasRecentGps = _vData.lat && _vData.lon && _vData.timestamp && (Date.now() - _vData.timestamp) < 5*60000;
                const _isFinishing = busyRide.status === 'picked_up'; // fährt aktuell Gast zum Ziel
                const _veryNearGps = _hasRecentGps && rideData.pickupCoords && (() => {
                    try {
                        const d = distanceKm(_vData.lat, _vData.lon, rideData.pickupCoords.lat, rideData.pickupCoords.lon);
                        return d < 5.0;
                    } catch (_) { return false; }
                })();
                if (_isFinishing && _veryNearGps) {
                    console.log(`   🤝 v6.63.401 ${info.name}: BUSY aber GPS-nah + fast fertig → biete trotzdem an, Fahrer entscheidet`);
                    vehicleScores[vehicleId] = {
                        status: 'soon-available',
                        reason: `Aktuell besetzt mit ${busyRide.customerName || '?'} (${busyRide.status}) — GPS nah, biete trotzdem an`,
                        check: 'busy-but-offered',
                        blockingRideCustomer: busyRide.customerName,
                        blockingRideStatus: busyRide.status,
                        offerReason: 'driver-decides'
                    };
                    // Vehicle als Kandidat aufnehmen — mit Marker dass Fahrer entscheidet
                    if (rideData.pickupCoords && rideData.pickupCoords.lat && rideData.pickupCoords.lon) {
                        const dist = distanceKm(_vData.lat, _vData.lon, rideData.pickupCoords.lat, rideData.pickupCoords.lon);
                        candidates.push({ vehicleId, name: info.name, distance: dist, priority: getVehiclePrio(vehicleId), telegramChatId: driver?.telegramChatId, posSource: 'GPS', soonAvailable: true });
                        console.log(`   🤝 ${info.name}: angeboten (GPS ${dist.toFixed(1)} km, finished gleich)`);
                    }
                    continue;
                }
                console.log(`   ❌ ${info.name}: Aktuell besetzt (Sofort)`);
                vehicleScores[vehicleId] = { status: 'busy', reason: `Aktuell besetzt: ${busyRide.customerName || '?'} (${busyRide.status})`, check: 'busy', blockingRideCustomer: busyRide.customerName, blockingRideStatus: busyRide.status };
                continue;
            }
            if (busyRide && !isSofort) {
                // Vorbestellung: nicht ausschliessen — Zeitkonflikt-Check unten entscheidet
                // ob die laufende Fahrt vor dem neuen Pickup endet.
                console.log(`   ℹ️ ${info.name}: aktuell besetzt mit ${busyRide.customerName || '?'} (${busyRide.status}) — pruefe Zeitkonflikt fuer Vorbestellung`);
            }

            // Zeitkonflikt mit bestehenden Fahrten prüfen
            if (rideData.pickupTimestamp) {
                const newPickup = rideData.pickupTimestamp;
                const newDur = (rideData.duration || rideData.estimatedDuration || 20) * 60000;
                // 🆕 v6.63.450 (Patrick 21.06. 06:46 Bridge: "Karenz vielleicht gar
                //   nicht nötig... System hat nur verkehrt gerechnet"): Versteckte 2-3 Min
                //   Default-Buffer entfernt. Nutzt jetzt rein settings/pricing-Werte.
                //   Patrick hat 1+1=2 Min explizit gesetzt; wenn settings fehlen, sind 0 Min
                //   sicherer (sichtbar) als 4 Min verstecktes Polster.
                const boardingTime = pricingSettings.boardingTime != null ? pricingSettings.boardingTime : 0;
                const alightingTime = pricingSettings.alightingTime != null ? pricingSettings.alightingTime : 0;
                const bufferMs = (boardingTime + alightingTime) * 60000;
                const _rueckfahrtMaxMs = (pricingSettings.standortRueckkehrPufferMinuten || 30) * 60000;
                const _rueckfahrtMinMs = 5 * 60000; // Minimum 5 Min Rückfahrt

                // 🔧 v6.33.8: DYNAMISCHER Rückfahrt-Puffer statt pauschal 30 Min!
                // v6.63.171 (Patrick 05.06.07:21): Rueckfahrt jetzt ueber OSRM, KEIN Cap 30 Min mehr.
                // 🆕 v6.63.438 (Patrick 20.06. 11:29 Bridge: "GPS-Position muss berechnet
                //   werden, oder zumindest dass die Rückfahrt auch berechnet wird"):
                //   Live-GPS-Position des Vehicles speichern (falls <15 Min alt) für
                //   Anfahrt-Schätzung. Reine Info im vehicleScores — kein Verhalten-Change.
                //   So sieht Patrick im Resolver: 'MY222 Live 23 km von Pickup' statt
                //   nur 'aus Wochenplan-Heimat berechnet'.
                let _liveGpsDistKm = null;
                let _liveGpsAgeMin = null;
                try {
                    const _vGps = _vData && (_vData.gps || _vData);
                    const _vLat = _vGps && (_vGps.lat || _vGps.latitude);
                    const _vLon = _vGps && (_vGps.lon || _vGps.longitude);
                    const _vGpsTs = (_vGps && (_vGps.timestamp || _vGps.lastUpdate)) || (_vData && _vData.timestamp);
                    const newPickupLatTmp = rideData.pickupCoords?.lat || rideData.pickupLat;
                    const newPickupLonTmp = rideData.pickupCoords?.lon || rideData.pickupLon;
                    if (_vLat && _vLon && _vGpsTs && newPickupLatTmp && newPickupLonTmp) {
                        const _ageMs = Date.now() - Number(_vGpsTs);
                        _liveGpsAgeMin = Math.round(_ageMs / 60000);
                        if (_liveGpsAgeMin < 15) {
                            _liveGpsDistKm = +gpsDistanceKm(_vLat, _vLon, newPickupLatTmp, newPickupLonTmp).toFixed(1);
                        }
                    }
                } catch (_gpsLogErr) { /* defensive */ }
                const homeCoords = getVehicleHomeCoords(vehicleId, shiftsData, dateStr, timeStr);
                async function calcReturnMsAsync(ride) {
                    const destLat = ride.destCoords?.lat || ride.destinationLat;
                    const destLon = ride.destCoords?.lon || ride.destinationLon;
                    if (!destLat || !destLon || !homeCoords?.lat || !homeCoords?.lon) return _rueckfahrtMaxMs;
                    const osrmMin = await osrmDrivingMin(destLat, destLon, homeCoords.lat, homeCoords.lon);
                    if (osrmMin == null) return _rueckfahrtMaxMs;
                    return Math.max(_rueckfahrtMinMs, osrmMin * 60000); // KEIN Max-Cap mehr
                }

                // 🔧 v6.33.7: Sofortfahrt — KEIN Rückfahrt-Puffer für die neue Fahrt!
                // Das Fahrzeug fährt direkt vom Ziel der Sofortfahrt zum nächsten Abholort.
                // 🆕 v6.62.542: Patrick (10.05.): "die Index-HTML hat das eigentlich über
                // den Konfliktchecker schon sehr, sehr gut gelöst. Entweder zurück zum
                // Standort oder halt zum nächsten Auftragspunkt." — Statt pauschalem
                // Rueckfahrt-zur-Basis-Puffer (max 30 Min) jetzt ECHTE Chain-Leerfahrt
                // vom Ziel der einen zur Pickup der naechsten Fahrt. Mirrors die Logik
                // die autoResolveConflicts (Phase 2) bereits seit v6.62.323 verwendet.
                // Anjas Fall: prev.dest war 35 Min von new.pickup entfernt, calcReturnMs
                // gab aber nur 30 Min (capped) zurueck → Konflikt nicht erkannt → Auto
                // wurde zugewiesen, kam zu spaet.
                const newPickupLat = rideData.pickupCoords?.lat || rideData.pickupLat;
                const newPickupLon = rideData.pickupCoords?.lon || rideData.pickupLon;
                const newDestLat = rideData.destCoords?.lat || rideData.destinationLat;
                const newDestLon = rideData.destCoords?.lon || rideData.destinationLon;
                // v6.63.171: .some() → for-of mit OSRM-await fuer echte Chain-/Rueckfahrt-Berechnung
                let _conflictRide = null;
                let _conflictMath = null; // v6.63.431
                let hasTimeConflict = false;
                for (const r of allRides) {
                    if (r.firebaseId === rideId) continue;
                    if (r.vehicleId !== vehicleId && r.assignedTo !== vehicleId && r.assignedVehicle !== vehicleId) continue;
                    if (!r.pickupTimestamp) continue;
                    if (['deleted','cancelled','storniert','cancelled_pending_driver','completed'].includes(r.status)) continue;
                    const rDur = (r.duration || r.estimatedDuration || 20) * 60000;
                    const rStart = r.pickupTimestamp;
                    const rDestLat = r.destCoords?.lat || r.destinationLat;
                    const rDestLon = r.destCoords?.lon || r.destinationLon;
                    const rPickupLat = r.pickupCoords?.lat || r.pickupLat;
                    const rPickupLon = r.pickupCoords?.lon || r.pickupLon;

                    let rEnd, newEnd;
                    let _chainMin = null; // v6.63.431: außerhalb des if-Blocks für späteres _conflictMath
                    if (rStart < newPickup) {
                        // Bestehende Fahrt r ist Vorgaenger der neuen Fahrt.
                        // r.dest → new.pickup als ECHTE Leerfahrt via OSRM.
                        _chainMin = await osrmDrivingMin(rDestLat, rDestLon, newPickupLat, newPickupLon);
                        const _chainMs = (_chainMin !== null) ? (_chainMin * 60000) : (await calcReturnMsAsync(r));
                        rEnd = rStart + rDur + bufferMs + _chainMs;
                        newEnd = newPickup + newDur + bufferMs;
                    } else {
                        // Neue Fahrt ist Vorgaenger der bestehenden Fahrt r.
                        _chainMin = await osrmDrivingMin(newDestLat, newDestLon, rPickupLat, rPickupLon);
                        const _chainMs = (_chainMin !== null) ? (_chainMin * 60000) : (isSofort ? 0 : (await calcReturnMsAsync(rideData)));
                        newEnd = newPickup + newDur + bufferMs + _chainMs;
                        rEnd = rStart + rDur + bufferMs;
                    }
                    // 🆕 v6.63.314 (Patrick 13.06. 07:38 Bridge: 'Nayef-Fahrt nicht auto
                    //   zugeteilt obwohl Marion knapp davor endet'): Karenz-Toleranz 5 Min
                    //   einbauen (Patrick-Regel '2 Min zu spaet ist egal, alles unter 5 Min
                    //   geht'). Ohne Karenz blieben knappe Anschluesse wie Marion 07:30 → Nayef
                    //   07:40 (rEnd 07:43, only 3 Min Verspaetung) in Wartepool stehen.
                    // 🔄 v6.63.435 (Patrick 20.06. 07:30 Bridge: "Marion hängt in der Luft,
                    //   ich bin online, einer muss doch die Fahrt machen. Das kann nicht sein
                    //   dass die rumliegt nur weil eine andere nicht geschafft wird"):
                    //   Karenz SYMMETRISCH machen. Bisher galt 5-Min-Toleranz nur wenn r
                    //   Vorgaenger war (newPickup darf 5 Min vor rEnd liegen). Wenn new
                    //   Vorgaenger ist (newEnd 3 Min > rStart), griff Karenz NICHT → Marion-
                    //   Fall blockiert. Jetzt: rStart + karenzMs < newEnd statt rStart < newEnd.
                    //   Dadurch akzeptiert das System bis zu 5 Min Verspaetung zur Folgefahrt.
                    // 🔄 v6.63.448 (Patrick 20.06. 19:29-19:30 Bridge: "10 Minuten als Toleranz
                    //   einbauen. Außer wenn die Destination Bahnhof ist — dann max 5 Min"):
                    //   Karenz pro Folgefahrt: Standard 10 Min, 5 Min wenn ZIEL der Folgefahrt
                    //   ein Bahnhof/Flughafen ist (Zug nicht verpassen).
                    //   Anwendung Brunke 21:00: 18 Min Anfahrt → 8 Min zu spät zu Gudrun Samst
                    //   (Ziel Neue Str 3B, kein Bahnhof) → 8 < 10 → akzeptiert ✅
                    const _isBahnhofDest = (s) => /bahnhof|flughafen|\bhbf\b/i.test(s || '');
                    const _karenzNewAsFolge = (_isBahnhofDest(rideData.destination) ? 5 : 10) * 60000;
                    const _karenzRAsFolge   = (_isBahnhofDest(r.destination)         ? 5 : 10) * 60000;
                    // v6.63.431 (Patrick 20.06. 06:56 Bridge: "Dann will ich aber auch sehen
                    //   wieviel berechnet wird"): bei Konflikt die exakten Berechnungswerte
                    //   im vehicleScores speichern, damit UI zeigen kann WARUM.
                    if ((newPickup + _karenzNewAsFolge < rEnd) && (rStart + _karenzRAsFolge < newEnd)) {
                        _conflictRide = r;
                        hasTimeConflict = true;
                        // Mathe-Detail für UI-Anzeige
                        if (rStart < newPickup) {
                            // r war Vorgänger: r-end → new-pickup
                            _conflictMath = {
                                rolle: 'r-vorgaenger',
                                rEnd: new Date(rEnd).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' }),
                                newPickup: new Date(newPickup).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' }),
                                overlapMin: Math.round((rEnd - newPickup) / 60000),
                                chainMin: Math.round(_chainMin || 0)
                            };
                        } else {
                            // new war Vorgänger: new-end → r-pickup
                            _conflictMath = {
                                rolle: 'new-vorgaenger',
                                newEnd: new Date(newEnd).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' }),
                                rStart: new Date(rStart).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' }),
                                overlapMin: Math.round((newEnd - rStart) / 60000),
                                chainMin: Math.round(_chainMin || 0)
                            };
                        }
                        break;
                    }
                }
                if (hasTimeConflict) {
                    const _cTime = _conflictRide ? new Date(_conflictRide.pickupTimestamp).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' }) : '?';
                    // 🔧 v6.38.53: busyUntil berechnen — wann ist das Fahrzeug wieder frei? (v6.63.171: OSRM)
                    let _cBusyUntil = _cTime;
                    if (_conflictRide) {
                        const _cDur = (_conflictRide.duration || _conflictRide.estimatedDuration || 20) * 60000;
                        const _cReturnMs = await calcReturnMsAsync(_conflictRide);
                        const _cEndMs = _conflictRide.pickupTimestamp + _cDur + bufferMs + _cReturnMs;
                        _cBusyUntil = new Date(_cEndMs).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' });
                    }
                    // v6.63.431: reason mit Mathe-Detail anreichern
                    let _reasonExt = `Zeitkonflikt: ${_conflictRide?.customerName || '?'} um ${_cTime}`;
                    if (_conflictMath && _conflictMath.overlapMin > 0) {
                        if (_conflictMath.rolle === 'new-vorgaenger') {
                            _reasonExt += ` (rechnet ${_conflictMath.newEnd} fertig, ${_conflictMath.chainMin} Min Anfahrt → ${_conflictMath.overlapMin} Min zu spät)`;
                        } else {
                            _reasonExt += ` (rechnet ${_conflictMath.rEnd} fertig, ${_conflictMath.chainMin} Min Anfahrt → ${_conflictMath.overlapMin} Min zu spät)`;
                        }
                    }
                    console.log(`   ⚠️ ${info.name}: ${_reasonExt}, frei ab ${_cBusyUntil} → übersprungen`);
                    vehicleScores[vehicleId] = {
                        status: 'overlap-hard',
                        reason: _reasonExt,
                        check: 'timeconflict',
                        blockingRideCustomer: _conflictRide?.customerName,
                        blockingRideTime: _cTime,
                        busyUntil: _cBusyUntil,
                        blockingRideDest: _conflictRide?.destination || _conflictRide?.destinationAddress || '',
                        conflictMath: _conflictMath || null  // v6.63.431: UI-Anzeige der Berechnung
                    };
                    continue;
                }
            }

            // Schicht-Info für gewählte Fahrzeuge mitspeichern
            vehicleScores[vehicleId] = { status: 'available', shiftDetails: _shiftInfo, shiftEnd: _shiftEnd || null };

            const driver = vehicles[vehicleId];

            if (isSofort) {
                // ═══ SOFORTFAHRT: GPS schlägt alles ═══
                let vLat = null, vLon = null, posSource = '';

                // 1. Aktives GPS (< 10 Min)
                if (driver && driver.lat && driver.lon && driver.timestamp && (Date.now() - driver.timestamp <= MAX_GPS_AGE)) {
                    vLat = driver.lat; vLon = driver.lon; posSource = 'GPS';
                } else {
                    // 2. Heimatstandort aus Schichtplan (mit Text-Auflösung!)
                    // 🔧 v6.38.35: Nutze getVehicleHomeCoords() mit homeLocation-Fallback
                    const homeCoords = getVehicleHomeCoords(vehicleId, shiftsData, dateStr, timeStr);
                    if (homeCoords && homeCoords.lat && homeCoords.lon) {
                        vLat = homeCoords.lat; vLon = homeCoords.lon; posSource = 'Schichtplan-Home';
                    } else {
                        // Fallback: Fahrzeug-Daten aus /vehicles/
                        if (driver && driver.homeCoords?.lat) {
                            vLat = driver.homeCoords.lat; vLon = driver.homeCoords.lon; posSource = 'Fahrzeug-Home';
                        }
                    }
                    // 3. Letzter bekannter GPS-Standort
                    if (!vLat && driver && driver.lat && driver.lon) {
                        vLat = driver.lat; vLon = driver.lon; posSource = 'Letzter-GPS';
                    }
                }

                // Sofortfahrt: NUR echtes GPS (< 10 Min) zulassen!
                // Homebase/Letzter-GPS reicht NICHT — wir brauchen die echte Position
                if (isSofort && posSource !== 'GPS') {
                    console.log(`   ❌ ${info.name}: ${posSource || 'kein Standort'} → bei Sofortfahrt NUR echtes GPS erlaubt`);
                    if (vehicleScores[vehicleId]) {
                        vehicleScores[vehicleId].status = 'no-gps';
                        vehicleScores[vehicleId].reason = `Sofortfahrt: Nur GPS erlaubt (hatte: ${posSource || 'nichts'})`;
                    }
                } else if (rideData.pickupCoords && vLat && vLon) {
                    const dist = gpsDistanceKm(rideData.pickupCoords.lat, rideData.pickupCoords.lon, vLat, vLon);
                    candidates.push({ vehicleId, name: info.name, distance: dist, priority: getVehiclePrio(vehicleId), telegramChatId: driver?.telegramChatId, posSource });
                    console.log(`   ✅ ${info.name}: ${dist.toFixed(1)} km (${posSource}) [Prio ${getVehiclePrio(vehicleId)}]`);
                } else {
                    // Vorbestellung: Ohne GPS nach Priorität aufnehmen
                    candidates.push({ vehicleId, name: info.name, distance: 999, priority: getVehiclePrio(vehicleId), telegramChatId: driver?.telegramChatId, posSource: posSource || 'kein-Standort' });
                    console.log(`   ⚠️ ${info.name}: Kein Standort → Priorität ${getVehiclePrio(vehicleId)}`);
                }
            } else {
                // ═══ VORBESTELLUNG: Schichtplan + Priorität ═══
                candidates.push({ vehicleId, name: info.name, distance: 0, priority: getVehiclePrio(vehicleId), telegramChatId: driver?.telegramChatId, posSource: 'Schichtplan' });
                console.log(`   ✅ ${info.name}: Im Dienst, Prio ${getVehiclePrio(vehicleId)}`);
            }
        }

        console.log(`\n📋 PRÜFPROTOKOLL ERGEBNIS: ${candidates.length} Kandidaten von ${Object.keys(OFFICIAL_VEHICLES).length} Fahrzeugen`);
        if (candidates.length > 0) {
            console.log(`   Kandidaten: ${candidates.map(c => `${c.name} (Prio ${c.priority}, ${c.posSource})`).join(' | ')}`);
        }

        if (candidates.length === 0) {
            console.log('⚠️ Kein Fahrzeug verfügbar für ' + (isSofort ? 'Sofortfahrt' : 'Vorbestellung'));
            // 🆕 v6.63.024 (Patrick 29.05. 21:16 "warum wird mir der Grund des Konflikts nicht
            //   angezeigt"): vehicleScores in die Ride persistieren auch wenn kein Match. Dann
            //   kann die Native-Dispo pro Fahrzeug die Reject-Reason anzeigen. Plus zusammen-
            //   gefasster wartepoolReason damit der Dispo-Card-Hint sprechend wird.
            try {
                // 🆕 v6.63.301 (Patrick 11.06. 22:37 'aber model y hat dienst wo ist der fehler'):
                //   Bisher zeigte der Reason nur den TOP-Grund. Bei Sachs gewann "3/6 Fahrzeuge:
                //   Fr nicht aktiv" obwohl MY222 + IK Dienst hatten — der Konflikt-Grund fuer
                //   die aktiven Vehicles war versteckt. Jetzt: Top-3 Gruende joinen damit Patrick
                //   sieht WAS bei den aktiven Vehicles schief lief.
                const _summary = (() => {
                    const _reasons = Object.values(vehicleScores)
                        .map(s => s && s.reason ? s.reason : '')
                        .filter(Boolean);
                    if (_reasons.length === 0) return 'Kein Fahrzeug im Schichtplan/verfügbar';
                    const _counts = {};
                    for (const r of _reasons) {
                        // v6.63.431 (Patrick 20.06. 06:56): 7 Wörter war zu kurz —
                        //   schnitt die Mathe-Detail-Erweiterung der Zeitkonflikt-Reason
                        //   ab. 20 Wörter erhalten die '(rechnet 07:48 fertig, 16 Min
                        //   Anfahrt → 3 Min zu spät)'-Info im wartepoolReason.
                        const _short = r.split(' ').slice(0, 20).join(' ');
                        _counts[_short] = (_counts[_short] || 0) + 1;
                    }
                    const _sorted = Object.entries(_counts).sort((a, b) => b[1] - a[1]);
                    const _total = candidates.length || Object.keys(vehicleScores).length;
                    // Top-3 Gruende joinen
                    const _parts = _sorted.slice(0, 3).map(([reason, count]) => `${count}× ${reason}`);
                    return `${_total} Fahrzeuge gepr.: ${_parts.join(' | ')}`;
                })();
                await db.ref('rides/' + rideId).update({
                    vehicleScores,
                    vehicleScoresAt: Date.now(),
                    autoAssignLastReason: _summary
                });
                // 🆕 v6.63.284 (Patrick 11.06. 13:53 'Logging verbessern'): Versuchs-Historie
                //   in /rideScoresHistory/{rideId}/{push}. Damit man sieht WARUM eine Ride
                //   X-mal fail wurde - jeder Versuch mit eigenem Snapshot der vehicleScores.
                try {
                    await db.ref('rideScoresHistory/' + rideId).push({
                        ts: Date.now(),
                        attempt: (rideData.autoAssignAttempts || 0) + 1,
                        summary: _summary,
                        vehicleScores
                    });
                } catch(_) { /* non-critical */ }
            } catch (_persistErr) {
                console.warn('vehicleScores-Persist Fehler:', _persistErr.message);
            }
            return null;
        }

        let best;
        let drivingTimeMin = 0;

        if (isSofort) {
            // 🔧 v6.38.45: Prioritäts-Vorsprung AUCH bei Sofortfahrten!
            // Vorher: nur Distanz → Prio 2 Fahrzeug (0.4 km) schlug Prio 1 (5 km)
            // Jetzt: Score = Fahrzeit (Min) + (Prio - 1) * priorityAdvantageMin
            // Beispiel: Prio-Vorsprung 10 Min → Tesla (Prio 2): 3 Min + 10 = 13 | Prius IK (Prio 1): 8 Min + 0 = 8 → Prius gewinnt!
            let bestScore = Infinity;
            best = candidates[0];
            for (const cand of candidates) {
                const prio = getVehiclePrio(cand.vehicleId);
                // 🔧 v6.38.45: Sofortfahrt + GPS AN → kein Prio-Aufschlag (echte Position, kürzeste Distanz zählt)
                // Sofortfahrt + GPS AUS → Prio-Aufschlag (Heimatadresse ist Schätzung, Priorität gleicht aus)
                // Vorbestellung → Priorität zählt IMMER (siehe else-Zweig unten)
                const hasRealGPS = cand.posSource === 'GPS';
                // 🆕 v6.62.518/520: Override beachten (Tag-Override > globaler Override > Formel)
                // 🐛 v6.62.536: Patrick (09.05.): "nein gps ist immer gleich". Vorher wurde
                // bei aktivem GPS der Prio-Malus auf 0 gesetzt (alte v6.38.45-Logik:
                // 'echte Position zaehlt'). Jetzt: Override greift IMMER, auch bei
                // Sofortfahrten mit GPS. Damit kann Tesla mit Override 999 wirklich
                // niemals gewaehlt werden, auch nicht wenn er gerade neben dem Kunden steht.
                const prioPenalty = getEffectivePrioMalus(cand.vehicleId, rideData.pickupTimestamp);
                const estDrivingMin = cand.distance >= 999 ? 10 : Math.max(3, Math.round((cand.distance / 40) * 60));
                // 🆕 v6.63.021: Großraum-Reserve-Bias bei Sofortfahrten
                const _candCap = (OFFICIAL_VEHICLES[cand.vehicleId] || {}).capacity || 4;
                const _paxReservePenalty = (_largeReserveActive && _candCap >= _LARGE_VEHICLE_CAPACITY)
                    ? ((_candCap - passengers) * 8) : 0;
                const score = estDrivingMin + prioPenalty + _paxReservePenalty;

                // vehicleScores aktualisieren
                if (vehicleScores[cand.vehicleId]) {
                    Object.assign(vehicleScores[cand.vehicleId], {
                        distanceKm: Math.round(cand.distance * 10) / 10,
                        drivingTimeMin: estDrivingMin,
                        priorityPenalty: prioPenalty,
                        paxReservePenalty: _paxReservePenalty,
                        posSource: cand.posSource,
                        totalScore: score
                    });
                }

                console.log(`   📊 ${cand.name}: ${cand.distance < 999 ? cand.distance.toFixed(1) + ' km' : 'kein GPS'} → ${estDrivingMin} Min Fahrzeit + ${prioPenalty} Min Prio-Penalty${_paxReservePenalty ? ' + ' + _paxReservePenalty + ' Pax-Reserve' : ''} = Score ${score} [P${prio}, ${cand.posSource}]`);

                if (score < bestScore) {
                    bestScore = score;
                    best = cand;
                    drivingTimeMin = estDrivingMin;
                }
            }

            // Gewähltes Fahrzeug markieren
            if (vehicleScores[best.vehicleId]) {
                vehicleScores[best.vehicleId].status = 'chosen';
            }

            console.log(`   🏆 Bestes Fahrzeug: ${best.name} (Score: ${bestScore}, Distanz: ${best.distance < 999 ? best.distance.toFixed(1) + ' km' : 'kein GPS'})`);
        } else {
            // 🔧 v6.25.4: Vorbestellung mit Smart Routing + Prioritäts-Penalty (wie Browser)
            // Score = Leerfahrt (Min) + (Prio - 1) * priorityAdvantageMin → niedrigster Score gewinnt
            let bestScore = Infinity;
            best = candidates[0]; // Fallback auf Priorität

            for (const cand of candidates) {
                let leerfahrtMin = 0;
                let leerfahrtVon = '';
                let routeMethod = 'prio-only';
                const prio = getVehiclePrio(cand.vehicleId);
                // 🆕 v6.62.518/520: Override beachten (mit Tag aus Pickup)
                const prioPenalty = getEffectivePrioMalus(cand.vehicleId, rideData.pickupTimestamp);

                // Smart Routing berechnen wenn Pickup-Koordinaten vorhanden
                if (rideData.pickupCoords?.lat && rideData.pickupCoords?.lon) {
                    try {
                        const result = await estimateVehicleLeerfahrt(
                            cand.vehicleId, rideData, allRides, vehicles, shiftsData, dateStr, pricingSettings
                        );
                        leerfahrtMin = result.durationMin;
                        routeMethod = result.method;
                        leerfahrtVon = result.method;
                    } catch(e) {
                        console.warn(`   ⚠️ ${cand.name}: Leerfahrt-Berechnung fehlgeschlagen`);
                    }
                }

                // 🆕 v6.32.0: LASTVERTEILUNG — Fahrzeuge mit vielen Fahrten werden benachteiligt
                // 🆕 v6.62.520: Pro-Wochentag-Override beachten
                // 🐛 v6.62.534: Patrick (09.05.): "loadPenalty 357 Min — Prius hat 390 Fahrten".
                // Bug: allRides enthielt ALLE jemals zugewiesenen Fahrten (auch completed historische).
                // Fix: nur AKTIVE Fahrten am SELBEN TAG wie Pickup zählen — gleicher Filter wie Browser.
                const lastverteilungMalusProFahrt = getOptForTimestamp(rideData.pickupTimestamp).lastenmalus;
                const _activeStatusesForLoad = ['new','vorbestellt','assigned','accepted','on_way','arrived','picked_up','sofort','warteschlange'];
                const _pickupDayStr = berlinDateGlobal(rideData.pickupTimestamp);
                const _isActiveSameDay = (r) => {
                    if (!r || !r.pickupTimestamp) return false;
                    if (r.firebaseId === rideId) return false;
                    if (!_activeStatusesForLoad.includes(r.status)) return false;
                    return berlinDateGlobal(r.pickupTimestamp) === _pickupDayStr;
                };
                const vehicleRideCount = allRides.filter(r =>
                    (r.vehicleId === cand.vehicleId || r.assignedVehicle === cand.vehicleId) &&
                    _isActiveSameDay(r)
                ).length;
                const _activeSameDay = allRides.filter(_isActiveSameDay);
                const avgRides = candidates.length > 0
                    ? _activeSameDay.filter(r => r.assignedVehicle || r.vehicleId).length / candidates.length
                    : 0;
                const loadPenalty = vehicleRideCount > avgRides
                    ? Math.round((vehicleRideCount - avgRides) * lastverteilungMalusProFahrt)
                    : 0;

                // 🆕 v6.32.0: Anschlussfahrt-Bonus verstärken
                const anschlussBonus = (routeMethod === 'anschlussfahrt' || routeMethod === 'anschlussfahrt-gps')
                    ? -(pricingSettings.anschlussfahrtBonusMinuten || 5) : 0;

                // 🆕 v6.63.021: Großraum-Reserve-Bias bei Vorbestellungen
                const _candCap = (OFFICIAL_VEHICLES[cand.vehicleId] || {}).capacity || 4;
                const _paxReservePenalty = (_largeReserveActive && _candCap >= _LARGE_VEHICLE_CAPACITY)
                    ? ((_candCap - passengers) * 8) : 0;
                const totalScore = Math.round(leerfahrtMin + prioPenalty + loadPenalty + anschlussBonus + _paxReservePenalty);

                Object.assign(vehicleScores[cand.vehicleId] || {}, {
                    status: 'available',
                    leerfahrtMin: Math.round(leerfahrtMin),
                    leerfahrtVon,
                    routeMethod,
                    priorityPenalty: prioPenalty,
                    loadPenalty,
                    vehicleRideCount,
                    anschlussBonus,
                    paxReservePenalty: _paxReservePenalty,
                    totalScore
                });

                console.log(`   📊 ${cand.name}: Leerfahrt ${Math.round(leerfahrtMin)} Min (${routeMethod}) + Prio ${prioPenalty} + Last ${loadPenalty} (${vehicleRideCount} Fahrten) + Kette ${anschlussBonus}${_paxReservePenalty ? ' + ' + _paxReservePenalty + ' Pax-Reserve' : ''} = Score ${totalScore} [P${prio}]`);

                if (totalScore < bestScore) {
                    bestScore = totalScore;
                    best = cand;
                    drivingTimeMin = Math.round(leerfahrtMin);
                }
            }

            // Gewähltes Fahrzeug im Score markieren
            if (vehicleScores[best.vehicleId]) {
                vehicleScores[best.vehicleId].status = 'chosen';
            }

            console.log(`   🏆 Bestes Fahrzeug: ${best.name} (Score: ${bestScore})`);
        }

        // 🆕 v6.25.5: Verfügbarkeits-Check — kann das Fahrzeug rechtzeitig ankommen?
        // Der einfache Zeitkonflikt-Check oben nutzt pauschale Rückfahrt-Puffer.
        // Hier prüfen wir mit der ECHTEN Leerfahrt ob das Fahrzeug tatsächlich frei ist.
        if (!isSofort && rideData.pickupTimestamp) {
            // 🆕 v6.63.450: Default 0 statt 2 — settings sind die Quelle der Wahrheit
            const boardingTime = pricingSettings.boardingTime != null ? pricingSettings.boardingTime : 0;
            const alightingTime = pricingSettings.alightingTime != null ? pricingSettings.alightingTime : 0;
            const _bufferMs = (boardingTime + alightingTime) * 60000;
            const _mindestAbstandMs = (pricingSettings.mindestAbstandMin || 0) * 60000;
            const _maxVerschiebungMin = pricingSettings.maxAutoVerschiebungMin || 15;

            // Vorherige Fahrt dieses Fahrzeugs finden (die zeitlich am nächsten VOR der neuen Fahrt liegt)
            const _prevRides = allRides.filter(r => {
                if (r.firebaseId === rideId) return false;
                if (r.vehicleId !== best.vehicleId && r.assignedTo !== best.vehicleId && r.assignedVehicle !== best.vehicleId) return false;
                if (!r.pickupTimestamp || r.pickupTimestamp >= rideData.pickupTimestamp) return false;
                if (['deleted','cancelled','storniert','cancelled_pending_driver','completed'].includes(r.status)) return false;
                return true;
            }).sort((a, b) => b.pickupTimestamp - a.pickupTimestamp);

            if (_prevRides.length > 0) {
                const _prevRide = _prevRides[0];
                // 🔧 v6.63.590: Fallback 20→10 Min — Heringsdorf ist klein, 20 Min war zu pessimistisch
                //   und führte zu falschen Konflikt-Shifts (Wagner 3 Min tatsächlich, 20 Min geschätzt).
                const _prevDurMs = (_prevRide.duration || _prevRide.estimatedDuration || 10) * 60000;
                // 🔧 v6.38.53: Rückfahrt-Puffer in prevEnd einrechnen (vorher fehlte der!)
                // 🐛 v6.63.467 (22.06.2026): calcReturnMsAsync war als async function in inneren
                //   if-Block (Z.1612, if(rideData.pickupTimestamp)) definiert → block-scoped
                //   → hier outside scope → ReferenceError "calcReturnMsAsync is not defined"
                //   → outer-catch crasht autoAssignRide, vehicleScores werden NICHT persistiert
                //   → Patrick sieht keine Scores bei Wartepool-Fahrten (Wilhelm/Schlegel 22.06.).
                //   Fix: Rückfahrt-Berechnung inline statt Helper-Aufruf (deckt 1:1 die Logik
                //   der inneren calcReturnMsAsync, mit best.vehicleId statt loop-vehicleId).
                const _prevHome = getVehicleHomeCoords(best.vehicleId, shiftsData, dateStr, timeStr);
                const _prevDestLat = _prevRide.destCoords?.lat || _prevRide.destinationLat;
                const _prevDestLon = _prevRide.destCoords?.lon || _prevRide.destinationLon;
                const _prevMaxMs = (pricingSettings.standortRueckkehrPufferMinuten || 30) * 60000;
                const _prevMinMs = 5 * 60000;
                let _prevReturnMs = _prevMaxMs;
                if (_prevDestLat && _prevDestLon && _prevHome?.lat && _prevHome?.lon) {
                    const _prevOsrmMin = await osrmDrivingMin(_prevDestLat, _prevDestLon, _prevHome.lat, _prevHome.lon);
                    if (_prevOsrmMin != null) _prevReturnMs = Math.max(_prevMinMs, _prevOsrmMin * 60000);
                }
                const _prevEndMs = _prevRide.pickupTimestamp + _prevDurMs + _bufferMs + _prevReturnMs;

                // Leerfahrt vom Ziel der Vorfahrt zum neuen Abholort berechnen
                let _leerfahrtToNewMs = drivingTimeMin * 60000; // Nutze bereits berechnete Leerfahrt
                if (drivingTimeMin === 0) {
                    // Fallback: Leerfahrt aus der Scoring-Phase nutzen oder schätzen
                    const _vs = vehicleScores[best.vehicleId];
                    _leerfahrtToNewMs = (_vs?.leerfahrtMin || 10) * 60000;
                }

                const _earliestArrivalMs = _prevEndMs + _leerfahrtToNewMs + _mindestAbstandMs;
                const _delayMs = _earliestArrivalMs - rideData.pickupTimestamp;
                const _delayMin = Math.round(_delayMs / 60000);

                if (_delayMs > 0) {
                    const _prevEndTime = new Date(_prevEndMs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' });
                    const _prevEndFormatted = new Date(_prevEndTime).toLocaleTimeString('de-DE', {hour:'2-digit',minute:'2-digit'});

                    // 🆕 v6.63.376 (Patrick 17.06. 08:45 Bridge: "Wenn das Fahrzeug
                    //   alleine gewesen wäre, hättest du die Fahrt auch nicht bekommen?"):
                    //   Single-Candidate-Bypass — wenn das gewählte best das EINZIGE
                    //   verfügbare Fahrzeug ist, IMMER zuweisen, auch wenn delay >
                    //   maxVerschiebung. Sonst landet die Ride in Wartepool obwohl
                    //   nur 1 Auto da ist — sinnlos, Kunde wird nicht bedient.
                    const _isSingleCandidate = candidates.length === 1;
                    if (_delayMin > _maxVerschiebungMin && _isSingleCandidate) {
                        console.log(`   ⚠️ v6.63.376: ${best.name} ist EINZIGES Fahrzeug — delay ${_delayMin}min ignoriert, trotzdem zuweisen`);
                        if (vehicleScores[best.vehicleId]) {
                            vehicleScores[best.vehicleId].forcedSingleCandidate = true;
                            vehicleScores[best.vehicleId].forcedDelayMin = _delayMin;
                        }
                        try {
                            await db.ref('debugLogs/autoassign').push({
                                ts: Date.now(),
                                rideId,
                                customer: rideData.customerName || '?',
                                pickup: rideData.pickup,
                                stage: 'single-candidate-bypass-v6.63.376',
                                bestVehicle: best.name,
                                delayMin: _delayMin,
                                maxVerschiebungMin: _maxVerschiebungMin,
                                action: 'force-assign-despite-delay'
                            });
                        } catch (_e) { /* */ }
                        // Skip delay-fail block → unten geht weiter mit Zuweisung
                    } else if (_delayMin > _maxVerschiebungMin) {
                        // Zu großer Konflikt → Fahrzeug NICHT zuweisen
                        console.log(`   ❌ v6.25.5: ${best.name} kann nicht rechtzeitig ankommen! Vorfahrt endet ${_prevEndFormatted} + ${Math.round(_leerfahrtToNewMs/60000)} Min Leerfahrt = ${_delayMin} Min zu spät (Max: ${_maxVerschiebungMin} Min)`);
                        if (vehicleScores[best.vehicleId]) {
                            vehicleScores[best.vehicleId].status = 'busy';
                            vehicleScores[best.vehicleId].busyUntil = _prevEndFormatted;
                            vehicleScores[best.vehicleId].overlapMin = _delayMin;
                            vehicleScores[best.vehicleId].reason = `Konflikt: Vorfahrt ${_prevRide.customerName || '?'} endet ${_prevEndFormatted} + ${Math.round(_leerfahrtToNewMs/60000)}min Anfahrt = ${_delayMin}min zu spät`;
                            vehicleScores[best.vehicleId].blockingRideCustomer = _prevRide.customerName;
                            vehicleScores[best.vehicleId].blockingRideTime = new Date(_prevRide.pickupTimestamp).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' });
                            vehicleScores[best.vehicleId].blockingRideDest = _prevRide.destination || '';
                        }
                        // 🆕 v6.63.374 (Patrick 17.06. 07:38 Bridge: "Mach mal ein Log von der
                        //   Funktion, warum das nicht funktioniert mit Rudolf"): vehicleScores
                        //   UND autoAssignLastReason schreiben + Debug-Log mit Detail-Trace damit
                        //   Patrick sehen kann WARUM das Fahrzeug abgelehnt wurde.
                        const _bestReason = vehicleScores[best.vehicleId]?.reason || `${best.name} ${_delayMin}min zu spät`;
                        const _busyDetail = `${best.name} 'busy' nach Vorfahrt ${_prevRide.customerName || '?'} (${_delayMin}min Delay > Max ${_maxVerschiebungMin}min)`;
                        try {
                            await db.ref('rides/' + rideId).update({
                                vehicleScores,
                                vehicleScoresAt: Date.now(),
                                autoAssignLastReason: _busyDetail
                            });
                            await db.ref('debugLogs/autoassign').push({
                                ts: Date.now(),
                                rideId,
                                customer: rideData.customerName || '?',
                                pickup: rideData.pickup,
                                destination: rideData.destination,
                                pickupTime: timeStr,
                                pickupDate: dateStr,
                                stage: 'busy-after-delay-check',
                                bestVehicle: best.name,
                                bestVehicleId: best.vehicleId,
                                prevRide: {
                                    customer: _prevRide.customerName,
                                    pickup: _prevRide.pickup,
                                    destination: _prevRide.destination,
                                    pickupTs: _prevRide.pickupTimestamp,
                                    durMin: (_prevRide.duration || _prevRide.estimatedDuration || 20),
                                    endFormatted: _prevEndFormatted
                                },
                                delayMin: _delayMin,
                                maxVerschiebungMin: _maxVerschiebungMin,
                                leerfahrtMin: Math.round(_leerfahrtToNewMs/60000),
                                vehicleScoresSnapshot: vehicleScores
                            });
                        } catch (_e) { console.warn('v6.63.374 debug-log Fehler:', _e.message); }
                        // 🆕 v6.63.378 (Patrick 17.06. 10:37 Bridge "Wenn ein Fahrzeug es nicht schafft,
                        //   muss das andere Fahrzeug genommen werden — Malus egal"): statt return null
                        //   rekursiv mit excludeVehicleIds aufrufen damit das nächst-beste Vehicle probiert
                        //   wird. Erst wenn ALLE Vehicles in Konflikt sind → final return null.
                        const _otherCandidates = candidates.filter(c => c.vehicleId !== best.vehicleId && !_excludeVehicleIds.includes(c.vehicleId));
                        if (_otherCandidates.length > 0) {
                            console.log(`   🔄 v6.63.378 delay-Fallback: ${best.name} fail (${_delayMin}min zu spät) → probiere ${_otherCandidates.length} weitere Vehicles`);
                            try {
                                await db.ref('debugLogs/autoassign').push({
                                    ts: Date.now(),
                                    rideId,
                                    customer: rideData.customerName || '?',
                                    stage: 'delay-fallback-recurse-v6.63.378',
                                    excludedVehicle: best.name,
                                    excludedId: best.vehicleId,
                                    delayMin: _delayMin,
                                    remainingCandidates: _otherCandidates.length
                                });
                            } catch (_) {}
                            return await autoAssignRide(rideId, rideData, [..._excludeVehicleIds, best.vehicleId]);
                        }
                        console.log(`⚠️ Kein Fahrzeug kann rechtzeitig ankommen für Vorbestellung ${rideId}`);
                        return null;
                    } else {
                        // Kleiner Konflikt → Abholzeit automatisch verschieben
                        // 🆕 v6.62.821 (Patrick 19.05. 09:40): Bei Anschluss-ZIELEN KEIN Zeit-Shift —
                        //   Kunde verpasst sonst den Zug/Flug/Termin.
                        // 🔧 v6.62.841 (Patrick 20.05. 17:03): Schutz NUR bei destination (nicht
                        //   pickup) und NUR bei echten Anschluss-POIs — 'Bahnhofstraße' als
                        //   Strassen­name darf NICHT mehr falsch triggern. Wort-Boundary plus
                        //   Suffix-Check (nicht ge­folgt von 'straße/str.').
                        const _destOnly = (rideData.destination || '').toLowerCase();
                        const _anschlussRe = /\b(bahnhof|flughafen|airport|krankenhaus|klinik|station|terminal)(?!(?:str|straße|allee|weg|platz|gasse))/i;
                        const _isAnschlussZiel = _anschlussRe.test(_destOnly);
                        if (_isAnschlussZiel) {
                            console.log(`   🚫 v6.62.841: Pickup-Shift blockiert — Anschluss-ZIEL: ${rideData.destination}`);
                            // 🆕 v6.63.378: best als 'anschluss-blocked' markieren bevor Fallback
                            if (vehicleScores[best.vehicleId]) {
                                vehicleScores[best.vehicleId].status = 'anschluss-blocked';
                                vehicleScores[best.vehicleId].reason = `Anschluss-Ziel '${rideData.destination}' — Pickup-Shift +${_delayMin}min nicht erlaubt (Kunde verpasst Zug/Flug/Termin)`;
                            }
                            try {
                                await db.ref('rides/' + rideId).update({
                                    vehicleScores,
                                    vehicleScoresAt: Date.now()
                                });
                            } catch (_) {}
                            // 🆕 v6.63.378 (Patrick 17.06. 10:40 Bridge "Lemmel-Wartepool Quatsch"):
                            //   Lemmel zum Bahnhof blieb 5x im Wartepool weil best Vehicle Konflikt hatte
                            //   und Anschluss-Block return null machte ohne 2.-bestes Vehicle zu probieren.
                            //   Fix: rekursiv mit excludeVehicleIds aufrufen.
                            const _otherCandidates = candidates.filter(c => c.vehicleId !== best.vehicleId && !_excludeVehicleIds.includes(c.vehicleId));
                            if (_otherCandidates.length > 0) {
                                console.log(`   🔄 v6.63.378 anschluss-Fallback: ${best.name} blockiert → probiere ${_otherCandidates.length} weitere Vehicles`);
                                try {
                                    await db.ref('debugLogs/autoassign').push({
                                        ts: Date.now(),
                                        rideId,
                                        customer: rideData.customerName || '?',
                                        stage: 'anschluss-fallback-recurse-v6.63.378',
                                        excludedVehicle: best.name,
                                        excludedId: best.vehicleId,
                                        anschlussZiel: rideData.destination,
                                        delayMin: _delayMin,
                                        remainingCandidates: _otherCandidates.length
                                    });
                                } catch (_) {}
                                return await autoAssignRide(rideId, rideData, [..._excludeVehicleIds, best.vehicleId]);
                            }
                            // Kein Alternativ → Admin warnen + return null wie bisher
                            await addRideLog(rideId, '🚫', `Auto-Verschiebung blockiert — Anschluss-Ziel '${rideData.destination}', kein Alternativ-Fahrzeug, manuell entscheiden`, {
                                grund: 'Anschluss-POI im ZIEL (Bahnhof/Flughafen/Klinik) — Zeit-Shift verbietet + alle anderen Fahrzeuge bereits ausgeschlossen',
                                vorgeschlagen: `+${_delayMin} Min auf ${best.name}`,
                                konflikt: rideData.pickupShiftReason || `${best.name} erst ab ${_prevEndFormatted} frei`,
                                excludedVehicles: _excludeVehicleIds
                            });
                            try {
                                if (typeof sendToAllAdmins === 'function') {
                                    await sendToAllAdmins(
                                        `🚫 <b>ANSCHLUSS-KONFLIKT NICHT AUFLÖSBAR</b>\n\n` +
                                        `👤 ${rideData.customerName || '?'}\n` +
                                        `📍 ${rideData.pickup || '?'}\n` +
                                        `🎯 ${rideData.destination || '?'}\n\n` +
                                        `Alle Fahrzeuge haben Konflikt oder müssten verschoben werden.\nKunde muss Anschluss erreichen — bitte manuell entscheiden!\n\n` +
                                        `🆔 <code>${rideId}</code>`,
                                        'anschluss_konflikt'
                                    );
                                }
                            } catch (_e) { /* ignore */ }
                            try {
                                await db.ref('rides/' + rideId).update({
                                    autoAssignLastReason: `Anschluss-Ziel '${rideData.destination}' — alle ${1+_excludeVehicleIds.length} Fahrzeuge im Konflikt`
                                });
                            } catch (_) {}
                            return null;
                        }

                        const _newPickupTs = _earliestArrivalMs + 2 * 60000; // +2 Min Puffer
                        const _newPickupTime = new Date(new Date(_newPickupTs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                        const _newPickupFormatted = _newPickupTime.toLocaleTimeString('de-DE', {hour:'2-digit',minute:'2-digit'});
                        const _oldPickupFormatted = new Date(new Date(rideData.pickupTimestamp).toLocaleString('en-US', { timeZone: 'Europe/Berlin' })).toLocaleTimeString('de-DE', {hour:'2-digit',minute:'2-digit'});

                        console.log(`   🔄 v6.25.5: Abholzeit verschoben ${_oldPickupFormatted} → ${_newPickupFormatted} (+${_delayMin} Min) — ${best.name} erst ab ${_prevEndFormatted} frei`);

                        // 🔧 v6.38.50 BUG-01 FIX: Original ZUERST speichern, dann überschreiben!
                        rideData.originalPickupTimestamp = rideData.pickupTimestamp;
                        rideData.pickupTimestamp = _newPickupTs;
                        rideData.pickupTimeShifted = true;
                        rideData.pickupShiftReason = `Fahrzeug ${best.name} erst ab ${_prevEndFormatted} frei (Vorfahrt)`;
                        rideData.pickupShiftMinutes = _delayMin;

                        // Neuen pickupTime-String generieren
                        const _newTimeStr = String(_newPickupTime.getHours()).padStart(2,'0') + ':' + String(_newPickupTime.getMinutes()).padStart(2,'0');
                        rideData.pickupTime = _newTimeStr;

                        // 🆕 v6.62.821: Lifecycle-Log fuer den Pickup-Shift selbst
                        //   (frueher: nur pickupShiftReason-Feld in der Ride, KEIN Audit-Trail).
                        try {
                            await addRideLog(rideId, '🔄', `Abholzeit verschoben: ${_oldPickupFormatted} → ${_newPickupFormatted} (+${_delayMin} Min)`, {
                                alt: _oldPickupFormatted,
                                neu: _newPickupFormatted,
                                delta: `+${_delayMin} Min`,
                                fahrzeug: best.name,
                                grund: `${best.name} erst ab ${_prevEndFormatted} frei (Vorfahrt)`,
                                ziel: rideData.destination || '?',
                                notifyLateSms: true
                            });
                        } catch (_logErr) { /* ignore */ }
                        // 🆕 v6.62.821: Admin-Telegram-Push damit Patrick sofort sieht
                        //   wenn Cloud eine Auto-Verschiebung gemacht hat (vorher nur SMS
                        //   an Kunde + Lifecycle-Log — Patrick erfuhr nichts).
                        try {
                            if (typeof sendToAllAdmins === 'function') {
                                await sendToAllAdmins(
                                    `🔄 Auto-Verschiebung\n` +
                                    `Kunde: ${rideData.customerName || '?'}\n` +
                                    `${_oldPickupFormatted} → ${_newPickupFormatted} (+${_delayMin} Min)\n` +
                                    `${rideData.pickup || '?'} → ${rideData.destination || '?'}\n` +
                                    `Fahrzeug: ${best.name}\n` +
                                    `Grund: ${best.name} erst ab ${_prevEndFormatted} frei`
                                );
                            }
                        } catch (_e) { /* ignore */ }
                    }
                }
            }
        }

        const bestInfo = OFFICIAL_VEHICLES[best.vehicleId] || {};

        // 🆕 v6.38.45: ENTSCHEIDUNGS-PROTOKOLL — jeder Schritt der Fahrzeugwahl wird geloggt
        try {
            // Zusammenfassung aller Fahrzeug-Entscheidungen für den Auftrags-Verlauf
            const _allVehicles = Object.entries(OFFICIAL_VEHICLES);
            const _rejected = Object.entries(vehicleScores).filter(([,s]) => s.status !== 'chosen' && s.status !== 'available');
            const _available = Object.entries(vehicleScores).filter(([,s]) => s.status === 'available' || s.status === 'chosen');

            // Ablehnungsgründe kompakt zusammenfassen
            const _rejectSummary = _rejected.map(([vid, s]) => {
                const name = (OFFICIAL_VEHICLES[vid] || {}).name || vid;
                return `${name}: ${s.reason || s.check || s.status}`;
            }).join(' | ');

            // Kandidaten mit Scores
            const _candSummary = _available.map(([vid, s]) => {
                const name = (OFFICIAL_VEHICLES[vid] || {}).name || vid;
                const score = s.totalScore ?? s.score ?? '?';
                const detail = s.distanceKm !== undefined
                    ? `${s.distanceKm}km/${s.drivingTimeMin}min+${s.priorityPenalty||0}prio=${score}`
                    : `Leerfahrt:${s.leerfahrtMin||0}min+${s.priorityPenalty||0}prio+${s.loadPenalty||0}last=${score}`;
                return `${vid === best.vehicleId ? '✅' : '🟡'} ${name} (${detail})`;
            }).join(' | ');

            await addRideLog(rideId, '🔍', `Auto-Zuweisung: ${isSofort ? 'SOFORTFAHRT' : 'VORBESTELLUNG'} | ${dateStr} ${timeStr}`, {
                modus: isSofort ? 'Sofortfahrt' : 'Vorbestellung',
                geprüft: _allVehicles.length,
                kandidaten: _available.length,
                abgelehnt: _rejected.length,
                gewählt: `${best.name} (Score: ${vehicleScores[best.vehicleId]?.totalScore ?? '?'})`,
                ablehnungen: _rejectSummary || 'keine',
                bewertung: _candSummary
            });
        } catch (_logErr) { console.warn('Decision-Log Fehler:', _logErr.message); }

        // 🔧 v6.38.97: Sofortfahrt → 'sofort' (Fahrer muss erst bestätigen!)
        // Erst wenn Fahrer im App "Annehmen" klickt → status wird 'assigned'
        const rideUpdate = {
            status: isSofort ? 'sofort' : 'vorbestellt',
            assignedTo: best.vehicleId,
            vehicleId: best.vehicleId,
            vehicle: best.name,
            vehicleLabel: best.name,
            assignedVehicleName: best.name,
            assignedVehiclePlate: bestInfo.plate || '',
            assignedVehicle: best.vehicleId,
            vehiclePlate: bestInfo.plate || '',
            assignedAt: Date.now(),
            assignedBy: 'cloud-auto-assign',
            updatedAt: Date.now()
        };
        // 🆕 v6.25.5: Verschobene Abholzeit in Firebase speichern
        if (rideData.pickupTimeShifted) {
            rideUpdate.pickupTimestamp = rideData.pickupTimestamp;
            rideUpdate.pickupTime = rideData.pickupTime;
            rideUpdate.pickupTimeShifted = true;
            rideUpdate.originalPickupTimestamp = rideData.originalPickupTimestamp;
            rideUpdate.pickupShiftReason = rideData.pickupShiftReason;
            rideUpdate.pickupShiftMinutes = rideData.pickupShiftMinutes;
        }
        // 🆕 v6.62.172: Wenn Kunde im buchen.html-Smart-ETA-Modus eine versprochene Anfahrt
        // gesehen hat (z.B. 18 Min inkl. Restfahrt), nehmen wir das Maximum aus
        // versprochener und direkter Anfahrt. Sonst kaeme der Fahrer mit 13 Min direkter
        // Anfahrt davon — sieht aber 13 Min waehrend der Kunde 18 Min erwartet → er faehrt
        // zu spaet los, Kunde wartet laenger. Patrick (01.05.): 'in der fahrer app die
        // gleiche zeit wie der kunde sehen'.
        const _promisedEta = rideData?.bookingPromisedEtaMin;
        const _effectiveDrivingMin = (typeof _promisedEta === 'number' && _promisedEta > drivingTimeMin)
            ? _promisedEta : drivingTimeMin;
        if (Object.keys(vehicleScores).length > 0) {
            rideUpdate.vehicleScores = vehicleScores;
            rideUpdate.drivingTimeToPickup = _effectiveDrivingMin;
        }
        if (isSofort) {
            rideUpdate.assignmentDistance = best.distance;
            rideUpdate.drivingTimeToPickup = _effectiveDrivingMin;
            rideUpdate.estimatedArrivalAt = Date.now() + (_effectiveDrivingMin * 60000);
            rideUpdate.assignmentExpiresAt = Date.now() + 60000;

            // 🆕 v6.62.974 (Patrick 27.05. 20:13): pickupTimestamp realistisch setzen.
            // Vorher: Sofortbuchung = pickupTimestamp = createdAt (= jetzt). Fahrer ist
            // aber noch X Min entfernt → Kunden-Track-Page zeigte sofort 'gelb/verspätet'.
            // Jetzt: pickupTimestamp = jetzt + max(Anfahrt, 5 Min) Puffer.
            // Original-Zeit als _originalPickupTimestamp gesichert für Statistik.
            //
            // 🐛 v6.63.071 (Patrick 01.06. Bridge "Heinrich 10:40 → 10:23 Bug"):
            //   Diese Anpassung darf NUR bei echten Sofortbuchungen feuern. Heinrich-
            //   Vorbestellung 10:40 wurde um 10:18 (22 Min vor Pickup) zugewiesen — die
            //   isSofort-Schwelle (15 + Default-Anfahrt 10) = 25 Min ist großzügig und
            //   triggerte true, wodurch pickupTimestamp auf 10:23 verschoben wurde.
            //   Google-Kalender liest pickupTimestamp und zeigte dann 10:23. Fix:
            //   Vorbestellungen vom Puffer-Update ausnehmen.
            // v6.63.085 (Patrick 02.06. Bridge 05:49 "Sandy Zornow 5:56"):
            //   Erweitert um Serie-/CRM-Pfade. v6.63.071 hatte nur
            //   "native_vorbestellung*" geschlossen — Sandy heute lief über
            //   das Multi-Day-Copy-Modal mit source="native_series_multi_copy".
            //   Defensive Regel: ALLES was kein klassischer Sofort-Webfall ist
            //   wird wie Vorbestellung behandelt. Whitelist statt Blacklist.
            const _sourceStr = String(rideData.source || '').toLowerCase();
            const _isSofortSource =
                _sourceStr === 'web-booking' ||
                _sourceStr === 'qr-aufsteller' ||
                _sourceStr === 'native_einsteiger' ||
                _sourceStr === 'native_sofort' ||
                rideData.isJetzt === true;
            const _isVorbestellung = !_isSofortSource || rideData.status === 'vorbestellt';
            if (!_isVorbestellung) {
                try {
                    const _pufferMin = Math.max(_effectiveDrivingMin || 0, 5);
                    const _newPickupTs = Date.now() + (_pufferMin * 60000);
                    if (rideData?.pickupTimestamp && !rideData._originalPickupTimestamp) {
                        rideUpdate._originalPickupTimestamp = rideData.pickupTimestamp;
                    }
                    rideUpdate.pickupTimestamp = _newPickupTs;
                    rideUpdate.pickupTimeAdjustedAt = Date.now();
                    rideUpdate.pickupTimeAdjustedBy = 'cloud-auto-assign-v6.63.071';
                    rideUpdate.pickupTimePufferMin = _pufferMin;
                } catch (_pufferErr) {
                    console.warn('v6.63.071 Pickup-Puffer Fehler:', _pufferErr.message);
                }
            } else {
                console.log(`🛡️ v6.63.071 Vorbestellung (${rideData.source || rideData.status}) — pickupTimestamp NICHT auf Sofort-Puffer geändert (war ${rideData.pickupTimestamp})`);
            }
        }
        await db.ref('rides/' + rideId).update(rideUpdate);

        console.log(`✅ ${rideId} → ${best.name} (${isSofort ? best.distance.toFixed(1) + ' km, ~' + drivingTimeMin + ' Min' : 'Score ' + (vehicleScores[best.vehicleId]?.totalScore || '?') + ', Prio ' + best.priority}) [${isSofort ? 'Sofort' : 'Vorbestellung'}]`);

        // 🆕 v6.38.96: Auto-Zuweisung ins buchenLog (System Monitor Remote Console)
        try {
            const _rejList = Object.entries(vehicleScores)
                .filter(([, s]) => s.status !== 'available')
                .map(([vid, s]) => `${(OFFICIAL_VEHICLES[vid] || {}).name || vid}: ${s.reason || s.status}`)
                .join(' | ');
            db.ref('settings/buchenLog').push({
                time: Date.now(), emoji: '🎯',
                msg: `AUTO-ZUWEISUNG: ${rideData.customerName || '?'} → ${best.name} | ${isSofort ? 'Sofort' : 'Vorbestellung'} | Score: ${vehicleScores[best.vehicleId]?.totalScore ?? '?'}${isSofort ? ' | ' + (best.distance < 999 ? best.distance.toFixed(1) + 'km' : 'kein GPS') + ', ~' + drivingTimeMin + 'min' : ''}${_rejList ? ' | Abgelehnt: ' + _rejList.substring(0, 200) : ''}`,
                session: 'cloud'
            }).catch(() => {});
        } catch(_blErr) { /* non-critical */ }

        // Fahrer per Telegram benachrichtigen
        if (best.telegramChatId) {
            const pickupLabel = rideData.pickupTime || (isSofort ? 'Sofort' : timeStr + ' Uhr');
            const _driverMsgResult = await sendTelegramMessage(best.telegramChatId,
                `🚕 <b>${isSofort ? 'NEUE FAHRT!' : '📅 NEUE VORBESTELLUNG!'}</b>\n\n` +
                `📍 <b>Von:</b> ${rideData.pickup}\n` +
                `🎯 <b>Nach:</b> ${rideData.destination}\n` +
                `👤 <b>Kunde:</b> ${rideData.customerName}\n` +
                (() => {
                    // v6.62.222: Fallback auf customerMobile/mobilePhone wenn customerPhone leer.
                    const _tel = rideData.customerPhone || rideData.customerMobile || rideData.mobilePhone;
                    return _tel ? `📱 <b>Tel:</b> ${_tel}${formatWhatsAppLink(_tel)}\n` : '';
                })() +
                `🕐 <b>Abholung:</b> ${pickupLabel}\n` +
                (isSofort ? `🚗 <b>Anfahrt:</b> ~${drivingTimeMin} Min${best.distance < 999 ? ` (${best.distance.toFixed(1)} km)` : ' (GPS nicht verfügbar)'}\n\n` : '\n') +
                (isSofort ? `⏱️ <i>Bitte in der App annehmen oder ablehnen!</i>` : `💡 <i>Fahrt vorgemerkt für ${pickupLabel}</i>`)
            );
            // 🆕 v6.38.45: Fahrer-Benachrichtigung loggen
            await addRideLog(rideId, '📨', `Fahrer-Telegram: ${best.name}`, {
                chatId: best.telegramChatId,
                ergebnis: _driverMsgResult ? 'gesendet' : 'FEHLGESCHLAGEN',
                fahrzeug: best.name
            });
        } else {
            // 🆕 v6.38.45: Kein Telegram → loggen warum nicht
            await addRideLog(rideId, '⚠️', `Fahrer-Telegram NICHT gesendet: ${best.name} hat keine Chat-ID`, {
                fahrzeug: best.name, vehicleId: best.vehicleId
            });
        }

        // 🚫 v6.62.927 (Patrick 25.05. 10:30, KORRIGIERT v6.62.921):
        //   "Nein, es soll überhaupt nichts gepusht werden bei der Vorbestellung. Es soll
        //   einfach nur abgelegt werden. Der Push soll kommen, kurz bevor die Fahrt ist.
        //   Der Alarm soll kommen 15 Min + Anfahrt. Vorher soll überhaupt nichts passieren,
        //   weil wir wissen ja gar nicht, wer GPS online ist."
        //   v6.62.921 hatte hier FCM-Push direkt bei Vorbest-Zuweisung — wird entfernt.
        //   Losfahr-Alarm (Native, 15 Min + drivingTimeToPickup vor Pickup) uebernimmt.

        best.drivingTimeMin = drivingTimeMin;
        return best;
    } catch (err) {
        console.error('❌ v6.15.1: AutoAssign Fehler:', err);
        // 🆕 v6.63.454: silent exception sichtbar machen — schreibt reason in DB
        try {
            await db.ref(`rides/${rideId}`).update({
                autoAssignLastReason: `outer-catch: ${err && err.message ? err.message.slice(0, 150) : 'unknown error'}`,
                autoAssignLastEarlyStage: 'outer-catch',
                autoAssignLastFailAtV454: Date.now()
            });
        } catch (_) { /* defensive */ }
        return null;
    }
}

// 🔧 v6.20.2: Wartezeit schätzen wenn alle Fahrer besetzt sind
async function estimateWaitTime(pickupCoords) {
    try {
        // 🔧 v6.63.217: nur nahe Pickups (= aktive Fahrten)
        const _eWS = Date.now() - 4 * 60 * 60 * 1000;
        const _eWE = Date.now() + 4 * 60 * 60 * 1000;
        const [vehiclesSnap, ridesSnap] = await Promise.all([
            db.ref('vehicles').once('value'),
            db.ref('rides').orderByChild('pickupTimestamp').startAt(_eWS).endAt(_eWE).once('value')
        ]);
        const vehicles = vehiclesSnap.val() || {};
        const activeRides = [];
        ridesSnap.forEach(c => {
            const r = c.val();
            if (r.status === 'on_way' || r.status === 'picked_up' || r.status === 'assigned') {
                activeRides.push(r);
            }
        });

        if (activeRides.length === 0) return { waitMin: 0, busyCount: 0 };

        // Kürzeste verbleibende Fahrzeit aller aktiven Fahrten schätzen
        let shortestRemaining = Infinity;
        const now = Date.now();

        for (const ride of activeRides) {
            let remainingMin;
            if (ride.status === 'assigned' || ride.status === 'on_way') {
                // Noch nicht abgeholt → Anfahrt + Fahrzeit
                const estDuration = ride.duration || ride.estimatedDuration || 20;
                const startedAt = ride.assignedAt || ride.pickupTimestamp || now;
                const elapsed = (now - startedAt) / 60000;
                remainingMin = Math.max(5, estDuration - elapsed + 5); // +5 Min Rückfahrt-Puffer
            } else if (ride.status === 'picked_up') {
                // Unterwegs → nur restliche Fahrzeit
                const estDuration = ride.duration || ride.estimatedDuration || 20;
                const pickedUpAt = ride.pickedUpAt || ride.assignedAt || now;
                const elapsed = (now - pickedUpAt) / 60000;
                remainingMin = Math.max(3, estDuration - elapsed + 5);
            } else {
                remainingMin = 20;
            }
            if (remainingMin < shortestRemaining) shortestRemaining = remainingMin;
        }

        // Zusätzliche Anfahrt zum neuen Kunden schätzen (~10 Min Durchschnitt auf Usedom)
        const totalWait = Math.round(shortestRemaining + 10);
        // Auf 5er-Schritte runden und Bereich angeben
        const waitMin = Math.max(10, Math.ceil(totalWait / 5) * 5);
        const waitMax = waitMin + 10;

        return { waitMin, waitMax, busyCount: activeRides.length };
    } catch (e) {
        console.error('[WaitEstimate] Fehler:', e.message);
        return { waitMin: 20, waitMax: 30, busyCount: 0 };
    }
}

