// GEOCODING & ROUTING
// ═══════════════════════════════════════════════════════════════

// 🆕 v6.62.839 (Patrick 20.05. 16:11): Hausnummer-Sub-Varianten-Suche.
// Wenn der User 'Strandpromenade 2' eingibt und der Bot eine eindeutige Hausnr 2 findet,
// dann gibt es aber in Wirklichkeit oft mehrere Varianten (2a/2b/2c — Wohneinheiten,
// Eingaenge). Patrick will dass das System bei Bestaetigung schon zeigt:
// 'Strandpromenade 2 existiert + 2a/2b/2c — welche genau?' — statt erst nach Buchung
// festzustellen dass die spezifische Variante anders ist.
//
// Sucht in Nominatim via Strukturierter Suche nach allen Suffixen a-f fuer die Basis-Hausnr.
// Returnt Array { hausnr, lat, lon, displayName, ort } — sortiert nach Suffix.
async function searchHausnumVariants(street, baseHausnr, plz, options = {}) {
    if (!street || !baseHausnr) return [];
    const variants = [];
    const suffixes = ['', 'a', 'b', 'c', 'd', 'e', 'f'];
    const queryBase = `${street} ${baseHausnr}`;
    // Parallele Nominatim-Anfragen fuer alle Suffixe
    const promises = suffixes.map(async (sfx) => {
        const hn = `${baseHausnr}${sfx}`;
        try {
            const url = new URL('https://nominatim.openstreetmap.org/search');
            url.searchParams.set('street', `${street} ${hn}`);
            if (plz) url.searchParams.set('postalcode', plz);
            url.searchParams.set('format', 'json');
            url.searchParams.set('limit', '3');
            url.searchParams.set('countrycodes', 'de');
            url.searchParams.set('addressdetails', '1');
            const resp = await fetch(url.toString(), {
                headers: { 'User-Agent': 'FunkTaxiHeringsdorf/v6.62.839' },
                signal: AbortSignal.timeout(6000)
            });
            if (!resp.ok) return null;
            const data = await resp.json();
            for (const r of (data || [])) {
                const aHn = r.address?.house_number || '';
                if (aHn.toLowerCase() !== hn.toLowerCase()) continue;
                const lat = parseFloat(r.lat), lon = parseFloat(r.lon);
                if (!isFinite(lat) || !isFinite(lon)) continue;
                if (lat < 53.8 || lat > 54.2 || lon < 13.6 || lon > 14.5) continue;
                const ort = r.address?.suburb || r.address?.village || r.address?.town || r.address?.city || '';
                return {
                    hausnr: hn,
                    lat, lon,
                    displayName: r.display_name,
                    ort,
                    road: r.address?.road || street,
                    postcode: r.address?.postcode || plz || ''
                };
            }
            return null;
        } catch (_e) { return null; }
    });
    const results = await Promise.all(promises);
    for (const r of results) {
        if (r) variants.push(r);
    }
    // Sort: zuerst Basis-Nummer, dann Suffix alphabetisch
    variants.sort((a, b) => a.hausnr.localeCompare(b.hausnr, 'de', { numeric: true }));
    return variants;
}

// 🆕 v6.62.839: Geographischer Kontext-Hint aus Google-Places-display_name extrahieren.
// "Strandpromenade 2, 17429 Heringsdorf-Seebad" → "Heringsdorf-Mitte"
// "Liehrstr. 10, 17424 Heringsdorf" → "Heringsdorf (südlich)"
function _buildGeoContext(displayName, hausnr, road) {
    if (!displayName) return '';
    const s = String(displayName);
    // Erkenne Kaiserbad-Ort + ggf. Suburb
    const kaiserbad = ['Bansin', 'Heringsdorf', 'Ahlbeck'].find(k => new RegExp('\\b' + k + '\\b', 'i').test(s));
    if (!kaiserbad) return '';
    // Bei Strandpromenade extra Kontext: durchgehende Promenade alle 3 Kaiserbäder
    if (/strandpromenade/i.test(road || s)) {
        const num = parseInt(hausnr || '0', 10);
        if (num >= 1 && num <= 8) return 'Heringsdorf-Pier-Bereich';
        if (num >= 9 && num <= 29) return 'Heringsdorf-Mitte';
        if (num >= 30 && num <= 45) return 'Bansin-Strandpromenade';
        if (num >= 46) return 'Ahlbeck-Strandpromenade';
    }
    return kaiserbad;
}

async function geocode(address) {
    const searchKey = address.toLowerCase().trim();
    // v6.48.0: KNOWN_PLACES kommt aus /pois (Firebase) statt Code
    const _kp = await getKnownPlaces();
    if (_kp[searchKey]) return _kp[searchKey];

    const cacheKey = 'geocodeCache/' + searchKey.replace(/[.#$/[\]]/g, '_');

    // Geocoding-Cache aus Firebase (mit Validierung) — unverändert übernommen
    try {
        const cacheSnap = await db.ref(cacheKey).once('value');
        const cached = cacheSnap.val();
        if (cached && typeof cached.lat === 'number' && typeof cached.lon === 'number' && cached.lat !== 0 && cached.lon !== 0) {
            const _anyPLZ = address.match(/\b(\d{5})\b/);
            const _usedomPLZ = address.match(/\b(1742[0-9]|1741[0-9]|1743[0-9]|1744[0-9]|1745[0-9])\b/);
            const _isNonUsedom = _anyPLZ && !_usedomPLZ;

            if (_isNonUsedom) {
                console.log(`[Geocode] Nicht-Usedom PLZ ${_anyPLZ[1]} → Cache akzeptiert: ${cached.lat}, ${cached.lon}`);
                return cached;
            }

            if (isNearUsedom(cached.lat, cached.lon)) {
                const plzInAddr = _usedomPLZ;
                if (plzInAddr) {
                    const _plzC = PLZ_CENTERS[plzInAddr[1]];
                    if (_plzC && distanceKm(cached.lat, cached.lon, _plzC.lat, _plzC.lon) > PLZ_MAX_RADIUS_KM) {
                        console.log(`[Geocode] Cache-PLZ-Distanz-Mismatch: ${plzInAddr[1]}, Cache ${distanceKm(cached.lat, cached.lon, _plzC.lat, _plzC.lon).toFixed(1)}km entfernt → neu geocodiert`);
                        try { await db.ref(cacheKey).remove(); } catch (e) {}
                    } else {
                        return cached;
                    }
                } else {
                    return cached;
                }
            } else {
                console.log(`[Geocode] Cache "${address}" außerhalb Usedom (${cached.lat}, ${cached.lon}) → neu geocodiert`);
                try { await db.ref(cacheKey).remove(); } catch (e) {}
            }
        }
    } catch (e) { /* Cache-Fehler ignorieren */ }

    try {
        const plzMatch = address.match(/\b(1742[0-9]|1741[0-9]|1743[0-9]|1744[0-9]|1745[0-9])\b/);
        const addressPLZ = plzMatch ? plzMatch[1] : null;
        const anyPLZMatch = address.match(/\b(\d{5})\b/);
        const isNonUsedomPLZ = anyPLZMatch && !plzMatch;

        // Google Places API Key aus Firebase Settings
        const gKeySnap = await db.ref('settings/googlePlacesApiKey').once('value');
        const gKey = gKeySnap.val();
        if (!gKey) {
            console.error(`[Geocode] ❌ Kein Google Places API Key in settings/googlePlacesApiKey gesetzt — bitte in Firebase eintragen!`);
            return null;
        }

        // Bei Nicht-Usedom PLZ: Suche ohne Region-Bias (deutschlandweit) und nutze Plain-Address
        // Bei Usedom-PLZ oder ohne PLZ: Suche mit locationBias um Heringsdorf
        const requestBody = {
            textQuery: address,
            languageCode: 'de',
            maxResultCount: 5
        };
        if (!isNonUsedomPLZ) {
            // Usedom-Bias: Kreis 25km um Heringsdorf-Mitte (lat 53.95, lon 14.10)
            requestBody.locationBias = {
                circle: { center: { latitude: 53.95, longitude: 14.10 }, radius: 25000.0 }
            };
        }

        const resp = await fetch('https://places.googleapis.com/v1/places:searchText', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-Goog-Api-Key': gKey,
                'X-Goog-FieldMask': 'places.location,places.displayName,places.formattedAddress,places.postalAddress'
            },
            body: JSON.stringify(requestBody)
        });
        const data = await resp.json();
        if (data.error) {
            console.warn(`[Geocode] Google Places Error für "${address}":`, data.error.message || data.error);
            return null;
        }
        if (!data.places || data.places.length === 0) {
            // 🆕 v6.62.198: Patrick will KEIN Nominatim — stattdessen Places mit Query-Varianten retry
            console.log(`[Geocode] Google Places: keine Treffer für "${address}" → versuche Varianten`);
            return await geocodePlacesRetry(address, gKey, addressPLZ, isNonUsedomPLZ, cacheKey);
        }

        // Konvertiere Places-Result in unser internes Format
        const candidates = data.places.map(p => ({
            lat: p.location?.latitude,
            lon: p.location?.longitude,
            display_name: p.formattedAddress || p.displayName?.text || '',
            address: {
                road: p.postalAddress?.addressLines?.[0] || '',
                postcode: p.postalAddress?.postalCode || '',
                city: p.postalAddress?.locality || ''
            }
        })).filter(c => typeof c.lat === 'number' && typeof c.lon === 'number');
        if (candidates.length === 0) return null;

        // Bei Nicht-Usedom PLZ: erstes Result direkt nehmen (Google sortiert nach Relevanz)
        if (isNonUsedomPLZ) {
            const first = candidates[0];
            console.log(`[Geocode] "${address}" → Google (Nicht-Usedom PLZ): ${first.lat}, ${first.lon} (${first.display_name})`);
            return first;
        }

        // PLZ-Validierung: Wenn PLZ in Adresse, Treffer innerhalb PLZ_MAX_RADIUS_KM bevorzugen
        const _plzC = addressPLZ ? PLZ_CENTERS[addressPLZ] : null;
        if (_plzC && candidates.length > 1) {
            const nearHits = candidates.filter(c => distanceKm(c.lat, c.lon, _plzC.lat, _plzC.lon) <= PLZ_MAX_RADIUS_KM);
            if (nearHits.length > 0) {
                console.log(`[Geocode] "${address}" → Google (PLZ ${addressPLZ}): ${nearHits[0].lat}, ${nearHits[0].lon} (${nearHits[0].display_name})`);
                const result = nearHits[0];
                if (isNearUsedom(result.lat, result.lon)) {
                    try { await db.ref(cacheKey).set(result); } catch (e) {}
                }
                return result;
            }
            console.log(`[Geocode] "${address}" → Kein Google-Treffer innerhalb ${PLZ_MAX_RADIUS_KM}km PLZ ${addressPLZ} — nutze besten: ${candidates[0].display_name}`);
        } else if (_plzC) {
            const dist = distanceKm(candidates[0].lat, candidates[0].lon, _plzC.lat, _plzC.lon);
            if (dist > PLZ_MAX_RADIUS_KM) {
                console.warn(`[Geocode] ⚠️ "${address}" → Treffer ${dist.toFixed(1)}km von PLZ ${addressPLZ} entfernt: ${candidates[0].display_name}`);
            }
        }

        const result = candidates[0];
        console.log(`[Geocode] "${address}" → Google: ${result.lat}, ${result.lon} (${result.display_name})`);
        if (isNearUsedom(result.lat, result.lon)) {
            try { await db.ref(cacheKey).set(result); } catch (e) {}
        }
        return result;
    } catch (e) {
        console.warn('Geocoding (Google Places) Fehler:', e.message);
        return null;
    }
}

// 🆕 v6.62.199: Patrick will KEIN Nominatim — stattdessen Places mit Query-Varianten retry
// Wenn Erst-Anfrage leer ist, probieren wir 4 alternative Schreibweisen:
// 1) Suffix ', Heringsdorf'  2) Suffix ', Usedom'  3) ohne PLZ  4) Strasse + Hausnr extrahiert
async function geocodePlacesRetry(address, gKey, addressPLZ, isNonUsedomPLZ, cacheKey) {
    const variants = [];
    // Hat schon 'Heringsdorf'/'Ahlbeck'/'Bansin'/'Usedom'? Dann nicht doppelt
    const lower = address.toLowerCase();
    const hasOrt = /heringsdorf|ahlbeck|bansin|zinnowitz|koserow|swinem|świnouj|usedom/.test(lower);
    if (!hasOrt) {
        variants.push(address + ', Heringsdorf');
        variants.push(address + ', Usedom');
    }
    // PLZ entfernen (manchmal stoert sie)
    const noPlz = address.replace(/\b\d{5}\b/g, '').replace(/,\s*,/g, ',').replace(/^\s*,\s*/, '').trim();
    if (noPlz && noPlz !== address) variants.push(noPlz);
    // Nur Strasse + Hausnummer extrahieren (vor erstem Komma)
    const firstPart = address.split(',')[0].trim();
    if (firstPart && firstPart !== address) variants.push(firstPart + (hasOrt ? '' : ', Heringsdorf'));

    for (const q of variants) {
        try {
            const requestBody = {
                textQuery: q,
                languageCode: 'de',
                maxResultCount: 5
            };
            if (!isNonUsedomPLZ) {
                requestBody.locationBias = {
                    circle: { center: { latitude: 53.95, longitude: 14.10 }, radius: 25000.0 }
                };
            }
            const resp = await fetch('https://places.googleapis.com/v1/places:searchText', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-Goog-Api-Key': gKey,
                    'X-Goog-FieldMask': 'places.location,places.displayName,places.formattedAddress,places.postalAddress'
                },
                body: JSON.stringify(requestBody)
            });
            const data = await resp.json();
            if (data.error || !data.places || data.places.length === 0) continue;
            const p = data.places[0];
            const lat = p.location?.latitude, lon = p.location?.longitude;
            if (typeof lat !== 'number' || typeof lon !== 'number') continue;
            console.log(`[Geocode] Retry-Treffer für "${address}" via "${q}" → ${lat}, ${lon}`);
            const result = {
                lat, lon,
                display_name: p.formattedAddress || p.displayName?.text || '',
                address: {
                    road: p.postalAddress?.addressLines?.[0] || '',
                    postcode: p.postalAddress?.postalCode || '',
                    city: p.postalAddress?.locality || ''
                },
                source: 'google-places-retry'
            };
            try { if (isNearUsedom(lat, lon)) await db.ref(cacheKey).set(result); } catch (e) {}
            return result;
        } catch (e) {
            console.warn(`[Geocode] Retry "${q}" Fehler:`, e.message);
        }
    }
    console.warn(`[Geocode] ❌ Kein Treffer für "${address}" auch nach ${variants.length} Varianten`);
    return null;
}

// Reverse-Geocoding: Koordinaten → Adresse
async function reverseGeocode(lat, lon) {
    try {
        const resp = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}&addressdetails=1&zoom=18`, {
            headers: { 'User-Agent': 'TaxiHeringsdorf/1.0' }
        });
        const data = await resp.json();
        if (data && data.address) {
            const addr = data.address;
            const poiName = (data.namedetails?.name || data.name || addr.amenity || addr.tourism || addr.shop || addr.leisure || '');
            let streetPart = '';
            const _road = addr.road || addr.residential || addr.neighbourhood || addr.suburb || addr.hamlet || '';
            if (_road) streetPart = _road + (addr.house_number ? ' ' + addr.house_number : '');
            else if (addr.pedestrian) streetPart = addr.pedestrian;
            const town = addr.town || addr.city || addr.village || addr.municipality || '';
            const postcode = addr.postcode || '';
            let fullName;
            if (poiName && streetPart && !poiName.includes(streetPart.split(' ')[0])) {
                fullName = `${poiName}, ${streetPart}` + (town ? `, ${postcode ? postcode + ' ' : ''}${town}` : '');
            } else if (streetPart) {
                fullName = streetPart + (town ? `, ${postcode ? postcode + ' ' : ''}${town}` : '');
            } else if (poiName) {
                fullName = poiName + (town ? `, ${postcode ? postcode + ' ' : ''}${town}` : '');
            } else if (data.display_name) {
                fullName = data.display_name.split(',').slice(0, 3).join(',').trim();
            } else {
                fullName = `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
            }
            return { name: fullName, lat: parseFloat(data.lat), lon: parseFloat(data.lon), display_name: data.display_name, address: addr };
        }
        return null;
    } catch (e) {
        console.warn('Reverse-Geocoding Fehler:', e.message);
        return null;
    }
}

// 🔧 v6.11.0: Adresse sauber validieren – wenn nur POI-Name ohne Straße, per Reverse-Geocoding nachrüsten
async function cleanupAddress(currentName, lat, lon) {
    if (!lat || !lon) return currentName;
    // Prüfe ob Adresse schon "sauber" ist (enthält Nummer + PLZ oder Komma)
    const hasStreetNumber = /\d/.test(currentName) && currentName.includes(',');
    if (hasStreetNumber) return currentName;
    // Reverse-Geocoding für saubere Adresse
    try {
        const rev = await reverseGeocode(lat, lon);
        if (rev && rev.name && rev.name.length > currentName.length) {
            console.log(`[CleanupAddr] "${currentName}" → "${rev.name}"`);
            return rev.name;
        }
    } catch (e) {}
    return currentName;
}

// 🔧 v6.15.1: Komplett überarbeitet — POIs + Kunden priorisiert, Nominatim nur als Ergänzung
// Gleiche Logik wie Browser-Autocomplete in index.html

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.25.5: GEOCACHE — Adressdatenbank in Firebase
// Jede geocodierte Adresse wird gespeichert und bei zukünftigen Suchen priorisiert.
// Admin kann Adressen über die App verifizieren/korrigieren.
// ═══════════════════════════════════════════════════════════════

// Adresse normalisieren für Cache-Key (Kleinbuchstaben, keine Doppel-Leerzeichen, Abkürzungen expandiert)
function normalizeAddressKey(address) {
    return address.toLowerCase().trim()
        .replace(/\bstr\.?\b/g, 'straße')
        .replace(/\bpl\.?\b/g, 'platz')
        .replace(/\bhbf\.?\b/g, 'hauptbahnhof')
        .replace(/\bbhf\.?\b/g, 'bahnhof')
        .replace(/[,.\-\/]+/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
}

// Geocache-Eintrag speichern (nach erfolgreicher Geocodierung oder Buchung)
async function saveToGeocache(address, lat, lon, source = 'nominatim') {
    if (!address || !lat || !lon) return;
    const key = normalizeAddressKey(address);
    if (key.length < 3) return;
    try {
        const existing = await db.ref('geocache').orderByChild('normalizedKey').equalTo(key).once('value');
        if (existing.exists()) {
            // Bereits im Cache → usageCount erhöhen, ggf. verifizieren
            const _shouldVerify = source === 'gps-verified' || source === 'admin-edit';
            existing.forEach(child => {
                const data = child.val();
                db.ref(`geocache/${child.key}`).update({
                    usageCount: (data.usageCount || 1) + 1,
                    lastUsed: Date.now(),
                    // Koordinaten updaten wenn nicht bereits verifiziert
                    ...(!data.verified && { lat, lon }),
                    // Verified-Status setzen wenn GPS-bestätigt oder Admin
                    ...(_shouldVerify && !data.verified && { verified: true, verifiedAt: Date.now() })
                });
            });
        } else {
            // Neu eintragen — GPS-verifiziert und Admin-Einträge direkt als verified markieren
            const _isVerified = source === 'gps-verified' || source === 'admin-edit';
            await db.ref('geocache').push({
                address: address.trim(),
                normalizedKey: key,
                lat: parseFloat(lat),
                lon: parseFloat(lon),
                source,
                verified: _isVerified,
                verifiedAt: _isVerified ? Date.now() : null,
                usageCount: 1,
                createdAt: Date.now(),
                lastUsed: Date.now()
            });
        }
    } catch (e) { console.warn('Geocache-Speichern Fehler:', e.message); }
}

// 🔧 v6.38.26: Top-Level Levenshtein für Fuzzy-Adresssuche (nicht nur CRM-Kundensuche)
function _levenshteinDist(a, b) {
    const m = a.length, n = b.length;
    if (m === 0) return n;
    if (n === 0) return m;
    const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
    for (let i = 0; i <= m; i++) dp[i][0] = i;
    for (let j = 0; j <= n; j++) dp[0][j] = j;
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            dp[i][j] = Math.min(
                dp[i - 1][j] + 1,
                dp[i][j - 1] + 1,
                dp[i - 1][j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1)
            );
        }
    }
    return dp[m][n];
}

// 🆕 v6.38.42: Google Maps Link erkennen → Koordinaten + Adresse extrahieren
function extractGoogleMapsCoords(text) {
    if (!text) return null;
    // Format 1: https://www.google.com/maps/place/.../@54.1234,13.5678,17z/...
    // Format 2: https://maps.google.com/?q=54.1234,13.5678
    // Format 3: https://www.google.de/maps/@54.1234,13.5678,...
    // Format 4: https://maps.app.goo.gl/... (short URL — can't resolve server-side)
    // Format 5: google.com/maps?q=... or maps?ll=...
    let match;
    // @lat,lon pattern (most common when sharing from Google Maps)
    match = text.match(/google\.[a-z.]+\/maps[^\s]*\/@(-?\d+\.\d+),(-?\d+\.\d+)/i);
    if (match) return { lat: parseFloat(match[1]), lon: parseFloat(match[2]) };
    // ?q=lat,lon or &q=lat,lon
    match = text.match(/google\.[a-z.]+\/maps[^\s]*[?&]q=(-?\d+\.\d+),(-?\d+\.\d+)/i);
    if (match) return { lat: parseFloat(match[1]), lon: parseFloat(match[2]) };
    // ?ll=lat,lon
    match = text.match(/google\.[a-z.]+\/maps[^\s]*[?&]ll=(-?\d+\.\d+),(-?\d+\.\d+)/i);
    if (match) return { lat: parseFloat(match[1]), lon: parseFloat(match[2]) };
    // place/.../ with coords in URL
    match = text.match(/google\.[a-z.]+\/maps\/place\/[^@]*@(-?\d+\.\d+),(-?\d+\.\d+)/i);
    if (match) return { lat: parseFloat(match[1]), lon: parseFloat(match[2]) };
    // Direct coordinate paste: 54.1234, 13.5678 (not in a URL context but could be useful)
    match = text.match(/^(-?\d{1,3}\.\d{3,8})\s*[,;]\s*(-?\d{1,3}\.\d{3,8})$/);
    if (match) {
        const lat = parseFloat(match[1]), lon = parseFloat(match[2]);
        if (lat >= -90 && lat <= 90 && lon >= -180 && lon <= 180) return { lat, lon };
    }
    return null;
}

// 🔧 v6.38.55: Duplikat reverseGeocode entfernt — die Version ab Zeile ~2369 wird verwendet (mit residential/neighbourhood/hamlet Fallbacks)

async function searchNominatimForTelegram(query) {
    if (!query) return [];
    // 🔧 v6.25.4: Hausnummern-Bereiche normalisieren ("7 bis 8" → "7", "7-8" → "7")
    // Nominatim kann keine Hausnummern-Bereiche, nimmt nur die erste Nummer
    query = query.replace(/(\d+)\s*(?:bis|[-–])\s*\d+/gi, '$1');
    // 🔧 v6.25.5: Deutsche Straßen-Abkürzungen expandieren für bessere Nominatim-Ergebnisse
    // 🔧 v6.35.0 Fix 4: Zusammengeschriebene Formen zuerst ("Kaiserstr" → "Kaiserstraße")
    // Vor dem standalone-\bStr\b-Replace, damit "Kaiserstr 9" korrekt expandiert wird
    query = query.replace(/([a-zäöüßA-ZÄÖÜ])str\.?(\s|$)/g, (m, pre, post) => pre + 'straße' + post);
    query = query.replace(/\bStr\.?\b/g, 'Straße').replace(/\bPl\.?\b/g, 'Platz').replace(/\bHbf\.?\b/gi, 'Hauptbahnhof').replace(/\bBhf\.?\b/gi, 'Bahnhof');
    // 🔧 Fix 4: Zusammengeschriebene Abkürzungen wie "Kaiserstr" (ohne Punkt/Leerzeichen) expandieren
    query = query.replace(/([a-zA-ZäöüÄÖÜß])str\.?\b/g, '$1straße')
                 .replace(/([a-zA-ZäöüÄÖÜß])pl\.?\b/gi, '$1platz');
    // 🔧 v6.25.5: Wenn nur Ortsname + Hausnummer (z.B. "Bansin 21a"),
    // erkennen und Ort vom Rest trennen — Nominatim sucht sonst nach einer Straße namens "Bansin"
    const ortsnamen = ['Heringsdorf', 'Ahlbeck', 'Bansin', 'Zinnowitz', 'Koserow', 'Ückeritz',
        'Loddin', 'Trassenheide', 'Zempin', 'Karlshagen', 'Peenemünde', 'Wolgast', 'Anklam'];
    for (const ort of ortsnamen) {
        const ortRegex = new RegExp(`^${ort}\\s+(\\d+\\s*[a-z]?)$`, 'i');
        const ortMatch = query.match(ortRegex);
        if (ortMatch) {
            // "Bansin 21a" → "21a, Bansin" — Nominatim versteht das besser
            query = ortMatch[1] + ', ' + ort;
            break;
        }
    }
    // 🔧 v6.25.5: Reine PLZ-Eingabe zu Ortsname expandieren (z.B. "17424" → "Heringsdorf")
    const purePlZMatch = query.trim().match(/^(\d{5})$/);
    if (purePlZMatch && PLZ_CENTERS[purePlZMatch[1]]) {
        query = PLZ_CENTERS[purePlZMatch[1]].name;
    }
    const searchKey = query.toLowerCase().trim();
    const fetchOpts = { headers: { 'User-Agent': 'TaxiHeringsdorf/1.0' } };
    const searchWords = searchKey.replace(/[,./]/g, ' ').split(/\s+/).filter(w => w.length > 2); // 🔧 v6.38.61: min 3 Zeichen (vorher >1) — "O", "am" etc. nicht matchen

    // Hilfsfunktion: Wort-Anfang-Match (höhere Priorität als includes)
    const wordBoundaryRegex = new RegExp('(^|\\s|,)' + searchKey.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i');

    // ═══════════════════════════════════════════════════════════
    // STUFE 0: GEOCACHE (bereits bekannte Adressen — höchste Priorität!)
    // ═══════════════════════════════════════════════════════════
    const localResults = [];
    const seen = new Set();

    const addIfNew = (entry) => {
        const coordKey = `${parseFloat(entry.lat).toFixed(3)}_${parseFloat(entry.lon).toFixed(3)}`;
        if (!seen.has(coordKey)) {
            seen.add(coordKey);
            localResults.push(entry);
        }
    };

    // 0) Geocache — gespeicherte Adressen mit Koordinaten (verifizierte zuerst!)
    // 🔧 v6.25.5: Verbesserte Suche — auch Teilwort-Matches (z.B. "Lidl" findet "Lidl, Ahlbecker Chaussee 9, Bansin")
    try {
        const geocacheSnap = await db.ref('geocache').once('value');
        if (geocacheSnap.exists()) {
            const cacheHits = [];
            geocacheSnap.forEach(child => {
                const entry = child.val();
                if (!entry.address || !entry.lat || !entry.lon) return;
                const addr = entry.address.toLowerCase();
                const normKey = entry.normalizedKey || '';
                // 🔧 v6.38.37: Label (Firmenname von CRM-Lieferanten) auch durchsuchen
                const label = (entry.label || '').toLowerCase();
                const labelNorm = label.replace(/[''`´]/g, '').replace(/[^a-zäöüß0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
                // Alle durchsuchbaren Texte kombinieren
                const allText = addr + ' ' + normKey + ' ' + label + ' ' + labelNorm;

                // Score berechnen: Je mehr Suchwörter matchen, desto besser
                let matchScore = 0;
                const isExact = wordBoundaryRegex.test(addr) || normKey === searchKey ||
                    wordBoundaryRegex.test(label) || wordBoundaryRegex.test(labelNorm);
                const isIncludes = addr.includes(searchKey) || (normKey.length >= 4 && searchKey.includes(normKey)) ||  // 🔧 v6.38.61: normKey min 4 Zeichen (vorher kein Limit!)
                    label.includes(searchKey) || labelNorm.includes(searchKey);
                const isAllWords = searchWords.length > 0 && searchWords.every(w => allText.includes(w));

                if (isExact) matchScore = 100;
                else if (isIncludes) matchScore = 80;
                else if (isAllWords) matchScore = 60;
                else if (searchWords.length > 0) {
                    // Teilwort-Match: Wie viele Suchwörter sind in Adresse ODER Label enthalten?
                    const matchedWords = searchWords.filter(w => allText.includes(w));
                    if (matchedWords.length > 0) {
                        matchScore = Math.round((matchedWords.length / searchWords.length) * 50);
                        if (matchedWords.some(w => addr.startsWith(w) || normKey.startsWith(w) || label.startsWith(w))) matchScore += 10;
                    }
                    // 🔧 v6.38.26: Fuzzy-Fallback — auch bei Tippfehlern matchen
                    // 🔧 v6.62.737: Fuzzy-Distanz auf max 1 (vorher 2) — verhindert
                    // 'ellenthin' → 'sallenthin' (Patrick 15.05.: Mellenthin-Drama).
                    // Substring-Match nur wenn Laengen-Diff <=2 (sonst 'mell' in 'mellenthin' gegen 'sallenthin' falsch positiv).
                    if (matchScore === 0) {
                        const allWords = allText.replace(/[,./]/g, ' ').split(/\s+/).filter(w => w.length > 1);
                        const fuzzyMatched = searchWords.filter(sw =>
                            allWords.some(aw => {
                                const lenDiff = Math.abs(sw.length - aw.length);
                                if (lenDiff <= 2 && (aw.includes(sw) || sw.includes(aw))) return true;
                                return _levenshteinDist(sw, aw) <= 1;
                            })
                        );
                        if (fuzzyMatched.length === searchWords.length) matchScore = 40;
                        else if (fuzzyMatched.length > 0) matchScore = Math.round((fuzzyMatched.length / searchWords.length) * 30);
                    }
                }

                // Mindestens 1 Wort muss matchen (Score > 0)
                if (matchScore > 0) {
                    // 🆕 v6.41.13: USEDOM-ORT-KONFLIKT-CHECK
                    // Bug: "bahnhof heringsdorf" → "Bahnhof Ahlbeck" (score 35 fuzzy/partial)
                    // Root cause: Score basiert nur auf Anzahl Treffer — ignoriert dass
                    //   ein Ortsname in der Suche fehlt UND ein ANDERER Ort in der Adresse ist.
                    // Fix: Wenn User Ort X sucht aber Adresse Ort Y enthält → reject.
                    // 🔧 v6.62.853 (Patrick 21.05. 19:13): Kaiserbäder-Synonym-Ausnahme.
                    //   Bansin/Ahlbeck/Heringsdorf sind EINE Gemeinde (PLZ 17424/17429).
                    //   'Strandpromenade 17, Bansin' fand in Geocache nur 'Heringsdorf'-Variante
                    //   und wurde mit Score=0 fälschlich verworfen. Mit Synonym-Liste: durchlassen.
                    const _USEDOM_ORTE = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz', 'ückeritz', 'uckeritz', 'loddin', 'zempin', 'koserow', 'karlshagen', 'peenemünde', 'peenemuende', 'trassenheide'];
                    const _KAISERBAEDER_SYN = ['heringsdorf', 'ahlbeck', 'bansin'];
                    const searchOrt = searchWords.find(w => _USEDOM_ORTE.includes(w));
                    if (searchOrt) {
                        const addrOrt = _USEDOM_ORTE.find(ort => addr.includes(ort) || labelNorm.includes(ort));
                        if (addrOrt && addrOrt !== searchOrt) {
                            const _bothKB = _KAISERBAEDER_SYN.includes(searchOrt) && _KAISERBAEDER_SYN.includes(addrOrt);
                            if (!_bothKB) {
                                console.log(`🛡️ Ort-Konflikt: Suche "${searchOrt}" vs. Adresse "${addrOrt}" → ${entry.address} verworfen`);
                                matchScore = 0;
                            }
                        }
                    }
                }

                // Nochmal prüfen nach Ort-Konflikt-Check
                if (matchScore > 0) {
                    // 🔧 v6.38.37: Bei Label-Match → "Label — Adresse" als Name anzeigen
                    const displayName = (label && matchScore >= 60 && searchWords.some(w => label.includes(w) || labelNorm.includes(w)))
                        ? `${entry.label} — ${entry.address}` : entry.address;
                    // 🔧 v6.38.61: matchReason für Log-Debugging
                    let matchReason = '';
                    if (isExact) matchReason = 'exact';
                    else if (isIncludes) matchReason = addr.includes(searchKey) ? 'addr⊇query' : (normKey.length >= 4 && searchKey.includes(normKey)) ? `query⊇normKey(${normKey})` : label.includes(searchKey) ? 'label⊇query' : 'labelNorm⊇query';
                    else if (isAllWords) matchReason = 'allWords';
                    else matchReason = 'fuzzy/partial';
                    cacheHits.push({
                        name: displayName,
                        lat: entry.lat,
                        lon: entry.lon,
                        source: entry.verified ? 'geocache-verified' : 'geocache',
                        priority: entry.verified ? -1 : 0,
                        usageCount: entry.usageCount || 1,
                        matchScore,
                        matchReason
                    });
                }
            });
            // Verifizierte zuerst, dann nach Match-Score, dann nach Nutzungshäufigkeit
            cacheHits.sort((a, b) => (a.priority - b.priority) || (b.matchScore - a.matchScore) || (b.usageCount - a.usageCount));
            for (const hit of cacheHits.slice(0, 3)) {
                addIfNew(hit);
            }
        }
    } catch (e) { console.warn('Geocache-Suche Fehler:', e.message); }

    // ═══════════════════════════════════════════════════════════
    // STUFE 1: LOKALE QUELLEN (gepflegte Daten)
    // ═══════════════════════════════════════════════════════════

    // 🔧 v6.38.26: Fuzzy-Wort-Match Hilfsfunktion für POI/Geocache/KNOWN_PLACES
    // Prüft ob JEDES Suchwort fuzzy (Levenshtein ≤ 2) in einem der Ziel-Wörter vorkommt
    const _fuzzyWordMatch = (searchWds, targetText) => {
        if (searchWds.length === 0) return false;
        const targetWords = targetText.replace(/[,./]/g, ' ').split(/\s+/).filter(w => w.length > 1);
        if (targetWords.length === 0) return false;
        return searchWds.every(sw =>
            targetWords.some(tw => {
                // 🆕 v6.62.199: Substring-Match nur bei Laengen-Diff <=2
                // Vorher: 'wolgastsee'.includes('wolgast') = true → POI 'Bahnhof Wolgast' matchte
                // bei Suche nach 'Idyll am Wolgastsee'. Patrick: 'Was soll der Scheiss?'
                // Jetzt: Substring nur wenn Laengen-Diff <= 2 (z.B. 'idyll' ↔ 'idylle' OK,
                // 'wolgast' ↔ 'wolgastsee' BLOCKIERT)
                const lenDiff = Math.abs(sw.length - tw.length);
                if (lenDiff <= 2 && (tw.includes(sw) || sw.includes(tw))) return true;
                // Fuzzy-Match: Levenshtein-Distanz ≤ 2 (bei kurzen Wörtern ≤ 1)
                const maxDist = Math.max(sw.length, tw.length) >= 7 ? 2 : 1;
                return _levenshteinDist(sw, tw) <= maxDist;
            })
        );
    };

    // 1a) POIs aus Firebase (⭐ deine gepflegten Favoriten)
    try {
        const poisSnap = await db.ref('pois').once('value');
        if (poisSnap.exists()) {
            poisSnap.forEach(child => {
                const poi = child.val();
                if (!poi.name || !poi.lat || !poi.lon) return;
                const poiName = poi.name.toLowerCase();
                const poiAddr = (poi.address || '').toLowerCase();
                const isExact = wordBoundaryRegex.test(poiName) || wordBoundaryRegex.test(poiAddr);
                const isIncludes = poiName.includes(searchKey) || poiAddr.includes(searchKey);
                const isWordMatch = searchWords.length > 0 && searchWords.every(w => poiName.includes(w) || poiAddr.includes(w));
                // 🔧 v6.38.26: Fuzzy-Match als Fallback (z.B. "Bierkuscher" → "Bierkutscher")
                const isFuzzy = !isExact && !isIncludes && !isWordMatch && _fuzzyWordMatch(searchWords, poiName + ' ' + poiAddr);
                if (isExact || isIncludes || isWordMatch || isFuzzy) {
                    const displayName = poi.address ? (poi.address.toLowerCase().startsWith(poi.name.toLowerCase()) ? poi.address : `${poi.name}, ${poi.address}`) : poi.name;
                    addIfNew({ name: displayName, lat: poi.lat, lon: poi.lon, source: 'poi', priority: isExact ? 0 : (isFuzzy ? 2 : 1) });
                }
            });
        }
    } catch (e) { console.warn('POI-Suche Fehler:', e.message); }

    // 1b) KNOWN_PLACES — v6.48.0: kommt jetzt aus /pois (Firebase) statt Code (deduped via getKnownPlaces)
    const _kpForSearch = await getKnownPlaces();
    for (const [key, place] of Object.entries(_kpForSearch)) {
        const placeName = (place.name || '').toLowerCase();
        const isExact = wordBoundaryRegex.test(key) || wordBoundaryRegex.test(placeName);
        const isIncludes = key.includes(searchKey) || placeName.includes(searchKey);
        const isWordMatch = searchWords.length > 0 && searchWords.every(w => key.includes(w) || placeName.includes(w));
        // 🔧 v6.39.0: Auch umgekehrt prüfen — Key-Wörter im Suchtext?
        // z.B. Key "bahnhof bansin" → Suchtext "Bahnhof Bansin Seebad, 17429 Heringsdorf" enthält BEIDE Key-Wörter
        const keyWords = key.split(/\s+/).filter(w => w.length > 2);
        const isReverseMatch = !isExact && !isIncludes && !isWordMatch && keyWords.length >= 2 &&
            keyWords.every(kw => searchKey.includes(kw));
        // 🔧 v6.38.26: Fuzzy-Match für KNOWN_PLACES
        const isFuzzy = !isExact && !isIncludes && !isWordMatch && !isReverseMatch && _fuzzyWordMatch(searchWords, key + ' ' + placeName);
        if (isExact || isIncludes || isWordMatch || isReverseMatch || isFuzzy) {
            addIfNew({ name: place.name || key, lat: place.lat, lon: place.lon, source: 'known', priority: isExact ? 0 : (isReverseMatch ? 0 : (isFuzzy ? 2 : 1)) });
        }
    }

    // 🔧 v6.25.4: PLZ aus Query extrahieren für lokale Quellen-Filterung
    const _queryPLZ = query.match(/\b(1742[0-9]|1741[0-9]|1743[0-9]|1744[0-9]|1745[0-9])\b/);
    const _queryPostcode = _queryPLZ ? _queryPLZ[1] : null;
    const _plzCenter = _queryPostcode ? PLZ_CENTERS[_queryPostcode] : null;

    // 1c) CRM-Kunden mit Adressen
    // 🔧 v6.15.7: Usedom-PLZ-Erkennung für Koordinaten-Validierung
    const USEDOM_PLZ = ['17424', '17429', '17419', '17438', '17440', '17449', '17454', '17459'];
    const _looksLikeUsedom = (text) => {
        const t = text.toLowerCase();
        return USEDOM_PLZ.some(p => t.includes(p)) ||
            /\b(usedom|heringsdorf|ahlbeck|bansin|zinnowitz|trassenheide|karlshagen|koserow|loddin|ückeritz|zempin|peenemünde|wolgast)\b/i.test(t);
    };
    try {
        const custSnap = await db.ref('customers').once('value');
        if (custSnap.exists()) {
            // 🔧 v6.38.37: Sonderzeichen-Normalisierung für Fuzzy-Vergleich
            // "Marc O'Polo" → "marc opolo", "Marco Polo" → "marco polo"
            const _normalizeName = (s) => s.toLowerCase().replace(/[''`´]/g, '').replace(/[^a-zäöüß0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
            const _searchNorm = _normalizeName(query);
            const _searchWordsNorm = _searchNorm.split(/\s+/).filter(w => w.length > 1);
            // 🔧 v6.38.59: Erkennung ob Query eine Adresse ist (Straße+Nr/PLZ)
            const _queryIsAddress = /(?:straße|str\.|weg\b|allee|platz|ring|gasse|chaussee|damm|promenade)\b/i.test(query) ||
                /\b\d{5}\b/.test(query) || /\b\d+[a-z]?\s*,/.test(query);
            if (_queryIsAddress) {
                console.log(`[CRM] Query "${query}" sieht nach Adresse aus → CRM-Fuzzy deaktiviert, nur exakte Matches`);
            }
            custSnap.forEach(child => {
                const c = child.val();
                if (!c.name || !c.address) return;
                const cName = c.name.toLowerCase();
                const cAddr = c.address.toLowerCase();
                const cNameNorm = _normalizeName(c.name);
                // Exakter/Teilstring-Match
                const isExactMatch = cName.includes(searchKey) || cAddr.includes(searchKey) ||
                    (searchWords.length > 0 && searchWords.every(w => cName.includes(w) || cAddr.includes(w)));
                // 🔧 v6.38.59: Bei Adress-Queries NUR exakte Matches — kein Fuzzy/Norm!
                if (_queryIsAddress) {
                    if (!isExactMatch) return;
                } else {
                // 🔧 v6.38.37: Normalisierter Match (Apostrophe/Sonderzeichen entfernt)
                // "marco polo" → Wörter ["marco", "polo"] — jedes muss irgendwo im normalisierten Namen vorkommen
                const isNormMatch = !isExactMatch && (cNameNorm.includes(_searchNorm) || _searchNorm.includes(cNameNorm.split(' ')[0]) ||
                    (_searchWordsNorm.length > 0 && _searchWordsNorm.every(w => cNameNorm.includes(w) || cNameNorm.split(' ').some(nw => nw.includes(w) || w.includes(nw)))));
                // 🔧 v6.38.37: Fuzzy-Match als letzter Fallback (Levenshtein)
                const isFuzzyMatch = !isExactMatch && !isNormMatch && _fuzzyWordMatch(_searchWordsNorm, cNameNorm);
                if (!isExactMatch && !isNormMatch && !isFuzzyMatch) return;
                }
                // Treffer gefunden:
                if (true) {
                    let lat = c.lat || c.pickupLat;
                    let lon = c.lon || c.pickupLon;
                    if (lat && lon) {
                        // 🔧 v6.15.7: Usedom-Adresse muss Usedom-Koordinaten haben
                        if (_looksLikeUsedom(c.address) && !isNearUsedom(parseFloat(lat), parseFloat(lon))) {
                            return; // Falsche Koordinaten → überspringen
                        }
                        // 🔧 v6.25.4: PLZ-Distanz-Check — CRM-Koordinaten müssen zum angefragten PLZ-Gebiet passen
                        if (_plzCenter) {
                            const dist = distanceKm(parseFloat(lat), parseFloat(lon), _plzCenter.lat, _plzCenter.lon);
                            if (dist > PLZ_MAX_RADIUS_KM) {
                                console.log(`[PLZ-Filter] CRM "${c.name}" übersprungen: ${dist.toFixed(1)}km von PLZ ${_queryPostcode} entfernt`);
                                return;
                            }
                        }
                        // 🔧 v6.38.9: name = nur Adresse (wird als Buchungsadresse gespeichert), label = für Anzeige
                        addIfNew({ name: c.address, label: `${c.name}: ${c.address}`, lat, lon, source: 'customer', priority: 2 });
                    } else {
                        // 🆕 v6.25.5: CRM-Kunde ohne Koordinaten → trotzdem anzeigen!
                        // Koordinaten werden bei Auswahl per Geocoding nachgeladen
                        console.log(`[CRM] "${c.name}" matcht aber hat keine Koordinaten → trotzdem vorschlagen`);
                        addIfNew({ name: c.address, label: `${c.name}: ${c.address}`, lat: 0, lon: 0, source: 'customer-nocoords', priority: 3 });
                    }
                }
            });
        }
    } catch (e) { console.warn('Kunden-Suche Fehler:', e.message); }

    // 1d) Häufige Ziele aus ALLEN Buchungen (nutzt USEDOM_PLZ/_looksLikeUsedom von oben)
    // 🔧 v6.38.27: ALLE Fahrten durchsuchen, nicht nur die letzten 200
    // 🔧 v6.63.217: Cost-Detox — auf letzte 90 Tage beschränken (Adress-Historie reicht)
    try {
        const _addrWS = Date.now() - 90 * 24 * 60 * 60 * 1000;
        const ridesSnap = await db.ref('rides').orderByChild('pickupTimestamp').startAt(_addrWS).once('value');
        const destCount = {};
        // 🔧 v6.38.48: Normalisierung für Duplikat-Erkennung
        const _normAddr = (a) => {
            if (!a) return '';
            let n = a.toLowerCase().trim();
            n = n.replace(/\b\d{5}\b/g, '');
            n = n.replace(/straße|str\.|str$/gi, 'str');
            n = n.replace(/[,.\-\/]/g, ' ');
            n = n.replace(/\s+/g, ' ').trim();
            return n;
        };
        const _ckRound = (lat, lon) => `${parseFloat(lat).toFixed(4)}_${parseFloat(lon).toFixed(4)}`;
        const _coordMap = {}; // coordKey → normKey
        const _addAddr = (addr, lat, lon) => {
            let key = _normAddr(addr);
            const ck = _ckRound(lat, lon);
            if (_coordMap[ck]) { key = _coordMap[ck]; } else { _coordMap[ck] = key; }
            if (!destCount[key]) destCount[key] = { name: addr, lat, lon, count: 0 };
            // Längsten Namen behalten
            if (addr.length > destCount[key].name.length) destCount[key].name = addr;
            destCount[key].count++;
        };
        ridesSnap.forEach(child => {
            const ride = child.val();
            // Zielorte
            const dest = ride.destination;
            const lat = ride.destinationLat || (ride.destCoords && ride.destCoords.lat);
            const lon = ride.destinationLon || (ride.destCoords && ride.destCoords.lon);
            if (dest && lat && lon) {
                if (_looksLikeUsedom(dest) && !isNearUsedom(parseFloat(lat), parseFloat(lon))) return;
                _addAddr(dest, lat, lon);
            }
            // Abholorte
            const pickup = ride.pickup;
            const pLat = ride.pickupLat || (ride.pickupCoords && ride.pickupCoords.lat);
            const pLon = ride.pickupLon || (ride.pickupCoords && ride.pickupCoords.lon);
            if (pickup && pLat && pLon) {
                if (_looksLikeUsedom(pickup) && !isNearUsedom(parseFloat(pLat), parseFloat(pLon))) return;
                _addAddr(pickup, pLat, pLon);
            }
        });
        const frequent = Object.values(destCount).sort((a, b) => b.count - a.count);
        for (const freq of frequent) {
            const freqName = freq.name.toLowerCase();
            // 🔧 v6.25.3: Flexiblerer Match — mind. 2/3 der Suchworte müssen treffen
            // UND Straßenname muss matchen (erstes Wort mit >3 Buchstaben)
            const mainWord = searchWords.find(w => w.length > 3) || searchWords[0] || '';
            const wordMatchCount = searchWords.filter(w => freqName.includes(w)).length;
            const wordMatchRatio = searchWords.length > 0 ? wordMatchCount / searchWords.length : 0;
            if (freqName.includes(searchKey) ||
                (searchWords.length > 0 && searchWords.every(w => freqName.includes(w))) ||
                (mainWord && freqName.includes(mainWord) && wordMatchRatio >= 0.6)) {
                // 🔧 v6.25.4: PLZ-Distanz-Check für Buchungs-Historie
                if (_plzCenter) {
                    const dist = distanceKm(parseFloat(freq.lat), parseFloat(freq.lon), _plzCenter.lat, _plzCenter.lon);
                    if (dist > PLZ_MAX_RADIUS_KM) continue;
                }
                addIfNew({ name: freq.name, lat: freq.lat, lon: freq.lon, source: 'booking', priority: 3 });
            }
        }
    } catch (e) { console.warn('Buchungs-Suche Fehler:', e.message); }

    // Sortiere lokale Ergebnisse: exakte Treffer zuerst, dann nach Quelle
    localResults.sort((a, b) => (a.priority || 0) - (b.priority || 0));

    // ═══════════════════════════════════════════════════════════
    // STUFE 2: NOMINATIM (nur als Ergänzung — wenn lokale Treffer da sind, weniger Nominatim)
    // ═══════════════════════════════════════════════════════════
    const nominatimResults = [];
    // Wenn schon 3+ lokale Treffer → max 2 Nominatim, sonst bis zu 5
    const maxNominatim = localResults.length >= 3 ? 2 : (localResults.length >= 1 ? 3 : 5);

    try {
        // 🔧 v6.25.5: PLZ aus Query extrahieren — DAS ist der Schlüssel für lokale Suche
        const queryPLZ = query.match(/\b(1742[0-9]|1741[0-9]|1743[0-9]|1744[0-9]|1745[0-9])\b/);
        const queryPostcode = queryPLZ ? queryPLZ[1] : null;
        // 🔧 v6.25.4: PLZ-Zentrum für Koordinaten-Plausibilitätsprüfung

        // 🔧 v6.25.5: Viewbox eng auf Usedom + näheres Umland
        const usedomViewbox = '13.60,54.20,14.45,53.75';
        const wideViewbox = '12.5,54.5,14.5,53.5';

        // 🔧 v6.25.5: PLZ ist der Schlüssel — Nominatim structured search nutzen
        // Wenn PLZ vorhanden: Straße + PLZ als structured query → treffsicher!
        const knownOrte = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz', 'koserow', 'ückeritz',
            'loddin', 'trassenheide', 'zempin', 'karlshagen', 'peenemünde', 'wolgast', 'anklam',
            'swinemünde', 'świnoujście', 'usedom', 'greifswald', 'züssow', 'lubmin'];
        const hasOrt = knownOrte.some(o => searchKey.includes(o));
        const hasPLZ = !!queryPostcode;

        // 🆕 v6.41.14: Nominatim-Haupt-Suche deaktiviert (User-Wunsch: nur Google Places).
        //   Google Places wird weiter unten als einzige externe Quelle aufgerufen.
        //   Nominatim-Calls in der Haupt-Suche komplett raus — keine Fuzzy/Score-Matches
        //   mehr aus OSM-Rohdaten die dann auf falsche Orte verweisen könnten.
        let usedomData = [], generalData = [], wideData = [];
        // hasPLZ / hasOrt Variablen bleiben erhalten — andere Code-Teile nutzen sie eventuell
        const plzCenter = queryPostcode ? PLZ_CENTERS[queryPostcode] : null;

        // Usedom-Ergebnisse zuerst, PLZ-Match bevorzugt, dann allgemeine
        let allItems = [...usedomData, ...generalData, ...wideData];

        // 🔧 v6.25.4: Ergebnisse filtern deren Koordinaten zu weit vom angegebenen PLZ-Zentrum entfernt sind
        if (plzCenter) {
            const before = allItems.length;
            allItems = allItems.filter(item => {
                const lat = parseFloat(item.lat), lon = parseFloat(item.lon);
                const dist = distanceKm(lat, lon, plzCenter.lat, plzCenter.lon);
                if (dist > PLZ_MAX_RADIUS_KM) {
                    console.log(`[PLZ-Filter] "${item.display_name}" rausgefiltert: ${dist.toFixed(1)}km von PLZ ${queryPostcode} ${plzCenter.name} entfernt`);
                    return false;
                }
                return true;
            });
            if (before > allItems.length) {
                console.log(`[PLZ-Filter] ${before - allItems.length} Ergebnisse wegen PLZ-Distanz gefiltert (PLZ ${queryPostcode}, max ${PLZ_MAX_RADIUS_KM}km)`);
            }
        }

        // 🆕 v6.38.96: Google Places (New API) als zusätzliche Quelle — IMMER suchen wenn Key vorhanden
        // 🔧 v6.38.35: Nutzt Places API (New) Endpoint statt veralteter textsearch/json
        try {
            const gKeySnap = await db.ref('settings/googlePlacesApiKey').once('value');
            const gKey = gKeySnap.val();
            if (gKey) {
                // 🔧 v6.62.737: Wenn Ort in Query → den nehmen statt generisches 'Usedom'
                // Patrick 15.05.: Mellenthin-Suche fand Pudagla, weil 'Usedom' zu breit war.
                const _USEDOM_ORTE_GP = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz',
                    'koserow', 'ückeritz', 'uckeritz', 'loddin', 'trassenheide', 'zempin',
                    'karlshagen', 'peenemünde', 'peenemuende', 'wolgast', 'mellenthin',
                    'pudagla', 'benz', 'usedom', 'morgenitz', 'neppermin', 'liepe',
                    'stolpe', 'krummin', 'rankwitz', 'kamminke', 'garz', 'korswandt',
                    'zirchow', 'dargen', 'mönchow', 'sauzin'];
                const _searchTextSuffix = (() => {
                    const _searchLow = query.toLowerCase();
                    for (const o of _USEDOM_ORTE_GP) {
                        if (_searchLow.includes(o)) return ''; // Ort schon in Query — nichts anhaengen
                    }
                    return ' Usedom';
                })();
                const _gQuery = query + _searchTextSuffix;
                console.log(`[Google Places] Key gefunden (${gKey.substring(0, 10)}...), suche: "${_gQuery}"`);
                const gResp = await fetch('https://places.googleapis.com/v1/places:searchText', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'X-Goog-Api-Key': gKey,
                        'X-Goog-FieldMask': 'places.displayName,places.formattedAddress,places.location'
                    },
                    body: JSON.stringify({
                        textQuery: _gQuery,
                        languageCode: 'de',
                        locationBias: {
                            circle: { center: { latitude: 53.95, longitude: 14.10 }, radius: 25000.0 }
                        },
                        maxResultCount: 3
                    })
                });
                const gData = await gResp.json();
                console.log(`[Google Places] Response Status: ${gResp.status}, places: ${gData.places?.length || 0}, error: ${gData.error?.message || 'none'}`);
                if (gData.places) {
                    for (const place of gData.places) {
                        if (place.location) {
                            const gLat = place.location.latitude;
                            const gLon = place.location.longitude;
                            const gName = place.formattedAddress || place.displayName?.text || '';
                            const gLabel = place.displayName?.text || '';
                            // 🆕 v6.62.856 (Patrick 21.05. 19:50): Google-Places-Treffer NIE mit
                            //   Geocache-Coord-Keys (3 Dezimal-Stellen) deduplizieren!
                            //   Bug: Strandpromenade 17 (53.9715/14.1463) + 18 (53.9716/14.1458)
                            //   landen im gleichen 3-Dezimal-Bucket '53.972_14.146'.
                            //   Geocache hatte 18 dort, Google's 17 wurde verworfen → der
                            //   v6.62.855-BYPASS hatte nichts zu finden.
                            //   Fix: gp_-Prefix + 5 Dezimal-Stellen (~1m) macht GP-Keys unique.
                            //   Echte Duplikate räumt der spätere seenCoords-Pass (Zeile ~4099)
                            //   mit 4 Dezimal-Stellen auf.
                            const coordKey = `gp_${gLat.toFixed(5)}_${gLon.toFixed(5)}`;
                            if (!seen.has(coordKey)) {
                                seen.add(coordKey);
                                // 🆕 v6.62.852: formattedAddress in structured Felder parsen
                                // Format: "Strasse Hausnr, PLZ Stadt, Deutschland"
                                const _gpParts = (gName || '').split(',').map(s => s.trim());
                                let _gpRoad = '', _gpHausnr = '', _gpPostcode = '', _gpCity = '';
                                if (_gpParts.length >= 1) {
                                    const _seg0 = _gpParts[0];
                                    const _hnM = _seg0.match(/^(.+?)\s+(\d+[a-z]?)$/i);
                                    if (_hnM) { _gpRoad = _hnM[1].trim(); _gpHausnr = _hnM[2].toLowerCase(); }
                                    else { _gpRoad = _seg0; }
                                }
                                if (_gpParts.length >= 2) {
                                    const _seg1 = _gpParts[1];
                                    const _plzM = _seg1.match(/^(\d{5})\s+(.+)$/);
                                    if (_plzM) { _gpPostcode = _plzM[1]; _gpCity = _plzM[2].trim(); }
                                    else { _gpCity = _seg1; }
                                }
                                const _isPoiHit = gLabel && gLabel !== _gpParts[0];
                                // 🔧 v6.62.854: name MUSS gefüllt sein damit Straßen-Filter funktioniert
                                //   (Patrick 21.05. 19:31: 'Strandpromenade 17' wurde rausgefiltert weil name='')
                                allItems.push({
                                    display_name: _isPoiHit ? (gLabel + ', ' + gName) : gName,
                                    name: _isPoiHit ? (gLabel + ', ' + gName) : gName,
                                    lat: gLat, lon: gLon,
                                    source: 'google-places',
                                    address: {
                                        road: _gpRoad,
                                        house_number: _gpHausnr,
                                        postcode: _gpPostcode,
                                        city: _gpCity,
                                        town: _gpCity,
                                    }
                                });
                                console.log(`[Google Places v6.62.852] road="${_gpRoad}" hnr="${_gpHausnr}" plz="${_gpPostcode}" city="${_gpCity}" poi="${_isPoiHit ? gLabel : '-'}"`);
                            }
                        }
                    }
                } else if (gData.error) {
                    console.warn('[Google Places] API Fehler:', gData.error.message || JSON.stringify(gData.error));
                }
            }
        } catch(gErr) { console.warn('Google Places Fehler:', gErr.message); }

        // 🆕 v6.62.196: Patrick (01.05.): "google places für den telegram bot der macht
        // mir noch zuviel mist". Nominatim-Fallback (v6.41.20) komplett raus —
        // Nominatim hat zu oft falsche Treffer geliefert (Ort-Verwechslungen,
        // unbekannte POIs als Strassennamen interpretiert). Wenn Google nichts findet,
        // lieber 0 Treffer im Bot als Schrott. Patrick kann dann manuell PLZ + Strasse
        // tippen oder GPS-Sticker schicken.

        // 🆕 v6.62.851 (21.05.2026): Strikt-gefilterter Nominatim-Fallback nur wenn
        //   Google Places NULL Hausnummer-Match liefert. Patrick: 'Strandpromenade 17
        //   Bansin' kam nicht durch, Google bot 18 + 15 → falsche Tueren.
        //   Bedingungen damit Nominatim ueberhaupt aufgerufen wird:
        //   1) keine Hausnummer-exakte Treffer in allItems
        //   2) Query enthaelt erkennbare Hausnummer (z.B. "Strandpromenade 17")
        //   3) Query enthaelt bekannten Usedom-Ort (z.B. "bansin")
        //   4) Nominatim-Treffer wird zusaetzlich gefiltert:
        //      - Hausnummer == Eingabe-Hausnummer (exakt)
        //      - Liegt in Usedom-Box (53.8–54.15 / 13.8–14.35)
        //      - Strassenname matcht Eingabe-Strasse (substring oder fuzzy)
        const _inputHausnrFB = (() => {
            const m = query.replace(/\b\d{5}\b/g, '').match(/\b(\d+[a-z]?)\b/i);
            return m ? m[1].toLowerCase() : '';
        })();
        const _USEDOM_ORTE_FB = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz',
            'koserow', 'ückeritz', 'uckeritz', 'loddin', 'trassenheide', 'zempin',
            'karlshagen', 'peenemünde', 'peenemuende', 'wolgast', 'mellenthin',
            'pudagla', 'benz', 'usedom', 'morgenitz', 'neppermin', 'liepe',
            'stolpe', 'krummin', 'rankwitz', 'kamminke', 'garz', 'korswandt',
            'zirchow', 'dargen', 'mönchow', 'sauzin'];
        const _queryLowFB = query.toLowerCase();
        const _hasOrtFB = _USEDOM_ORTE_FB.find(o => _queryLowFB.includes(o));
        const _hasExactHausnrMatchInResults = _inputHausnrFB && allItems.some(it => {
            const hn = ((it.address && it.address.house_number) || '').toLowerCase();
            const dn = ((it.display_name || '') + ' ' + (it.address?.road || '')).toLowerCase();
            return hn === _inputHausnrFB || new RegExp(`\\b${_inputHausnrFB}\\b`).test(dn.replace(/\d{5}/g, ''));
        });
        if (_inputHausnrFB && _hasOrtFB && !_hasExactHausnrMatchInResults) {
            try {
                // Strasse aus Query extrahieren: alles vor der Hausnummer, ohne Ort
                let _streetGuess = query
                    .replace(new RegExp(`\\b${_inputHausnrFB}\\b.*$`, 'i'), '')
                    .replace(new RegExp(_hasOrtFB, 'gi'), '')
                    .replace(/,/g, ' ')
                    .replace(/\b\d{5}\b/g, '')
                    .trim();
                if (_streetGuess.length >= 3) {
                    const _nomUrl = `https://nominatim.openstreetmap.org/search?street=${encodeURIComponent(_inputHausnrFB + ' ' + _streetGuess)}&city=${encodeURIComponent(_hasOrtFB)}&country=Germany&format=json&limit=5&addressdetails=1`;
                    const _nomResp = await fetch(_nomUrl, { headers: { 'User-Agent': 'FunkTaxiHeringsdorf/1.0' } });
                    const _nomData = await _nomResp.json();
                    if (Array.isArray(_nomData) && _nomData.length > 0) {
                        const _streetLowFB = _streetGuess.toLowerCase().replace(/straße$|str\.?$/, '');
                        for (const r of _nomData) {
                            const _lat = parseFloat(r.lat), _lon = parseFloat(r.lon);
                            if (!(_lat >= 53.8 && _lat <= 54.15 && _lon >= 13.8 && _lon <= 14.35)) continue;
                            const _rHn = ((r.address && r.address.house_number) || '').toLowerCase();
                            if (_rHn !== _inputHausnrFB) continue;
                            const _rRoad = ((r.address && r.address.road) || '').toLowerCase().replace(/straße$|str\.?$/, '');
                            if (!_rRoad) continue;
                            if (!(_rRoad.includes(_streetLowFB) || _streetLowFB.includes(_rRoad))) continue;
                            const _ck = `${_lat.toFixed(3)}_${_lon.toFixed(3)}`;
                            if (seen.has(_ck)) continue;
                            seen.add(_ck);
                            allItems.push({
                                display_name: r.display_name,
                                lat: _lat, lon: _lon,
                                source: 'nominatim-fallback-exact',
                                address: r.address,
                                importance: r.importance || 0.1
                            });
                            console.log(`[Nominatim-Fallback v6.62.851] Exakt-Match aufgenommen: ${r.display_name}`);
                            break; // einer reicht
                        }
                    }
                }
            } catch (_nomFbErr) {
                console.warn('[Nominatim-Fallback v6.62.851] Fehler:', _nomFbErr.message);
            }
        }

        // 🔧 v6.25.5: Duplikate nach Koordinaten entfernen (beide Requests liefern oft gleiche Ergebnisse)
        const seenCoords = new Set();
        allItems = allItems.filter(item => {
            const key = `${parseFloat(item.lat).toFixed(4)}_${parseFloat(item.lon).toFixed(4)}`;
            if (seenCoords.has(key)) return false;
            seenCoords.add(key);
            return true;
        });

        allItems.sort((a, b) => {
            // 🆕 v6.47.9: POI/KNOWN_PLACES priority IMMER zuerst — Patrick erlebte 'Bahnhof
            // Heringsdorf' wurde zu 'Bahnhof Anklam' geocoded weil USEDOM_BOUNDS Anklam
            // mit einschließt (53.85/13.70 in 53.75-54.20 / 13.60-14.45). POI-Match
            // (priority 0) muss IMMER VOR Nominatim-Result kommen, egal welche Bounds.
            const aPrio = (a.priority !== undefined) ? a.priority : 99;
            const bPrio = (b.priority !== undefined) ? b.priority : 99;
            if (aPrio !== bPrio) return aPrio - bPrio;
            const aUsedom = isNearUsedom(parseFloat(a.lat), parseFloat(a.lon)) ? 0 : 1;
            const bUsedom = isNearUsedom(parseFloat(b.lat), parseFloat(b.lon)) ? 0 : 1;
            if (aUsedom !== bUsedom) return aUsedom - bUsedom;
            // 🔧 v6.15.7: Bei gleicher Usedom-Zugehörigkeit → PLZ-Match bevorzugen
            if (queryPostcode) {
                const aPLZ = (a.address && a.address.postcode === queryPostcode) ? 0 : 1;
                const bPLZ = (b.address && b.address.postcode === queryPostcode) ? 0 : 1;
                if (aPLZ !== bPLZ) return aPLZ - bPLZ;
            }
            // 🔧 v6.25.5: Importance-Score von Nominatim als Tiebreaker
            return (parseFloat(b.importance) || 0) - (parseFloat(a.importance) || 0);
        });

        for (const item of allItems) {
            if (nominatimResults.length >= maxNominatim) break;
            const lat = parseFloat(item.lat), lon = parseFloat(item.lon);
            const coordKey = `${lat.toFixed(3)}_${lon.toFixed(3)}`;
            if (!seen.has(coordKey)) {
                seen.add(coordKey);
                const addr = item.address || {};
                const poiName = item.name || '';
                const road = addr.road || addr.residential || addr.neighbourhood || addr.suburb || addr.hamlet || addr.pedestrian || '';
                const houseNr = addr.house_number || '';
                const town = addr.town || addr.city || addr.village || addr.municipality || '';
                const postcode = addr.postcode || '';
                let streetPart = road ? (road + (houseNr ? ' ' + houseNr : '')) : '';
                let displayName;
                if (poiName && streetPart && !poiName.includes(road)) {
                    displayName = `${poiName}, ${streetPart}` + (town ? `, ${postcode ? postcode + ' ' : ''}${town}` : '');
                } else if (streetPart) {
                    displayName = streetPart + (town ? `, ${postcode ? postcode + ' ' : ''}${town}` : '');
                } else if (poiName) {
                    displayName = poiName + (town ? `, ${postcode ? postcode + ' ' : ''}${town}` : '');
                } else {
                    displayName = item.display_name.split(',').slice(0, 3).join(',').trim();
                }
                // 🆕 v6.62.857 (Patrick 21.05. 20:00): source UND address aus dem Originalitem erhalten!
                //   Bug: alle allItems wurden hardcoded als source:'nominatim' kopiert — Google-Places-Treffer
                //   wurden dadurch im _v855Took-BYPASS unsichtbar (filter source!=='google-places' = always true)
                //   UND im _hasTrustedSugg2-Pfad als untrusted weggefiltert. address fehlte komplett, sodass
                //   spätere Hausnr-Checks ins Leere liefen. Jetzt: original source/address durchreichen,
                //   Fallback 'nominatim' nur bei wirklich-unbekannter Quelle.
                nominatimResults.push({
                    name: displayName, lat, lon,
                    source: item.source || 'nominatim',
                    address: item.address || undefined
                });
            }
        }
    } catch (e) { console.warn('Nominatim Fehler:', e); }

    // ═══════════════════════════════════════════════════════════
    // 🔧 v6.38.1: RELEVANZ-FILTER für Nominatim-Ergebnisse
    // Zeige nur Nominatim-Treffer wo der gesuchte Straßenname vorkommt.
    // Verhindert: "Im Mühlenkamp 19" suchen → "Maxim-Gorki-Straße" angezeigt
    // ═══════════════════════════════════════════════════════════
    if (nominatimResults.length > 0) {
        // Straßenwörter extrahieren: alles >3 Buchstaben, keine PLZ-Zahlen, keine Ortsnamen
        const knownOrtWords = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz', 'koserow', 'ückeritz',
            'loddin', 'trassenheide', 'zempin', 'karlshagen', 'wolgast', 'peenemünde', 'greifswald',
            'anklam', 'usedom', 'swinemünde', 'berlin', 'hamburg', 'rostock', 'stralsund'];
        const streetWords = searchWords.filter(w =>
            w.length > 3 &&
            !/^\d{4,5}$/.test(w) &&  // keine PLZ
            !knownOrtWords.includes(w) // keine Ortsnamen
        );
        if (streetWords.length > 0) {
            const relevantNominatim = nominatimResults.filter(r => {
                const rName = r.name.toLowerCase();
                return streetWords.some(w => rName.includes(w));
            });
            // Wenn kein Nominatim-Treffer relevant → alle raus (lieber 0 Treffer als Schrott)
            nominatimResults.splice(0, nominatimResults.length, ...relevantNominatim);
        }
    }

    // ═══════════════════════════════════════════════════════════
    // 🔧 v6.62.737: GLOBALER ORT-FILTER über ALLE Stufen
    // Wenn Suche einen Ort nennt (z.B. 'mellenthin'), MÜSSEN Treffer aus
    // diesem Ort sein — sonst raus. Verhindert: Suche 'Schloss­strasse 7
    // Mellenthin' liefert 'Delbrueckstrasse Heringsdorf' (15 km weg).
    // Ausnahme: Direkt benachbarte Orte/Ortsteile gleicher PLZ (Pudagla
    // gehoert zu Mellenthin → PLZ 17429 fuer beide).
    // ═══════════════════════════════════════════════════════════
    const _ALL_USEDOM_ORTE = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz',
        'koserow', 'ückeritz', 'uckeritz', 'loddin', 'trassenheide', 'zempin',
        'karlshagen', 'peenemünde', 'peenemuende', 'wolgast', 'mellenthin',
        'pudagla', 'benz', 'usedom', 'morgenitz', 'neppermin', 'liepe',
        'stolpe', 'krummin', 'rankwitz', 'lieper-winkel', 'kamminke',
        'garz', 'korswandt', 'zirchow', 'dargen', 'mönchow', 'sauzin'];
    const _searchOrt = searchWords.find(w => _ALL_USEDOM_ORTE.includes(w));
    let _combined = [...localResults, ...nominatimResults];
    if (_searchOrt) {
        const _before = _combined.length;
        _combined = _combined.filter(r => {
            const rName = (r.name || '').toLowerCase();
            const rLabel = (r.label || '').toLowerCase();
            const rText = rName + ' ' + rLabel;
            // Treffer-Ort aus dem Ergebnis-Text
            const rOrt = _ALL_USEDOM_ORTE.find(o => rText.includes(o));
            if (!rOrt) return true; // kein erkennbarer Ort → behalten (z.B. nur Strasse)
            if (rOrt === _searchOrt) return true; // exakter Ort-Match
            // PLZ-Nachbarschaft erlauben: gleiche PLZ → behalten
            // Vereinfacht: Mellenthin/Pudagla/Benz/Morgenitz teilen PLZ 17429
            const _GROUP_17429 = ['mellenthin', 'pudagla', 'benz', 'morgenitz', 'neppermin', 'liepe', 'stolpe'];
            const _GROUP_17424 = ['heringsdorf', 'ahlbeck', 'bansin'];
            const _GROUP_17449 = ['zinnowitz', 'trassenheide', 'karlshagen', 'peenemünde', 'peenemuende', 'zempin'];
            const _GROUP_17459 = ['koserow', 'loddin', 'ückeritz', 'uckeritz', 'kölpinsee'];
            for (const grp of [_GROUP_17429, _GROUP_17424, _GROUP_17449, _GROUP_17459]) {
                if (grp.includes(_searchOrt) && grp.includes(rOrt)) return true;
            }
            console.log(`🛡️ Ort-Filter: "${r.name}" verworfen (Suche=${_searchOrt}, Treffer=${rOrt})`);
            return false;
        });
        if (_combined.length < _before) {
            console.log(`🛡️ Ort-Filter "${_searchOrt}": ${_before} → ${_combined.length} Treffer`);
        }
    }

    // 🔧 v6.62.737: HAUSNR-EXACT-MATCH PRIORITAET
    // Wenn Suche Hausnr X enthaelt und ein Treffer Hausnr X hat → ganz nach vorn.
    const _hausnrInQuery = (() => {
        const _q = (query || '').replace(/\b\d{5}\b/g, '');
        const _m = _q.match(/\b(\d+\s*[a-z]?)\b/);
        return _m ? _m[1].replace(/\s+/g, '').toLowerCase() : null;
    })();
    if (_hausnrInQuery) {
        _combined.sort((a, b) => {
            const _extract = (s) => {
                const _str = (s || '').replace(/\b\d{5}\b/g, '').toLowerCase();
                const _m = _str.match(/\b(\d+\s*[a-z]?)\b/);
                return _m ? _m[1].replace(/\s+/g, '') : null;
            };
            const aMatch = _extract(a.name) === _hausnrInQuery ? 1 : 0;
            const bMatch = _extract(b.name) === _hausnrInQuery ? 1 : 0;
            return bMatch - aMatch;
        });
    }

    return _combined.slice(0, 5);
}

// 🆕 v6.63.447 (Patrick 20.06. 19:00): Cloud-seitiger Route-Cache vor calculateRoute
//   und googleRoutesDrivingMin. Vorher: 20+ Aufrufer × Cron-Frequenz × keine
//   Wiederverwendung → Maps Platform Routes ~378 €/Monat Top-Posten. Jetzt: vor jedem
//   Google-Call /routeCache lookup, TTL 60 Min (Stau-Aware) bzw. 30 Tage für reine
//   Distance-Reads. Geschätzt -70 % Maps-Routes-Calls.
const _ROUTE_CACHE_DURATION_TTL_MS = 60 * 60 * 1000;      // 60 Min: Duration (Verkehr ändert sich)
const _ROUTE_CACHE_DISTANCE_TTL_MS = 30 * 24 * 60 * 60 * 1000; // 30 Tage: Distance (km ändern sich nicht)
// 🆕 v6.63.473 (Patrick 22.06. 21:00 Cost-Cut): In-Memory-Layer vor DB-Read.
//   Bei 5 Vehicles x 4 Rides x alle 5 Min = 240 DB-Reads/h auf /routeCache/.
//   Pro Cloud-Function-Instance Map mit 90s-TTL → repeat-Reads kommen direkt aus
//   Memory (0 ms, 0 Bytes Outbound), nur First-Lookup pro Routenpaar hits DB.
//   Erwartete Einsparung: 90-95% der routeCache-DB-Reads.
const _routeCacheMem = new Map();  // key → { value, expiresAt }
const _ROUTE_CACHE_MEM_TTL_MS = 90 * 1000;
function _routeCacheKey(from, to, waypointCoords, mode) {
    const _round = v => (typeof v === 'number' ? v : parseFloat(v)).toFixed(4);
    const _f = _round(from.lat) + '_' + _round(from.lon);
    const _t = _round(to.lat) + '_' + _round(to.lon);
    const _wp = (waypointCoords && waypointCoords.length)
        ? '~' + waypointCoords.map(w => _round(w.lat) + '_' + _round(w.lon)).join('~')
        : '';
    return (_f + _wp + '-' + _t + '-' + (mode || 'hybrid')).replace(/[.#$/[\]]/g, '_');
}
async function _readRouteCache(from, to, waypointCoords, mode, needFreshDuration) {
    const key = _routeCacheKey(from, to, waypointCoords, mode);
    // 🆕 v6.63.473: In-Memory-Lookup zuerst (kein DB-Read wenn frisch in Memory).
    const _mem = _routeCacheMem.get(key);
    if (_mem && _mem.expiresAt > Date.now()) {
        const ageMs = Date.now() - _mem.value.cachedAt;
        if (needFreshDuration ? ageMs <= _ROUTE_CACHE_DURATION_TTL_MS : ageMs <= _ROUTE_CACHE_DISTANCE_TTL_MS) {
            return _mem.value;
        }
    }
    try {
        const snap = await db.ref('routeCache/' + key).once('value');
        const v = snap.val();
        if (!v || !v.cachedAt) return null;
        const ageMs = Date.now() - v.cachedAt;
        if (needFreshDuration) {
            if (ageMs > _ROUTE_CACHE_DURATION_TTL_MS) return null;
        } else {
            if (ageMs > _ROUTE_CACHE_DISTANCE_TTL_MS) return null;
        }
        // In Memory cachen fuer naechsten Aufruf
        _routeCacheMem.set(key, { value: v, expiresAt: Date.now() + _ROUTE_CACHE_MEM_TTL_MS });
        return v;
    } catch (_) { return null; }
}
async function _writeRouteCache(from, to, waypointCoords, mode, result) {
    try {
        const key = _routeCacheKey(from, to, waypointCoords, mode);
        const payload = {
            distance: result.distance,
            duration: result.duration,
            legs: result.legs || null,
            source: result.source,
            mode: mode || 'hybrid',
            cachedAt: Date.now(),
            timestamp: Date.now() // bestehender Cleanup-Cron v6.63.445 nutzt 'timestamp'
        };
        // 🆕 v6.63.473: parallel in Memory cachen
        _routeCacheMem.set(key, { value: payload, expiresAt: Date.now() + _ROUTE_CACHE_MEM_TTL_MS });
        await db.ref('routeCache/' + key).set(payload);
    } catch (e) { console.warn('routeCache write:', e.message); }
}

// 🔧 v6.33.6: Waypoints-Support für Multi-Stop-Routen
// 🆕 v6.62.967 (Patrick 26.05.): Reihenfolge gedreht — Google Routes API (NEW)
//   primaer mit TRAFFIC_AWARE, OSRM nur noch Notfall-Fallback wenn Google streikt.
//   Patrick: "kein Umwegfaktor, Verkehr soll automatisch beruecksichtigt werden".
//   Google Routes API liefert duration MIT aktueller Verkehrslage,
//   distanceMeters auf der Strasse (nicht Luftlinie).
// 🔧 v6.63.467 (Patrick 26.06.): Dual-Engine Minimum-Distanz.
//   Beeck-Vorfall: Google Routes gab 6,42 km für Kulmstr→Bahnhof (falsch, vermutl.
//   Fußgängerzone-Routing), OSRM gab 1,59 km (korrekt). Fix: beide parallel anfragen,
//   kürzere Distanz gewinnt. Wenn Google > 3× OSRM → OSRM bevorzugt (Sanity-Check).
// v6.63.646: routeMode 5-Min-In-Memory-Cache (war: jeder calculateRoute-Call = 1 DB-Read)
let _routeModeCache = null, _routeModeCachedAt = 0;
async function _getRouteMode() {
    if (_routeModeCache && (Date.now() - _routeModeCachedAt) < 5 * 60 * 1000) return _routeModeCache;
    try {
        const snap = await db.ref('settings/dispatch/routeMode').once('value');
        const v = snap.val();
        _routeModeCache = (v === 'fastest' || v === 'shortest' || v === 'hybrid') ? v : 'shortest';
    } catch(_) { _routeModeCache = 'shortest'; }
    _routeModeCachedAt = Date.now();
    return _routeModeCache;
}

async function calculateRoute(from, to, waypointCoords = []) {
    const _routeMode = await _getRouteMode();

    // Cache-Lookup VOR jedem API-Call
    const _cached = await _readRouteCache(from, to, waypointCoords, _routeMode, true);
    if (_cached) {
        return {
            distance: _cached.distance,
            duration: _cached.duration,
            legs: _cached.legs || [{ duration: _cached.duration, distance: +_cached.distance }],
            source: (_cached.source || 'shortest-dual') + '-cache'
        };
    }

    // Parallel: Google Routes + OSRM gleichzeitig anfragen → kürzere Distanz gewinnt
    const _buildGoogleResult = async () => {
        const apiKeySnap = await db.ref('settings/googleMapsApiKey').once('value');
        const apiKey = apiKeySnap.val();
        if (!apiKey) throw new Error('No API key');
        const body = {
            origin: { location: { latLng: { latitude: from.lat, longitude: from.lon } } },
            destination: { location: { latLng: { latitude: to.lat, longitude: to.lon } } },
            travelMode: 'DRIVE',
            routingPreference: 'TRAFFIC_UNAWARE',
            computeAlternativeRoutes: true
        };
        if (waypointCoords && waypointCoords.length > 0) {
            body.intermediates = waypointCoords.map(wp => ({
                location: { latLng: { latitude: wp.lat, longitude: wp.lon } }
            }));
        }
        const resp = await fetch('https://routes.googleapis.com/directions/v2:computeRoutes', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-Goog-Api-Key': apiKey,
                'X-Goog-FieldMask': 'routes.duration,routes.distanceMeters,routes.legs.duration,routes.legs.distanceMeters'
            },
            body: JSON.stringify(body),
            signal: AbortSignal.timeout(8000)
        });
        if (!resp.ok) throw new Error('Google Routes HTTP ' + resp.status);
        const data = await resp.json();
        if (!data.routes || !data.routes[0]) throw new Error('Google Routes kein Ergebnis');
        // Immer kürzeste Distanz aus Alternativen wählen
        const _allRoutes = data.routes.map(r => ({
            distanceM: r.distanceMeters || 0,
            durationS: parseInt(String(r.duration || '0').replace('s', '')) || 0,
            legs: r.legs || [],
            raw: r
        }));
        _allRoutes.sort((a, b) => a.distanceM - b.distanceM);
        const best = _allRoutes[0];
        const route = best.raw;
        const totalDistanceKm = best.distanceM / 1000;
        const totalDurationMin = Math.round(best.durationS / 60);
        const legs = (route.legs || []).map(l => ({
            duration: Math.round(parseInt(String(l.duration || '0').replace('s', '')) / 60),
            distance: +(((l.distanceMeters || 0) / 1000).toFixed(1))
        }));
        if (_allRoutes.length > 1) {
            console.log(`🛣️ Google Routes: ${_allRoutes.length} Alternativen, kürzeste ${totalDistanceKm.toFixed(1)}km gewählt`);
        }
        return { distanceKm: totalDistanceKm, durationMin: totalDurationMin, legs, source: 'google-routes-shortest' };
    };

    const _buildOsrmResult = async () => {
        let coordinates = `${from.lon},${from.lat}`;
        if (waypointCoords && waypointCoords.length > 0) {
            waypointCoords.forEach(wp => { coordinates += `;${wp.lon},${wp.lat}`; });
        }
        coordinates += `;${to.lon},${to.lat}`;
        // 🔧 v6.63.578: alternatives=3 damit OSRM auch kürzere Distanz-Varianten liefert.
        // OSRM wählt ohne alternatives immer die SCHNELLSTE Route (kann 5+ km länger sein
        // als die kürzeste — z.B. Bansin→Flughafen: 19.6 km Waldweg vs 14.5 km via HDF).
        // Nach dem Fetch nehmen wir die kürzeste Distanz aus den Alternativen.
        const hasWaypoints = waypointCoords && waypointCoords.length > 0;
        const altParam = hasWaypoints ? '' : '&alternatives=3';
        const resp = await fetch(`https://router.project-osrm.org/route/v1/driving/${coordinates}?overview=false${altParam}`, {
            signal: AbortSignal.timeout(8000)
        });
        if (!resp.ok) throw new Error('OSRM HTTP ' + resp.status);
        const data = await resp.json();
        if (!data.routes || !data.routes[0]) throw new Error('OSRM kein Ergebnis');
        // Kürzeste Distanz aus allen Alternativen wählen
        const _allOsrm = (data.routes || []).filter(r => r.distance > 0);
        _allOsrm.sort((a, b) => a.distance - b.distance);
        const route = _allOsrm[0];
        if (_allOsrm.length > 1) {
            console.log(`🛣️ OSRM: ${_allOsrm.length} Alternativen, kürzeste ${(route.distance/1000).toFixed(1)}km gewählt (längste: ${(_allOsrm[_allOsrm.length-1].distance/1000).toFixed(1)}km)`);
        }
        const legs = (route.legs || []).map(l => ({
            duration: Math.round((l.duration || 0) / 60),
            distance: +(((l.distance || 0) / 1000).toFixed(1))
        }));
        return { distanceKm: route.distance / 1000, durationMin: Math.round(route.duration / 60), legs, source: 'osrm' };
    };

    // Beide parallel, dann Minimum-Distanz-Entscheidung
    const [_googleRes, _osrmRes] = await Promise.allSettled([
        _buildGoogleResult().catch(e => { console.warn('⚠️ Google Routes:', e.message); return null; }),
        _buildOsrmResult().catch(e => { console.warn('⚠️ OSRM:', e.message); return null; })
    ]);
    const _g = _googleRes.status === 'fulfilled' ? _googleRes.value : null;
    const _o = _osrmRes.status === 'fulfilled' ? _osrmRes.value : null;

    let _chosen = null;
    if (_g && _o) {
        // Sanity-Check: wenn Google > 3× OSRM → OSRM (Google routet falsch z.B. Fußgängerzone)
        if (_g.distanceKm > _o.distanceKm * 3) {
            console.log(`⚠️ Google Routes Sanity-Check FAIL: ${_g.distanceKm.toFixed(1)}km > 3× OSRM ${_o.distanceKm.toFixed(1)}km → OSRM bevorzugt`);
            _chosen = _o;
        } else {
            // Normale Wahl: kürzere Distanz gewinnt
            _chosen = (_g.distanceKm <= _o.distanceKm) ? _g : _o;
            console.log(`✅ Routing: Google ${_g.distanceKm.toFixed(1)}km vs OSRM ${_o.distanceKm.toFixed(1)}km → ${_chosen.source} (${_chosen.distanceKm.toFixed(1)}km)`);
        }
    } else if (_g) {
        _chosen = _g;
    } else if (_o) {
        _chosen = _o;
    } else {
        console.error('❌ Beide Routing-Engines down (Google + OSRM)');
        return null;
    }

    const _result = {
        distance: _chosen.distanceKm.toFixed(1),
        duration: _chosen.durationMin,
        legs: _chosen.legs.length > 0 ? _chosen.legs : [{ duration: _chosen.durationMin, distance: +_chosen.distanceKm.toFixed(1) }],
        source: _chosen.source
    };
    _writeRouteCache(from, to, waypointCoords, _routeMode, _result).catch(() => {});
    return _result;
}

function isFeiertag(date) {
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    if (FEIERTAGE.includes(`${month}-${day}`)) return true;
    // 🔧 v6.62.708: Bewegliche Feiertage (Karfreitag/Ostermontag/Christi Himmelfahrt/Pfingstmontag)
    const year = date.getFullYear();
    const easter = easterDate(year);
    const easterDayOnly = new Date(year, easter.getMonth(), easter.getDate());
    const targetDayOnly = new Date(year, date.getMonth(), date.getDate());
    const diffDays = Math.round((targetDayOnly.getTime() - easterDayOnly.getTime()) / 86400000);
    return diffDays === -2 || diffDays === 1 || diffDays === 39 || diffDays === 50;
}

// 🔧 v6.62.440: ECOVIS-/Tarif-Komplettierung — Cloud Function calculatePrice ist jetzt
//   feature-gleich mit index.html.calculatePrice. Patrick (08.05. 08:38): „Die sechs
//   Personen, der Zuschlag, wurde schon mal nicht mitgerechnet". Großraumzuschlag,
//   Wartezeit-pro-Stopp, Vehicle-Capacity-Surcharge fehlten komplett.
//   - persons >= 5 → +10 € Großraumzuschlag (Funk-Taxi-Tarif)
//   - waypointCount > 0 → +Wartezeit pro Stopp (default 5 min × 0,67 €/min = 3,35 €)
//   - vehicleCapacity 5 → +10 %, 6-7 → +20 %, 8+ → +30 % (vom Basis-Preis)
function calculatePrice(distance, timestamp = null, opts = {}) {
    const persons = (opts && typeof opts.persons === 'number') ? opts.persons : 0;
    const waypointCount = (opts && typeof opts.waypointCount === 'number') ? opts.waypointCount : 0;
    const vehicleCapacity = (opts && typeof opts.vehicleCapacity === 'number') ? opts.vehicleCapacity : 0;
    const waitMinutesOverride = (opts && opts.waitMinutesOverride != null) ? parseFloat(opts.waitMinutesOverride) : null;

    const calcTime = timestamp ? new Date(timestamp) : new Date();
    // 🔧 v6.38.24: BERLIN-Zeit für Tarifberechnung! getHours() ist UTC → falscher Nachttarif!
    const berlinTime = new Date(calcTime.toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
    const hour = berlinTime.getHours(), day = berlinTime.getDay();
    const istFeiertag_ = isFeiertag(berlinTime);
    const isNight = (hour >= 22 || hour < 6) || (day === 0) || istFeiertag_;

    const grundgebuehr = isNight ? TARIF.nacht_grundgebuehr : TARIF.grundgebuehr;
    const km_1_2 = isNight ? TARIF.nacht_km_1_2 : TARIF.km_1_2;
    const km_3_4 = isNight ? TARIF.nacht_km_3_4 : TARIF.km_3_4;
    const km_ab_5 = isNight ? TARIF.nacht_km_ab_5 : TARIF.km_ab_5;

    let kmPreis = 0;
    if (distance <= 2) { kmPreis = distance * km_1_2; }
    else if (distance <= 4) { kmPreis = (2 * km_1_2) + ((distance - 2) * km_3_4); }
    else { kmPreis = (2 * km_1_2) + (2 * km_3_4) + ((distance - 4) * km_ab_5); }

    let base = grundgebuehr + kmPreis;
    const text = [];

    // Vehicle-Capacity Surcharge (PKW groß, Van, 8-Sitzer)
    if (vehicleCapacity >= 8)      { base *= 1.30; text.push('🚐 8-Sitzer (+30%)'); }
    else if (vehicleCapacity >= 6) { base *= 1.20; text.push('🚐 Van (+20%)'); }
    else if (vehicleCapacity >= 5) { base *= 1.10; text.push('🚗 PKW groß (+10%)'); }

    // Großraumzuschlag bei 5+ Personen (pauschal +10€)
    let grossraumZuschlag = 0;
    if (persons >= 5) {
        grossraumZuschlag = 10.00;
        base += grossraumZuschlag;
        text.push('🚐 Großraumzuschlag (+10€)');
    }

    // Wartezeit pro Zwischenstopp
    let wartezeitMin = 0, wartezeitEuro = 0;
    const ratePerMin = parseFloat(TARIF.wartezeit_pro_minute) || 0;
    if (ratePerMin > 0) {
        if (waitMinutesOverride != null && !isNaN(waitMinutesOverride)) {
            wartezeitMin = Math.max(0, waitMinutesOverride);
        } else if (waypointCount > 0) {
            const perStop = parseFloat(TARIF.wartezeit_pro_stopp_min) || 5;
            const freeMin = parseFloat(TARIF.wartezeit_frei_minuten) || 0;
            wartezeitMin = Math.max(0, waypointCount * perStop - waypointCount * freeMin);
        }
        if (wartezeitMin > 0) {
            wartezeitEuro = wartezeitMin * ratePerMin;
            base += wartezeitEuro;
            text.push(`⏱ Wartezeit ${wartezeitMin}min (+${wartezeitEuro.toFixed(2)}€)`);
        }
    }

    if (istFeiertag_) text.push('Feiertag (Nachttarif)');
    else if (day === 0) text.push('Sonntag (Nachttarif)');
    else if (isNight) text.push('Nachttarif');

    const totalRounded = Math.round(base / 0.1) * 0.1;
    return { total: totalRounded.toFixed(2), zuschlagText: text, distance, basePrice: base.toFixed(2),
             grossraumZuschlag, wartezeitMin, wartezeitEuro };
}

// Parse datetime string as German time (CET/CEST) → returns UTC timestamp
// ═══════════════════════════════════════════════════════════════
// VERFÜGBARKEITS-PRÜFUNG (Telegram-Bot)
// ═══════════════════════════════════════════════════════════════

async function checkTelegramTimeConflict(pickupTimestamp, estimatedDuration) {
    try {
        const requestedDate = new Date(pickupTimestamp);
        // Nur Fahrten vom selben Tag laden
        const dayStart = new Date(requestedDate);
        dayStart.setHours(0, 0, 0, 0);
        const dayEnd = new Date(requestedDate);
        dayEnd.setHours(23, 59, 59, 999);

        const ridesSnap = await db.ref('rides')
            .orderByChild('pickupTimestamp')
            .startAt(dayStart.getTime())
            .endAt(dayEnd.getTime())
            .once('value');

        const rides = ridesSnap.val();
        if (!rides) return null; // Keine Fahrten → kein Konflikt

        const activeStatuses = ['new', 'open', 'sofort', 'assigned', 'vorbestellt', 'picked_up', 'ongoing', 'accepted']; // v6.63.425 'sofort' ergänzt
        const duration = estimatedDuration || 30; // Fallback: 30 Min
        const requestedEnd = pickupTimestamp + (duration * 60000);
        // 🆕 v6.63.450: 10 Min Hardcoded-Buffer → settings-konfigurierbar
        //   (slotBufferMin in settings/pricing, Default 10 für Sammelfahrt-Slot-Vorschläge)
        const _slotBufferMin = (pricingSettings && pricingSettings.slotBufferMin != null) ? pricingSettings.slotBufferMin : 10;
        const bufferMs = _slotBufferMin * 60000;

        const conflicts = [];
        for (const [rideId, ride] of Object.entries(rides)) {
            if (!activeStatuses.includes(ride.status)) continue;
            const rideStart = ride.pickupTimestamp || 0;
            const rideDuration = ride.duration ? parseInt(ride.duration) : (ride.estimatedDuration ? parseInt(ride.estimatedDuration) : 30);
            const rideEnd = rideStart + (rideDuration * 60000);

            // Überlappungs-Check mit Puffer
            if (pickupTimestamp < (rideEnd + bufferMs) && requestedEnd > (rideStart - bufferMs)) {
                const rideTime = new Date(rideStart).toLocaleTimeString('de-DE', { ...TZ_BERLIN, hour: '2-digit', minute: '2-digit', hour12: false });
                const rideEndTime = new Date(rideEnd).toLocaleTimeString('de-DE', { ...TZ_BERLIN, hour: '2-digit', minute: '2-digit', hour12: false });
                conflicts.push({
                    rideId,
                    pickup: ride.pickup || '?',
                    destination: ride.destination || '?',
                    startTime: rideTime,
                    endTime: rideEndTime,
                    rideStart,
                    rideEnd
                });
            }
        }

        if (conflicts.length === 0) return null;

        // Fahrzeug-Anzahl prüfen (mehrere Fahrzeuge = evtl. kein echter Konflikt)
        let vehicleCount = 1;
        try {
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val();
            if (vehicles) {
                vehicleCount = Object.values(vehicles).filter(v => v.active !== false).length;
            }
        } catch (e) { /* Fallback: 1 Fahrzeug */ }

        // Wenn mehr Fahrzeuge als Konflikte → kein Problem
        if (vehicleCount > conflicts.length) return null;

        // Frühestmöglichen freien Slot berechnen
        const allEnds = conflicts.map(c => c.rideEnd + bufferMs).sort((a, b) => a - b);
        const earliestFree = allEnds[allEnds.length - 1];
        const earliestFreeTime = new Date(earliestFree).toLocaleTimeString('de-DE', { ...TZ_BERLIN, hour: '2-digit', minute: '2-digit', hour12: false });

        return { conflicts, earliestFree, earliestFreeTime, vehicleCount };
    } catch (e) {
        console.error('[Verfügbarkeit] Prüfung fehlgeschlagen:', e.message);
        return null; // Im Fehlerfall Buchung trotzdem zulassen
    }
}

// 🆕 v6.11.6: Fahrer-Online-Check für Sofortfahrten
async function checkDriversOnline() {
    try {
        const vehiclesSnap = await db.ref('vehicles').once('value');
        const vehicles = vehiclesSnap.val();
        if (!vehicles) return { online: false, count: 0, total: 0 };

        const now = Date.now();
        const maxAge = 10 * 60 * 1000; // 10 Minuten

        let total = 0;
        let onlineCount = 0;
        const onlineDrivers = [];

        for (const [id, v] of Object.entries(vehicles)) {
            if (v.active === false) continue;
            total++;
            const gpsAge = v.timestamp ? (now - v.timestamp) : Infinity;
            const isOnline = gpsAge <= maxAge && v.online !== false && v.dispatchStatus !== 'offline' && v.lat && v.lon;
            if (isOnline) {
                onlineCount++;
                onlineDrivers.push({ id, name: v.name || id, lat: v.lat, lon: v.lon });
            }
        }

        return { online: onlineCount > 0, count: onlineCount, total, drivers: onlineDrivers };
    } catch (e) {
        console.error('[DriverCheck] Fehler:', e.message);
        return { online: true, count: 0, total: 0 }; // Im Fehlerfall optimistisch
    }
}

// 🆕 v6.14.7: Freitext-Datum parsen ("morgen 14:00", "15.03. 10 Uhr", "14:30", etc.)
function parseFreeformDatetime(text) {
    if (!text) return null;
    const now = new Date();
    const berlinNow = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));

    let targetDate = new Date(berlinNow);
    let hours = null, minutes = null;

    const t = text.toLowerCase().trim();

    // "morgen", "übermorgen", "heute"
    if (/morgen/i.test(t) && !/übermorgen/i.test(t)) {
        targetDate.setDate(targetDate.getDate() + 1);
    } else if (/übermorgen/i.test(t)) {
        targetDate.setDate(targetDate.getDate() + 2);
    }
    // Wochentage
    const wochentage = { montag: 1, dienstag: 2, mittwoch: 3, donnerstag: 4, freitag: 5, samstag: 6, sonntag: 0 };
    for (const [tag, dow] of Object.entries(wochentage)) {
        if (t.includes(tag)) {
            let diff = dow - targetDate.getDay();
            if (diff <= 0) diff += 7;
            targetDate.setDate(targetDate.getDate() + diff);
            break;
        }
    }
    // Datum: "15.03.", "15.3.2026", "15.03.2026"
    const dateMatch = t.match(/(\d{1,2})\.(\d{1,2})\.?(\d{2,4})?/);
    if (dateMatch) {
        targetDate.setDate(parseInt(dateMatch[1]));
        targetDate.setMonth(parseInt(dateMatch[2]) - 1);
        if (dateMatch[3]) {
            let year = parseInt(dateMatch[3]);
            if (year < 100) year += 2000;
            targetDate.setFullYear(year);
        }
        // Wenn Datum in Vergangenheit → nächstes Jahr
        if (targetDate < berlinNow && !dateMatch[3]) {
            targetDate.setFullYear(targetDate.getFullYear() + 1);
        }
    }
    // Uhrzeit: "14:00", "14 Uhr", "14.30", "14:30 Uhr"
    const timeMatch = t.match(/(\d{1,2})[:\.](\d{2})/);
    const timeMatch2 = t.match(/(\d{1,2})\s*uhr/i);
    if (timeMatch) {
        hours = parseInt(timeMatch[1]);
        minutes = parseInt(timeMatch[2]);
    } else if (timeMatch2) {
        hours = parseInt(timeMatch2[1]);
        minutes = 0;
    }

    if (hours === null) return null; // Mindestens Uhrzeit muss angegeben sein

    targetDate.setHours(hours, minutes, 0, 0);

    // Convert Berlin local time to UTC timestamp
    const berlinStr = targetDate.toLocaleString('en-US');
    const berlinAsUTC = new Date(berlinStr);
    const offsetMs = berlinAsUTC.getTime() - targetDate.getTime();
    return targetDate.getTime() - offsetMs;
}

function parseGermanDatetime(datetimeStr) {
    if (!datetimeStr) {
        console.warn('⚠️ parseGermanDatetime: datetimeStr ist leer/null → Fallback auf Date.now()! Das kann zu falscher Sofortfahrt-Erkennung führen.');
        return Date.now();
    }
    const d = new Date(datetimeStr);
    if (isNaN(d.getTime())) {
        console.warn(`⚠️ parseGermanDatetime: "${datetimeStr}" konnte NICHT geparst werden → Fallback auf Date.now()! Sofortfahrt-Fehlklassifizierung möglich.`);
        return Date.now();
    }
    // If already has explicit timezone suffix (Z or +/-offset), use as-is
    if (typeof datetimeStr === 'string' && (datetimeStr.endsWith('Z') || /[+-]\d{2}:?\d{2}$/.test(datetimeStr))) {
        return d.getTime();
    }
    // Treat as Europe/Berlin: compute offset and correct
    const berlinStr = d.toLocaleString('en-US', { timeZone: 'Europe/Berlin' });
    const berlinAsUTC = new Date(berlinStr);
    const offsetMs = berlinAsUTC.getTime() - d.getTime();
    const result = d.getTime() - offsetMs;
    console.log(`📅 parseGermanDatetime: "${datetimeStr}" → ${new Date(result).toISOString()} (Berlin: ${new Date(result).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' })})`);
    return result;
}

// 🔧 v6.63.467: DST-sicherer Berlin-Timestamp-Rechner.
// Ersetzt hardcodiertes +02:00 (bricht im Winter) und +01:00 (bricht im Sommer).
// Funktioniert für CEST (UTC+2) UND CET (UTC+1) automatisch.
function _berlinToTs(dateStr, timeStr) {
    const probe = new Date(dateStr + 'T12:00:00Z');
    const berlinNoonHour = parseInt(
        probe.toLocaleString('en-US', { timeZone: 'Europe/Berlin', hour: '2-digit', hour12: false })
    );
    const offsetMs = (berlinNoonHour - 12) * 3600000;
    return new Date(dateStr + 'T' + timeStr + ':00Z').getTime() - offsetMs;
}

const TZ_BERLIN = { timeZone: 'Europe/Berlin' };

// 🆕 v6.62.684: Patrick (13.05. 17:13): Korridor-Tarif fuer 3-Kaiserbaeder-Bereich.
//   "Wenn BEIDE Pickup UND Destination ausserhalb der Kaiserbaeder liegen, muessen
//   wir die Anfahrt vom WEITESTEN Punkt aus berechnen — also der, von dem wir wieder
//   zurueckmuessen — mit 1,20 €/km."
const KAISERBAEDER_CENTER = { lat: 53.9501, lon: 14.16 }; // Heringsdorf-Mitte
const KAISERBAEDER_RADIUS_KM = 8;                          // deckt Ahlbeck/HG/Bansin
const ANFAHRT_EUR_PER_KM = 1.20;

function haversineKm(a, b) {
    const R = 6371;
    const dLat = (b.lat - a.lat) * Math.PI / 180;
    const dLon = (b.lon - a.lon) * Math.PI / 180;
    const aa = Math.sin(dLat/2)**2 + Math.cos(a.lat*Math.PI/180) * Math.cos(b.lat*Math.PI/180) * Math.sin(dLon/2)**2;
    return R * 2 * Math.atan2(Math.sqrt(aa), Math.sqrt(1-aa));
}

function isInKaiserbaederZone(lat, lon) {
    if (lat == null || lon == null) return true; // bei fehlenden Coords: 'innen' = kein Aufschlag
    return haversineKm(KAISERBAEDER_CENTER, { lat, lon }) <= KAISERBAEDER_RADIUS_KM;
}

async function calcKorridorAnfahrtAufschlag(pickupLat, pickupLon, destLat, destLon) {
    // 🆕 v6.62.687: Patrick: "Anfahrt zum PICKUP, das ist am unkompliziertesten."
    // 🔧 v6.62.756 (Patrick 16.05. 07:03): "Wenn Abholort ODER Zielort in den Kaiserbaedern,
    //   dann KEINE Anfahrt. Nur wenn BEIDE ausserhalb."
    //   Begruendung: Wenn der Tesla z.B. Flughafen → Heringsdorf faehrt, ist das eine
    //   normale Hin-Strecke (er fuhr eh aus den Kaiserbaedern hin). Kein Aufschlag.
    if (isInKaiserbaederZone(pickupLat, pickupLon) || isInKaiserbaederZone(destLat, destLon)) {
        return { km: 0, eur: 0, applied: false, reason: 'Pickup ODER Destination in Kaiserbaedern' };
    }
    try {
        const r1 = await calculateRoute(KAISERBAEDER_CENTER, { lat: pickupLat, lon: pickupLon });
        const km = parseFloat(r1 && r1.distance || 0);
        if (!km || km <= 0) return { km: 0, eur: 0, applied: false, reason: 'OSRM lieferte 0 km' };
        return {
            km: km,
            eur: Math.round(km * ANFAHRT_EUR_PER_KM * 100) / 100,
            applied: true,
            reason: `Anfahrt zum Pickup (${km.toFixed(1)} km Strasse × 1,20 €/km)`
        };
    } catch (e) {
        console.warn('calcKorridorAnfahrt Fehler:', e.message);
        return { km: 0, eur: 0, applied: false, reason: 'OSRM-Fehler: ' + e.message };
    }
}

async function calculateTelegramRoutePrice(booking) {
    if (!booking.pickupLat || !booking.destinationLat) return null;
    try {
        // 🔧 v6.38.20: Zwischenstopps geocoden, als {address,lat,lon} Objekte speichern und in Route einbeziehen
        const waypointCoords = [];
        if (booking.waypoints && booking.waypoints.length > 0) {
            console.log(`[RoutePrice] ${booking.waypoints.length} Zwischenstopps geocoden...`);
            for (let _wpI = 0; _wpI < booking.waypoints.length; _wpI++) {
                const wp = booking.waypoints[_wpI];
                const wpAddr = typeof wp === 'string' ? wp : (wp.address || String(wp));
                // Gespeicherte Koordinaten direkt verwenden (kein re-geocoding nötig)
                if (typeof wp === 'object' && wp.lat && wp.lon) {
                    waypointCoords.push({ lat: wp.lat, lon: wp.lon });
                    console.log(`[RoutePrice] ✅ Zwischenstopp "${wpAddr}" → gespeicherte Koordinaten: ${wp.lat}, ${wp.lon}`);
                    continue;
                }
                try {
                    const coords = await geocode(wpAddr);
                    if (coords && coords.lat && coords.lon) {
                        waypointCoords.push({ lat: coords.lat, lon: coords.lon });
                        // String-Waypoint → Objekt mit Koordinaten upgraden
                        booking.waypoints[_wpI] = { address: wpAddr, lat: coords.lat, lon: coords.lon };
                        console.log(`[RoutePrice] ✅ Zwischenstopp "${wpAddr}" → geocodiert: ${coords.lat}, ${coords.lon}`);
                    } else {
                        // Kein Geocode-Treffer → trotzdem als Objekt speichern
                        if (typeof wp === 'string') booking.waypoints[_wpI] = { address: wpAddr };
                        console.warn(`[RoutePrice] ⚠️ Zwischenstopp "${wpAddr}" konnte nicht geocodiert werden`);
                    }
                } catch (e) {
                    if (typeof wp === 'string') booking.waypoints[_wpI] = { address: wpAddr };
                    console.warn(`[RoutePrice] Geocode-Fehler für Zwischenstopp "${wpAddr}":`, e.message);
                }
            }
        }

        console.log(`[RoutePrice] Berechne Route: (${booking.pickupLat}, ${booking.pickupLon}) → (${booking.destinationLat}, ${booking.destinationLon})${waypointCoords.length > 0 ? ` mit ${waypointCoords.length} Zwischenstopps` : ''}`);
        const route = await calculateRoute(
            { lat: booking.pickupLat, lon: booking.pickupLon },
            { lat: booking.destinationLat, lon: booking.destinationLon },
            waypointCoords
        );
        if (!route || !route.distance) return null;
        console.log(`[RoutePrice] OSRM Ergebnis: ${route.distance} km, ${route.duration} min`);
        if (parseFloat(route.distance) > 500) {
            console.warn(`[RoutePrice] Unrealistische Distanz: ${route.distance} km → Berechnung übersprungen`);
            return null;
        }
        const pickupTimestamp = booking.datetime ? parseGermanDatetime(booking.datetime) : Date.now();
        // v6.62.440: persons + waypointCount weitergeben für Großraum/Wartezeit-Zuschlag
        const _persons = parseInt(booking.persons || booking.passengers || booking.personenzahl || 1, 10);
        const _wpCount = (booking.waypoints && booking.waypoints.length) || 0;
        const pricing = calculatePrice(parseFloat(route.distance), pickupTimestamp,
            { persons: _persons, waypointCount: _wpCount });
        // Korridor-Aufschlag entfernt (Patrick 31.05.2026): "es gibt keinen Korridor-Aufschlag".
        let _totalPrice = parseFloat(pricing.total);
        let _zuschlagText = Array.isArray(pricing.zuschlagText) ? [...pricing.zuschlagText] : (pricing.zuschlagText ? [pricing.zuschlagText] : []);
        console.log(`[RoutePrice] Preis: ${_totalPrice}€ für ${route.distance} km (persons=${_persons}, wp=${_wpCount})`);
        return {
            distance: route.distance,
            duration: route.duration,
            price: _totalPrice.toFixed(2),
            zuschlagText: _zuschlagText,
            korridorAufschlag: null
        };
    } catch (e) {
        console.error('[RoutePrice] Fehler:', e.message);
        return null;
    }
}

async function validateTelegramAddresses(chatId, booking, originalText) {
    await sendTelegramMessage(chatId, '📍 <i>Prüfe Adressen...</i>');
    await addTelegramLog('📍', chatId, `Adress-Check: "${booking.pickup}" → "${booking.destination}"`);

    // Bereits gesetzte Koordinaten überspringen (z.B. GPS-Standort, beliebte Ziele)
    const hasPickupCoords = !!(booking.pickupLat && booking.pickupLon);
    const hasDestCoords = !!(booking.destinationLat && booking.destinationLon);

    // 🔧 v6.38.1: _pickupConfirmedByCRM = Admin hat Adresse selbst eingetragen → kein Geocoding
    const needPickup = !hasPickupCoords && !!booking.pickup && !booking._pickupConfirmedByCRM;
    const needDest = !hasDestCoords && !!booking.destination;

    // Wenn Adressen per Text eingegeben → IMMER Vorschläge zeigen, Kunde wählt selbst
    if (needPickup || needDest) {
        // Zuerst Pickup lösen, dann Destination
        const fieldToResolve = needPickup ? 'pickup' : 'destination';
        const addressToResolve = needPickup ? booking.pickup : booking.destination;
        const fieldLabel = needPickup ? '📍 Abholort' : '🎯 Zielort';
        const prefix = needPickup ? 'np' : 'nd';

        try {
            // 🔧 v6.25.5: Prüfe ob Ort/PLZ fehlt — wenn ja, NACHFRAGEN statt raten
            const _addrHasPlz = /\b\d{5}\b/.test(addressToResolve);
            const _addrOrtNames = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz', 'trassenheide', 'karlshagen', 'koserow', 'loddin', 'ückeritz', 'zempin', 'peenemünde', 'wolgast', 'usedom', 'swinemünde', 'świnoujście', 'greifswald', 'anklam', 'rostock', 'berlin', 'stralsund', 'hamburg', 'szczecin'];
            const _addrHasOrt = _addrOrtNames.some(o => addressToResolve.toLowerCase().includes(o));
            const _addrLooksLikeStreet = /straße|weg\b|ring\b|allee|chaussee|platz|gasse|damm|steig|pfad|ufer|str\b|str\./i.test(addressToResolve);
            if (!_addrHasPlz && !_addrHasOrt && _addrLooksLikeStreet) {
                // Straße ohne Ort → Nachfragen!
                const pendingState = { partial: { ...booking, missing: [] }, originalText };
                pendingState._awaitingOrtForAddress = { field: fieldToResolve, address: addressToResolve };
                await setPending(chatId, pendingState);
                await addTelegramLog('❓', chatId, `${fieldLabel} "${addressToResolve}" ohne Ort/PLZ → frage nach`);
                await sendTelegramMessage(chatId,
                    `❓ <b>Welcher Ort?</b>\n\n` +
                    `Sie haben eingegeben: <b>${addressToResolve}</b>\n\n` +
                    `Bitte ergänzen Sie den <b>Ort</b> oder die <b>PLZ</b>:\n` +
                    `<i>z.B. „Heringsdorf", „Ahlbeck", „17424"</i>\n\n` +
                    `💡 Oder senden Sie Ihren <b>Standort</b> (📎 → Standort)`,
                    { reply_markup: { inline_keyboard: [
                        [{ text: '📍 Heringsdorf', callback_data: `addr_ort_heringsdorf_${fieldToResolve}` },
                         { text: '📍 Ahlbeck', callback_data: `addr_ort_ahlbeck_${fieldToResolve}` },
                         { text: '📍 Bansin', callback_data: `addr_ort_bansin_${fieldToResolve}` }],
                        [{ text: '✏️ Anderen Ort eingeben', callback_data: `addr_retry_${fieldToResolve}` }],
                        [{ text: '❌ Abbrechen', callback_data: 'cancel_booking' }]
                    ] } }
                );
                return null;
            }

            // 🔧 v6.38.48: DIREKT-GEOCODING — immer wenn Ort/PLZ vorhanden ist
            // Funktioniert mit: "Friedrichstraße 9, Ahlbeck", "Friedrichstraße, Ahlbeck", "Bahnhof Heringsdorf"
            const _hasHausnr = /\b\d+[a-z]?\b/i.test(addressToResolve.replace(/\b\d{5}\b/g, ''));
            const _hasOrtOrPlz = _addrHasPlz || _addrHasOrt;
            let _directGeoResult = null;
            // Direkt-Geocoding wenn: (Straße+Ort) ODER (Hausnr+Ort) — nicht mehr NUR wenn alle 3 da sind
            if (_hasOrtOrPlz) {
                try {
                    // Schritt 1: Direkt mit dem vollen String suchen
                    const _dq = encodeURIComponent(addressToResolve);
                    const _dUrl = `https://nominatim.openstreetmap.org/search?q=${_dq}&format=json&limit=5&countrycodes=de&addressdetails=1`;
                    const _dResp = await fetch(_dUrl, { headers: { 'User-Agent': 'FunkTaxiHeringsdorf/1.0' } });
                    const _dResults = await _dResp.json();

                    if (_dResults && _dResults.length > 0) {
                        // Usedom-Umkreis filtern
                        const _usedomResults = _dResults.filter(r => {
                            const lat = parseFloat(r.lat); const lon = parseFloat(r.lon);
                            return lat >= 53.5 && lat <= 54.3 && lon >= 13.5 && lon <= 14.5;
                        });

                        if (_usedomResults.length > 0) {
                            // Straßen-Matching wenn Straße vorhanden
                            if (_addrLooksLikeStreet) {
                                const _qStreetLow = addressToResolve.replace(/\s*\d[\d\w]*\s*[,]?\s*.*$/, '').trim().toLowerCase();
                                const _qStreetCore = _qStreetLow.replace(/straße$|str\.?$|weg$|allee$|platz$|ring$|gasse$|damm$|ufer$|steig$/,'');
                                for (const r of _usedomResults) {
                                    const rStreet = (r.address?.road || '').toLowerCase();
                                    const rCore = rStreet.replace(/straße$|str\.?$|weg$|allee$|platz$|ring$|gasse$|damm$|ufer$|steig$/,'');
                                    if (rCore.includes(_qStreetCore) || _qStreetCore.includes(rCore)) {
                                        const lat = parseFloat(r.lat); const lon = parseFloat(r.lon);
                                        const _displayName = `${r.address?.road || ''} ${r.address?.house_number || ''}, ${r.address?.postcode || ''} ${r.address?.city || r.address?.town || r.address?.village || ''}`.replace(/\s+/g, ' ').trim();
                                        _directGeoResult = { name: _displayName, lat, lon, source: 'nominatim-direct' };
                                        await addTelegramLog('✅', chatId, `Direkt-Geocoding: "${addressToResolve}" → ${_displayName} (${lat.toFixed(5)}, ${lon.toFixed(5)})`);
                                        break;
                                    }
                                }
                            }
                            // 🔧 v6.38.50 BUG-08 FIX: Kein Straßen-Match → NICHT auto-akzeptieren!
                            // Nur wenn Straße+Hausnr vorhanden war, den besten Treffer nehmen
                            if (!_directGeoResult && _hasHausnr && _addrLooksLikeStreet) {
                                const bestR = _usedomResults[0];
                                const lat = parseFloat(bestR.lat); const lon = parseFloat(bestR.lon);
                                const _displayName = `${bestR.address?.road || bestR.address?.amenity || bestR.display_name.split(',')[0]} ${bestR.address?.house_number || ''}, ${bestR.address?.postcode || ''} ${bestR.address?.city || bestR.address?.town || bestR.address?.village || ''}`.replace(/\s+/g, ' ').trim();
                                _directGeoResult = { name: _displayName, lat, lon, source: 'nominatim-direct-best' };
                                await addTelegramLog('✅', chatId, `Direkt-Geocoding (bester Treffer): "${addressToResolve}" → ${_displayName}`);
                            } else if (!_directGeoResult) {
                                // Unverifizierter Treffer → weiter zur normalen Such-Pipeline für Bestätigung durch User
                                await addTelegramLog('⚠️', chatId, `Direkt-Geocoding: ${_usedomResults.length} Usedom-Treffer aber kein Straßen-Match → Such-Pipeline`);
                            }
                        } else if (_dResults.length > 0) {
                            await addTelegramLog('⚠️', chatId, `Direkt-Geocoding: ${_dResults.length} Treffer aber keiner auf Usedom. Erster: "${_dResults[0].display_name}"`);
                        }
                    }

                    // 🔧 v6.38.59: Schritt 1b: "Seebad X" → "X" Fallback (Nominatim kennt "Seebad" nicht)
                    if (!_directGeoResult) {
                        const _cleanedAddr = addressToResolve.replace(/\bSeebad\s+/gi, '').replace(/\bOstseebad\s+/gi, '').replace(/\bKaiserbad\s+/gi, '');
                        if (_cleanedAddr !== addressToResolve) {
                            const _cq = encodeURIComponent(_cleanedAddr);
                            const _cUrl = `https://nominatim.openstreetmap.org/search?q=${_cq}&format=json&limit=5&countrycodes=de&addressdetails=1`;
                            const _cResp = await fetch(_cUrl, { headers: { 'User-Agent': 'FunkTaxiHeringsdorf/1.0' } });
                            const _cResults = await _cResp.json();
                            if (_cResults && _cResults.length > 0) {
                                const _cUsedom = _cResults.filter(r => {
                                    const lat = parseFloat(r.lat); const lon = parseFloat(r.lon);
                                    return lat >= 53.5 && lat <= 54.3 && lon >= 13.5 && lon <= 14.5;
                                });
                                if (_cUsedom.length > 0 && _addrLooksLikeStreet) {
                                    const _qStreetLow = _cleanedAddr.replace(/\s*\d[\d\w]*\s*[,]?\s*.*$/, '').trim().toLowerCase();
                                    const _qStreetCore = _qStreetLow.replace(/straße$|str\.?$|weg$|allee$|platz$|ring$|gasse$|damm$|ufer$|steig$/,'');
                                    for (const r of _cUsedom) {
                                        const rStreet = (r.address?.road || '').toLowerCase();
                                        const rCore = rStreet.replace(/straße$|str\.?$|weg$|allee$|platz$|ring$|gasse$|damm$|ufer$|steig$/,'');
                                        if (rCore.includes(_qStreetCore) || _qStreetCore.includes(rCore)) {
                                            const lat = parseFloat(r.lat); const lon = parseFloat(r.lon);
                                            const _displayName = `${r.address?.road || ''} ${r.address?.house_number || ''}, ${r.address?.postcode || ''} ${r.address?.city || r.address?.town || r.address?.village || ''}`.replace(/\s+/g, ' ').trim();
                                            _directGeoResult = { name: _displayName, lat, lon, source: 'nominatim-seebad-fix' };
                                            await addTelegramLog('✅', chatId, `Seebad-Fallback: "${addressToResolve}" → "${_cleanedAddr}" → ${_displayName}`);
                                            break;
                                        }
                                    }
                                }
                                if (!_directGeoResult && _cUsedom.length > 0 && _hasHausnr && _addrLooksLikeStreet) {
                                    const bestR = _cUsedom[0];
                                    const lat = parseFloat(bestR.lat); const lon = parseFloat(bestR.lon);
                                    const _displayName = `${bestR.address?.road || bestR.display_name.split(',')[0]} ${bestR.address?.house_number || ''}, ${bestR.address?.postcode || ''} ${bestR.address?.city || bestR.address?.town || bestR.address?.village || ''}`.replace(/\s+/g, ' ').trim();
                                    _directGeoResult = { name: _displayName, lat, lon, source: 'nominatim-seebad-best' };
                                    await addTelegramLog('✅', chatId, `Seebad-Fallback (bester Treffer): "${_cleanedAddr}" → ${_displayName}`);
                                }
                            }
                        }
                    }

                    // Schritt 2: Wenn nichts gefunden → strukturierte Suche (Straße + Ort getrennt)
                    if (!_directGeoResult && _addrLooksLikeStreet) {
                        // Adresse in Teile zerlegen: "Friedrichstraße 9, Ahlbeck" → street="Friedrichstraße 9", city="Ahlbeck"
                        const _parts = addressToResolve.split(/[,;]\s*/);
                        let _street = '', _city = '';
                        if (_parts.length >= 2) {
                            _street = _parts[0].trim();
                            // 🔧 v6.38.59: "Seebad" aus Ort entfernen
                            _city = _parts[_parts.length - 1].replace(/\b\d{5}\b/, '').replace(/\bSeebad\s*/gi, '').replace(/\bOstseebad\s*/gi, '').replace(/\bKaiserbad\s*/gi, '').trim();
                        } else {
                            // Kein Komma → Ort am Ende extrahieren
                            const _ortMatch = addressToResolve.match(new RegExp(`(${_addrOrtNames.join('|')})`, 'i'));
                            if (_ortMatch) {
                                _city = _ortMatch[1];
                                _street = addressToResolve.replace(_ortMatch[0], '').replace(/\s+/g, ' ').trim();
                            }
                        }
                        if (_street && _city) {
                            const _sUrl = `https://nominatim.openstreetmap.org/search?street=${encodeURIComponent(_street)}&city=${encodeURIComponent(_city)}&format=json&limit=3&countrycodes=de&addressdetails=1`;
                            const _sResp = await fetch(_sUrl, { headers: { 'User-Agent': 'FunkTaxiHeringsdorf/1.0' } });
                            const _sResults = await _sResp.json();
                            if (_sResults && _sResults.length > 0) {
                                const r = _sResults[0];
                                const lat = parseFloat(r.lat); const lon = parseFloat(r.lon);
                                if (lat >= 53.5 && lat <= 54.3 && lon >= 13.5 && lon <= 14.5) {
                                    const _displayName = `${r.address?.road || _street} ${r.address?.house_number || ''}, ${r.address?.postcode || ''} ${r.address?.city || r.address?.town || r.address?.village || _city}`.replace(/\s+/g, ' ').trim();
                                    _directGeoResult = { name: _displayName, lat, lon, source: 'nominatim-structured' };
                                    await addTelegramLog('✅', chatId, `Strukturierte Suche: "${_street}" + "${_city}" → ${_displayName}`);
                                }
                            }
                        }
                    }
                } catch(_dgErr) {
                    console.error('Direkt-Geocoding Fehler:', _dgErr.message);
                }
            }

            // Wenn Direkt-Geocoding erfolgreich → sofort übernehmen, keine weitere Suche nötig
            if (_directGeoResult) {
                if (needPickup) {
                    booking.pickup = _directGeoResult.name; booking.pickupLat = _directGeoResult.lat; booking.pickupLon = _directGeoResult.lon;
                } else {
                    booking.destination = _directGeoResult.name; booking.destinationLat = _directGeoResult.lat; booking.destinationLon = _directGeoResult.lon;
                }
                await addRideLog(null, '📍', `${fieldLabel} direkt aufgelöst: ${_directGeoResult.name}`, { quelle: 'nominatim-direct', koordinaten: `${_directGeoResult.lat.toFixed(5)}, ${_directGeoResult.lon.toFixed(5)}` });
                return await continueBookingFlow(chatId, booking, originalText);
            }

            const suggestions = await searchNominatimForTelegram(addressToResolve);

            // 🆕 v6.40.23: Kunden-Favoriten (häufige Ziele aus Historie) als Top-Vorschläge einblenden
            // Grund: User fragte "wir haben ja die beliebten Ziele warum wurden die nicht vorgeschlagen"
            if (fieldToResolve === 'destination') {
                try {
                    const _custName = booking.customerName || booking.name;
                    const _custPhone = booking.customerPhone || booking.customerMobile || booking.phone;
                    const _custId = booking.customerId || booking._crmCustomerId;
                    if (_custName && (_custPhone || _custId)) {
                        const _favs = await getCustomerFavoriteDestinations(_custName, _custPhone, _custId);
                        if (_favs && _favs.length > 0) {
                            const _validFavs = _favs.filter(f => f.destinationLat && f.destinationLon).slice(0, 3);
                            const _existingCoords = new Set();
                            for (const s of suggestions) {
                                if (s.lat && s.lon) _existingCoords.add(`${parseFloat(s.lat).toFixed(4)}_${parseFloat(s.lon).toFixed(4)}`);
                            }
                            const _favSuggestions = _validFavs
                                .filter(f => !_existingCoords.has(`${parseFloat(f.destinationLat).toFixed(4)}_${parseFloat(f.destinationLon).toFixed(4)}`))
                                .map(f => ({
                                    name: f.destination,
                                    label: `⭐ ${f.count}× ${f.destination}`,
                                    lat: f.destinationLat,
                                    lon: f.destinationLon,
                                    source: 'customer-favorite',
                                    priority: 1
                                }));
                            if (_favSuggestions.length > 0) {
                                suggestions.unshift(..._favSuggestions);
                                await addTelegramLog('⭐', chatId, `${_favSuggestions.length} Kunden-Favorit(en) von ${_custName} vorgeschlagen`, {
                                    favoriten: _favSuggestions.map(f => f.name).join(' | ')
                                });
                            }
                        }
                    }
                } catch (_favErr) {
                    console.warn('v6.40.23 Kunden-Favoriten Fehler:', _favErr.message);
                }
            }

            if (suggestions.length > 0) {
                // 🆕 v6.25.5: Verifizierte Adresse direkt übernehmen ohne Nachfrage!
                // 🔧 v6.38.10: Ersten VERTRAUENSWÜRDIGEN Treffer für auto-select nutzen (nicht Nominatim-Müll)
                const topHit = suggestions.find(s => s.source !== 'nominatim') || suggestions[0];
                // 🔧 v6.38.9: KNOWN_PLACES/POI/Cache/CRM → auto-selektieren wenn guter Match
                const isVerified = topHit.source === 'geocache-verified' || topHit.source === 'crm-verified'
                    || topHit.source === 'known' || topHit.source === 'poi';
                const _topFirst = (topHit.name || '').split(',')[0].trim().toLowerCase();
                const _addrLow = addressToResolve.toLowerCase().trim();
                const isCacheStartMatch = (topHit.source === 'geocache' || topHit.source === 'geocache-verified') &&
                    (_topFirst === _addrLow || topHit.name.toLowerCase().startsWith(_addrLow + ','));
                // 🔧 v6.38.10: Wortüberschneidung für known/poi (z.B. "Bahnhof Osebach-Bansin" → "Bahnhof Bansin")
                const _searchWords = _addrLow.split(/[\s,]+/).filter(w => w.length > 3);
                const _hitWords = topHit.name.toLowerCase().split(/[\s,]+/).filter(w => w.length > 3);
                const _wordOverlap = _searchWords.filter(w => _hitWords.some(hw => hw.includes(w) || w.includes(hw))).length;
                const isExactMatch = topHit.name && addressToResolve &&
                    (topHit.name.toLowerCase().includes(addressToResolve.toLowerCase()) ||
                     addressToResolve.toLowerCase().includes(topHit.name.toLowerCase().split(',')[0]) ||
                     ((topHit.source === 'known' || topHit.source === 'poi') && _wordOverlap >= 2));

                if ((isVerified || isCacheStartMatch) && isExactMatch && topHit.lat && topHit.lon) {
                    console.log(`✅ Verifizierte Adresse direkt übernommen: ${topHit.name} (${topHit.source})`);
                    await addTelegramLog('✅', chatId, `${fieldLabel} "${addressToResolve}" → exakt: ${topHit.name}`);
                    if (needPickup) {
                        booking.pickup = topHit.name;
                        booking.pickupLat = topHit.lat;
                        booking.pickupLon = topHit.lon;
                    } else {
                        booking.destination = topHit.name;
                        booking.destinationLat = topHit.lat;
                        booking.destinationLon = topHit.lon;
                    }
                    await continueBookingFlow(chatId, booking, originalText);
                    return null;
                }

                // 🔧 v6.38.10: Vage Adresse ohne Hausnummer/PLZ + nur Nominatim → Rückfrage
                // 🆕 v6.38.15: NUR wenn auch KEINE Nominatim-Ergebnisse — mit Ergebnissen → Vorschläge zeigen (wie Autocomplete)
                const _hasTrustedSugg1 = suggestions.some(s => s.source !== 'nominatim');
                const _hasPlzInAddr1 = /\b\d{5}\b/.test(addressToResolve);
                const _hasHausnrInAddr1 = /\b\d+[a-z]?\b/i.test(addressToResolve.replace(/\b\d{5}\b/g, '').trim());
                const _isVagueAddr1 = !_hasPlzInAddr1 && !_hasHausnrInAddr1 && addressToResolve.trim().split(/\s+/).length <= 2;
                if (_isVagueAddr1 && !_hasTrustedSugg1 && suggestions.length === 0) {
                    const _psVague1 = { partial: { ...booking, missing: [] }, originalText };
                    _psVague1.nominatimResults = []; // damit Text-Eingabe als Adressklärung erkannt wird
                    _psVague1._resolvingField = fieldToResolve; // 🔧 v6.39.0: Merke welches Feld aufgelöst wird
                    if (hasPickupCoords) { _psVague1.partial.pickupLat = booking.pickupLat; _psVague1.partial.pickupLon = booking.pickupLon; }
                    if (hasDestCoords) { _psVague1.partial.destinationLat = booking.destinationLat; _psVague1.partial.destinationLon = booking.destinationLon; }
                    await setPending(chatId, _psVague1);
                    await addTelegramLog('❓', chatId, `${fieldLabel} "${addressToResolve}" zu vage → Rückfrage`);
                    await sendTelegramMessage(chatId,
                        `❓ <b>${fieldLabel} nicht eindeutig</b>\n\nBitte Straße, Hausnummer und PLZ eingeben:\n<i>Beispiel: Bahnhofstraße 5, 17419 Ahlbeck</i>`,
                        { reply_markup: { inline_keyboard: [
                            [{ text: '✏️ Adresse eingeben', callback_data: `addr_retry_${fieldToResolve}` }],
                            [{ text: '❌ Abbrechen', callback_data: 'cancel_booking' }]
                        ] } }
                    );
                    return null;
                }
                // 🔧 v6.38.32: Hausnummer-Auto-Select NUR für verifizierte Quellen!
                // Nominatim-Treffer müssen IMMER vom User bestätigt werden
                if (_hasHausnrInAddr1 && suggestions.length > 0) {
                    const _qStreet1 = addressToResolve.replace(/\s*\d[\d\w]*\s*[,]?\s*.*$/, '').trim().toLowerCase();
                    const _qHausnr1 = addressToResolve.match(/\b(\d+)\s*[a-z]?\s*(?:,|$|\s)/i)?.[1] || '';
                    const _streetOk1 = (s) => {
                        if (!_qStreet1) return true;
                        const sName = s.name.toLowerCase().split(',')[0].trim();
                        const sStreet = sName.replace(/\s*\d+[a-z]?\s*$/i, '').trim();
                        return sStreet === _qStreet1 || sStreet.startsWith(_qStreet1 + ' ') || _qStreet1.startsWith(sStreet + ' ');
                    };
                    const _hausnrOk1 = (s) => {
                        if (!_qHausnr1) return true;
                        const sName = s.name || '';
                        const sNr = sName.match(/\b(\d+)\s*[a-z]?\s*(?:,|$|\s)/i)?.[1] || '';
                        return sNr === _qHausnr1;
                    };
                    // NUR verifizierte Quellen dürfen auto-selektiert werden!
                    const _TRUSTED1 = ['geocache-verified', 'crm-verified', 'known', 'poi'];
                    const _KAISERBAEDER1 = ['heringsdorf', 'ahlbeck', 'bansin'];
                    const _TOWNS1 = ['heringsdorf', 'ahlbeck', 'bansin', 'zinnowitz', 'koserow', 'ückeritz', 'loddin', 'trassenheide', 'zempin', 'karlshagen', 'peenemünde', 'wolgast', 'anklam'];
                    const _explTown1 = _TOWNS1.find(t => addressToResolve.toLowerCase().includes(t));
                    const _isKaiserbad1 = _KAISERBAEDER1.includes(_explTown1);
                    const _townOk1 = (s) => {
                        if (!_explTown1) return true;
                        const sLow = s.name.toLowerCase();
                        if (sLow.includes(_explTown1)) return true;
                        if (_isKaiserbad1) return _KAISERBAEDER1.some(k => sLow.includes(k));
                        return false;
                    };
                    // 🔧 v6.38.32: NUR verifizierte Quellen auto-selektieren — Nominatim IMMER fragen!
                    const _bestHit = suggestions.find(s => _TRUSTED1.includes(s.source) && s.lat && s.lon && _townOk1(s) && _streetOk1(s) && _hausnrOk1(s))
                        || (_explTown1 && suggestions.find(s => s.source !== 'nominatim' && s.lat && s.lon && _townOk1(s) && _streetOk1(s) && _hausnrOk1(s)));
                    // Dritte Stufe (Nominatim mit isNearUsedom) ENTFERNT — Nominatim muss immer bestätigt werden
                    if (_bestHit && _bestHit.lat && _bestHit.lon) {
                        await addTelegramLog('✅', chatId, `${fieldLabel} "${addressToResolve}" → verifiziert (${_bestHit.source}): ${_bestHit.name}`);
                        if (needPickup) {
                            booking.pickup = _bestHit.name; booking.pickupLat = _bestHit.lat; booking.pickupLon = _bestHit.lon;
                        } else {
                            booking.destination = _bestHit.name; booking.destinationLat = _bestHit.lat; booking.destinationLon = _bestHit.lon;
                        }
                        await continueBookingFlow(chatId, booking, originalText);
                        return null;
                    }
                }

                // Nominatim-Rauschen rausfiltern wenn vertrauenswürdige Quellen vorhanden
                const _displaySugg1 = _hasTrustedSugg1 ? suggestions.filter(s => s.source !== 'nominatim') : suggestions;

                // 🔧 v6.38.10: Nur 1 vertrauenswürdiger Treffer nach Filter → direkt auto-selektieren
                // 🔧 v6.38.14: POI-Name muss zur Suchanfrage passen (nicht nur die Stadtadresse)
                if (_displaySugg1.length === 1 && _hasTrustedSugg1 && _displaySugg1[0].lat && _displaySugg1[0].lon) {
                    const _solo = _displaySugg1[0];
                    const _soloFirstName = (_solo.name || '').toLowerCase().split(',')[0].trim();
                    const _qLow = addressToResolve.trim().toLowerCase();
                    const _qWords = _qLow.split(/[\s,]+/).filter(w => w.length > 3);
                    const _nameMatches = _soloFirstName.includes(_qLow) || _qLow.includes(_soloFirstName) ||
                        _qWords.some(w => _soloFirstName.includes(w));
                    if (_nameMatches) {
                        await addTelegramLog('✅', chatId, `${fieldLabel} "${addressToResolve}" → Einzel-Treffer: ${_solo.name}`);
                        if (needPickup) {
                            booking.pickup = _solo.name; booking.pickupLat = _solo.lat; booking.pickupLon = _solo.lon;
                        } else {
                            booking.destination = _solo.name; booking.destinationLat = _solo.lat; booking.destinationLon = _solo.lon;
                        }
                        await continueBookingFlow(chatId, booking, originalText);
                        return null;
                    }
                    // Name passt nicht → weiter zu Vorschlägen
                }

                // 🔧 v6.25.4: Zurück-Button bei Adressvorschlägen
                // 🔧 v6.38.1: "So verwenden" jetzt klarer benannt
                const shortAddrNorm = addressToResolve.length > 28 ? addressToResolve.slice(0, 26) + '…' : addressToResolve;
                const addrBottomRow = [{ text: '✏️ Andere Adresse eingeben', callback_data: `addr_retry_${fieldToResolve}` }];
                const addrLastRow = [];
                if (!needPickup && needDest) {
                    addrLastRow.push({ text: '◀️ Zurück', callback_data: 'addr_back_to_pickup' });
                }
                // 🔧 v6.38.34: "So verwenden" ENTFERNT — Adressen MÜSSEN aus Liste gewählt werden!
                // Ohne verifizierte Koordinaten keine Fahrt möglich
                addrLastRow.push({ text: '❌ Abbrechen', callback_data: 'cancel_booking' });
                const keyboard = {
                    inline_keyboard: [
                        ..._displaySugg1.map((s, i) => [{ text: `${s.source === 'poi' || s.source === 'known' ? '⭐' : s.source === 'customer' || s.source === 'customer-nocoords' ? '👤' : s.source === 'booking' ? '🔁' : '📍'} ${s.label || s.name}`, callback_data: `${prefix}_${i}` }]),
                        addrBottomRow,
                        addrLastRow
                    ]
                };

                const pendingState = { partial: { ...booking, missing: [] }, originalText };
                pendingState.nominatimResults = _displaySugg1;
                pendingState._resolvingField = fieldToResolve; // 🔧 v6.39.0: Merke welches Feld aufgelöst wird
                if (hasPickupCoords) { pendingState.partial.pickupLat = booking.pickupLat; pendingState.partial.pickupLon = booking.pickupLon; }
                if (hasDestCoords) { pendingState.partial.destinationLat = booking.destinationLat; pendingState.partial.destinationLon = booking.destinationLon; }
                // Wenn beide Adressen noch aufgelöst werden müssen, Destination nachher
                pendingState.pendingDestValidation = (needPickup && needDest);
                await setPending(chatId, pendingState);

                // 🔧 v6.39.0: Vorschläge im Log mit anzeigen
                const _suggNames1 = _displaySugg1.map(s => `${s.source === 'known' || s.source === 'poi' ? '⭐' : '📍'}${s.name}`).join(' | ');
                await addTelegramLog('🔍', chatId, `${fieldLabel} "${addressToResolve}" → ${_displaySugg1.length} Vorschläge: ${_suggNames1}`);
                await sendTelegramMessage(chatId,
                    `🔍 <b>${fieldLabel}: "${addressToResolve}"</b>\n\n` +
                    `Bitte wählen Sie die korrekte Adresse:`,
                    { reply_markup: keyboard }
                );
                return null; // Warte auf Kundenauswahl
            } else {
                // Keine exakten Ergebnisse → Fuzzy-Suche in KNOWN_PLACES + POIs + Buchungen + Kunden
                // 🔧 v6.38.26: Echtes Levenshtein-Matching statt nur includes()
                const fuzzyWords = addressToResolve.toLowerCase().replace(/[,./]/g, ' ').split(/\s+/).filter(w => w.length > 2);
                const similarPlaces = [];
                // 🆕 v6.62.70: Common-Word-Liste — Generika zaehlen weniger als Eigennamen.
                // Patrick: 'Hotel Admiral' soll NICHT 'Hotel Residenz' vorschlagen weil nur 'hotel' matched.
                const _COMMON_WORDS = new Set([
                    'hotel', 'pension', 'restaurant', 'cafe', 'café', 'bar', 'imbiss',
                    'bahnhof', 'flughafen', 'parkplatz', 'parkhaus', 'apotheke', 'tankstelle',
                    'supermarkt', 'rewe', 'edeka', 'aldi', 'lidl', 'penny',
                    'arzt', 'praxis', 'klinik', 'krankenhaus', 'zahnarzt',
                    'strandhotel', 'promenadenhotel', 'gasthaus', 'gasthof',
                    'strasse', 'straße', 'weg', 'platz', 'allee',
                    'usedom', 'heringsdorf', 'bansin', 'ahlbeck', 'kamminke', 'koserow',
                    'der', 'die', 'das', 'dem', 'den', 'des', 'ein', 'eine', 'einer'
                ]);
                // Eigennamen 2 Pkt, Common-Words 0.5 Pkt
                const _wordWeight = (w) => _COMMON_WORDS.has(w) ? 0.5 : 2.0;
                // Hilfsfunktion: Fuzzy-Wort-Match mit Levenshtein + Score-Gewichtung
                const _fuzzyWordCount = (fWords, targetText) => {
                    const tWords = targetText.replace(/[,./]/g, ' ').split(/\s+/).filter(w => w.length > 1);
                    let score = 0;
                    for (const fw of fWords) {
                        const matched = tWords.some(tw => {
                            if (tw.includes(fw) || fw.includes(tw)) return true;
                            const maxD = Math.max(fw.length, tw.length) >= 7 ? 2 : 1;
                            return _levenshteinDist(fw, tw) <= maxD;
                        });
                        if (matched) score += _wordWeight(fw);
                    }
                    return score;
                };
                // 🆕 v6.62.70: Mindest-Score-Schwelle — mind. 50% des MAX-moeglichen Scores
                // (verhindert dass 'Hotel Admiral' mit 'Hotel Residenz' beantwortet wird wenn nur 'hotel' matched).
                const _maxPossibleScore = fuzzyWords.reduce((sum, w) => sum + _wordWeight(w), 0);
                const _minRequiredScore = Math.max(1.0, _maxPossibleScore * 0.5);
                // 1. KNOWN_PLACES (v6.48.0 — aus /pois)
                const _kpFuzzy = await getKnownPlaces();
                for (const [key, place] of Object.entries(_kpFuzzy)) {
                    const pName = (place.name || '').toLowerCase();
                    const matchCount = _fuzzyWordCount(fuzzyWords, key + ' ' + pName);
                    if (matchCount >= _minRequiredScore) {
                        similarPlaces.push({ ...place, name: place.name || key, score: matchCount });
                    }
                }
                // 2. POIs aus Firebase
                try {
                    const poisSnap = await db.ref('pois').once('value');
                    if (poisSnap.exists()) {
                        poisSnap.forEach(child => {
                            const poi = child.val();
                            if (!poi.name || !poi.lat || !poi.lon) return;
                            const pName = poi.name.toLowerCase();
                            const pAddr = (poi.address || '').toLowerCase();
                            const matchCount = _fuzzyWordCount(fuzzyWords, pName + ' ' + pAddr);
                            if (matchCount >= _minRequiredScore) {
                                const displayName = poi.address ? (poi.address.toLowerCase().startsWith(poi.name.toLowerCase()) ? poi.address : `${poi.name}, ${poi.address}`) : poi.name;
                                similarPlaces.push({ name: displayName, lat: poi.lat, lon: poi.lon, score: matchCount });
                            }
                        });
                    }
                } catch (e) { console.warn('Fuzzy POI-Suche Fehler:', e.message); }
                // 3. Häufige Ziele aus Buchungen
                try {
                    const ridesSnap = await db.ref('rides').orderByChild('createdAt').limitToLast(200).once('value');
                    const seen = new Set();
                    ridesSnap.forEach(child => {
                        const r = child.val();
                        for (const [addr, lat, lon] of [
                            [r.destination, r.destinationLat || (r.destCoords && r.destCoords.lat), r.destinationLon || (r.destCoords && r.destCoords.lon)],
                            [r.pickup, r.pickupLat || (r.pickupCoords && r.pickupCoords.lat), r.pickupLon || (r.pickupCoords && r.pickupCoords.lon)]
                        ]) {
                            if (!addr || !lat || !lon) continue;
                            const key = addr.toLowerCase().trim();
                            if (seen.has(key)) continue;
                            seen.add(key);
                            const matchCount = _fuzzyWordCount(fuzzyWords, key);
                            if (matchCount >= _minRequiredScore) {
                                similarPlaces.push({ name: addr, lat, lon, score: matchCount });
                            }
                        }
                    });
                } catch (e) { console.warn('Fuzzy Buchungs-Suche Fehler:', e.message); }
                // 4. Kunden mit Adressen
                try {
                    const custSnap = await db.ref('customers').once('value');
                    if (custSnap.exists()) {
                        custSnap.forEach(child => {
                            const c = child.val();
                            if (!c.name || !c.address) return;
                            const cName = c.name.toLowerCase();
                            const cAddr = c.address.toLowerCase();
                            const lat = c.lat || c.pickupLat;
                            const lon = c.lon || c.pickupLon;
                            if (!lat || !lon) return;
                            const matchCount = _fuzzyWordCount(fuzzyWords, cName + ' ' + cAddr);
                            if (matchCount >= _minRequiredScore) {
                                similarPlaces.push({ name: `${c.name}, ${c.address}`, lat, lon, score: matchCount });
                            }
                        });
                    }
                } catch (e) { console.warn('Fuzzy Kunden-Suche Fehler:', e.message); }
                // Deduplizieren und sortieren
                const deduped = [];
                for (const p of similarPlaces) {
                    const exists = deduped.some(d => Math.abs(d.lat - p.lat) < 0.001 && Math.abs(d.lon - p.lon) < 0.001);
                    if (!exists) deduped.push(p);
                }
                deduped.sort((a, b) => b.score - a.score);
                const topSimilar = deduped.slice(0, 5);

                if (topSimilar.length > 0) {
                    // Ähnliche Orte gefunden → als Buttons anbieten
                    const simSuggestions = topSimilar.map(p => ({ name: p.name, lat: p.lat, lon: p.lon, source: 'known' }));
                    const shortAddrSim = addressToResolve.length > 28 ? addressToResolve.slice(0, 26) + '…' : addressToResolve;
                    // 🔧 v6.38.34: "So verwenden" ENTFERNT — Adressen MÜSSEN aus Liste gewählt werden!
                    const keyboard = {
                        inline_keyboard: [
                            ...simSuggestions.map((s, i) => [{ text: `${s.source === 'poi' || s.source === 'known' ? '⭐' : s.source === 'customer' ? '👤' : s.source === 'booking' ? '🔁' : '📍'} ${s.name}`, callback_data: `${prefix}_${i}` }]),
                            [{ text: '✏️ Andere Adresse eingeben', callback_data: `addr_retry_${fieldToResolve}` }],
                            [{ text: '❌ Abbrechen', callback_data: 'cancel_booking' }]
                        ]
                    };
                    const pendingState = { partial: { ...booking, missing: [] }, originalText };
                    pendingState.nominatimResults = simSuggestions;
                    pendingState._resolvingField = fieldToResolve; // 🔧 v6.39.0
                    if (hasPickupCoords) { pendingState.partial.pickupLat = booking.pickupLat; pendingState.partial.pickupLon = booking.pickupLon; }
                    if (hasDestCoords) { pendingState.partial.destinationLat = booking.destinationLat; pendingState.partial.destinationLon = booking.destinationLon; }
                    pendingState.pendingDestValidation = (needPickup && needDest);
                    await setPending(chatId, pendingState);

                    await addTelegramLog('🔍', chatId, `${fieldLabel} "${addressToResolve}" → ${topSimilar.length} ähnliche Vorschläge`);
                    await sendTelegramMessage(chatId,
                        `🔍 <b>${fieldLabel}: "${addressToResolve}"</b>\n\n` +
                        `Exakte Adresse nicht gefunden. Meinten Sie vielleicht:`,
                        { reply_markup: keyboard }
                    );
                    return null;
                }

                // 🔧 v6.38.1: Adresse unbekannt → als-ist anbieten + Neu-Eingabe
                // (nicht einfach löschen — die Adresse könnte trotzdem richtig sein, nur Nominatim kennt sie nicht)
                await addTelegramLog('⚠️', chatId, `${fieldLabel} "${addressToResolve}" → nicht in Nominatim/Cache, biete as-is an`);
                if (needPickup) {
                    booking.pickupLat = null; booking.pickupLon = null;
                } else {
                    booking.destinationLat = null; booking.destinationLon = null;
                }
                const pendingForUnknown = { partial: { ...booking, missing: [] }, originalText };
                if (hasPickupCoords) { pendingForUnknown.partial.pickupLat = booking.pickupLat; pendingForUnknown.partial.pickupLon = booking.pickupLon; }
                if (hasDestCoords) { pendingForUnknown.partial.destinationLat = booking.destinationLat; pendingForUnknown.partial.destinationLon = booking.destinationLon; }
                pendingForUnknown.pendingDestValidation = (needPickup && needDest);
                await setPending(chatId, pendingForUnknown);
                // 🔧 v6.38.48: Intelligente Analyse — WAS fehlt an der Adresse?
                const _addr = addressToResolve;
                const _hasStreet = /straße|weg\b|ring\b|allee|chaussee|platz|gasse|damm|steig|pfad|ufer|str\b|str\./i.test(_addr);
                const _hasNr = /\b\d+[a-z]?\b/i.test(_addr.replace(/\b\d{5}\b/g, ''));
                const _hasOrt = _addrHasOrt || _addrHasPlz;

                let _missingHint = '';
                let _missingButtons = [];
                if (_hasStreet && _hasNr && _hasOrt) {
                    // Alles da, aber Nominatim kennt die Adresse nicht → evtl. Tippfehler
                    _missingHint = `Die Adresse scheint vollständig zu sein, wurde aber nicht gefunden.\n\n` +
                        `🔍 <b>Bitte prüfen:</b>\n` +
                        `• Ist der <b>Straßenname</b> richtig geschrieben?\n` +
                        `• Stimmt der <b>Ort</b>? (z.B. Ahlbeck ≠ Heringsdorf)\n` +
                        `• Gibt es die <b>Hausnummer</b> an dieser Straße?`;
                } else if (_hasStreet && !_hasNr && _hasOrt) {
                    _missingHint = `<b>Hausnummer fehlt!</b>\n\nBitte ergänzen Sie die Hausnummer:\n` +
                        `<i>z.B. "${_addr} <b>5</b>"</i>`;
                    _missingButtons.push([{ text: '✏️ Hausnummer ergänzen', callback_data: `addr_retry_${fieldToResolve}` }]);
                } else if (_hasStreet && _hasNr && !_hasOrt) {
                    // Dieser Fall sollte oben schon gefangen werden, aber als Fallback
                    _missingHint = `<b>Ort/PLZ fehlt!</b>\n\nIn welchem Ort ist diese Adresse?`;
                    _missingButtons.push(
                        [{ text: '📍 Heringsdorf', callback_data: `addr_ort_heringsdorf_${fieldToResolve}` },
                         { text: '📍 Ahlbeck', callback_data: `addr_ort_ahlbeck_${fieldToResolve}` },
                         { text: '📍 Bansin', callback_data: `addr_ort_bansin_${fieldToResolve}` }],
                        [{ text: '📍 Zinnowitz', callback_data: `addr_ort_zinnowitz_${fieldToResolve}` },
                         { text: '📍 Koserow', callback_data: `addr_ort_koserow_${fieldToResolve}` },
                         { text: '📍 Trassenheide', callback_data: `addr_ort_trassenheide_${fieldToResolve}` }]
                    );
                } else if (!_hasStreet && _hasOrt) {
                    _missingHint = `<b>Straße fehlt!</b>\n\nBitte geben Sie die Straße + Hausnummer ein:\n` +
                        `<i>z.B. "Strandstraße 5, ${_addr}"</i>`;
                } else if (_hasStreet && !_hasNr && !_hasOrt) {
                    _missingHint = `<b>Hausnummer + Ort fehlen!</b>\n\nBitte vollständig eingeben:\n` +
                        `<i>z.B. "${_addr} 5, Heringsdorf"</i>`;
                } else {
                    _missingHint = `Diese Adresse konnte nicht zugeordnet werden.\n\n` +
                        `💡 <b>So geht's:</b> Straße + Hausnummer + Ort\n` +
                        `<i>z.B. Strandstraße 5, Heringsdorf</i>`;
                }

                const _smartButtons = [
                    ..._missingButtons,
                    [{ text: '📍 GPS-Standort senden', callback_data: `gps_help_${fieldToResolve}` }],
                    [{ text: '✏️ Adresse neu eingeben', callback_data: `addr_retry_${fieldToResolve}` }],
                    [{ text: '📞 Telefonisch: 038378/22022', callback_data: 'cancel_booking' }],
                    [{ text: '❌ Abbrechen', callback_data: 'cancel_booking' }]
                ];

                await addTelegramLog('🧠', chatId, `Intelligente Analyse: Straße=${_hasStreet}, Nr=${_hasNr}, Ort=${_hasOrt} → "${addressToResolve}"`);
                await sendTelegramMessage(chatId,
                    `❌ <b>${fieldLabel}: "${addressToResolve}"</b>\n\n` +
                    _missingHint + `\n\n` +
                    `📍 <b>Alternativ:</b> Senden Sie Ihren <b>GPS-Standort</b> (📎 → Standort)`,
                    { reply_markup: { inline_keyboard: _smartButtons } }
                );
                return null;
            }
        } catch (e) {
            console.warn('Adress-Suche Fehler:', e);
            await addTelegramLog('⚠️', chatId, 'Adress-Suche Fehler: ' + e.message);
        }
    }

    // Beide Adressen haben bereits Koordinaten (GPS, beliebte Ziele, vorherige Auswahl)
    if (hasPickupCoords && hasDestCoords) {
        await addTelegramLog('📍', chatId, `Koordinaten: Pickup(${booking.pickupLat?.toFixed(4)}, ${booking.pickupLon?.toFixed(4)}) → Dest(${booking.destinationLat?.toFixed(4)}, ${booking.destinationLon?.toFixed(4)})`);
        await sendTelegramMessage(chatId, `✅ <b>Adressen verifiziert:</b>\n📍 ${booking.pickup}\n🎯 ${booking.destination}`);
    }
    return booking;
}

