// 🆕 v6.62.793 (Patrick 17.05. 22:38): SMART-AUDIO-PRE-ANALYSE
// Extrahiert aus Audio-Transkript ALLE Felder einer Buchung in EINEM
// KI-Call. Wird VOR dem Customer-Anlage-Dialog aufgerufen — damit
// Patrick nur EINEN Confirm-Klick braucht statt 5-6 Stufen.
// Feature-Flag: /settings/telegram/smartAudioMode (default false).
// ═══════════════════════════════════════════════════════════════
async function extractAudioBookingData(transcript, callerPhone, audioFileName) {
    if (!transcript || transcript.length < 5) return null;
    const apiKey = await getAnthropicApiKey();
    if (!apiKey) return null;
    const _todayDate = new Date().toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin' });
    const _todayTime = new Date().toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });
    // 🆕 v6.62.799 (Patrick 18.05. 09:46): ACR-Dateiname als Name-Hint mitschicken.
    //   Format: 'Ort_Kunden-Name_Strasse_Hausnr_+TelNr_YYYY_MM_DD.m4a' — die ersten Tokens
    //   vor der Telefonnummer sind oft der korrekt geschriebene Kunden-Name. Wenn das Audio
    //   schlecht ist (Verhoerer 'Villa-See-Schleswig-Nord' statt 'Villa Seeschloßchen'),
    //   ist der Dateiname die einzige zuverlaessige Quelle fuer die richtige Namens-Schreibweise.
    let _fileNameHint = '';
    if (audioFileName) {
        const _stem = String(audioFileName).replace(/\.[^.]+$/, '');
        const _beforePhone = _stem.split(/[+\(]\d/)[0].replace(/[_]+$/, '');
        if (_beforePhone && _beforePhone.length > 2) {
            _fileNameHint = `\n\nDATEINAME-HINWEIS: "${audioFileName}" — der Teil vor der Telefonnummer ist oft Ort/Name/Strasse: "${_beforePhone}". Wenn der Name im Transkript unklar ist, bevorzuge die Schreibweise aus dem Dateinamen.`;
        }
    }
    const systemPrompt = `Du bist ein Taxi-Buchungs-Datenextraktor. Aktuelle Zeit in Berlin: ${_todayDate} ${_todayTime}. Anrufer-Telefon: ${callerPhone || 'unbekannt'}.${_fileNameHint}

Analysiere folgendes Anruf-Transkript eines Taxi-Kunden. Extrahiere alle Buchungs-Daten und gib NUR ein JSON-Objekt zurueck (keine Erklaerung davor/danach):

{
  "name": "Name wie der Anrufer sich vorstellt — Vorname, Nachname, 'Herr X', 'Frau Y', oder kompletter Name. NICHT null wenn der Anrufer sich irgendwie vorstellt" (oder null wenn wirklich kein Name im Transkript),
  "mobilPhone": "Mobilnummer im E.164-Format wenn im Gespraech genannt" (oder null),
  "pickup": "Abholadresse — moeglichst genau mit Ort. POI-Namen wie Hotel/Restaurant als Pickup akzeptieren" (oder null),
  "destination": "Zieladresse" (oder null),
  "pickupTimestamp": "absoluter Unix-Timestamp ms wann Abholung sein soll" (oder null),
  "pickupTimeReadable": "menschenlesbare Zeit z.B. 'morgen 12:00' oder 'in 10 Minuten'" (oder null),
  "passengers": Personenzahl als Nummer (oder null),
  "gepaeck": true wenn Gepaeck erwaehnt sonst false,
  "wagentyp": "klein"/"gross"/null je nach 'normales Taxi' vs 'Grossraumtaxi/Bus',
  "tourType": "einfach"/"hin_und_zurueck"/null,
  "festpreisEUR": Festpreis in Euro wenn explizit ausgemacht (oder null),
  "notes": "Sonstige relevante Info (Stamm-Bahnhof, Flugnummer, Gehbehinderung etc.)",
  "customerKind": "hotel"/"firma"/"klinik"/"gelegenheitskunde" — Kunden-Typ aus dem Namen (siehe Regel unten),
  "guestName": "Name des Fahrgastes wenn der Anrufer FÜR einen Anderen bucht (typisch bei Hotels: 'für Gast Müller', 'Familie Schmidt steigt um 10 ein') — sonst null",
  "confidence": "high"/"medium"/"low" basierend auf wie klar alle Felder im Transkript waren
}

Regeln:
- "morgen 12:00" → pickupTimestamp = morgen 12:00 Berlin-Zeit als Unix-Timestamp ms
- "in 10 Minuten" → jetzt + 10*60*1000 ms
- "Bansindorf" → "Bansin Dorf" (Bansin-Ortsteil)
- "Melntin" → "Mellenthin"
- POI-Namen wie "Fischers Fritz", "Wald und See" als pickup beibehalten (nicht zu Adresse zwingen)
- Wenn Personenzahl >= 5 → wagentyp "gross"
- "Hin und zurueck" mit Wartezeit → tourType "hin_und_zurueck"
- customerKind-Auto-Erkennung aus dem Namen:
  • "hotel" — wenn Name "Hotel", "Villa", "Pension", "Residenz", "Strandhotel", "Garni", "Aja", "Seetel", "Maritim", "Steigenberger", "Travel Charme" oder ähnliche Beherbergung enthält
  • "klinik" — wenn Name "Klinik", "Reha", "Rehabilitation", "Praxis", "Arzt", "Doktor", "Krankenhaus"
  • "firma" — wenn Name "GmbH", "OHG", "AG", "Gewerbe", "Werkstatt" oder klar gewerblicher Lieferant
  • "gelegenheitskunde" — Default fuer Privatkunden (Personen-Name ohne Firmen-/Hotel-Bezeichnung)
- guestName-Erkennung: typisch bei Hotel-Anrufen ("Familie Endress um 14 Uhr", "Herr Müller braucht ein Taxi"). Wenn der Anrufer einen ANDEREN Namen als sich selbst nennt → guestName, NICHT name. Bei Privat-Anrufen meistens null.

NUR JSON, keine Erklaerung.`;
    try {
        const resp = await callAnthropicAPI(apiKey, 'claude-sonnet-4-6', 1500, [
            { role: 'user', content: systemPrompt + '\n\nTRANSKRIPT:\n' + transcript }
        ]);
        const txt = (resp?.content?.[0]?.text || '').trim();
        // JSON aus Antwort extrahieren (KI baut manchmal Backticks)
        const jsonMatch = txt.match(/\{[\s\S]*\}/);
        if (!jsonMatch) return null;
        const data = JSON.parse(jsonMatch[0]);
        return data;
    } catch (e) {
        console.error('extractAudioBookingData Fehler:', e.message);
        return null;
    }
}

// Smart-Audio-Confirm-Karte zeigen (1-Klick-Anlage von Customer + Ride)
async function showSmartAudioConfirmCard(chatId, extracted, callerPhone, originalText, userName) {
    const tokenId = Date.now().toString(36);
    // Pending speichern: bei Confirm-Klick werden Customer + Ride angelegt
    await setPending(chatId, {
        _smartAudioPending: true,
        _smartAudio: { extracted, callerPhone, originalText, userName },
        tokenId
    });
    let msg = `🎙️ <b>Smart-Audio-Analyse</b>\n<i>(KI hat alles aus dem Transkript extrahiert)</i>\n\n`;
    msg += `👤 Name: <b>${extracted.name || '?'}</b>\n`;
    // 🆕 v6.62.800 (Patrick 18.05. 11:37): Kunden-Typ anzeigen — KI erkennt jetzt
    //   hotel/firma/klinik/gelegenheitskunde. Zeigt Patrick was beim Anlegen passiert.
    if (extracted.customerKind) {
        const _kindLabels = { hotel: '🏨 Hotel', firma: '🏢 Firma', klinik: '🏥 Klinik', gelegenheitskunde: '🏠 Privat', stammkunde: '⭐ Stammkunde' };
        msg += `${_kindLabels[String(extracted.customerKind).toLowerCase()] || ('🏷️ ' + extracted.customerKind)}\n`;
    }
    // 🆕 v6.62.801 (Patrick 18.05. 11:37): Gastname-Feld bei Hotel/Auftraggeber-Anrufen
    //   wenn KI einen anderen Namen als den Anrufer erkennt. Wird beim Anlegen als
    //   ride.guestName gespeichert.
    if (extracted.guestName) msg += `🧳 Gast: <b>${extracted.guestName}</b>\n`;
    // 🔧 v6.62.794: Mobil-Erkennung — wenn Phone startet mit 015/016/017 oder +49 15/16/17 → Mobil-Label
    const _phoneClean = String(callerPhone || '').replace(/[^0-9+]/g, '');
    const _isMobile = /^(\+49(15|16|17)|0(15|16|17))/.test(_phoneClean);
    msg += `${_isMobile ? '📱 Mobil' : '☎️ Festnetz'}: ${callerPhone}\n`;
    if (extracted.mobilPhone && extracted.mobilPhone !== callerPhone) msg += `📱 Weitere Mobil: ${extracted.mobilPhone}\n`;
    msg += `\n📍 Von: <b>${extracted.pickup || '?'}</b>\n`;
    msg += `🎯 Nach: <b>${extracted.destination || '?'}</b>\n`;
    if (extracted.pickupTimeReadable) msg += `🕐 Zeit: <b>${extracted.pickupTimeReadable}</b>\n`;
    if (extracted.passengers) msg += `👥 Personen: <b>${extracted.passengers}</b>${extracted.gepaeck ? ' + Gepäck' : ''}\n`;
    if (extracted.wagentyp === 'gross') msg += `🚐 Großraumtaxi\n`;
    if (extracted.tourType === 'hin_und_zurueck') msg += `🔄 Hin und zurück\n`;
    if (extracted.festpreisEUR) msg += `💰 Festpreis: ${extracted.festpreisEUR}€\n`;
    if (extracted.notes) msg += `📝 ${extracted.notes}\n`;
    msg += `\nKonfidenz: <b>${extracted.confidence || '?'}</b>`;
    const hasAll = extracted.name && extracted.pickup && extracted.destination && extracted.pickupTimestamp;
    const hasMost = (extracted.pickup && extracted.destination); // Pickup + Ziel = Minimum fuer Anlage
    const buttons = [];
    if (hasAll) {
        buttons.push([{ text: '✅ KOMPLETT anlegen + buchen', callback_data: `smart_audio_confirm_${tokenId}` }]);
    } else {
        const _missing = [
            !extracted.name && 'Name',
            !extracted.pickup && 'Pickup',
            !extracted.destination && 'Ziel',
            !extracted.pickupTimestamp && 'Zeit',
            !extracted.passengers && 'Personenzahl'
        ].filter(Boolean);
        msg += `\n\n⚠️ <i>Fehlt: ${_missing.join(', ')}</i>`;
        // 🔧 v6.62.794: Wenn zumindest Pickup+Ziel da → trotzdem Anlage anbieten,
        // Restfragen werden nach Confirm gestellt (statt komplett zurueck zum 5-Klick-Flow)
        if (hasMost) {
            buttons.push([{ text: '✅ Anlegen mit Defaults + Restfragen', callback_data: `smart_audio_confirm_${tokenId}` }]);
        }
        buttons.push([{ text: '🔄 Klassischer Flow (alle Fragen)', callback_data: `smart_audio_fallback_${tokenId}` }]);
    }
    // 🆕 v6.62.799/822 (Patrick 18.05. + 19.05. 09:40): Felder einzeln aenderbar
    //   via Sub-Menue 'Ändern' statt nur Name. Patrick: "wenn ich auf ändern klicke,
    //   dass da ein Menü kommt, was möchtest du ändern".
    buttons.push([{ text: '✏️ Felder ändern', callback_data: `smart_audio_edit_menu_${tokenId}` }]);
    buttons.push([{ text: '🔄 Klassisch (5-Klick Flow)', callback_data: `smart_audio_fallback_${tokenId}` }]);
    buttons.push([{ text: '❌ Abbrechen', callback_data: 'cancel_booking' }]);
    await sendTelegramMessage(chatId, msg, { reply_markup: { inline_keyboard: buttons } });
}


