    hotel:            { keywords: ['hotel', 'pension', 'unterkunft', 'übernachtung', 'ferienwohnung'], label: 'Hotel' },
    bahnhof:          { keywords: ['bahnhof', 'bahn', 'zug', 'zugfahrt', 'gleis'], label: 'Bahnhof' },
