// BELIEBTE ZIELE (Kundenhistorie)
// ═══════════════════════════════════════════════════════════════

async function getCustomerFavoriteDestinations(customerName, customerPhone, customerId) {
    try {
        // 🔧 v6.38.19: Suche nach Name + Nachname + Telefon + customerId (parallel)
        const queries = [
            db.ref('rides').orderByChild('customerName').equalTo(customerName).limitToLast(200).once('value')
        ];
        // Nachname extrahieren: "Frau Strömig" → auch nach "Strömig" suchen
        const _nameParts = customerName.split(/\s+/);
        if (_nameParts.length > 1) {
            const _lastName = _nameParts[_nameParts.length - 1];
            queries.push(db.ref('rides').orderByChild('customerName').equalTo(_lastName).limitToLast(100).once('value'));
            // Auch "Vorname Nachname" Variante: "Stephanie Strömig"
            if (_nameParts[0].toLowerCase() !== 'herr' && _nameParts[0].toLowerCase() !== 'frau') {
                queries.push(db.ref('rides').orderByChild('customerName').equalTo(_nameParts[0] + ' ' + _lastName).limitToLast(100).once('value'));
            }
        }
        if (customerPhone) {
            // 🔧 v6.38.27: Mehrere Telefon-Formate suchen (Firebase braucht exakte Übereinstimmung)
            const _cleanPhone = customerPhone.replace(/[\s\-\(\)\/]/g, '');
            const _phoneVariants = new Set([_cleanPhone]);
            // +49... → 0... und umgekehrt
            if (_cleanPhone.startsWith('+49')) _phoneVariants.add('0' + _cleanPhone.slice(3));
            if (_cleanPhone.startsWith('0') && !_cleanPhone.startsWith('00')) _phoneVariants.add('+49' + _cleanPhone.slice(1));
            // Mit Leerzeichen nach Vorwahl: +49 178...
            if (_cleanPhone.startsWith('+49') && _cleanPhone.length > 5) _phoneVariants.add('+49 ' + _cleanPhone.slice(3));
            if (_cleanPhone.startsWith('0') && _cleanPhone.length > 4) _phoneVariants.add(_cleanPhone.slice(0, 4) + ' ' + _cleanPhone.slice(4));
            for (const variant of _phoneVariants) {
                queries.push(db.ref('rides').orderByChild('customerPhone').equalTo(variant).limitToLast(100).once('value'));
                queries.push(db.ref('rides').orderByChild('customerMobile').equalTo(variant).limitToLast(100).once('value'));
            }
        }
        if (customerId) {
            queries.push(db.ref('rides').orderByChild('customerId').equalTo(customerId).limitToLast(100).once('value'));
        }
        const snaps = await Promise.all(queries);

        const destCount = {};
        const destDetails = {};
        const _seenRides = new Set(); // 🔧 v6.38.27: Duplikate verhindern

        // 🔧 v6.38.48: Adress-Normalisierung — gleiche Orte zusammenfassen
        const _normalizeAddr = (addr) => {
            if (!addr) return '';
            let n = addr.toLowerCase().trim();
            n = n.replace(/\b\d{5}\b/g, '');               // PLZ entfernen
            n = n.replace(/straße|str\.|str$/gi, 'str');    // Straße vereinheitlichen
            n = n.replace(/[,.\-\/]/g, ' ');                // Satzzeichen → Leerzeichen
            n = n.replace(/\s+/g, ' ').trim();              // Mehrfach-Leerzeichen
            return n;
        };

        // 🔧 v6.38.50 BUG-17 FIX: Koordinaten auf ~11m runden (toFixed(4) statt toFixed(3))
        const _coordKey = (lat, lon) => {
            if (!lat || !lon) return null;
            return `${parseFloat(lat).toFixed(4)}_${parseFloat(lon).toFixed(4)}`;
        };
        const _coordToNormKey = {}; // coordKey → normKey Mapping für Zusammenführung

        const _processRide = (r, rideKey) => {
            if (!r.destination || r.status === 'cancelled' || r.status === 'storniert' || r.status === 'deleted') return;
            // Deduplizierung: gleiche Fahrt kann über Name + Telefon doppelt gefunden werden
            const _rideFingerprint = rideKey || (r.pickupTimestamp + '_' + (r.customerName || '') + '_' + (r.destination || ''));
            if (_seenRides.has(_rideFingerprint)) return;
            _seenRides.add(_rideFingerprint);
            const dest = r.destination.trim();
            const lat = r.destinationLat || null;
            const lon = r.destinationLon || null;

            // Normalisierter Key für Textvergleich
            let normKey = _normalizeAddr(dest);

            // Koordinaten-basierte Zusammenführung: gleiche Koordinaten = gleicher Ort
            const ck = _coordKey(lat, lon);
            if (ck && _coordToNormKey[ck]) {
                normKey = _coordToNormKey[ck]; // Verwende den existierenden Key
            } else if (ck) {
                _coordToNormKey[ck] = normKey;
            }

            destCount[normKey] = (destCount[normKey] || 0) + 1;
            if (!destDetails[normKey]) {
                destDetails[normKey] = { name: dest, lat, lon, names: [dest] };
            } else {
                // Längsten/vollständigsten Namen behalten
                if (!destDetails[normKey].names.includes(dest)) destDetails[normKey].names.push(dest);
                if (dest.length > destDetails[normKey].name.length) destDetails[normKey].name = dest;
            }
            if (!destDetails[normKey].lastPickup && r.pickup) {
                destDetails[normKey].lastPickup = r.pickup;
                destDetails[normKey].pickupLat = r.pickupLat || null;
                destDetails[normKey].pickupLon = r.pickupLon || null;
            }
        };
        for (const snap of snaps) {
            if (snap.exists()) snap.forEach(child => _processRide(child.val(), child.key));
        }

        // 🔧 v6.38.48: Kundennamen aus Adressen entfernen (z.B. "Marion, Dorf Bansin 8d")
        for (const key of Object.keys(destDetails)) {
            const d = destDetails[key];
            // Prüfe ob Adresse mit Kundenname beginnt (z.B. "Marion, ...")
            const _commaMatch = d.name.match(/^([^,]+),\s*(.+)$/);
            if (_commaMatch) {
                const _firstPart = _commaMatch[1].trim();
                const _rest = _commaMatch[2].trim();
                // 🔧 v6.38.50 BUG-18 FIX: Mehr Orts-Keywords + nur echte Personennamen entfernen
                const _isStreetOrPlace = /straße|str\.|weg\b|ring\b|allee|platz|gasse|damm|dorf|bahnhof|hotel|pension|villa|haus\b|kurhaus|café|cafe|restaurant|klinik|praxis|markt|kirche|schule|zum\b|zur\b|am\b|seebrücke|flughafen|\d/i.test(_firstPart);
                // Nur entfernen wenn: kein Ort-Keyword UND sieht aus wie ein einzelner Vorname (< 20 Zeichen, ein Wort)
                if (!_isStreetOrPlace && _firstPart.length < 20 && /^[A-ZÄÖÜ][a-zäöüß]+$/.test(_firstPart.trim())) {
                    d.name = _rest; // "Marion, Dorf Bansin 8d" → "Dorf Bansin 8d"
                }
            }
        }

        // Sortiere nach Häufigkeit, max 5 Ziele
        return Object.entries(destCount)
            .sort((a, b) => b[1] - a[1])
            .slice(0, 5)
            .map(([key, count]) => ({
                destination: destDetails[key].name,
                destinationLat: destDetails[key].lat,
                destinationLon: destDetails[key].lon,
                lastPickup: destDetails[key].lastPickup,
                pickupLat: destDetails[key].pickupLat,
                pickupLon: destDetails[key].pickupLon,
                count
            }));
    } catch (e) {
        console.warn('getCustomerFavoriteDestinations:', e.message);
        return [];
    }
}

