// 🆕 v6.38.0: FOTO/SCREENSHOT-HANDLER — Claude Vision OCR + Analyse
// Foto senden → Text erkennen → Termin oder CRM-Kontakt anlegen
// ═══════════════════════════════════════════════════════════════

function _buildBookingText(booking) {
    if (!booking) return '';
    return [
        booking.datetime && `Zeit: ${booking.datetime}`,
        booking.name && `Name: ${booking.name}`,
        booking.phone && `Tel: ${booking.phone}`,
        booking.pickup && `Von: ${booking.pickup}`,
        booking.destination && `Nach: ${booking.destination}`,
        booking.passengers && booking.passengers > 1 && `Personen: ${booking.passengers}`,
        booking.notes && `Hinweis: ${booking.notes}`,
    ].filter(Boolean).join('\n');
}

async function handlePhoto(message) {
    const chatId = message.chat.id;
    const photos = message.photo;
    const caption = message.caption || '';

    if (!photos || photos.length === 0) {
        await sendTelegramMessage(chatId, '⚠️ Bild konnte nicht verarbeitet werden.');
        return;
    }

    const isAdmin = await isTelegramAdmin(chatId);

    try {
        // 1. Anthropic API Key prüfen
        const anthropicKey = await getAnthropicApiKey();
        if (!anthropicKey) {
            await addTelegramLog('⚠️', chatId, 'Foto empfangen, aber kein Anthropic API Key');
            await sendTelegramMessage(chatId, '⚠️ Bildanalyse nicht konfiguriert.\nBitte Anfrage als Text oder Sprachnachricht senden.');
            return;
        }

        await sendTelegramMessage(chatId, '🖼️ <i>Screenshot wird analysiert...</i>');

        // 2. Höchste Auflösung wählen (letztes Element = größtes Bild)
        const bestPhoto = photos[photos.length - 1];

        // 3. Datei von Telegram holen
        const token = await loadBotToken();
        const fileResp = await fetch(`https://api.telegram.org/bot${token}/getFile`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ file_id: bestPhoto.file_id })
        });
        const fileData = await fileResp.json();
        if (!fileData.ok || !fileData.result?.file_path) {
            await sendTelegramMessage(chatId, '⚠️ Bild konnte nicht geladen werden.');
            return;
        }

        // 4. Bild herunterladen + Base64 konvertieren
        const fileUrl = `https://api.telegram.org/file/bot${token}/${fileData.result.file_path}`;
        const imgResp = await fetch(fileUrl);
        if (!imgResp.ok) {
            await sendTelegramMessage(chatId, '⚠️ Bild-Download fehlgeschlagen.');
            return;
        }
        const base64 = Buffer.from(await imgResp.arrayBuffer()).toString('base64');
        const filePath = fileData.result.file_path || '';
        const mediaType = filePath.endsWith('.png') ? 'image/png' :
                          filePath.endsWith('.webp') ? 'image/webp' : 'image/jpeg';

        // 5. Claude Vision — Text + Typ erkennen
        const prompt = `Du bist ein Assistent für ein Taxi-Unternehmen auf Usedom (Heringsdorf, Ahlbeck, Bansin, Zinnowitz, Wolgast).
${caption ? `Zusatz-Text des Senders: "${caption}"\n` : ''}
Analysiere dieses Bild. Lies ALLEN sichtbaren Text und bestimme ob es eine Buchung/Termin oder ein Kontakt ist.

Antworte NUR mit diesem JSON (kein anderer Text):
{
  "type": "booking" | "contact" | "both" | "unknown",
  "extractedText": "Gesamter sichtbarer Text aus dem Bild",
  "booking": {
    "name": null,
    "phone": null,
    "email": null,
    "pickup": null,
    "destination": null,
    "datetime": null,
    "passengers": 1,
    "notes": null
  },
  "contact": {
    "name": null,
    "phone": null,
    "mobile": null,
    "address": null,
    "email": null,
    "company": null,
    "notes": null
  },
  "confidence": "high" | "medium" | "low",
  "summary": "Kurze Zusammenfassung was erkannt wurde (1 Satz)"
}

Regeln:
- "booking": enthält Datum/Uhrzeit + Adresse/Ort (Taxi-Fahrt, Termin, Buchungsbestätigung)
- "contact": enthält Name + Telefon/Adresse (Visitenkarte, Kontaktliste, WhatsApp-Profil)
- "both": beides erkennbar
- "unknown": keine verwertbaren Daten (Foto, Landschaft etc.)
- Unbekannte Felder als null lassen`;

        const visionResp = await callAnthropicAPI(anthropicKey, 'claude-haiku-4-5-20251001', 1024, [{
            role: 'user',
            content: [
                { type: 'image', source: { type: 'base64', media_type: mediaType, data: base64 } },
                { type: 'text', text: prompt }
            ]
        }]);

        const rawText = (visionResp.content?.[0]?.text || '').trim();
        await addTelegramLog('📷', chatId, `Foto-Analyse: ${rawText.substring(0, 120)}`);

        // 6. JSON parsen
        let analysis;
        try {
            const jsonMatch = rawText.match(/\{[\s\S]*\}/);
            analysis = JSON.parse(jsonMatch ? jsonMatch[0] : rawText);
        } catch (e) {
            // Fallback: Rohtext als Buchungstext verwenden
            await addTelegramLog('⚠️', chatId, `Foto JSON-Fehler, Fallback auf Rohtext: ${e.message}`);
            if (rawText.length > 10) {
                await sendTelegramMessage(chatId, `📷 <b>Text erkannt:</b>\n<i>"${rawText.substring(0, 300)}"</i>\n\n⏳ Wird als Buchung verarbeitet...`);
                const fakeMsg = { chat: { id: chatId }, from: message.from, text: rawText, _isPhotoTranscript: true };
                await handleMessage(fakeMsg);
            } else {
                await sendTelegramMessage(chatId, '⚠️ Konnte keinen Text aus dem Bild lesen. Bitte bessere Beleuchtung oder schärferes Bild versuchen.');
            }
            return;
        }

        const { type, extractedText, booking, contact, confidence, summary } = analysis;

        // 7. Wenn nichts erkannt
        if (type === 'unknown' || (!extractedText && !booking?.name && !contact?.name)) {
            await sendTelegramMessage(chatId, `🖼️ <b>Bild analysiert</b>\n\n${summary || 'Keine verwertbaren Informationen gefunden.'}\n\n💡 Tipp: Screenshot von WhatsApp-Nachricht, Buchungsformular oder Visitenkarte senden.`);
            return;
        }

        // 8. Zusammenfassung aufbauen
        let infoMsg = `📷 <b>Erkannt (${confidence || 'medium'}):</b> ${summary || type}\n\n`;
        if (type === 'booking' || type === 'both') {
            if (booking?.datetime) infoMsg += `🕐 ${booking.datetime}\n`;
            if (booking?.name) infoMsg += `👤 ${booking.name}\n`;
            if (booking?.phone) infoMsg += `📱 ${booking.phone}\n`;
            if (booking?.pickup) infoMsg += `📍 Von: ${booking.pickup}\n`;
            if (booking?.destination) infoMsg += `🎯 Nach: ${booking.destination}\n`;
            if (booking?.passengers && booking.passengers > 1) infoMsg += `👥 ${booking.passengers} Personen\n`;
        }
        if (type === 'contact' || type === 'both') {
            if (contact?.name) infoMsg += `👤 ${contact.name}\n`;
            if (contact?.company) infoMsg += `🏢 ${contact.company}\n`;
            if (contact?.mobile) infoMsg += `📱 ${contact.mobile}\n`;
            if (contact?.phone) infoMsg += `☎️ ${contact.phone}\n`;
            if (contact?.address) infoMsg += `📍 ${contact.address}\n`;
            if (contact?.email) infoMsg += `✉️ ${contact.email}\n`;
        }
        infoMsg += '\nWas soll ich tun?';

        // 9. Inline-Buttons je nach Typ + Admin-Status
        const buttons = [];
        if (type === 'booking' || type === 'both') {
            buttons.push({ text: '📋 Als Buchung anlegen', callback_data: 'photo_action_booking' });
        }
        if ((type === 'contact' || type === 'both') && isAdmin) {
            buttons.push({ text: '👤 Im CRM speichern', callback_data: 'photo_action_contact' });
        }
        if (type === 'unknown' || (!buttons.length && extractedText)) {
            buttons.push({ text: '📋 Als Buchung versuchen', callback_data: 'photo_action_booking' });
        }
        buttons.push({ text: '❌ Abbrechen', callback_data: 'photo_action_cancel' });

        // 10. Analyse in Pending speichern (60 Minuten)
        await setPending(chatId, {
            _photoAnalysis: { type, extractedText, booking, contact, summary },
            _createdAt: Date.now()
        });

        await sendTelegramMessage(chatId, infoMsg, {
            reply_markup: { inline_keyboard: [buttons] }
        });

    } catch (error) {
        console.error('handlePhoto Fehler:', error);
        await addTelegramLog('❌', chatId, `Foto-Fehler: ${error.message}`);
        await sendTelegramMessage(chatId, '⚠️ Fehler bei der Bildanalyse: ' + error.message);
    }
}

async function handleLocation(message) {
    const chatId = message.chat.id;
    const lat = message.location.latitude;
    const lon = message.location.longitude;
    const userName = message.from?.first_name || 'Unbekannt';

    await addTelegramLog('📍', chatId, `GPS-Standort empfangen: ${lat.toFixed(5)}, ${lon.toFixed(5)}`);

    // Reverse-Geocoding: Koordinaten → Adresse
    let addressName = `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
    const reversed = await reverseGeocode(lat, lon);
    // 🔧 v6.38.56: reverseGeocode gibt .name zurück (Duplikat-Version entfernt)
    if (reversed && reversed.name) {
        addressName = reversed.name;
        await addTelegramLog('📍', chatId, `Reverse-Geocoding: ${addressName}`);
    }

    // 🆕 v6.11.5: Prüfe ob Neukunden-Adress-Schritt aktiv → Standort als Kundenadresse übernehmen
    const pending = await getPending(chatId);

    // 🔧 v6.26.0: Admin bearbeitet Fahrt-Adresse → GPS direkt als neue Adresse übernehmen
    if (pending && pending._adminEditRide && pending._adminEditField) {
        const rideId = pending._adminEditRide;
        const field = pending._adminEditField;
        const label = field === 'pickup' ? 'Abholort' : 'Zielort';
        await deletePending(chatId);
        await addTelegramLog('📍', chatId, `GPS als ${label} für Fahrt ${rideId}: ${addressName}`);
        await applyAdminAddressChange(chatId, rideId, field, addressName, { lat, lon });
        return;
    }

    if (pending && pending._adminNewCust && (pending._adminNewCustStep === 'address' || pending._adminNewCustStep === 'address_select')) {
        await addTelegramLog('📍', chatId, `GPS-Standort als Kundenadresse: ${addressName} (${lat.toFixed(5)}, ${lon.toFixed(5)})`);

        // 🔧 v6.38.45: GPS = exakte Position. KEINE Nominatim-Vorwärtssuche!
        // Nur Reverse-Geocoding Adresse + nahegelegene CRM/Geocache-Adressen (< 200m)
        const GPS_RADIUS_KM = 0.2; // 200 Meter — GPS ist auf den Meter genau
        const nearbyAddresses = [];
        const seenAddrs = new Set();

        // Reverse-Geocoding Adresse als Hauptvorschlag
        nearbyAddresses.push({ name: addressName, lat, lon, source: 'gps-reverse' });
        seenAddrs.add(addressName.toLowerCase().trim());

        // Nur CRM-Kunden und Geocache im Umkreis von 200m prüfen — KEIN Nominatim!
        try {
            const [geocacheSnap, custSnap] = await Promise.all([
                db.ref('geocache').once('value'),
                db.ref('customers').once('value')
            ]);
            // Geocache: gespeicherte Adressen in der Nähe
            if (geocacheSnap.exists()) {
                geocacheSnap.forEach(child => {
                    const e = child.val();
                    if (!e.address || !e.lat || !e.lon) return;
                    const dist = distanceKm(lat, lon, parseFloat(e.lat), parseFloat(e.lon));
                    if (dist <= GPS_RADIUS_KM && !seenAddrs.has(e.address.toLowerCase().trim())) {
                        seenAddrs.add(e.address.toLowerCase().trim());
                        nearbyAddresses.push({ name: e.address, lat: e.lat, lon: e.lon, source: 'geocache' });
                    }
                });
            }
            // CRM: Kunden-Adressen in der Nähe
            if (custSnap.exists()) {
                custSnap.forEach(child => {
                    const c = child.val();
                    if (!c.address || !c.lat || !c.lon) return;
                    const dist = distanceKm(lat, lon, parseFloat(c.lat), parseFloat(c.lon));
                    if (dist <= GPS_RADIUS_KM && !seenAddrs.has(c.address.toLowerCase().trim())) {
                        seenAddrs.add(c.address.toLowerCase().trim());
                        nearbyAddresses.push({ name: `${c.name}: ${c.address}`, lat: c.lat, lon: c.lon, source: 'customer' });
                    }
                });
            }
        } catch (e) { console.warn('GPS-Nearby-Suche Fehler:', e.message); }

        console.log(`📍 GPS-Adressvorschläge: ${nearbyAddresses.length} im Umkreis von ${GPS_RADIUS_KM * 1000}m`);
        const confirmId = Date.now().toString(36);

        if (nearbyAddresses.length > 1) {
            // Mehrere Adressen in der Nähe → Auswahl anbieten
            const keyboard = nearbyAddresses.map((s, i) => [{ text: `${s.source === 'customer' ? '👤' : s.source === 'geocache' ? '💾' : '📍'} ${s.name}`, callback_data: `admin_newcust_adr_${i}_${confirmId}` }]);
            keyboard.push([{ text: '✏️ Andere Adresse eingeben', callback_data: `admin_newcust_addr_retry_${confirmId}` }]);

            await setPending(chatId, {
                ...pending,
                _adminNewCustStep: 'address_select',
                _adminNewCustAddr: addressName,
                _adminNewCustAddrLat: lat,
                _adminNewCustAddrLon: lon,
                _adminNewCustSuggestions: nearbyAddresses,
                _addrConfirmId: confirmId
            });
            await sendTelegramMessage(chatId,
                `📍 <b>GPS-Standort erkannt:</b>\n🏠 ${addressName}\n\nBitte wähle die richtige Adresse:`, {
                reply_markup: { inline_keyboard: keyboard }
            });
        } else {
            // Nur eine Adresse (die Reverse-Geocoding Adresse) → direkt weiter zur Kundenart
            await setPending(chatId, {
                ...pending,
                _adminNewCustStep: 'customerKind',
                _adminNewCustAddr: addressName,
                _adminNewCustAddrLat: lat,
                _adminNewCustAddrLon: lon
            });
            await sendTelegramMessage(chatId,
                `🏷️ <b>Kundenart festlegen</b>\n\n👤 <b>${pending._adminNewCustName}</b>\n📍 ${addressName}\n\nIst das die <b>Wohnanschrift</b> oder nur eine <b>Abholadresse</b>?`, {
                reply_markup: { inline_keyboard: [
                    [{ text: '🏠 Wohnanschrift (Stammkunde)', callback_data: 'admin_newcust_kind_stamm' }],
                    [{ text: '📍 Nur Abholadresse (Gelegenheitskunde)', callback_data: 'admin_newcust_kind_gelegenheit' }],
                    [{ text: '🏨 Hotel / Pension (bucht für Gäste)', callback_data: 'admin_newcust_kind_hotel' }],
                    [{ text: '🏢 Firma (Klinik/bucht für Andere)', callback_data: 'admin_newcust_kind_firma' }]
                ] }
            });
        }
        return;
    }

    // 🔧 v6.15.8: Laufende Buchung → prüfe was fehlt
    if (pending) {
        const booking = pending.booking || pending.partial;
        if (booking) {
            const missingPickup = !booking.pickup || (booking.missing && booking.missing.includes('pickup'));
            const missingDest = !booking.destination || (booking.missing && booking.missing.includes('destination'));

            // Nur Abholort fehlt → direkt als Abholort setzen + Geocache-Frage
            if (missingPickup && !missingDest) {
                booking.pickup = addressName;
                booking.pickupLat = lat;
                booking.pickupLon = lon;
                if (booking.missing) booking.missing = booking.missing.filter(m => m !== 'pickup');
                await sendTelegramMessage(chatId, `📍 <b>Abholort per GPS gesetzt:</b>\n🏠 ${addressName}`);
                // 🆕 v6.38.15: Geocache-Frage stellen (pausiert Buchungsfluss bis Ja/Nein)
                const _gcUpdated = { ...pending, _awaitingGeocache: true, _geocacheLat: lat, _geocacheLon: lon, _geocacheAddr: addressName };
                if (pending.partial) _gcUpdated.partial = booking; else _gcUpdated.booking = booking;
                await setPending(chatId, _gcUpdated);
                await sendTelegramMessage(chatId,
                    `💾 <b>Adresse im Geocache speichern?</b>\n📍 ${addressName}\n\n<i>Gespeicherte Adressen werden beim nächsten Mal bevorzugt angezeigt.</i>`, {
                    reply_markup: { inline_keyboard: [
                        [{ text: '✅ Ja, speichern', callback_data: `geocache_save_${lat.toFixed(5)}_${lon.toFixed(5)}` },
                         { text: '❌ Nein', callback_data: 'geocache_skip' }]
                    ] }
                });
                return;
            }

            // Nur Zielort fehlt → direkt als Zielort setzen + Geocache-Frage
            if (!missingPickup && missingDest) {
                booking.destination = addressName;
                booking.destinationLat = lat;
                booking.destinationLon = lon;
                if (booking.missing) booking.missing = booking.missing.filter(m => m !== 'destination');
                await sendTelegramMessage(chatId, `📍 <b>Zielort per GPS gesetzt:</b>\n🎯 ${addressName}`);
                // 🆕 v6.38.15: Geocache-Frage stellen (pausiert Buchungsfluss bis Ja/Nein)
                const _gcUpdated2 = { ...pending, _awaitingGeocache: true, _geocacheLat: lat, _geocacheLon: lon, _geocacheAddr: addressName };
                if (pending.partial) _gcUpdated2.partial = booking; else _gcUpdated2.booking = booking;
                await setPending(chatId, _gcUpdated2);
                await sendTelegramMessage(chatId,
                    `💾 <b>Adresse im Geocache speichern?</b>\n📍 ${addressName}\n\n<i>Gespeicherte Adressen werden beim nächsten Mal bevorzugt angezeigt.</i>`, {
                    reply_markup: { inline_keyboard: [
                        [{ text: '✅ Ja, speichern', callback_data: `geocache_save_${lat.toFixed(5)}_${lon.toFixed(5)}` },
                         { text: '❌ Nein', callback_data: 'geocache_skip' }]
                    ] }
                });
                return;
            }

            // Beides fehlt oder beides schon da → Fragen: Abholort oder Zielort?
            await setPending(chatId, {
                ...pending,
                _gpsChoice: { addressName, lat, lon }
            });
            await sendTelegramMessage(chatId,
                `📍 <b>Standort empfangen:</b>\n🏠 ${addressName}\n\n❓ <b>Ist das der Abholort oder der Zielort?</b>`, {
                reply_markup: { inline_keyboard: [
                    [{ text: '📍 Abholort', callback_data: 'gps_set_pickup' }, { text: '🎯 Zielort', callback_data: 'gps_set_dest' }],
                    [{ text: '❌ Abbrechen', callback_data: 'cancel_booking' }]
                ] }
            });
            return;
        }
    }

    // 🔧 v6.16.1: Neukunden-Anlage aktiv → GPS als Kundenadresse behandeln (Race-Condition-Schutz)
    // Erneuter Check nötig, weil pending sich zwischen erstem Check und hier geändert haben kann
    const pendingRecheck = await getPending(chatId);
    if (pendingRecheck && pendingRecheck._adminNewCust && (pendingRecheck._adminNewCustStep === 'address' || pendingRecheck._adminNewCustStep === 'address_select')) {
        await addTelegramLog('📍', chatId, `GPS-Standort als Kundenadresse übernommen (Recheck): ${addressName}`);
        const confirmId = Date.now().toString(36);
        await setPending(chatId, {
            ...pendingRecheck,
            _adminNewCustStep: 'customerKind',
            _adminNewCustAddr: addressName,
            _adminNewCustAddrLat: lat,
            _adminNewCustAddrLon: lon
        });
        await sendTelegramMessage(chatId,
            `🏷️ <b>Kundenart festlegen</b>\n\n👤 <b>${pendingRecheck._adminNewCustName}</b>\n📍 ${addressName}\n\nIst das die <b>Wohnanschrift</b> oder nur eine <b>Abholadresse</b>?`, {
            reply_markup: { inline_keyboard: [
                [{ text: '🏠 Wohnanschrift (Stammkunde)', callback_data: 'admin_newcust_kind_stamm' }],
                [{ text: '📍 Nur Abholadresse (Gelegenheitskunde)', callback_data: 'admin_newcust_kind_gelegenheit' }],
                [{ text: '🏨 Hotel/Pension', callback_data: 'admin_newcust_kind_hotel' }],
                [{ text: '🏢 Auftraggeber/Firma', callback_data: 'admin_newcust_kind_auftraggeber' }]
            ] }
        });
        return;
    }

    // 🔧 v6.15.8: Kein laufender Buchungsvorgang → Fragen ob Abhol- oder Zielort
    const customer = await getTelegramCustomer(chatId);
    const newBooking = {
        missing: ['pickup', 'destination', 'datetime'],
        intent: 'buchung'
    };
    if (customer) {
        newBooking.name = customer.name;
        newBooking.phone = customer.mobile || customer.phone || '';
    }

    await setPending(chatId, {
        partial: newBooking,
        originalText: `GPS: ${addressName}`,
        _gpsChoice: { addressName, lat, lon }
    });
    await sendTelegramMessage(chatId,
        `📍 <b>Standort empfangen!</b>\n🏠 ${addressName}\n\n❓ <b>Ist das der Abholort oder der Zielort?</b>`, {
        reply_markup: { inline_keyboard: [
            [{ text: '📍 Abholort (hier abholen)', callback_data: 'gps_set_pickup' }, { text: '🎯 Zielort (dorthin fahren)', callback_data: 'gps_set_dest' }],
            [{ text: '❌ Abbrechen', callback_data: 'cancel_booking' }]
        ] }
    });
}

