// 🆕 v6.62.813 (Patrick 19.05.): HTTP-Function um PDF rueckwirkend zu regenerieren.
//   Use-Cases:
//     a) Pesch-Rechnung 20-26-188 (Patrick will sehen wie Andrea Pesch + Simmerath
//        im neuen DIN-5008-Layout aussieht)
//     b) 76 Bestand-Rechnungen ohne PDF (briefing-Stat) nachtraeglich aufbauen
//     c) Tests von Layout-Anpassungen ohne neue Fahrt zu provozieren
//
//   URL: https://europe-west1-taxi-heringsdorf.cloudfunctions.net/regenerateInvoicePdf
//        ?invoice=20-26-188&token=<TELEGRAM-BOT-TOKEN>
//
//   Was passiert:
//     1. Lade /invoices/{nr} + /rides/{rideId} + /customers/{customerId} + /settings/invoice
//     2. Resolved billingAddresses[default] -> customerName/customerAddress
//        (ueberschreibt nur wenn vorher leer ODER == customer.name fallback)
//     3. position.description = 'Taxifahrt' wenn alte 'Taxifahrt: X -> Y' Form
//     4. Speichert die korrigierten Felder in /invoices/{nr} zurueck
//     5. buildInvoicePdfBuffer -> Storage-Upload -> pdfUrl
//     6. /invoices/{nr}.pdfUrl + /rides/{rideId}.invoicePdfUrl gesetzt
//     7. JSON-Response mit before/after Diff
// 🆕 v6.63.296 (Patrick 11.06. 20:00 'Neu generierte E-Mails koennen immer noch
//   nicht angezeigt werden'): Logik aus dem HTTP-Endpoint extrahiert damit auch
//   der DB-Trigger (onInvoicePdfRegenRequested) sie verwenden kann, ohne ueber
//   HTTP zu gehen + Token-Round-Trip.
async function _doRegenerateInvoicePdf(invoiceNumber) {
    const invSnap = await db.ref(`invoices/${invoiceNumber}`).once('value');
    const invoice = invSnap.val();
    if (!invoice) throw new Error(`Rechnung ${invoiceNumber} nicht gefunden`);
    const rideId = invoice.rideId;
    let ride = {};
    if (rideId) {
        const rs = await db.ref(`rides/${rideId}`).once('value');
        ride = rs.val() || {};
    }
    let customer = {};
    const custId = ride.customerId || invoice.customerId;
    if (custId) {
        const cs = await db.ref(`customers/${custId}`).once('value');
        customer = cs.val() || {};
    }
    // billingAddresses[] resolven
    let _billingName = '';
    let _billingAddrStr = '';
    if (Array.isArray(customer.billingAddresses) && customer.billingAddresses.length > 0) {
        const _ba = customer.billingAddresses.find(b => b && b.isDefault) || customer.billingAddresses[0];
        if (_ba) {
            _billingName = (_ba.empfaengerName || _ba.label || '').trim();
            const _parts = [];
            if (_ba.strasse) _parts.push(_ba.strasse + (_ba.adresszusatz ? ', ' + _ba.adresszusatz : ''));
            const _plzOrt = [_ba.plz, _ba.ort].filter(Boolean).join(' ').trim();
            if (_plzOrt) _parts.push(_plzOrt);
            if (_ba.land && _ba.land.toLowerCase() !== 'deutschland') _parts.push(_ba.land);
            _billingAddrStr = _parts.join(', ');
        }
    }
    const before = {
        customerName: invoice.customerName,
        customerAddress: invoice.customerAddress,
        positionDesc: invoice.positions?.[0]?.description
    };
    const fixes = {};
    if (_billingName && (!invoice.customerName
        || invoice.customerName.trim() === (customer.name || '').trim()
        || invoice.customerName === 'Kunde')) {
        fixes.customerName = _billingName;
    }
    // v6.63.527: Fallback auf customer.address + billingAddresses[].address (altes Format)
    //   wenn _billingAddrStr leer ist (billingAddresses hat kein strasse/plz/ort).
    const _addrFallback = _billingAddrStr
        || (Array.isArray(customer.billingAddresses) && customer.billingAddresses.length > 0
            ? (customer.billingAddresses.find(b => b && b.isDefault) || customer.billingAddresses[0])?.address || ''
            : '')
        || customer.invoiceAddress || customer.billingAddress || customer.address || '';
    if (_addrFallback && !invoice.customerAddress) {
        fixes.customerAddress = _addrFallback;
    }
    if (Array.isArray(invoice.positions) && invoice.positions[0]) {
        const desc = invoice.positions[0].description || '';
        const _routeText = `${invoice.pickup || ''} ${invoice.destination || ''}`;
        const _shouldBeKranken = /(krankenhaus|klinik|arzt|doktor|praxis)/i.test(_routeText);
        const _targetDesc = _shouldBeKranken ? 'Krankenfahrt' : 'Taxifahrt';
        const _isOldLongForm = desc.startsWith('Taxifahrt:') && desc.length > 'Taxifahrt'.length + 5;
        const _isWrongCategory = (_shouldBeKranken && desc === 'Taxifahrt');
        if (_isOldLongForm || _isWrongCategory) {
            const newPos = [...invoice.positions];
            newPos[0] = { ...newPos[0], description: _targetDesc };
            fixes.positions = newPos;
        }
    }
    const correctedInvoice = { ...invoice, ...fixes };
    if (Object.keys(fixes).length > 0) {
        await db.ref(`invoices/${invoiceNumber}`).update({
            ...fixes,
            regeneratedAt: Date.now(),
            regeneratedFrom: 'cloud_function_v6.63.296'
        });
    }
    const invoicePdfMod = require('./invoice-pdf');
    const settings = await invoicePdfMod.loadInvoiceSettings(db);
    const pdfBuffer = await invoicePdfMod.buildInvoicePdfBuffer(
        invoiceNumber, ride, customer, settings, correctedInvoice
    );
    const fileName = `rechnung-${invoiceNumber}.pdf`;
    const bucket = admin.storage().bucket();
    const fileRef = bucket.file(`invoices/${fileName}`);
    await fileRef.save(pdfBuffer, { metadata: { contentType: 'application/pdf' }, resumable: false });
    await fileRef.makePublic();
    // 🆕 v6.63.298 Cache-Buster (Patrick 11.06. 20:52 'Sabine steht immer noch'):
    //   Browser/Native-App cached PDFs unter der pdfUrl. Bei Re-Generate aendert
    //   sich der Dateiname nicht → alter Cache wird gezeigt. Mit ?t=Timestamp
    //   sieht der Client eine andere URL und laedt neu.
    const _cacheBuster = Date.now();
    const pdfUrl = `https://storage.googleapis.com/${bucket.name}/${encodeURI(`invoices/${fileName}`)}?t=${_cacheBuster}`;
    await db.ref(`invoices/${invoiceNumber}`).update({
        pdfUrl,
        pdfFileName: fileName,
        pdfGeneratedAt: Date.now(),
        pdfGeneratedVia: 'cloud_function_puppeteer_v6.63.298_regenerate',
        needsPdfRegeneration: null,   // 🆕 v6.63.612: Flag clearen damit Trigger nicht loopt (vorher: pdfNeedsRegeneration — toter Feldname)
        pdfNeedsRegeneration: null    // Legacy-Cleanup
    });
    if (rideId) {
        await db.ref(`rides/${rideId}`).update({
            invoicePdfUrl: pdfUrl,
            invoicePdfGeneratedAt: Date.now()
        });
    }
    return {
        ok: true,
        invoiceNumber,
        pdfUrl,
        fixes: Object.keys(fixes),
        before,
        after: {
            customerName: correctedInvoice.customerName,
            customerAddress: correctedInvoice.customerAddress,
            positionDesc: correctedInvoice.positions?.[0]?.description
        }
    };
}

exports.regenerateInvoicePdf = onRequest(
    {
        region: 'europe-west1',
        cors: true,
        memory: '2GiB',          // chromium braucht das
        timeoutSeconds: 120
    },
    async (req, res) => {
        try {
            const invoiceNumber = String(req.query.invoice || req.body?.invoice || '').trim();
            const token = String(req.query.token || req.body?.token || '').trim();
            if (!invoiceNumber) {
                return res.status(400).json({ error: 'param ?invoice= fehlt' });
            }
            // Auth via Telegram-Bot-Token (nur Patrick hat den)
            const tokSnap = await db.ref('settings/telegram/botToken').once('value');
            const expected = String(tokSnap.val() || '').trim();
            if (!expected) {
                return res.status(500).json({ error: 'settings/telegram/botToken leer — auth nicht moeglich' });
            }
            if (token !== expected) {
                return res.status(401).json({ error: 'token falsch — TELEGRAM_BOT_TOKEN als ?token= mitschicken' });
            }

            const result = await _doRegenerateInvoicePdf(invoiceNumber);
            return res.status(200).json(result);
        } catch (e) {
            console.error('regenerateInvoicePdf-Fehler:', e);
            return res.status(e.message?.includes('nicht gefunden') ? 404 : 500)
                .json({ error: e.message, stack: (e.stack || '').split('\n').slice(0, 5).join('\n') });
        }
    }
);

// 🆕 v6.63.296: DB-Trigger fuer pdfNeedsRegeneration=true
//   Patrick 11.06. 20:00 Bridge: "Neu generierte E-Mails koennen immer noch nicht
//   angezeigt werden". Native-App setzt pdfUrl=null + pdfNeedsRegeneration=true,
//   ABER bisher reagierte niemand auf das Flag. Dieser Trigger feuert
//   _doRegenerateInvoicePdf und setzt pdfNeedsRegeneration zurueck auf false.
// 🐛 v6.63.305 (Patrick 12.06. 11:48 Bridge): Trigger feuerte nicht bei Ostseeblick
//   20-26-942 Preis-Edit weil onValueUpdated nicht feuert wenn Sub-Field NEU
//   geschrieben wird (vorher gar nicht existierte). Plus: updateChildren auf
//   Parent setzt mehrere Felder atomisch — Sub-Field-Trigger erwischt das
//   manchmal nicht. Switch auf onValueWritten + auch wenn before undefined ist.
exports.onInvoicePdfRegenRequested = onValueWritten(
    {
        // 🆕 v6.63.612: needsPdfRegeneration (nicht pdfNeedsRegeneration) — das ist was
        //   Native-App + openInvoiceModal setzen. Alter Feldname war toter Code.
        ref: '/invoices/{invoiceNumber}/needsPdfRegeneration',
        region: 'europe-west1',
        memory: '2GiB',
        timeoutSeconds: 120
    },
    async (event) => {
        try {
            const after = event.data.after.val();
            const before = event.data.before.val();
            // Nur reagieren wenn Flag NEU true wird (undef/false/missing -> true)
            if (after !== true) return;
            if (before === true) return; // schon true, kein Re-Trigger
            const invoiceNumber = event.params.invoiceNumber;
            console.log(`🔄 v6.63.305 pdfNeedsRegeneration=true Trigger fuer ${invoiceNumber} (before=${before}, after=${after}) — starte Regenerierung`);
            const result = await _doRegenerateInvoicePdf(invoiceNumber);
            console.log(`✅ v6.63.305 PDF neu generiert: ${invoiceNumber} -> ${result.pdfUrl}`);
        } catch (e) {
            console.error('❌ v6.63.305 onInvoicePdfRegenRequested-Fehler:', e);
            await logError('onInvoicePdfRegenRequested', e, {
                invoiceNumber: event.params.invoiceNumber,
                severity: 'critical'
            });
        }
    }
);

exports.scheduledShiftReminder = onSchedule(
    // v6.63.443 (Patrick 20.06. 13:31 GO Phase 1 Cost-Cut): 5 → 10 Min.
    //   Shift-Reminder muss nicht öfter laufen. -50% Reads.
    { schedule: 'every 10 minutes', region: 'europe-west1', timeZone: 'Europe/Berlin' },
    async (event) => {
        try {
            const now = Date.now();
            const REMINDER_WINDOW_MS = 15 * 60 * 1000;
            const OFFLINE_TOLERANCE_MS = 30 * 60 * 1000;
            const [shiftPlanSnap, vehiclesSnap, sentSnap] = await Promise.all([
                db.ref('shiftPlan').once('value'),
                db.ref('vehicles').once('value'),
                db.ref('settings/shiftReminderSent').once('value')
            ]);
            const shiftPlan = shiftPlanSnap.val() || {};
            const vehicles = vehiclesSnap.val() || {};
            const sentMap = sentSnap.val() || {};
            const today = new Date(now);
            const dateStr = today.toISOString().slice(0, 10);
            const dayKey = ['sonntag', 'montag', 'dienstag', 'mittwoch', 'donnerstag', 'freitag', 'samstag'][today.getDay()];
            for (const [vid, vData] of Object.entries(vehicles)) {
                const plan = shiftPlan[vid];
                if (!plan) continue;
                const dayPlan = (plan.exceptions && plan.exceptions[dateStr]) || (plan.weekly && plan.weekly[dayKey]);
                if (!dayPlan || !dayPlan.start) continue;
                const [h, m] = dayPlan.start.split(':').map(Number);
                const shiftStartTs = new Date(now).setHours(h, m, 0, 0);
                const minToShift = (shiftStartTs - now) / 60000;
                const lastSeen = vData.lastSeen || vData.lastUpdate || 0;
                const isOnline = vData.lat && vData.lon && lastSeen > 0 && (now - lastSeen) < OFFLINE_TOLERANCE_MS;
                // 15-Min-Reminder
                if (minToShift > 10 && minToShift <= 15) {
                    const sentKey = vid + '_' + dateStr + '_pre';
                    if (sentMap[sentKey]) continue;
                    if (vData.driverChatId) {
                        try {
                            await sendTelegram(vData.driverChatId, `⏰ Deine Schicht startet in ${Math.round(minToShift)} Min (${dayPlan.start}).\n\nApp jetzt oeffnen + GPS aktivieren wenn nicht schon online.`);
                            await db.ref(`settings/shiftReminderSent/${sentKey}`).set(now);
                        } catch (_) {}
                    }
                }
                // Offline-Warnung 30 Min nach Schichtbeginn
                if (minToShift < -30 && minToShift > -120 && !isOnline) {
                    const sentKey = vid + '_' + dateStr + '_offline';
                    if (sentMap[sentKey]) continue;
                    await sendToAllAdmins(`⚠️ <b>Fahrer noch nicht online</b>\n\n${vData.name || vid} sollte seit ${Math.abs(Math.round(minToShift))} Min Schicht haben (${dayPlan.start}) ist aber offline.\n\nGPS prüfen oder Fahrer anrufen.`);
                    await db.ref(`settings/shiftReminderSent/${sentKey}`).set(now);
                }
            }
        } catch (e) { console.error('❌ scheduledShiftReminder:', e.message); }
    }
);

exports.scheduledShiftHeartbeatCheck = onSchedule(
    {
        // v6.47.1: 1 → 2 Min — Heartbeat-Timeout ist 10 Min, 2-Min-Intervall reicht völlig
        // v6.63.443 (Patrick 20.06. 13:31 GO Phase 1): 2 → 5 Min. Timeout ist 10 Min,
        //   5-Min-Check reicht. -60% Reads.
        schedule: 'every 5 minutes',
        region: 'europe-west1',
        timeoutSeconds: 60,
        memory: '256MiB'
    },
    async (event) => {
        try {
            // 🆕 v6.41.15: Timeout von 2 → 10 Min (User-Feedback: "Power-Knopf → Timeout")
            //   Bei Bildschirm-aus drosselt Android den WebView komplett (Doze-Mode).
            //   2 Min waren zu streng — Bildschirm kurz aus beim Einkaufen/Pause-Machen
            //   reicht nicht für 2-Min-Beat. 10 Min gibt Puffer ohne App-Crash-Erkennung
            //   zu verlieren.
            const HEARTBEAT_TIMEOUT_MS = 10 * 60 * 1000; // 10 Minuten ohne Beat → tot
            const now = Date.now();

            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val() || {};

            // 🆕 v6.62.67: PAUSE-AUTO-RESUME — Fahrer hat Pause mit pauseUntil gesetzt.
            // Sobald pauseUntil < now → wieder online schalten. Backup falls die App
            // den eigenen Resume-Handler nicht ausgefuehrt hat (App-Crash, Doze-Mode).
            for (const [vid, v] of Object.entries(vehicles)) {
                if (!v || !v.shift) continue;
                if (v.shift.status !== 'active') continue;
                if (v.online !== false) continue; // ist schon online
                const pauseUntil = v.pauseUntil;
                if (typeof pauseUntil !== 'number' || pauseUntil <= 0) continue;
                if (pauseUntil > now) continue; // noch in Pause
                // Pause vorbei → resume
                try {
                    await db.ref('vehicles/' + vid).update({
                        online: true,
                        dispatchStatus: 'online',
                        pauseUntil: null,
                        pauseResumedAt: now,
                        pauseResumedBy: 'cloud-auto-resume'
                    });
                    console.log(`▶️ Pause-Auto-Resume: ${v.name || vid} wieder online (Pause bis ${new Date(pauseUntil).toLocaleString('de-DE',{ timeZone:'Europe/Berlin' })})`);
                } catch (_e) { console.warn('Pause-Resume Fehler ' + vid + ': ' + _e.message); }
            }

            // v6.47.2: KOSTEN-OPTIMIERUNG — vorher las diese Function ALLE rides bei jedem
            // Aufruf alle 2 Min. Jetzt: nur status active/on_way/picked_up/accepted/arrived
            // (nur die brauchen wir für die Schicht-Lebendcheck-Logik).
            const activeStati = ['accepted', 'on_way', 'arrived', 'picked_up'];
            const ridesPromises = activeStati.map(st =>
                db.ref('rides').orderByChild('status').equalTo(st).once('value')
            );
            const ridesSnaps = await Promise.all(ridesPromises);
            const rides = {};
            for (const snap of ridesSnaps) {
                snap.forEach(c => { rides[c.key] = c.val(); });
            }

            // Map: vehicleId → hat laufende Fahrt?
            const vehicleHasActiveRide = {};
            for (const [rid, r] of Object.entries(rides)) {
                if (!r) continue;
                if (r.status === 'on_way' || r.status === 'picked_up') {
                    const vid = r.vehicleId || r.assignedVehicle;
                    if (vid) vehicleHasActiveRide[vid] = rid;
                }
            }

            let autoEnded = 0;
            let warned = 0;
            let reactivated = 0;

            // 🆕 v6.62.963 (Patrick 26.05.2026 16:08): REACTIVATE-Check vor Auto-End.
            //   Bug-Scenario: shift wurde auto-ended (Heartbeat 11 Min Pause), aber
            //   Native-App startet wieder → Heartbeat kommt → shift.status='auto-ended'
            //   bleibt aber stehen → Patrick sieht in App »online«, Cloud-Dispo sieht
            //   »beendet« → keine neuen Fahrten zugewiesen. Fix: bei frischem Signal
            //   nach autoEndedAt → reaktivieren.
            for (const [vid, v] of Object.entries(vehicles)) {
                if (!v || !v.shift) continue;
                if (v.shift.status !== 'auto-ended') continue;
                if (!v.shift.autoEndedAt) continue;

                const lastBeat = v.shift.lastHeartbeat || 0;
                const gpsBeat = v.timestamp || v.lastUpdate || 0;
                const freshSignal = Math.max(lastBeat, gpsBeat);
                const signalAge = now - freshSignal;

                // Frischer Heartbeat ODER GPS-Update innerhalb 5 Min UND nach autoEnd
                if (signalAge < 5 * 60 * 1000 && freshSignal > v.shift.autoEndedAt) {
                    const offlineMin = Math.round((now - v.shift.autoEndedAt) / 60000);
                    console.log(`🔄 Watchdog: Schicht von ${v.name || vid} reaktivieren (Heartbeat zurueck nach ${offlineMin} Min)`);
                    try {
                        await db.ref(`vehicles/${vid}/shift`).update({
                            status: 'active',
                            autoEndedAt: null,
                            endedAt: null,
                            endedReason: null,
                            reactivatedAt: now,
                            reactivatedReason: `Heartbeat zurueck nach ${offlineMin} Min`
                        });
                        await db.ref(`vehicles/${vid}`).update({
                            online: true,
                            available: true,
                            updatedAt: now
                        });
                        const msg = `🔄 <b>Schicht REAKTIVIERT</b>\n\n` +
                            `🚗 ${v.name || vid}\n` +
                            `👤 ${v.shift.driverName || v.currentDriver || 'Fahrer'}\n` +
                            `💓 Heartbeat zurück nach ${offlineMin} Min Offline-Zeit\n` +
                            `✅ Fahrzeug ist wieder dispatchbar`;
                        await sendToAllAdmins(msg, 'shift_reactivated');
                        reactivated++;
                    } catch (_reactErr) {
                        console.error(`❌ Schicht-Reaktivierung ${vid}:`, _reactErr.message);
                    }
                }
            }

            for (const [vid, v] of Object.entries(vehicles)) {
                if (!v || !v.shift) continue;
                if (v.shift.status !== 'active') continue;

                const lastBeat = v.shift.lastHeartbeat || v.shift.startTime || 0;
                const age = now - lastBeat;

                if (age <= HEARTBEAT_TIMEOUT_MS) continue; // Frisch → alles OK

                // 🆕 v6.41.8: GPS-Timestamp als Fallback. Wenn der Fahrer GPS-Positionen
                //   sendet, läuft die App nachweislich — egal ob der Heartbeat gedrosselt
                //   wurde. In dem Fall nicht auto-beenden.
                const gpsTimestamp = v.timestamp || v.lastUpdate || 0;
                const gpsAge = gpsTimestamp ? (now - gpsTimestamp) : Infinity;
                if (gpsAge < HEARTBEAT_TIMEOUT_MS) {
                    console.log(`💓 Watchdog: ${v.name || vid} Heartbeat ${Math.round(age/60000)} Min alt ABER GPS ${Math.round(gpsAge/1000)}s frisch → nicht beenden`);
                    continue;
                }

                const ageMin = Math.round(age / 60000);
                const vName = v.name || vid;
                const driverName = v.shift.driverName || v.currentDriver || 'Fahrer';

                // Sicherheitsnetz: laufende Fahrt? → NICHT auto-beenden
                if (vehicleHasActiveRide[vid]) {
                    const rid = vehicleHasActiveRide[vid];
                    console.warn(`💓 Watchdog: ${vName} Heartbeat ${ageMin} Min alt ABER Fahrt ${rid} läuft — nur warnen`);
                    // Einmal warnen (Flag auf shift)
                    if (!v.shift.heartbeatWarned) {
                        await db.ref(`vehicles/${vid}/shift/heartbeatWarned`).set(true);
                        const msg = `⚠️ <b>Fahrer-App nicht erreichbar</b>\n\n` +
                            `🚗 ${vName}\n` +
                            `👤 ${driverName}\n` +
                            `💓 Letzter Heartbeat vor ${ageMin} Min\n\n` +
                            `🚨 <b>Laufende Fahrt — Schicht NICHT auto-beendet!</b>\n` +
                            `Bitte manuell prüfen ob Fahrer erreichbar ist.`;
                        try { await sendToAllAdmins(msg, 'warning'); } catch(_) {}
                        warned++;
                    }
                    continue;
                }

                // Keine laufende Fahrt → Schicht auto-beenden (Lock freigeben)
                console.log(`💓 Watchdog: Schicht von ${vName} auto-beenden (Heartbeat ${ageMin} Min alt)`);

                const shiftDurationMs = now - (v.shift.startTime || now);
                await db.ref(`vehicles/${vid}/shift`).set({
                    status: 'auto-ended',
                    endedAt: new Date().toISOString(),
                    endedReason: 'heartbeat_timeout',
                    durationMs: shiftDurationMs,
                    lastHeartbeat: lastBeat,
                    startTime: v.shift.startTime || null,
                    autoEndedAt: now
                });

                // 🆕 v6.41.4: Auch /shiftHistory als beendet markieren (sonst zeigt Admin "AKTIV")
                try {
                    if (v.shift.startTime) {
                        const shiftId = String(v.shift.startTime);
                        await db.ref(`shiftHistory/${vid}/${shiftId}`).update({
                            status: 'auto-ended',
                            endTime: now,
                            endedAt: new Date().toISOString(),
                            endedReason: 'heartbeat_timeout',
                            durationMs: shiftDurationMs,
                            _autoEnded: true,
                            _heartbeatAgeMin: ageMin
                        });
                        await db.ref(`shiftHistory/${vid}/${shiftId}/events`).push({
                            ts: now,
                            type: 'shift_auto_ended',
                            message: `Schicht auto-beendet (Heartbeat ${ageMin} Min alt)`,
                            data: { lastHeartbeat: lastBeat, ageMin: ageMin }
                        });
                    }
                } catch(e) { console.warn('⚠️ shiftHistory auto-end update fehlgeschlagen:', e.message); }

                // Fahrzeug offline setzen, damit keine neuen Fahrten zugewiesen werden
                try {
                    await db.ref(`vehicles/${vid}`).update({
                        online: false,
                        available: false,
                        updatedAt: now
                    });
                } catch(_) {}

                autoEnded++;

                // Admins + Fahrer informieren
                const tsStr = formatBerlinTime();
                const adminMsg = `💓 <b>Schicht auto-beendet (Heartbeat-Timeout)</b>\n\n` +
                    `🚗 ${vName}\n` +
                    `👤 ${driverName}\n` +
                    `⏱️ Schicht-Dauer: ${Math.round(shiftDurationMs / 60000)} Min\n` +
                    `💓 Letzter Heartbeat vor ${ageMin} Min\n` +
                    `📱 Grund: App-Crash oder Netz-/Akku-Problem\n\n` +
                    `✅ Fahrzeug-Lock freigegeben\n` +
                    `⏰ ${tsStr}`;
                try { await sendToAllAdmins(adminMsg, 'info'); } catch(_) {}

                // Fahrer-Telegram (best effort)
                try {
                    if (v.shift.driverUid) {
                        const tgSnap = await db.ref(`users/${v.shift.driverUid}/telegramChatId`).once('value');
                        const chatId = tgSnap.val();
                        if (chatId) {
                            await sendTelegramMessage(chatId,
                                `💓 <b>Schicht wurde automatisch beendet</b>\n\n` +
                                `Grund: Deine App hat ${ageMin} Min nichts gemeldet (App-Crash, Akku leer oder Netz weg).\n\n` +
                                `Falls du weiterfährst: App öffnen und Schicht neu starten.`
                            );
                        }
                    }
                } catch(_) {}

                await addTelegramLog('💓', 'cloud', `Schicht auto-beendet: ${vName} (Heartbeat ${ageMin} Min alt)`, { vehicleId: vid });
            }

            if (autoEnded > 0 || warned > 0) {
                console.log(`💓 Watchdog abgeschlossen: ${autoEnded} auto-beendet, ${warned} gewarnt`);
            }
        } catch (e) {
            console.error('❌ scheduledShiftHeartbeatCheck Fehler:', e.message);
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 🩺 SYSTEM-HEALTH-REPORT — v6.62.73
// /health im Telegram-Hauptbot ruft buildHealthReport() ab.
// Plus scheduledHealthReport: taeglich 06:00 Berlin an alle Admins.
// ═══════════════════════════════════════════════════════════════

async function buildHealthReport() {
    const now = Date.now();
    const lines = ['🩺 <b>SYSTEM-HEALTH</b>', `<i>${new Date(now).toLocaleString('de-DE',{ timeZone:'Europe/Berlin' })}</i>`, ''];

    // 1. Fahrzeuge
    const vSnap = await db.ref('vehicles').once('value');
    const vehicles = vSnap.val() || {};
    let vehActive = 0, vehNoFcm = 0, vehList = [];
    for (const [vid, v] of Object.entries(vehicles)) {
        if (!v) continue;
        const isActive = v.shift?.status === 'active';
        const hasFcm = !!v.fcmToken?.token;
        if (isActive) vehActive++;
        if (!hasFcm) vehNoFcm++;
        vehList.push({ vid, name: v.name || vid, isActive, hasFcm, online: v.online });
    }
    lines.push('🚖 <b>Fahrzeuge:</b>');
    for (const v of vehList) {
        const icons = (v.isActive ? '🟢' : '⚪') + (v.hasFcm ? '📲' : '📵') + (v.online ? '' : ' ⏸');
        lines.push(`${icons} ${v.name}`);
    }
    lines.push('');

    // 2. Offene Vorbestellungen <60 Min
    const ridesV = await db.ref('rides').orderByChild('status').equalTo('vorbestellt').once('value');
    let openVorbest = 0, openIds = [];
    ridesV.forEach(c => {
        const r = c.val();
        if (!r || !r.pickupTimestamp) return;
        const min = (r.pickupTimestamp - now) / 60000;
        if (min > 0 && min < 60) { openVorbest++; openIds.push(`${r.customerName || '?'} in ${Math.round(min)}min`); }
    });

    // 3. Warteschlange
    const ridesW = await db.ref('rides').orderByChild('status').equalTo('warteschlange').once('value');
    let ws = 0;
    ridesW.forEach(() => ws++);

    // 4. SMS-Queue offen
    const smsSnap = await db.ref('smsQueue').once('value');
    let smsOpen = 0, smsExpired = 0;
    smsSnap.forEach(c => {
        const s = c.val();
        if (!s) return;
        if (s.status === 'expired') { smsExpired++; return; }
        if (s.status !== 'sent' && s.status !== 'failed_max_retries') smsOpen++;
    });

    lines.push(`📅 Vorbestellungen <60min: <b>${openVorbest}</b>`);
    if (openIds.length > 0) lines.push('   ' + openIds.slice(0, 5).join(', '));
    lines.push(`⏳ Warteschlange: <b>${ws}</b>`);
    lines.push(`📱 SMS-Queue offen: <b>${smsOpen}</b> ${smsExpired > 0 ? `(${smsExpired} expired)` : ''}`);
    lines.push(`🚖 Aktive Schichten: <b>${vehActive}/${vehList.length}</b>`);
    if (vehNoFcm > 0) lines.push(`⚠️ Fahrzeuge ohne FCM-Token: <b>${vehNoFcm}</b> (App muessten geoeffnet werden)`);

    return lines.join('\n');
}

// 🆕 v6.62.373: TÜV-Reminder — taeglich um 8:30 Berlin alle aktiven Fahrzeuge auf
// naechsterTuev pruefen und bei <30 Tagen Restzeit Telegram-Push an Admins.
// Patrick (06.05. 15:25): "Fahrzeuge anlegen + Erinnerung an TÜV etc".
exports.scheduledVehicleTuevCheck = onSchedule(
    {
        schedule: '30 8 * * *', // taeglich 08:30 Berlin
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 60,
        memory: '128MiB'
    },
    async () => {
        try {
            const now = Date.now();
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val() || {};
            const sent = [];
            for (const [id, v] of Object.entries(vehicles)) {
                if (!v || v.archived) continue;
                if (!v.naechsterTuev) continue;
                const parts = String(v.naechsterTuev).split('-');
                if (parts.length < 2) continue;
                const year = parseInt(parts[0]);
                const month = parseInt(parts[1]);
                if (!year || !month) continue;
                // Letzter Tag des angegebenen Monats — TUEV laeuft bis Monatsende
                const tuevEnd = new Date(year, month, 0, 23, 59, 59);
                const daysToTuev = Math.round((tuevEnd.getTime() - now) / 86400000);
                // Anti-Spam: einmal pro Tag pro Fahrzeug
                const lastReminder = v.lastTuevReminderAt || 0;
                const hoursSince = (now - lastReminder) / 3600000;
                if (hoursSince < 23) continue;
                // Push-Schwellen
                let msg = null;
                if (daysToTuev < 0) {
                    msg = `🚨 TÜV ABGELAUFEN seit ${-daysToTuev} Tagen!\n\n🚗 ${v.label || v.name || id}\n🔢 ${v.plate || '?'}\n📅 War gueltig bis ${v.naechsterTuev}\n\nFahrzeug NICHT mehr fahren bis TUEV-Termin!`;
                } else if (daysToTuev <= 7) {
                    msg = `⚠️ TÜV LÄUFT IN ${daysToTuev} TAGEN AB — DRINGEND!\n\n🚗 ${v.label || v.name || id}\n🔢 ${v.plate || '?'}\n📅 Gueltig bis Ende ${v.naechsterTuev}\n\nSofort Termin bei TÜV-Stelle vereinbaren.`;
                } else if (daysToTuev <= 30) {
                    msg = `📅 TÜV in ${daysToTuev} Tagen faellig\n\n🚗 ${v.label || v.name || id}\n🔢 ${v.plate || '?'}\n📅 Gueltig bis Ende ${v.naechsterTuev}\n\nTermin bei TÜV-Stelle vereinbaren (4 Wochen Vorlauf empfohlen).`;
                }
                if (msg) {
                    await sendToAllAdmins(msg);
                    await db.ref(`vehicles/${id}/lastTuevReminderAt`).set(now);
                    sent.push({ id, plate: v.plate, daysToTuev });
                }
            }
            console.log(`📅 scheduledVehicleTuevCheck: ${sent.length} Pushs gesendet`, sent);
        } catch (e) {
            console.error('❌ scheduledVehicleTuevCheck Fehler:', e.message, e.stack);
        }
    }
);

