// 🆕 v6.62.712: Daily-Morning-Briefing per Telegram an Admins.
// Patrick (14.05. 11:01): "Wartepool prominenter machen — Daily-Briefing morgens".
// Taeglich 07:30 Berlin-Zeit. Erste Iteration zeigt: Wartepool-Stand + Heutige Fahrten.
// Spaeter erweiterbar um Umsatz, Schichten, Konflikte.
// 🆕 v6.63.084 (Patrick 01.06. Bridge 21:50): "jeden Tag um 9 oder um 10
//   Statusbericht von den E-Mails per Cron". Liest /personalMailInbox
//   (gefüllt vom mailInboxPoller alle 15 Min) und schickt eine kompakte
//   Übersicht der letzten 24h per Telegram. Klassifikation aus
//   classifyPersonalEmail wird genutzt.
exports.scheduledDailyMailBriefing = onSchedule(
    {
        schedule: '0 9 * * *',
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 120,
        memory: '256MiB'
    },
    async (event) => {
        try {
            const inboxSnap = await db.ref('personalMailInbox').once('value');
            if (!inboxSnap.exists()) {
                await sendToAllAdmins('📭 <b>Mail-Briefing</b>\n\nKeine Einträge in /personalMailInbox.', 'mail_briefing');
                return;
            }
            const cutoff = Date.now() - 24 * 60 * 60 * 1000;
            const buckets = {};
            const importantEntries = [];
            let total = 0;
            inboxSnap.forEach(c => {
                const mail = c.val();
                if (!mail || typeof mail !== 'object') return;
                const ts = Number(mail.receivedAt || mail.date || mail.ts || 0);
                if (ts < cutoff) return;
                total++;
                const cat = mail.category || 'sonstige';
                const prio = mail.priority || 'normal';
                buckets[cat] = (buckets[cat] || 0) + 1;
                if (prio === 'high' || cat === 'whitelist' || cat === 'wichtig' || cat === 'behoerde' || cat === 'gesundheit') {
                    importantEntries.push({ ts, from: mail.from || '?', subject: mail.subject || '(ohne Betreff)', cat, prio });
                }
            });
            const order = ['whitelist', 'behoerde', 'gesundheit', 'wichtig', 'finanz', 'geschaeft', 'sonstige', 'system', 'werbung'];
            const lines = ['📬 <b>Mail-Briefing letzte 24h</b>', `Gesamt: <b>${total}</b> Mails\n`];
            for (const cat of order) {
                const n = buckets[cat];
                if (!n) continue;
                lines.push(`• ${cat}: ${n}`);
            }
            if (importantEntries.length) {
                lines.push('\n<b>🔥 Wichtige Mails:</b>');
                importantEntries.sort((a, b) => b.ts - a.ts);
                for (const e of importantEntries.slice(0, 10)) {
                    const t = new Date(e.ts).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' });
                    lines.push(`${t} · ${String(e.from).substring(0, 40)}\n   <i>${String(e.subject).substring(0, 90)}</i>`);
                }
            }
            await sendToAllAdmins(lines.join('\n'), 'mail_briefing');
            console.log(`📬 v6.63.084 Mail-Briefing gesendet: ${total} Mails, ${importantEntries.length} wichtig`);
        } catch (e) {
            console.error('scheduledDailyMailBriefing Fehler:', e.message);
            try { await sendToAllAdmins('⚠️ Mail-Briefing fehlgeschlagen: ' + e.message, 'mail_briefing'); } catch (_) {}
        }
    }
);

exports.scheduledMorningBriefing = onSchedule(
    {
        schedule: '30 7 * * *',
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 60,
        memory: '256MiB'
    },
    async (event) => {
        try {
            const now = Date.now();
            const dateStr = new Date(now).toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin' });
            // Wartepool laden
            const wpSnap = await db.ref('rides').orderByChild('status').equalTo('wartepool').once('value');
            const wartepool = [];
            wpSnap.forEach(c => {
                const r = c.val();
                if (!r) return;
                const pickupAt = r.pickupTimestamp
                    ? new Date(r.pickupTimestamp).toLocaleString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' })
                    : '?';
                wartepool.push({
                    id: c.key,
                    customerName: r.customerName || '?',
                    pickup: r.pickup || '?',
                    destination: r.destination || '?',
                    pickupAt
                });
            });
            // Heutige Fahrten zaehlen
            const todayStart = new Date(new Date(now).toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' }) + 'T00:00:00').getTime();
            const todayEnd = todayStart + 24 * 60 * 60 * 1000;
            const ridesSnap = await db.ref('rides').orderByChild('pickupTimestamp')
                .startAt(todayStart).endAt(todayEnd).once('value');
            let heuteCount = 0;
            let heuteAssigned = 0;
            let heuteUnassigned = 0;
            ridesSnap.forEach(c => {
                const r = c.val();
                if (!r) return;
                if (['cancelled', 'storniert', 'deleted'].includes(r.status)) return;
                heuteCount++;
                if (r.assignedVehicle) heuteAssigned++;
                else heuteUnassigned++;
            });
            // Message bauen
            let msg = `☀️ <b>Morgen-Briefing ${dateStr}</b>\n\n`;
            if (wartepool.length > 0) {
                msg += `🚨 <b>WARTEPOOL (${wartepool.length})</b> — manuelle Disposition noetig:\n`;
                wartepool.slice(0, 5).forEach(w => {
                    msg += `  • ${w.customerName} um ${w.pickupAt}\n     📍 ${w.pickup.substring(0, 40)}\n`;
                });
                if (wartepool.length > 5) msg += `  ... +${wartepool.length - 5} weitere\n`;
                msg += '\n';
            } else {
                msg += `✅ Wartepool leer\n\n`;
            }
            msg += `📅 <b>Heute</b>: ${heuteCount} Fahrten (${heuteAssigned} zugewiesen, ${heuteUnassigned} offen)\n`;
            await sendToAllAdmins(msg, 'morning_briefing');
            console.log(`✅ Morgen-Briefing gesendet (Wartepool: ${wartepool.length}, heute: ${heuteCount})`);
        } catch (e) {
            console.error('scheduledMorningBriefing Fehler:', e.message);
        }
    }
);

exports.scheduledHistorySnapshot = onSchedule(
    {
        // v6.63.233: 5min → 15min. History-Snapshot ist kein Hot-Path.
        schedule: 'every 15 minutes',
        region: 'europe-west1',
        timeoutSeconds: 30,
        memory: '256MiB'
    },
    async (event) => {
        try {
            const now = Date.now();
            const dateStr = new Date(now).toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' });

            // GPS-Snapshot
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val() || {};
            const gpsBatch = {};
            Object.entries(vehicles).forEach(([vid, v]) => {
                if (!v) return;
                const _lat = parseFloat(v.lat), _lon = parseFloat(v.lon);
                if (Number.isFinite(_lat) && Number.isFinite(_lon)) {
                    gpsBatch[vid] = {
                        lat: _lat,
                        lon: _lon,
                        online: v.online === true,
                        status: v.status || null,
                        gpsAgeMs: v.timestamp ? Math.max(0, now - v.timestamp) : null,
                        currentRideId: v.currentRideId || null,
                        speed: typeof v.speed === 'number' ? v.speed : null
                    };
                }
            });
            if (Object.keys(gpsBatch).length > 0) {
                await db.ref(`historicalGPS/${dateStr}/${now}`).set(gpsBatch);
            }

            // Shifts-Snapshot — nur 1× pro Stunde (Plan aendert sich selten)
            const hourMark = Math.floor(now / (60 * 60 * 1000));
            const lastSnap = await db.ref(`historicalShifts/${dateStr}/lastHourMark`).once('value').then(s => s.val() || 0);
            if (hourMark > lastSnap) {
                const shiftsSnap = await db.ref('vehicleShifts').once('value');
                await db.ref(`historicalShifts/${dateStr}/${now}`).set(shiftsSnap.val() || null);
                await db.ref(`historicalShifts/${dateStr}/lastHourMark`).set(hourMark);
            }
        } catch (e) {
            console.error('scheduledHistorySnapshot Fehler:', e.message);
        }
    }
);

// 🆕 v6.63.081 (Patrick 01.06. Bridge 21:14 — Cost-Detox Phase 3):
//   Logs-Cleanup-Cron. Bei /debugLogs (94k+), /activityLog (76k+),
//   /optimierungsLog (24k+) sammeln sich tausende alte Einträge die nichts
//   mehr beitragen aber bei jedem Pfad-Listener bzw. Initial-Read mitgezogen
//   werden. Cleanup einmal täglich 02:00 Berlin Zeit:
//     debugLogs/<category>/<id>   ts < jetzt-7 Tage   → löschen
//     activityLog/<id>            t/ts < jetzt-14 Tage → löschen
//     optimierungsLog/<id>        t/ts < jetzt-7 Tage  → löschen
//     assignmentLog/<id>          ts < jetzt-30 Tage   → löschen
//     errorLogs/<id>              t/ts < jetzt-30 Tage → löschen
//     importLog/<id>              ts < jetzt-30 Tage   → löschen
//     emailLog/<id>               ts < jetzt-30 Tage   → löschen
//     autoCloseLog/<id>           ts < jetzt-30 Tage   → löschen
//   Pro Pfad in 500er-Batches gelöscht damit kein einzelner Update zu groß wird.
exports.scheduledLogsCleanup = onSchedule(
    {
        schedule: '0 2 * * *',
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 540,
        memory: '512MiB'
    },
    async (event) => {
        const now = Date.now();
        const day = 24 * 60 * 60 * 1000;
        const plans = [
            { path: 'debugLogs',       cutoffMs: now - 7 * day,  nested: true  },
            { path: 'activityLog',     cutoffMs: now - 14 * day, nested: false },
            { path: 'optimierungsLog', cutoffMs: now - 7 * day,  nested: false },
            { path: 'assignmentLog',   cutoffMs: now - 30 * day, nested: false },
            { path: 'errorLogs',       cutoffMs: now - 30 * day, nested: false },
            { path: 'importLog',       cutoffMs: now - 30 * day, nested: false },
            { path: 'emailLog',        cutoffMs: now - 30 * day, nested: false },
            { path: 'autoCloseLog',    cutoffMs: now - 30 * day, nested: false },
            // v6.63.083 (Patrick 01.06. 21:47): rideLogs ab 60 Tagen entfernen —
            //   bei abgeschlossenen Rides brauchen wir die Audit-Trail-Einträge
            //   nicht ewig. Hier liegt jetzt das Hauptvolumen durch Phase 2.
            // v6.63.444 (Patrick 20.06. 13:44 Bridge "Datenmenge tödlich"):
            //   60 → 14 Tage. rideLogs sind technische Audit-Trails (Status-Wechsel
            //   etc), Patrick braucht im CRM nur die Rides selbst (archiveRides via
            //   scheduledArchiveCompletedRides). 14 Tage reicht für nachträgliche
            //   Diagnose. -75% rideLogs-Volumen (von 4 MB auf ~1 MB).
            { path: 'rideLogs',        cutoffMs: now - 14 * day, nested: true  },
            // v6.63.444: rideScoresHistory war 1.9 MB. Technische Vehicle-Bewertungs-
            //   Snapshots pro Auto-Assign-Versuch — nach 7 Tagen irrelevant.
            { path: 'rideScoresHistory', cutoffMs: now - 7 * day, nested: true  },
            // v6.63.444: wartepoolAuditLog auch trimmen — nach 14 Tagen irrelevant
            { path: 'wartepoolAuditLog', cutoffMs: now - 14 * day, nested: false },
            // v6.63.445 (Patrick 20.06. 14:09 Bridge Foto: 5.33 GB Storage, archiveRides
            //   13.7 MB, routeCache 7.2 MB Top-Verbraucher): Cleanups erweitern.
            //   archiveRides 13.7 MB — nach 90 Tagen weg (Patrick hat CRM-Daten in /customers).
            //   routeCache 7.2 MB — OSRM/Google-Routen-Cache, 30 Tage reicht (Adressen rechnen sich neu).
            //   geocodeCache 30 Tage.
            //   smsQueue 1.5 MB — abgewickelte SMS älter 7 Tage löschen.
            { path: 'archiveRides',    cutoffMs: now - 90 * day, nested: false, tsField: 'pickupTimestamp' },
            { path: 'routeCache',      cutoffMs: now - 30 * day, nested: false, tsField: 'timestamp' },
            { path: 'geocodeCache',    cutoffMs: now - 30 * day, nested: false, tsField: 'timestamp' },
            { path: 'smsQueue',        cutoffMs: now - 7 * day,  nested: false, tsField: 'processedAt' },
        ];
        const BATCH = 500;

        function extractTs(v, tsField) {
            if (!v || typeof v !== 'object') return 0;
            // v6.63.445: optional tsField (z.B. 'pickupTimestamp' für archiveRides)
            if (tsField && v[tsField]) return Number(v[tsField]) || 0;
            return Number(v.ts || v.t || v.time || v.timestamp || v.createdAt || v.pickupTimestamp || v.processedAt || 0) || 0;
        }

        for (const plan of plans) {
            try {
                if (plan.nested) {
                    // debugLogs/<category>/<id>
                    const catSnap = await db.ref(plan.path).once('value');
                    if (!catSnap.exists()) continue;
                    let total = 0;
                    for (const cat of Object.keys(catSnap.val() || {})) {
                        const subSnap = await db.ref(plan.path + '/' + cat).once('value');
                        if (!subSnap.exists()) continue;
                        const data = subSnap.val() || {};
                        const removals = {};
                        let count = 0;
                        for (const [k, v] of Object.entries(data)) {
                            if (extractTs(v, plan.tsField) < plan.cutoffMs) {
                                removals[k] = null;
                                count++;
                                if (count >= BATCH) {
                                    await db.ref(plan.path + '/' + cat).update(removals);
                                    Object.keys(removals).forEach(kk => delete removals[kk]);
                                    count = 0;
                                }
                            }
                        }
                        if (Object.keys(removals).length) {
                            await db.ref(plan.path + '/' + cat).update(removals);
                        }
                        const removed = Object.keys(data).filter(k => extractTs(data[k]) < plan.cutoffMs).length;
                        total += removed;
                    }
                    console.log(`🧹 v6.63.081 Cleanup /${plan.path}: ${total} alte Einträge entfernt`);
                } else {
                    const snap = await db.ref(plan.path).once('value');
                    if (!snap.exists()) continue;
                    const data = snap.val() || {};
                    const removals = {};
                    let count = 0;
                    let totalRemoved = 0;
                    for (const [k, v] of Object.entries(data)) {
                        if (extractTs(v, plan.tsField) < plan.cutoffMs) {
                            removals[k] = null;
                            count++;
                            totalRemoved++;
                            if (count >= BATCH) {
                                await db.ref(plan.path).update(removals);
                                Object.keys(removals).forEach(kk => delete removals[kk]);
                                count = 0;
                            }
                        }
                    }
                    if (Object.keys(removals).length) await db.ref(plan.path).update(removals);
                    console.log(`🧹 v6.63.081 Cleanup /${plan.path}: ${totalRemoved} Einträge entfernt (vor ${new Date(plan.cutoffMs).toLocaleDateString('de-DE')})`);
                }
            } catch (e) {
                console.warn(`⚠️ Cleanup ${plan.path} Fehler:`, e.message);
            }
        }
        console.log('✅ v6.63.081 scheduledLogsCleanup abgeschlossen');
    }
);

exports.scheduledHistoryCleanup = onSchedule(
    {
        schedule: '0 3 * * *',
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 120,
        memory: '256MiB'
    },
    async (event) => {
        try {
            const cutoffDays = 30;
            const cutoffMs = Date.now() - cutoffDays * 24 * 60 * 60 * 1000;
            // YYYY-MM-DD-Cutoff
            const cutoffDate = new Date(cutoffMs).toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' });

            // Tag-basierte Pfade: historicalGPS/<YYYY-MM-DD>, historicalShifts/<YYYY-MM-DD>,
            // deletedRides/<YYYY-MM-DD>, historicalSessions/<YYYY-MM-DD> (v6.62.703)
            for (const path of ['historicalGPS', 'historicalShifts', 'deletedRides', 'historicalSessions']) {
                const snap = await db.ref(path).once('value');
                if (!snap.val()) continue;
                const removals = {};
                snap.forEach(c => {
                    const dateKey = c.key;
                    if (dateKey < cutoffDate) removals[dateKey] = null;
                });
                if (Object.keys(removals).length > 0) {
                    await db.ref(path).update(removals);
                    console.log(`🧹 Cleanup ${path}: ${Object.keys(removals).length} Tage entfernt (vor ${cutoffDate})`);
                }
            }

            // debugLogs sind ts-keyed: scan + filter
            for (const sub of ['lateCheck', 'reassign']) {
                const snap = await db.ref(`debugLogs/${sub}`).once('value');
                if (!snap.val()) continue;
                const removals = {};
                snap.forEach(c => {
                    const v = c.val();
                    if (v && typeof v.ts === 'number' && v.ts < cutoffMs) removals[c.key] = null;
                });
                if (Object.keys(removals).length > 0) {
                    await db.ref(`debugLogs/${sub}`).update(removals);
                    console.log(`🧹 Cleanup debugLogs/${sub}: ${Object.keys(removals).length} Eintraege entfernt`);
                }
            }
        } catch (e) {
            console.error('scheduledHistoryCleanup Fehler:', e.message);
        }
    }
);

