// 🆕 v6.62.728 (Patrick 15.05. 10:36): Auftragsbestaetigung an Auftraggeber (Vetter etc.)
// Nach 'Auftrag uebernehmen' im Native/Web → Email mit Trip-Liste + Bestaetigungs-Bestaetigung.
exports.sendAuftragsBestaetigung = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        if (req.method !== 'POST') { res.status(405).json({ error: 'Method not allowed' }); return; }
        try {
            const { toEmail, toName, trips, auftragsId, customerName, customerNotes } = req.body;
            if (!toEmail || !trips || trips.length === 0) {
                res.status(400).json({ error: 'toEmail + trips erforderlich' });
                return;
            }
            const smtp = (await db.ref('settings/smtp').once('value')).val();
            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                res.status(400).json({ error: 'SMTP nicht konfiguriert' });
                return;
            }
            const invSettings = (await db.ref('settings/invoice').once('value')).val() || {};
            const companyName = invSettings.companyName || 'Funk Taxi Heringsdorf';
            const ownerName = invSettings.ownerName || 'Patrick Wydra';
            const companyPhone = invSettings.companyPhone || '038378-22555';
            const companyEmail = invSettings.companyEmail || smtp.user;

            const tripRows = trips.map((t, i) => {
                const dt = t.datetime ? new Date(t.datetime).toLocaleString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }) : (t.date || '?');
                const pax = t.passengers || t.pax || '?';
                const guest = t.destinationName || t.pickupName || t.guestName || '';
                return `<tr style="border-bottom:1px solid #e5e7eb;">
                    <td style="padding:8px;">${i + 1}</td>
                    <td style="padding:8px;">${dt}</td>
                    <td style="padding:8px;"><strong>${guest}</strong></td>
                    <td style="padding:8px;">${t.pickup || '?'} → ${t.destination || '?'}</td>
                    <td style="padding:8px;text-align:center;">${pax}</td>
                </tr>`;
            }).join('');

            const html = `
                <div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;color:#111827;">
                    <div style="background:#10b981;color:#fff;padding:18px 22px;border-radius:8px 8px 0 0;">
                        <h2 style="margin:0;font-size:20px;">✅ Auftragsbestätigung</h2>
                        <div style="font-size:13px;opacity:0.9;margin-top:4px;">${companyName}</div>
                    </div>
                    <div style="background:#fff;padding:22px;border:1px solid #e5e7eb;">
                        <p>Sehr geehrte Damen und Herren${toName ? ' ' + toName : ''},</p>
                        <p>vielen Dank für Ihre Buchungsanfrage. Wir bestätigen den Erhalt und die Annahme der folgenden ${trips.length} Fahrt${trips.length > 1 ? 'en' : ''}:</p>
                        ${auftragsId ? `<p style="color:#6b7280;font-size:13px;">Auftrags-ID: <strong>${auftragsId}</strong></p>` : ''}
                        <table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;">
                            <thead style="background:#f3f4f6;">
                                <tr>
                                    <th style="padding:8px;text-align:left;">#</th>
                                    <th style="padding:8px;text-align:left;">Termin</th>
                                    <th style="padding:8px;text-align:left;">Fahrgast</th>
                                    <th style="padding:8px;text-align:left;">Strecke</th>
                                    <th style="padding:8px;text-align:center;">Pax</th>
                                </tr>
                            </thead>
                            <tbody>${tripRows}</tbody>
                        </table>
                        ${customerNotes ? `<p style="background:#fef3c7;padding:10px;border-radius:6px;font-size:13px;color:#92400e;">📋 ${customerNotes}</p>` : ''}
                        <p>Bei Änderungswünschen oder Fragen melden Sie sich bitte umgehend.</p>
                        <p>Mit freundlichen Grüßen<br>${ownerName}<br><strong>${companyName}</strong></p>
                    </div>
                    <div style="background:#f9fafb;padding:14px;text-align:center;font-size:12px;color:#6b7280;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 8px 8px;">
                        📞 ${companyPhone} &nbsp;|&nbsp; ✉️ ${companyEmail}
                    </div>
                </div>`;

            const transporter = require('nodemailer').createTransport({
                host: smtp.host, port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: { user: smtp.user, pass: smtp.pass }
            });
            const fromName = smtp.fromName || companyName;
            const fromEmail = smtp.fromEmail || smtp.user;
            await transporter.sendMail({
                from: `"${fromName}" <${fromEmail}>`,
                to: toEmail,
                subject: `Auftragsbestätigung — ${trips.length} Fahrt${trips.length > 1 ? 'en' : ''} angenommen`,
                html
            });
            // Audit-Log
            await db.ref('auftragBestaetigungenLog').push({
                ts: Date.now(), toEmail, toName, customerName, auftragsId, tripCount: trips.length
            });
            res.json({ ok: true, sentAt: Date.now() });
        } catch (e) {
            console.error('sendAuftragsBestaetigung Fehler:', e.message);
            res.status(500).json({ error: e.message });
        }
    }
);

// 🆕 v6.63.090 (Patrick 02.06. 18:32): Email-Vorschau-Dialog vor Versand.
//   Native EmailPreviewActivity ruft diesen Endpoint mit dem Body den
//   Patrick im Dialog freigegeben hat. Optional Stripe-Vorkasse-Link
//   generieren + einfügen. Plus Audit-Log + Ride-Update.
//
// POST body: {
//   rideId, toEmail, subject, htmlBody, textBody?,
//   includeStripeLink (bool), includeTrackingLink (bool)
// }
exports.sendRideConfirmationEmail = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        if (req.method !== 'POST') { res.status(405).json({ error: 'Method not allowed' }); return; }
        try {
            const { rideId, toEmail, subject, htmlBody, textBody, includeStripeLink, includeTrackingLink } = req.body || {};
            if (!rideId || !toEmail || !subject || !htmlBody) {
                res.status(400).json({ error: 'rideId, toEmail, subject, htmlBody erforderlich' });
                return;
            }
            const smtp = (await db.ref('settings/smtp').once('value')).val();
            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                res.status(500).json({ error: 'SMTP nicht konfiguriert' });
                return;
            }
            const rideSnap = await db.ref(`rides/${rideId}`).once('value');
            const ride = rideSnap.val();
            if (!ride) { res.status(404).json({ error: 'Ride nicht gefunden' }); return; }

            let _stripeUrl = null;
            let _belegNr = null;

            // Stripe-Link erzeugen wenn Toggle aktiv
            if (includeStripeLink) {
                try {
                    _belegNr = `VK-${rideId.slice(-10)}-${Date.now().toString().slice(-6)}`;
                    const _gross = parseFloat(String(ride.price || '0').replace(',', '.')) || 0;
                    if (_gross < 0.5) {
                        res.status(400).json({ error: 'Preis fehlt oder zu klein für Stripe' });
                        return;
                    }
                    const stripe = await getStripe();
                    const session = await stripe.checkout.sessions.create({
                        mode: 'payment',
                        line_items: [{
                            price_data: {
                                currency: 'eur',
                                product_data: { name: `Rechnung ${_belegNr}`, description: `Fahrt ${ride.pickup || ''} → ${ride.destination || ''}` },
                                unit_amount: Math.round(_gross * 100)
                            }, quantity: 1
                        }],
                        metadata: { invoiceNumber: _belegNr, source: 'taxi-heringsdorf', rideId },
                        success_url: 'https://umwelt-taxi-insel-usedom.de/pay-ok.html',
                        cancel_url: 'https://umwelt-taxi-insel-usedom.de/pay-cancel.html'
                    });
                    _stripeUrl = session.url;
                } catch (_stripeErr) {
                    console.error('Stripe-Generation Fehler:', _stripeErr.message);
                    res.status(500).json({ error: 'Stripe-Link konnte nicht erstellt werden: ' + _stripeErr.message });
                    return;
                }
            }

            // Body anreichern mit Stripe/Tracking-Link wenn nicht schon enthalten
            let finalHtml = htmlBody;
            let finalText = textBody || htmlBody.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

            if (_stripeUrl && !finalHtml.includes('checkout.stripe.com')) {
                const stripeBlock = `<div style="margin:20px 0;text-align:center;background:#dbeafe;border-radius:8px;padding:18px;">
                    <p style="margin:0 0 12px 0;font-weight:bold;color:#1e3a8a;">💳 Bezahlung per Vorkasse (Stripe)</p>
                    <a href="${_stripeUrl}" style="display:inline-block;background:#1d4ed8;color:#fff;text-decoration:none;padding:14px 28px;border-radius:6px;font-weight:bold;font-size:16px;">Jetzt sicher bezahlen</a>
                    <p style="font-size:11px;color:#475569;margin-top:10px;word-break:break-all;">${_stripeUrl}</p>
                </div>`;
                finalHtml = finalHtml.replace(/<\/body>/i, stripeBlock + '</body>');
                if (!finalHtml.includes('</body>')) finalHtml += stripeBlock;
                finalText += `\n\nZahlungslink (Stripe): ${_stripeUrl}`;
            }

            if (includeTrackingLink) {
                const _trackUrl = `https://umwelt-taxi-insel-usedom.de/track.html?ride=${rideId}`;
                if (!finalHtml.includes('/track.html')) {
                    const trackBlock = `<p style="font-size:13px;color:#475569;">📍 Live-Status & Storno: <a href="${_trackUrl}">${_trackUrl}</a></p>`;
                    finalHtml = finalHtml.replace(/<\/body>/i, trackBlock + '</body>');
                    if (!finalHtml.includes('</body>')) finalHtml += trackBlock;
                    finalText += `\n\nLive-Status: ${_trackUrl}`;
                }
            }

            // SMTP senden
            const transporter = require('nodemailer').createTransport({
                host: smtp.host, port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: { user: smtp.user, pass: smtp.pass }
            });
            const fromName = smtp.fromName || 'Funk Taxi Heringsdorf';
            const fromEmail = smtp.fromEmail || smtp.user;
            const info = await transporter.sendMail({
                from: `"${fromName}" <${fromEmail}>`,
                to: toEmail,
                subject,
                text: finalText,
                html: finalHtml
            });

            // Ride-Update + Log
            const updates = {
                emailConfirmationSentAt: Date.now(),
                emailConfirmationTo: toEmail,
                updatedAt: Date.now()
            };
            if (includeStripeLink && _stripeUrl) {
                updates.paymentMethod = 'stripe';
                updates.paymentStatus = 'offen';
                updates._vorkasseRequested = true;
                updates.vorkasseRequestedAt = Date.now();
                updates.vorkasseRequestedBy = 'native-email-preview-dialog';
                updates.stripeCheckoutUrl = _stripeUrl;
                updates.stripeBelegNr = _belegNr;
            }
            await db.ref(`rides/${rideId}`).update(updates);
            try {
                await addRideLog(rideId, '📧', `Email-Bestätigung an ${toEmail}${includeStripeLink ? ' (mit Stripe-Link)' : ''}`, {
                    quelle: 'native-email-preview-dialog',
                    messageId: info.messageId,
                    stripeBelegNr: _belegNr,
                    subject
                });
            } catch (_logErr) {}

            res.json({
                ok: true,
                sentAt: Date.now(),
                messageId: info.messageId,
                stripeUrl: _stripeUrl,
                stripeBelegNr: _belegNr
            });
        } catch (e) {
            console.error('sendRideConfirmationEmail Fehler:', e.message);
            res.status(500).json({ error: e.message });
        }
    }
);

exports.sendInvoiceEmail = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        // CORS
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        if (req.method !== 'POST') {
            res.status(405).json({ error: 'Method not allowed' });
            return;
        }

        try {
            const {
                invoiceNumber,
                toEmail,
                toName,
                subject,
                htmlBody,
                paymentLink,  // Optional: Stripe Checkout URL
                pdfUrl,       // Optional: PDF-URL für Anhang
                attachPdf     // Optional: true = PDF als Anhang senden
            } = req.body;

            if (!toEmail || !invoiceNumber) {
                res.status(400).json({ error: 'toEmail und invoiceNumber sind erforderlich' });
                return;
            }

            // SMTP-Einstellungen aus Firebase laden
            const smtpSnap = await db.ref('settings/smtp').once('value');
            const smtp = smtpSnap.val();

            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                res.status(400).json({ error: 'SMTP nicht konfiguriert! Bitte unter Einstellungen → Rechnungseinstellungen → SMTP einrichten.' });
                return;
            }

            // Nodemailer Transporter erstellen
            const nodemailer = require('nodemailer');
            const transporter = nodemailer.createTransport({
                host: smtp.host,
                port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: {
                    user: smtp.user,
                    pass: smtp.pass
                }
            });

            // Rechnungsdaten aus Firebase laden (wenn kein htmlBody mitgegeben)
            let emailHTML = htmlBody;
            let emailSubject = subject;

            if (!emailHTML) {
                // Rechnung aus Firebase laden und HTML generieren
                const invoiceSnap = await db.ref(`invoices/${invoiceNumber}`).once('value');
                const invoice = invoiceSnap.val();

                if (!invoice) {
                    res.status(404).json({ error: `Rechnung ${invoiceNumber} nicht gefunden` });
                    return;
                }

                // Firmen-Einstellungen laden
                const settingsSnap = await db.ref('settings/invoice').once('value');
                const invSettings = settingsSnap.val() || {};
                const companyName = invSettings.companyName || 'Taxi Wydra';
                const companyPhone = invSettings.phone || '+49 151 27585179';
                const companyEmail = invSettings.email || 'taxiwydra@googlemail.com';
                const ownerName = invSettings.ownerName || 'Patrick Wydra';

                const customerName = toName || invoice.customerName || 'Kunde';
                const pdfUrl = invoice.pdfUrl || '';
                const totalGross = parseFloat(invoice.totalGross) || 0;
                const totalNet = parseFloat(invoice.totalNet) || 0;

                // Positionen-HTML
                const positions = invoice.positions || [];
                const positionsHTML = positions.map(pos => `
                    <tr>
                        <td style="padding:8px;border:1px solid #e5e7eb;">${pos.description || 'Position'}</td>
                        <td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(pos.amount).toFixed(2)} &euro;</td>
                    </tr>
                `).join('');

                // MwSt-Aufschlüsselung
                const vatBreakdown = invoice.vatBreakdown || {};
                const netBreakdown = invoice.netBreakdown || {};
                const vatRates = Object.keys(vatBreakdown).sort((a, b) => parseFloat(b) - parseFloat(a));

                let vatHTML = '';
                if (vatRates.length === 1) {
                    const rate = vatRates[0];
                    vatHTML = `<tr><td style="padding:8px;border:1px solid #e5e7eb;">zzgl. MwSt (${parseFloat(rate).toFixed(0)}%):</td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(vatBreakdown[rate]).toFixed(2)} &euro;</td></tr>`;
                } else {
                    vatHTML = vatRates.map(rate => `
                        <tr><td style="padding:8px;border:1px solid #e5e7eb;">davon Netto (${parseFloat(rate).toFixed(0)}%):</td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(netBreakdown[rate]).toFixed(2)} &euro;</td></tr>
                        <tr><td style="padding:8px;border:1px solid #e5e7eb;">davon MwSt (${parseFloat(rate).toFixed(0)}%):</td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(vatBreakdown[rate]).toFixed(2)} &euro;</td></tr>
                    `).join('');
                }

                // Bezahl-Link-Bereich (wenn Stripe aktiv)
                const stripeUrl = paymentLink || invoice.stripeCheckoutUrl || '';
                const paymentSection = stripeUrl ? `
                    <div style="background:#f0f0ff;border:2px solid #635bff;border-radius:8px;padding:15px;margin:20px 0;text-align:center;">
                        <p style="margin:0 0 10px 0;font-weight:700;color:#0a2540;">&#x1F4B3; Jetzt online bezahlen</p>
                        <a href="${stripeUrl}" style="display:inline-block;background:#635bff;color:white;padding:12px 30px;text-decoration:none;border-radius:6px;font-weight:bold;">Zur sicheren Zahlung</a>
                        <p style="font-size:12px;color:#6b7280;margin:10px 0 0 0;">Kreditkarte, Giropay oder Sofort&uuml;berweisung</p>
                    </div>
                ` : '';

                // PDF-Download-Bereich
                const pdfSection = pdfUrl ? `
                    <div style="background:#dbeafe;border-left:4px solid #3b82f6;padding:15px;margin:20px 0;">
                        <h3 style="margin-top:0;">&#x1F4C4; Ihre Rechnung als PDF</h3>
                        <p><a href="${pdfUrl}" style="display:inline-block;background:#3b82f6;color:white;padding:12px 24px;text-decoration:none;border-radius:6px;font-weight:bold;">&#x1F4E5; Rechnung herunterladen</a></p>
                    </div>
                ` : '';

                emailHTML = `
                    <div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;color:#1f2937;">
                        <div style="background:linear-gradient(135deg,#3b82f6,#1d4ed8);color:white;padding:20px;border-radius:8px 8px 0 0;text-align:center;">
                            <h2 style="margin:0;">Rechnung ${invoiceNumber}</h2>
                            <p style="margin:5px 0 0 0;opacity:0.9;">${companyName}</p>
                        </div>
                        <div style="padding:20px;background:#ffffff;border:1px solid #e5e7eb;">
                            <p>Guten Tag ${customerName},</p>
                            <p>vielen Dank f&uuml;r Ihre Fahrt mit ${companyName}!</p>

                            <h3>&#x1F4CB; Rechnungsdetails:</h3>
                            <table style="border-collapse:collapse;width:100%;margin:15px 0;">
                                <tr style="background:#f3f4f6;"><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Rechnungsnummer:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoiceNumber}</td></tr>
                                <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Datum:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoice.rideDate || ''} ${invoice.rideTime || ''}</td></tr>
                                <tr style="background:#f3f4f6;"><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Von:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoice.pickup || ''}</td></tr>
                                <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Nach:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoice.destination || ''}</td></tr>
                            </table>

                            <h3>&#x1F4CA; Positionen:</h3>
                            <table style="border-collapse:collapse;width:100%;margin:15px 0;">
                                <tr style="background:#3b82f6;color:white;"><th style="padding:8px;text-align:left;">Beschreibung</th><th style="padding:8px;text-align:right;">Betrag</th></tr>
                                ${positionsHTML}
                            </table>

                            <table style="border-collapse:collapse;width:100%;margin:15px 0;">
                                <tr style="background:#f3f4f6;"><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Netto:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${totalNet.toFixed(2)} &euro;</td></tr>
                                ${vatHTML}
                                <tr style="background:#10b981;color:white;"><td style="padding:8px;border:1px solid #059669;"><strong>Gesamt (brutto):</strong></td><td style="padding:8px;border:1px solid #059669;text-align:right;"><strong>${totalGross.toFixed(2)} &euro;</strong></td></tr>
                            </table>

                            ${paymentSection}
                            ${pdfSection}

                            <p>Bei Fragen stehen wir Ihnen gerne zur Verf&uuml;gung.</p>
                            <p>Mit freundlichen Gr&uuml;&szlig;en<br>${ownerName}<br><strong>${companyName}</strong></p>
                        </div>
                        <div style="background:#f9fafb;padding:15px;border-radius:0 0 8px 8px;text-align:center;font-size:12px;color:#6b7280;border:1px solid #e5e7eb;border-top:none;">
                            &#x1F4DE; ${companyPhone} &nbsp;|&nbsp; &#x2709; ${companyEmail}
                        </div>
                    </div>
                `;

                emailSubject = subject || `Ihre Rechnung ${invoiceNumber} - ${companyName}`;
            }

            // Absender-Name aus Settings
            const fromName = smtp.fromName || 'Taxi Wydra';
            const fromEmail = smtp.fromEmail || smtp.user;

            // 🆕 v6.22.0: PDF als Anhang herunterladen (wenn gewünscht)
            // v6.63.635: pdfUrl immer aus Invoice-Record nachladen wenn nicht explizit übergeben
            let attachments = [];
            const shouldAttachPdf = attachPdf !== false;
            let effectivePdfUrl = pdfUrl;
            if (!effectivePdfUrl && invoiceNumber) {
                try {
                    const _pSnap = await db.ref('invoices/' + invoiceNumber + '/pdfUrl').once('value');
                    if (_pSnap.val()) effectivePdfUrl = _pSnap.val();
                } catch (_pe) {}
            }
            if (!effectivePdfUrl && typeof invoice !== 'undefined' && invoice && invoice.pdfUrl) {
                effectivePdfUrl = invoice.pdfUrl;
            }

            if (shouldAttachPdf && effectivePdfUrl) {
                // v6.63.676 (Patrick 10.07. 15:11 Bridge: "gesendete PDF konnte nicht
                //   geöffnet werden weil beschädigt"): Robuster PDF-Fetch mit Content-Length-
                //   Prüfung + PDF-Header/Footer-Verifikation. Bisher konnte ein unvollständig
                //   heruntergeladenes PDF stillschweigend angehängt werden → Empfänger sah
                //   "PDF-Datei ist beschädigt". Jetzt: bei jeder Anomalie ABBRECHEN und
                //   Fehler zurückgeben statt kaputten Anhang zu senden.
                try {
                    console.log('📎 Lade PDF für Anhang:', effectivePdfUrl);
                    const https = require('https');
                    const http = require('http');
                    async function fetchPdf(url, maxRedirects = 3) {
                        return new Promise((resolve, reject) => {
                            const client = url.startsWith('https') ? https : http;
                            client.get(url, (response) => {
                                if ([301, 302, 303, 307, 308].includes(response.statusCode) && response.headers.location && maxRedirects > 0) {
                                    return fetchPdf(response.headers.location, maxRedirects - 1).then(resolve, reject);
                                }
                                if (response.statusCode !== 200) {
                                    return reject(new Error(`HTTP ${response.statusCode} beim PDF-Download`));
                                }
                                const expectedLen = parseInt(response.headers['content-length'] || '0', 10);
                                const chunks = [];
                                let totalLen = 0;
                                response.on('data', chunk => { chunks.push(chunk); totalLen += chunk.length; });
                                response.on('end', () => {
                                    const buf = Buffer.concat(chunks);
                                    // 1) Länge gegen Content-Length prüfen
                                    if (expectedLen > 0 && buf.length !== expectedLen) {
                                        return reject(new Error(`PDF-Download unvollständig: ${buf.length}/${expectedLen} Bytes`));
                                    }
                                    // 2) PDF-Header/Footer verifizieren
                                    if (buf.length < 128) {
                                        return reject(new Error(`PDF zu klein (${buf.length} Bytes) — vermutlich Fehler-Response`));
                                    }
                                    const head = buf.slice(0, 8).toString('ascii');
                                    if (!head.startsWith('%PDF-')) {
                                        return reject(new Error(`Datei ist kein PDF (Header: ${head.slice(0, 5)})`));
                                    }
                                    const tail = buf.slice(-16).toString('ascii');
                                    if (!tail.includes('%%EOF')) {
                                        return reject(new Error(`PDF-Footer fehlt (%%EOF) — Datei möglicherweise abgeschnitten`));
                                    }
                                    resolve(buf);
                                });
                                response.on('error', reject);
                            }).on('error', reject);
                        });
                    }
                    const pdfBuffer = await fetchPdf(effectivePdfUrl);
                    attachments.push({
                        filename: `rechnung-${invoiceNumber}.pdf`,
                        content: pdfBuffer,
                        contentType: 'application/pdf'
                    });
                    console.log(`📎 PDF-Anhang bereit: ${pdfBuffer.length} Bytes (Header + Footer verifiziert)`);
                } catch (pdfError) {
                    console.error('❌ PDF-Anhang FEHLGESCHLAGEN — Send wird abgebrochen:', pdfError.message);
                    res.status(500).json({
                        error: `PDF-Anhang konnte nicht erstellt werden: ${pdfError.message}. Rechnung wurde NICHT versendet — bitte PDF neu generieren und erneut versuchen.`,
                        pdfError: pdfError.message
                    });
                    return;
                }
            }

            // Email senden
            const mailOptions = {
                from: `"${fromName}" <${fromEmail}>`,
                to: toEmail,
                subject: emailSubject || `Rechnung ${invoiceNumber}`,
                html: emailHTML,
                attachments: attachments
            };

            const info = await transporter.sendMail(mailOptions);
            console.log(`📧 Email gesendet: ${invoiceNumber} → ${toEmail} (${info.messageId})`);

            // Status in Firebase aktualisieren
            const updateData = {
                emailSent: true,
                emailSentAt: Date.now(),
                emailSentTo: toEmail,
                emailSentVia: 'smtp',
                emailMessageId: info.messageId,
                status: 'versendet'
            };

            await db.ref(`invoices/${invoiceNumber}`).update(updateData);

            // Auch Ride aktualisieren wenn vorhanden
            const invoiceSnap2 = await db.ref(`invoices/${invoiceNumber}/rideId`).once('value');
            const rideId = invoiceSnap2.val();
            if (rideId) {
                await db.ref(`rides/${rideId}`).update({
                    invoiceSent: true,
                    invoiceSentAt: Date.now(),
                    invoiceSentVia: 'email',
                    invoiceSentTo: toEmail
                });
            }

            res.status(200).json({
                success: true,
                messageId: info.messageId,
                sentTo: toEmail
            });

        } catch (error) {
            console.error('❌ Email-Versand Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

