// Reminder-Eskalation alle 2h, escalation-stages basierend auf Tagen-seit-Anlage
exports.scheduledTodoReminder = onSchedule(
    { schedule: 'every 2 hours', region: 'europe-west1', timeZone: 'Europe/Berlin', timeoutSeconds: 60 },
    async () => {
        try {
            const cfgSnap = await db.ref('settings/todos').once('value');
            const cfg = cfgSnap.val() || {};
            if (cfg.remindersDisabled === true) return;
            const now = Date.now();
            const snap = await db.ref('personalTodos').orderByChild('status').equalTo('open').once('value');
            const todos = snap.val() || {};
            const escalated = [];
            for (const [id, t] of Object.entries(todos)) {
                if (!t || typeof t !== 'object') continue;
                const createdAt = Number(t.createdAt || now);
                const ageDays = (now - createdAt) / (24 * 60 * 60 * 1000);
                const dueDate = Number(t.dueDate || 0);
                const overdue = dueDate && dueDate < now;
                const dueWithin24h = dueDate && (dueDate - now) > 0 && (dueDate - now) < 24 * 60 * 60 * 1000;
                let stage = null;
                if (overdue) stage = 'overdue';
                else if (dueWithin24h) stage = 'due-soon';
                else if (ageDays >= 7) stage = 'critical';
                else if (ageDays >= 4) stage = 'mahnung';
                else if (ageDays >= 2) stage = 'erinnerung';
                if (!stage) continue;
                // Pro Stage max 1 Reminder pro 12h
                const lastRem = Number(t.lastReminderAt || 0);
                if ((now - lastRem) < 12 * 60 * 60 * 1000) continue;
                escalated.push({ id, t, stage, ageDays: Math.floor(ageDays) });
                await db.ref(`personalTodos/${id}`).update({
                    lastReminderAt: now,
                    reminderCount: (Number(t.reminderCount) || 0) + 1,
                    lastReminderStage: stage
                });
            }
            if (escalated.length === 0) return;
            const lines = escalated.map(e => {
                const tagStr = e.t.tag || '#privat';
                const stageIcon = {
                    'overdue': '🚨 ÜBERFÄLLIG',
                    'due-soon': '⏰ Heute fällig',
                    'critical': '🔴 SEIT 7+ TAGEN',
                    'mahnung': '🟠 4 Tage offen',
                    'erinnerung': '🟡 2 Tage offen'
                }[e.stage] || e.stage;
                return `${stageIcon}  <b>${tagStr}</b>\n  <code>${e.id.slice(-6)}</code>  ${e.t.title || '?'}`;
            });
            const msg = `🔔 <b>TODO-ERINNERUNG</b>\n\n${lines.join('\n\n')}\n\n<i>'done <id>' erledigen oder 'snooze <id> 2d' verschieben.</i>`;
            await sendToAllAdmins(msg, 'todo_reminder');
            console.log(`🔔 ${escalated.length} ToDo-Erinnerungen gesendet`);
        } catch (e) { console.error('scheduledTodoReminder Fehler:', e.message); }
    }
);

// 🆕 v6.41.91: Claude-Bridge Outbox-Trigger
// Wenn Claude (lokal über Browser-Session oder anderswo) was zurück an Telegram sagen will,
// schreibt es nach /claudeBridge/outbox/{ts} und dieser Trigger sendet es als Bot-Message
// an die targetChatId. Daten: { message, targetChatId, ts, sent?, via? }.
// Defaults: wenn keine targetChatId angegeben → an alle Admins.
// 🔧 v6.41.92: Optional 'via: claude' → nutzt den separaten Claude-Bot statt Hauptbot.
exports.onClaudeBridgeOutbox = onValueCreated(
    {
        ref: '/claudeBridge/outbox/{outboxId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const outboxId = event.params.outboxId;
        const data = event.data.val();
        // 🆕 v6.62.185: Keep-Warm-Heartbeats halten die Function-Instance aktiv,
        // damit Patrick keine 5-15 Sek Cold-Start-Verzoegerung mehr hat. Loescht
        // sich selbst sobald angekommen — keine Telegram-Nachricht, kein Spam.
        if (data && data.keepWarm) {
            try { await event.data.ref.remove(); } catch (_) {}
            return;
        }
        if (!data || data.sent || !data.message) return;
        try {
            // 🆕 v6.63.251 (Patrick 09.06.): parse_mode=HTML ausgeschaltet fuer Bridge-Pushes.
            // Symptom: ab 11:36 kamen Pushes zwar mit sent=True + telegramMessageId vergeben
            // in der Outbox an, wurden aber bei Patrick nicht ausgeliefert (Stille). Direct-API
            // ohne parse_mode klappte gleichzeitig. Vermutung: Telegram akzeptiert API-Call,
            // droppt aber Zustellung wenn Mix aus Unicode-Trennlinien (━) + Emojis im
            // HTML-Parser stockt. Plain-Text umgeht das komplett. HTML-Escape damit hinfaellig.
            //
            // (Alter v6.62.352-Kommentar verbleibt nur als Doku: dort war "<5" das Problem.
            // Mit parse_mode='' geht <, >, & jetzt als Literal durch — ist OK fuer Bridge.)
            const text = '🤖 ' + String(data.message).slice(0, 3500);
            const useClaudeBot = data.via === 'claude' || data.source === 'claudeBot';
            const _bridgeExtra = { parse_mode: '' }; // Plain-Text, KEIN HTML — v6.63.251
            let textMsgResult = null;
            if (data.targetChatId) {
                if (useClaudeBot) {
                    textMsgResult = await sendClaudeBotMessage(data.targetChatId, text, _bridgeExtra);
                } else {
                    textMsgResult = await sendTelegramMessage(data.targetChatId, text, _bridgeExtra);
                }
                // 🆕 v6.62.317: Silent-Fail-Schutz — sendXxxMessage returnt null wenn
                // Telegram-API ablehnt (HTML-Parse-Fehler, Throttle, Bot blockiert,
                // Token leer). Vorher wurde trotzdem sent:true gesetzt → Push-Verlust
                // war unsichtbar. Jetzt: deliveryFailed-Flag + KEIN sent:true.
                if (!textMsgResult) {
                    await event.data.ref.update({
                        deliveryFailed: true,
                        failedAt: Date.now(),
                        failReason: useClaudeBot
                            ? 'Claude-Bot sendMessage returned null (siehe Functions-Log)'
                            : 'Hauptbot sendMessage returned null (siehe Functions-Log)'
                    });
                    console.error(`❌ Bridge-OUT silent-fail outbox/${outboxId} → ${data.targetChatId} (${useClaudeBot ? 'Claude-Bot' : 'Hauptbot'})`);
                    return;
                }
            } else {
                // ohne Target → Hauptbot an alle Admins (Claude-Bot hat keine "alle"-Liste)
                await sendToAllAdmins(text);
            }
            // 🆕 v6.62.317: telegramMessageId speichern → "grauer Haken" Beweis
            // dass Telegram die Nachricht akzeptiert hat (nicht: Patrick gelesen).
            const sentUpdate = { sent: true, sentAt: Date.now() };
            if (textMsgResult?.message_id) sentUpdate.telegramMessageId = textMsgResult.message_id;
            await event.data.ref.update(sentUpdate);
            // 🆕 v6.62.60: Jede ausgehende Claude-Nachricht zählt als Heartbeat — egal ob Browser-Tab offen ist.
            try { await db.ref('claudeBridge/heartbeat').set({ ts: Date.now(), pid: 'outbox' }); } catch(_) {}
            console.log(`✅ Claude-Bridge: outbox/${outboxId} an ${data.targetChatId || 'alle Admins'} (${useClaudeBot ? 'Claude-Bot' : 'Hauptbot'}) gesendet`);

            // 🆕 v6.62.143: TTS-Voice-Version fuer lange Nachrichten (Patrick: 'die Sachen
            // vorlesen lassen'). Schwelle aus settings/bridge/voiceMinChars (Default 200).
            // Nur an einzelne targetChatId — broadcast skip wir hier (zuviel Voice-Spam).
            if (data.targetChatId && data.voice !== false) {
                try {
                    await maybeSendVoiceVersion(
                        String(data.message),       // Original ohne 🤖-Prefix
                        data.targetChatId,
                        useClaudeBot,
                        textMsgResult?.message_id    // als Reply, sodass Voice unter dem Text haengt
                    );
                } catch (_voiceErr) {
                    console.warn('TTS-Voice-Push fehlgeschlagen:', _voiceErr.message);
                }
            }
        } catch (err) {
            console.error('❌ onClaudeBridgeOutbox Fehler:', err.message);
            try { await event.data.ref.update({ error: err.message, errorAt: Date.now() }); } catch(_) {}
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.62.185: Bridge-Keep-Warm
// Patrick (01.05. 17:24): nach 15 Min Idle-Zeit haben Bridge-Pushes 5-15 Sek
// Cold-Start-Verzoegerung. Diese Schedule-Function schreibt alle 5 Min einen
// Heartbeat-Eintrag in /claudeBridge/outbox/_keepwarm-{ts} → triggert
// onClaudeBridgeOutbox → die Function bleibt warm. Heartbeat-Eintraege
// loeschen sich selbst (keepWarm-Check oben in onClaudeBridgeOutbox).
// ═══════════════════════════════════════════════════════════════
exports.scheduledClaudeBridgeKeepWarm = onSchedule(
    {
        schedule: 'every 5 minutes',
        region: 'europe-west1',
        timeZone: 'Europe/Berlin'
    },
    async (_event) => {
        const ts = Date.now();
        try {
            await db.ref('claudeBridge/outbox/_keepwarm-' + ts).set({
                keepWarm: true,
                ts: ts
            });
            console.log('🔥 Bridge Keep-Warm Heartbeat geschrieben (ts=' + ts + ')');
        } catch (err) {
            console.warn('Keep-Warm-Fehler:', err.message);
        }
    }
);

