// 🆕 v6.62.138: Invoice-Request-Trigger
// Wenn die Track-Page (oder das Kundenportal) /invoiceRequests/{rideId}
// schreibt, schicken wir die Rechnung per Email an die angegebene Adresse.
// Daten: { rideId, email, invoiceNumber?, customerName?, requestedAt, source }
// ═══════════════════════════════════════════════════════════════
exports.onInvoiceRequested = onValueCreated(
    {
        ref: '/invoiceRequests/{rideId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const data = event.data.val();
        if (!data || data.sent || !data.email) return;
        const rideId = event.params.rideId;
        try {
            // invoiceNumber bestimmen — aus payload oder aus der Ride nachladen
            let invoiceNumber = data.invoiceNumber;
            let customerName = data.customerName;
            if (!invoiceNumber || !customerName) {
                const rideSnap = await db.ref(`rides/${rideId}`).once('value');
                const ride = rideSnap.val() || {};
                invoiceNumber = invoiceNumber || ride.invoiceNumber;
                customerName = customerName || ride.customerName;
            }
            if (!invoiceNumber) {
                // 🆕 v6.62.311: Patrick (05.05. 19:25): "1 Rechnung kommt nicht beim Kunden an".
                //   Cause: Kunde klickt 'Rechnung anfordern' BEVOR Patrick die Rechnung im
                //   Admin erstellt hat. Jetzt: Telegram-Push an Patrick + ride markieren
                //   damit onRideUpdated bei nachtraeglicher Rechnungs-Erstellung re-triggert.
                await event.data.ref.update({
                    pending: true,
                    pendingReason: 'invoice-not-created-yet',
                    pendingAt: Date.now(),
                    error: null,
                    errorAt: null
                });
                try {
                    await db.ref(`rides/${rideId}`).update({
                        pendingInvoiceRequestEmail: data.email,
                        pendingInvoiceRequestSince: Date.now()
                    });
                } catch (_e) {}
                try {
                    const _custName = customerName || 'Kunde';
                    const _trackLink = `https://umwelt-taxi-insel-usedom.de/Taxi-App/track.html?ride=${rideId}`;
                    const _msg = `🧾 <b>Rechnung angefordert</b>\n\n👤 <b>Kunde:</b> ${_custName}\n📧 <b>Email:</b> ${data.email}\n🆔 <b>Ride:</b> <code>${rideId}</code>\n\n⚠️ <i>Du hast die Rechnung noch nicht erstellt.</i>\n\nBitte im Admin-Tab Rechnung anlegen — sobald <code>invoiceNumber</code> gesetzt ist, geht die Email automatisch raus.\n\n${_trackLink}`;
                    await sendToAllAdmins(_msg, 'invoice-request-pending');
                } catch (_tgErr) {
                    console.warn('onInvoiceRequested Telegram-Push Fehler:', _tgErr.message);
                }
                console.log(`📧 onInvoiceRequested ${rideId}: invoiceNumber fehlt → pending + Admin-Telegram`);
                return;
            }
            // PDF-URL fuer Anhang ermitteln
            const invSnap = await db.ref(`invoices/${invoiceNumber}`).once('value');
            const inv = invSnap.val() || {};
            // sendInvoiceEmail Cloud-Function intern aufrufen — aber die ist HTTP.
            // Wir bauen die Email-Logik direkt nach, weil es im selben Process laeuft.
            const smtpSnap = await db.ref('settings/smtp').once('value');
            const smtp = smtpSnap.val();
            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                await event.data.ref.update({ error: 'SMTP nicht konfiguriert', errorAt: Date.now() });
                console.warn('onInvoiceRequested: SMTP fehlt');
                return;
            }
            const nodemailer = require('nodemailer');
            const transporter = nodemailer.createTransport({
                host: smtp.host,
                port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: { user: smtp.user, pass: smtp.pass }
            });
            const safeName = (customerName || 'Kunde').replace(/[<>]/g, '');
            const totalGross = parseFloat(inv.totalGross) || parseFloat(inv.amount) || 0;
            const subj = `Ihre Rechnung Nr. ${invoiceNumber} — Funk Taxi Heringsdorf`;
            const html = `<!DOCTYPE html><html><body style="font-family: -apple-system, Segoe UI, Roboto, sans-serif; color:#0f172a;">
                <div style="max-width:560px; margin:0 auto; padding:20px;">
                    <div style="background:linear-gradient(135deg,#3b82f6,#0ea5e9); padding:24px; border-radius:12px 12px 0 0; color:white;">
                        <h2 style="margin:0;font-size:20px;">🧾 Ihre Rechnung</h2>
                        <p style="margin:4px 0 0 0;font-size:13px;opacity:.95;">Funk Taxi Heringsdorf</p>
                    </div>
                    <div style="background:#f8fafc; padding:20px; border:1px solid #e2e8f0; border-top:none; border-radius:0 0 12px 12px;">
                        <p>Sehr geehrte/r ${safeName},</p>
                        <p>vielen Dank für Ihre Fahrt mit uns! Im Anhang dieser Email finden Sie Ihre Rechnung als PDF.</p>
                        <ul style="line-height:1.8;">
                            <li>Rechnungs-Nr.: <b>${invoiceNumber}</b></li>
                            <li>Betrag: <b>${totalGross.toFixed(2).replace('.', ',')} €</b></li>
                        </ul>
                        ${inv.pdfUrl ? `<p style="margin-top:20px;text-align:center;"><a href="${inv.pdfUrl}" style="display:inline-block;padding:12px 24px;background:#3b82f6;color:white;text-decoration:none;border-radius:8px;font-weight:600;">⬇️ Rechnung anzeigen / herunterladen</a></p>` : ''}
                        <p style="margin-top:20px;font-size:12px;color:#64748b;">Bei Fragen erreichen Sie uns unter 038378 / 22022.</p>
                        <p style="font-size:12px;color:#64748b;">Mit freundlichen Grüßen<br>Patrick Wydra<br>Funk Taxi Heringsdorf</p>
                    </div>
                </div>
            </body></html>`;
            const mailOptions = {
                from: `"Funk Taxi Heringsdorf" <${smtp.user}>`,
                to: data.email,
                subject: subj,
                html
            };
            // PDF-Anhang
            if (inv.pdfUrl) {
                try {
                    mailOptions.attachments = [{
                        filename: `Rechnung-${invoiceNumber}.pdf`,
                        path: inv.pdfUrl
                    }];
                } catch (_e) { /* if path-based fails, mail goes without attachment */ }
            }
            const info = await transporter.sendMail(mailOptions);
            await event.data.ref.update({
                sent: true,
                sentAt: Date.now(),
                messageId: info.messageId || null
            });
            console.log(`✅ onInvoiceRequested: Email an ${data.email} fuer Rechnung ${invoiceNumber}`);
        } catch (err) {
            console.error('❌ onInvoiceRequested Fehler:', err.message);
            try { await event.data.ref.update({ error: err.message, errorAt: Date.now() }); } catch(_) {}
        }
    }
);

// 🆕 v6.41.95: Auto-Forward von /debugErrors → /claudeBridge/inbox.
// Wenn der JS-Crash-Logger einen neuen Eintrag schreibt (Window-Error,
// Unhandled-Rejection, console.error, native Crash via __reportNativeCrash),
// landet der zusätzlich in der Claude-Bridge — ich sehe ihn live im Polling
// statt manuell zu suchen.
// 🛡️ Filter: nur Einträge mit 'kind' aus echten Fehlerklassen (kein 'battery_check' o.ä.).
exports.onDebugErrorForwardToBridge = onValueCreated(
    {
        ref: '/debugErrors/{errorId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const errorId = event.params.errorId;
        const data = event.data.val();
        if (!data || !data.kind) return;
        const realErrorKinds = ['window.error', 'unhandledrejection', 'console.error', 'native'];
        if (!realErrorKinds.includes(data.kind)) return; // battery_check etc. nicht spammen

        // v6.62.247: Throttle — pro identischer (kind+message)-Kombination max 1 Push pro 5 Min.
        // v6.62.721 (15.05. 06:55): Timestamps + ISO-Dates aus Message rausfiltern damit
        // Throttle nicht von "[2026-05-14T16:50:32.196Z]" geprefixten Crashes umgangen wird.
        // v6.62.722 (15.05. 08:09): permission_denied + read/write errors auf SETTINGS/* werden
        // jetzt KOMPLETT auf einen einzigen Fingerprint kollabiert (war: pro Pfad einzeln).
        // Wenn Patrick einen alten Tab nicht eingeloggt offen hat, spammt er sonst pro
        // settings/* Pfad einen einzelnen Crash → 30+ unique Pushes.
        let cleanedMsg = (data.message || '').slice(0, 400)
            .replace(/\[\d{4}-\d{2}-\d{2}T[\d:.]+Z\]/g, '[TS]')
            .replace(/\d{13}/g, '[MS]')
            .replace(/\d{10}/g, '[S]');
        // permission_denied auf irgendeinem Pfad → einheitlicher Fingerprint
        if (/permission[_ ]denied|PERMISSION_DENIED/i.test(cleanedMsg)) {
            cleanedMsg = 'PERMISSION_DENIED firebase read/write (collapsed)';
        }
        const fingerprint = require('crypto').createHash('md5')
            .update((data.kind || '') + '|' + cleanedMsg.slice(0, 200))
            .digest('hex').slice(0, 16);
        const throttleRef = db.ref(`debugErrorThrottle/${fingerprint}`);
        const lastSnap = await throttleRef.once('value');
        const lastTs = lastSnap.val();
        const now = Date.now();
        if (lastTs && (now - lastTs) < 5 * 60 * 1000) {
            // Throttled — increment counter, kein Bridge-Push
            await db.ref(`debugErrorThrottle/${fingerprint}_count`).transaction(c => (c || 0) + 1);
            console.log(`🔇 debugError ${errorId} throttled (Fingerprint ${fingerprint}, letzte Push vor ${Math.round((now - lastTs)/1000)}s)`);
            return;
        }
        await throttleRef.set(now);
        const cntSnap = await db.ref(`debugErrorThrottle/${fingerprint}_count`).once('value');
        const skippedCount = cntSnap.val() || 0;
        if (skippedCount > 0) {
            await db.ref(`debugErrorThrottle/${fingerprint}_count`).remove();
        }

        try {
            const ts = Date.now();
            const skipNote = skippedCount > 0 ? ` (vorher ${skippedCount}× wiederholt — gedrosselt)` : '';
            const summary = `🚨 JS-Crash: ${data.kind} | ${(data.message || '').slice(0, 200)} | App ${data.appVersion || '?'} | Vehicle ${data.vehicleId || '?'} | Akku ${data.battery_level || '?'}%${skipNote}`;
            await db.ref(`claudeBridge/inbox/${ts}`).set({
                ts,
                fromName: 'system',
                message: summary + (data.stack ? `\n\nStack:\n${(data.stack || '').slice(0, 1500)}` : ''),
                read: false,
                source: 'auto-debugError',
                originalRef: `/debugErrors/${errorId}`
            });
            console.log(`✅ debugError ${errorId} an Bridge weitergeleitet (Fingerprint ${fingerprint})`);
        } catch (err) {
            console.error('❌ onDebugErrorForwardToBridge Fehler:', err.message);
        }
    }
);

// 🆕 v6.41.99: rideAction — HTTP-Endpoint für Annehmen/Ablehnen-Buttons aus der
// Native-FCM-Notification. Authentifiziert über den FCM-Token (der ist Geräte-eindeutig).
// POST { rideId, action: 'accept'|'reject', vehicleId, fcmToken }
// → Updated /rides/{rideId}/{status,acceptedAt,rejectedAt,acceptedVia}
exports.rideAction = onRequest(
    { region: 'europe-west1', timeoutSeconds: 30, memory: '256MiB', minInstances: 0, invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        if (req.method !== 'POST') { res.status(405).send('Method not allowed'); return; }
        try {
            const { rideId, action, vehicleId, fcmToken } = req.body || {};
            if (!rideId || !action) { res.status(400).json({ error: 'rideId+action required' }); return; }

            // 1. FCM-Token-Auth: Token muss zum Vehicle gespeichert sein
            if (vehicleId && fcmToken) {
                const tokSnap = await db.ref(`vehicles/${vehicleId}/fcmToken/token`).once('value');
                if (tokSnap.val() !== fcmToken) {
                    console.warn(`rideAction: FCM-Token Mismatch für ${vehicleId}`);
                    res.status(403).json({ error: 'token mismatch' });
                    return;
                }
            }

            // 2. Ride-Status auf accept oder reject setzen
            const now = Date.now();
            if (action === 'accept') {
                // v6.62.9: Race-Condition-Fix — Patrick: 'Status springt immer wieder zurück'.
                // FCM-Action und Status-Button-Tap parallel: rideAction-Async-Call kommt nach
                // Status-Update an und überschreibt 'on_way' wieder mit 'accepted'.
                // Lösung: prüfe current status, kein Downgrade von on_way/arrived/picked_up/completed.
                const _curSnap = await db.ref(`rides/${rideId}`).once('value');
                const _curRide = _curSnap.val();
                const _curStatus = _curRide && _curRide.status;
                if (['on_way', 'arrived', 'picked_up', 'completed', 'cancelled', 'storniert'].includes(_curStatus)) {
                    console.log(`⏭️ rideAction: ${rideId} ist schon '${_curStatus}' — kein Downgrade auf accepted`);
                    // acceptedAt trotzdem nachpflegen (zeigt dass Fahrer Push gesehen hat)
                    if (!_curRide.acceptedAt) {
                        try {
                            await db.ref(`rides/${rideId}`).update({
                                acceptedAt: now,
                                acceptedVia: 'fcm-notification-action',
                                acceptedByVehicle: vehicleId || null
                            });
                        } catch(_) {}
                    }
                    res.status(200).json({ ok: true, action: 'accepted', alreadyProgressed: _curStatus });
                    return;
                }
                // 🛡️ v6.62.663: rejectedVehicles vom akzeptierenden Fahrzeug bereinigen
                //   (Patrick 13.05. 10:04: Tesla hatte zuvor abgelehnt, dann doch angenommen,
                //   aber rejectedVehicles enthielt es noch. Watchdog dachte "Tesla hat nicht
                //   bestaetigt" → Re-Assign auf Prius. Bug-Quelle.)
                // 🆕 v6.62.936 (Patrick 25.05. 14:37 "warum kann es zu mir zurückkommen wenn
                //   ich abgelehnt habe?"): Wenn nach dem Filter <=1 Element uebrig bleibt, war
                //   die Logik vorher rejectedVehicles=null zu setzen — das wischte ALLE OTHER
                //   rejects weg. Jetzt nur das akzeptierende Fahrzeug rausziehen, REST belassen.
                let _cleanRejected = _curRide.rejectedVehicles || null;
                if (Array.isArray(_cleanRejected) && vehicleId) {
                    const _before = [..._cleanRejected];
                    _cleanRejected = _cleanRejected.filter(v => v !== vehicleId);
                    // ← v6.62.936: NICHT mehr auf null setzen wenn leer — leere Liste belassen
                    //   (sonst werden andere rejects geloescht durch ein null-overwrite, was im
                    //   Folge-Lauf scheduledAutoAssign nicht weiss dass es vermeiden soll)
                    if (_before.length !== _cleanRejected.length) {
                        console.log(`🛡️ v6.62.936 rideAction Accept: ${vehicleId} aus rejectedVehicles entfernt, bleibt: ${_cleanRejected.join(',') || '[]'}`);
                    }
                }
                const _acceptUpdate = {
                    status: 'accepted',
                    acceptedAt: now,
                    acceptedVia: 'fcm-notification-action',
                    acceptedByVehicle: vehicleId || null,
                    updatedAt: now
                };
                if (Array.isArray(_cleanRejected) && _cleanRejected.length !== ((_curRide.rejectedVehicles || []).length)) {
                    _acceptUpdate.rejectedVehicles = _cleanRejected;
                }
                // 🆕 v6.62.772 (Patrick 16.05. 10:23 "Bin mit Tesla unterwegs"):
                //   Wenn vor dem FCM-Accept ein Reassign assignedVehicle genullt hat,
                //   blieb die Ride mit status='accepted' aber leerem Fahrzeug-Feld
                //   liegen. Folge: kein Track-Link-Update, keine 'Fahrer faehrt los'-
                //   SMS, Native-Dashboard erkannte die Fahrt nicht als 'meine'.
                //   Fix: assignedVehicle/vehicleId/assignedTo/vehicle/vehicleLabel/
                //   vehiclePlate aus dem akzeptierenden Fahrzeug zurueckschreiben
                //   wenn aktuell null.
                if (vehicleId && !_curRide.assignedVehicle && !_curRide.vehicleId) {
                    const _meta = OFFICIAL_VEHICLES[vehicleId] || {};
                    _acceptUpdate.assignedVehicle = vehicleId;
                    _acceptUpdate.vehicleId = vehicleId;
                    _acceptUpdate.assignedTo = vehicleId;
                    _acceptUpdate.assignedBy = 'fcm-notification-action';
                    _acceptUpdate.assignedAt = now;
                    if (_meta.name) {
                        _acceptUpdate.vehicle = _meta.name;
                        _acceptUpdate.vehicleLabel = _meta.name;
                        _acceptUpdate.assignedVehicleName = _meta.name;
                    }
                    if (_meta.plate) _acceptUpdate.vehiclePlate = _meta.plate;
                    console.log(`🔧 v6.62.772 rideAction: assignedVehicle war NULL → aus acceptedByVehicle ${vehicleId} rekonstruiert`);
                }
                await db.ref(`rides/${rideId}`).update(_acceptUpdate);
                console.log(`✅ rideAction: ${rideId} → accepted via FCM-Action (vehicle ${vehicleId}) | rejectedVehicles bereinigt`);
                try { await addRideLog(rideId, '✅', `Auftrag via FCM-Notification angenommen`, {
                    quelle: 'rideAction',
                    rejectedBereinigt: vehicleId && Array.isArray(_curRide.rejectedVehicles) && _curRide.rejectedVehicles.includes(vehicleId) ? 'ja (' + vehicleId + ')' : 'nein'
                }); } catch(_) {}
                // 🆕 v6.62.937 (Patrick 25.05. 14:37): Status-Diary Telegram
                try {
                    const _vName = (OFFICIAL_VEHICLES[vehicleId] || {}).name || vehicleId || '?';
                    const _custName = _curRide.customerName || '?';
                    const _pickup = (_curRide.pickup || '').slice(0, 50);
                    await sendToAllAdmins(
                        `✅ <b>AKZEPTIERT</b>\n📋 ${_custName} • ${_pickup}\n🚖 ${_vName}`,
                        'status_diary'
                    );
                } catch(_te) { /* non-critical */ }
                res.status(200).json({ ok: true, action: 'accepted' });
            } else if (action === 'reject') {
                // v6.62.248: rejectedVehicles[]-Array updaten + autoAssignRide direkt
                // erneut aufrufen. Vorher: nur rejectedBy (singular) wurde gesetzt, kein
                // Re-Assign — Patrick (10:30): Tesla lehnte ab, autoAssign lief nicht
                // erneut, Ride blieb manuell-zuweisungsbeduerftig.
                const _curSnap = await db.ref(`rides/${rideId}`).once('value');
                const _curRide = _curSnap.val() || {};
                // v6.63.087 (Patrick 02.06. 07:33 'Ich drücke auf Ablehnen und nichts passiert'):
                //   Status-Guard analog zu accept — wenn Fahrt bereits auf accepted/on_way/
                //   arrived/picked_up/completed/cancelled steht, NICHT downgraden auf 'new'.
                //   Sonst zerstört ein verspäteter Reject-Klick (auf altem Push) eine laufende
                //   Fahrt. Plus: HTTP-Body sagt UI was zu tun ist.
                const _curStatus = _curRide.status;
                if (['accepted','on_way','arrived','picked_up','completed','cancelled','storniert'].includes(_curStatus)) {
                    console.log(`⏭️ rideAction-Reject: ${rideId} ist schon '${_curStatus}' — kein Downgrade, ignoriere Klick`);
                    try { await addRideLog(rideId, '⏭️', `Reject-Klick ignoriert — Fahrt ist schon '${_curStatus}'`, { quelle: 'rideAction-reject v6.63.087', byVehicle: vehicleId, statusWasAlready: _curStatus }); } catch(_) {}
                    res.status(200).json({ ok: true, action: 'reject_skipped', alreadyProgressed: _curStatus, message: `Fahrt bereits ${_curStatus} — Ablehnen nicht mehr möglich` });
                    return;
                }
                // v6.63.087: Re-Assign-Guard — wenn Ride mittlerweile assignmentLocked oder auf
                //   anderem Vehicle, NICHT zurücksetzen.
                if (_curRide.assignmentLocked === true) {
                    console.log(`⏭️ rideAction-Reject: ${rideId} ist assignmentLocked — Ignore`);
                    try { await addRideLog(rideId, '🔒', `Reject-Klick ignoriert — assignmentLocked`, { quelle: 'rideAction-reject v6.63.087', byVehicle: vehicleId }); } catch(_) {}
                    res.status(200).json({ ok: true, action: 'reject_skipped', reason: 'assignmentLocked', message: 'Fahrt fest zugewiesen, nicht ablehnbar' });
                    return;
                }
                // Wenn der ablehnende Fahrer gar nicht (mehr) zugewiesen ist, ignorieren
                const _curAssigned = _curRide.assignedVehicle || _curRide.vehicleId;
                if (vehicleId && _curAssigned && _curAssigned !== vehicleId) {
                    console.log(`⏭️ rideAction-Reject: ${vehicleId} ist nicht zugewiesen (aktuell: ${_curAssigned})`);
                    try { await addRideLog(rideId, '⏭️', `Reject-Klick ignoriert — ${vehicleId} ist nicht zugewiesen (aktuell: ${_curAssigned})`, { quelle: 'rideAction-reject v6.63.087' }); } catch(_) {}
                    res.status(200).json({ ok: true, action: 'reject_skipped', reason: 'not_assigned', currentVehicle: _curAssigned, message: 'Fahrt ist auf anderem Fahrzeug — kein Ablehnen nötig' });
                    return;
                }
                const existingRejected = Array.isArray(_curRide.rejectedVehicles) ? _curRide.rejectedVehicles : [];
                const newRejected = vehicleId && !existingRejected.includes(vehicleId)
                    ? [...existingRejected, vehicleId]
                    : existingRejected;
                await db.ref(`rides/${rideId}`).update({
                    assignedVehicle: null,
                    vehicleId: null,
                    vehicle: null,
                    assignedTo: null,
                    assignedAt: null,
                    assignedBy: null,
                    assignmentExpiresAt: null,
                    status: 'new',
                    rejectedBy: vehicleId || null,
                    rejectedAt: now,
                    rejectedVia: 'fcm-notification-action',
                    rejectedVehicles: newRejected,
                    updatedAt: now
                });
                console.log(`❌ rideAction: ${rideId} → rejected by ${vehicleId}. Rejected-List: ${newRejected.join(', ')}. Versuche Re-Assign…`);
                try { await addRideLog(rideId, '❌', `Auftrag via FCM-Notification abgelehnt`, { quelle: 'rideAction', rejectedBy: vehicleId, rejectedVehicles: newRejected }); } catch(_) {}
                // 🆕 v6.62.937 (Patrick 25.05. 14:37 'Status-Diary'): Telegram
                try {
                    const _vName = (OFFICIAL_VEHICLES[vehicleId] || {}).name || vehicleId || '?';
                    const _custName = _curRide.customerName || '?';
                    const _pickup = (_curRide.pickup || '').slice(0, 50);
                    await sendToAllAdmins(
                        `❌ <b>ABGELEHNT</b>\n📋 ${_custName} • ${_pickup}\n🚖 ${_vName} hat abgelehnt → Re-Assign laeuft`,
                        'status_diary'
                    );
                } catch(_te) { /* non-critical */ }
                // Sofort autoAssignRide nochmal aufrufen mit aktualisierter Reject-List
                try {
                    const _ride = { ..._curRide, rejectedVehicles: newRejected, _rejectedVehicles: newRejected, status: 'new', vehicleId: null, assignedVehicle: null };
                    const _result = await autoAssignRide(rideId, _ride);
                    if (_result && _result.vehicleId) {
                        const _name = _result.name || (OFFICIAL_VEHICLES[_result.vehicleId] || {}).name || _result.vehicleId;
                        console.log(`✅ Reject-Re-Assign: ${rideId} → ${_name}`);
                        try { await addRideLog(rideId, '🔄', `Reject-Re-Assign: ${_name}`, { quelle: 'rideAction-reject v6.62.248', rejectedVehicles: newRejected }); } catch(_) {}
                    } else {
                        console.log(`⚠️ Reject-Re-Assign: kein anderes Fahrzeug verfügbar für ${rideId}`);
                        try { await sendToAllAdmins(`⚠️ <b>Re-Assign fehlgeschlagen</b>\n\nFahrt von ${_curRide.customerName || '?'} (${_curRide.pickup || '?'}) wurde abgelehnt — kein anderes Fahrzeug verfügbar.\n\n→ <b>Manuell zuweisen erforderlich!</b>`, 'unassigned'); } catch(_) {}
                    }
                } catch (reassignErr) {
                    console.error('❌ Reject-Re-Assign Fehler:', reassignErr.message);
                }
                res.status(200).json({ ok: true, action: 'rejected', rejectedVehicles: newRejected });
            } else {
                res.status(400).json({ error: 'unknown action' });
            }
        } catch (e) {
            console.error('rideAction Fehler:', e.message);
            res.status(500).json({ error: e.message });
        }
    }
);

// 🆕 v6.41.92: Webhook für separaten Claude-Bot.
// JEDE Admin-Nachricht hier landet im /claudeBridge/inbox — kein Prefix nötig.
// Non-Admin → höfliche Abweisung (Bot ist nur für Betreiber).
// 🆕 v6.62.317: Read-Receipt-Approximation ("blauer Haken").
// Telegram-Bot-API liefert keine echten Read-Receipts. Wir markieren stattdessen:
// Wenn Patrick (oder ein anderer Admin) eine Nachricht an den Claude-Bot schickt,
// gelten ALLE seiner pending Bridge-Pushes als "gelesen" — er ist offensichtlich
// gerade im Telegram. Wir scannen die letzten 50 outbox-Einträge (mehr braucht
// es nicht — alte sind eh vergessen).
async function markOutboxRead(chatId) {
    if (!chatId) return;
    try {
        const snap = await db.ref('claudeBridge/outbox')
            .orderByKey()
            .limitToLast(50)
            .once('value');
        const updates = {};
        const now = Date.now();
        snap.forEach(child => {
            const o = child.val();
            if (!o || !o.sent || o.readAt) return;
            if (Number(o.targetChatId) !== Number(chatId)) return;
            updates[`${child.key}/readAt`] = now;
        });
        if (Object.keys(updates).length > 0) {
            await db.ref('claudeBridge/outbox').update(updates);
        }
    } catch (e) {
        console.warn('markOutboxRead Fehler:', e.message);
    }
}

exports.claudeBotWebhook = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, memory: '256MiB', minInstances: 0, invoker: 'public' },
    async (req, res) => {
        if (req.method === 'GET') {
            res.set('Access-Control-Allow-Origin', '*');
            res.json({ name: 'claudeBotWebhook', status: 'ok' });
            return;
        }
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        if (req.method !== 'POST') { res.status(200).send('Claude-Bot Webhook'); return; }

        // Webhook-Secret validieren (eigenes Secret, nicht das vom Hauptbot)
        const expectedSecret = await ensureClaudeBotWebhookSecret();
        const incoming = req.headers['x-telegram-bot-api-secret-token'];
        if (!incoming || incoming !== expectedSecret) {
            res.status(403).send('Forbidden');
            return;
        }

        try {
            const update = req.body;
            const msg = update?.message;
            if (!msg) { res.status(200).send('OK'); return; }
            const chatId = msg.from?.id || msg.chat?.id;
            const fromName = msg.from?.first_name || msg.from?.username || 'admin';
            // 🆕 v6.62.317: User schickt was → markiere alle seine pending Pushes
            // als gelesen ("blauer Haken"-Approximation). Fire-and-forget, blockiert
            // den Webhook nicht.
            markOutboxRead(chatId).catch(_ => {});

            // 🆕 v6.41.94: Foto / Screenshot → Claude Vision → Beschreibung in Inbox
            if (Array.isArray(msg.photo) && msg.photo.length > 0) {
                if (!await isTelegramAdmin(chatId)) {
                    await sendClaudeBotMessage(chatId, '🤖 Bilder nur für Admins.');
                    res.status(200).send('OK');
                    return;
                }
                await sendClaudeBotMessage(chatId, '🖼️ <i>Bild wird analysiert…</i>');
                const claudeToken = await loadClaudeBotToken();
                const bestPhoto = msg.photo[msg.photo.length - 1]; // höchste Auflösung
                const description = await describeImageForClaudeBridge(claudeToken, bestPhoto.file_id, msg.caption || '');
                const ts = Date.now();
                const inboxMsg = (msg.caption ? `[Bildunterschrift: "${msg.caption}"]\n\n` : '') +
                    `[Bild-Beschreibung]\n${description}`;
                await db.ref(`claudeBridge/inbox/${ts}`).set({
                    ts,
                    fromChatId: chatId,
                    fromName,
                    message: inboxMsg.slice(0, 4000),
                    read: false,
                    source: 'claudeBot+photo'
                });
                // v6.62.60: Online/Offline-Hinweis entfernt — Heartbeat war fragil und alarmistisch
                await sendClaudeBotMessage(chatId,
                    `🖼️ <b>Bild analysiert:</b>\n<i>"${description.slice(0, 800)}"</i>\n\n📥 Posteingang #${ts}.`);
                res.status(200).send('OK');
                return;
            }

            // 🆕 v6.41.92: Sprachnachricht / Audio-Datei → Whisper-Transkription → in Inbox
            const isAudioDoc = msg.document && /^(audio\/|video\/ogg|application\/ogg)/.test(msg.document.mime_type || '') ;
            const audioFileId = msg.voice?.file_id || msg.audio?.file_id || (isAudioDoc ? msg.document.file_id : null);
            if (audioFileId) {
                if (!await isTelegramAdmin(chatId)) {
                    await sendClaudeBotMessage(chatId, `🤖 Sprachnachrichten nur für Admins. Bitte schreibe als Text oder ruf an: 038378/22022`);
                    res.status(200).send('OK');
                    return;
                }
                await sendClaudeBotMessage(chatId, '🎙️ <i>Sprachnachricht wird transkribiert…</i>');
                const claudeToken = await loadClaudeBotToken();
                const transcript = await transcribeAudio(claudeToken, audioFileId, 'Patrick spricht über Taxi-App-Themen: Buchungen, Schichten, Fahrer, Crashes, Bugs, Code-Änderungen.');
                if (!transcript) {
                    await sendClaudeBotMessage(chatId, '⚠️ Konnte nichts erkennen. Bitte als Text senden.');
                    res.status(200).send('OK');
                    return;
                }
                const ts = Date.now();
                await db.ref(`claudeBridge/inbox/${ts}`).set({
                    ts,
                    fromChatId: chatId,
                    fromName,
                    message: transcript.slice(0, 4000),
                    read: false,
                    source: 'claudeBot+voice'
                });
                // v6.62.60: Online/Offline-Hinweis entfernt
                await sendClaudeBotMessage(chatId,
                    `🎙️ <b>Transkribiert:</b>\n<i>"${transcript.slice(0,1000)}"</i>\n\n📥 In Posteingang (#${ts}).`);
                res.status(200).send('OK');
                return;
            }

            // Ab hier nur noch Text-Nachrichten
            if (!msg.text) {
                res.status(200).send('OK');
                return;
            }
            const text = (msg.text || '').trim();

            // Spezielle Slash-Commands für den Claude-Bot
            if (text === '/start' || text === '/start@' || text.startsWith('/start ')) {
                await sendClaudeBotMessage(chatId,
                    `🤖 <b>Claude-Bot aktiv</b>\n\n` +
                    `Du kannst hier <b>direkt drauflos schreiben</b> — alles geht in meinen Posteingang. ` +
                    `Kein Prefix nötig.\n\n` +
                    `Antworten kommen über diesen Chat zurück.\n\n` +
                    (await isTelegramAdmin(chatId)
                        ? `✅ Du bist als Admin erkannt (chatId: ${chatId}).`
                        : `⚠️ Deine Chat-ID (${chatId}) ist NICHT in den Admin-Liste. Bitte in /settings/telegram/adminChats eintragen.`));
                res.status(200).send('OK');
                return;
            }
            if (text === '/help' || text === '/hilfe') {
                await sendClaudeBotMessage(chatId,
                    `🤖 Schreib einfach drauflos — jede Nachricht geht direkt an Claude.\n\n` +
                    `Befehle:\n` +
                    `/start — Begrüßung + Status\n` +
                    `/help — diese Hilfe\n` +
                    `/inbox — wie viele ungelesene Nachrichten warten\n` +
                    `/todo — offene Aufgaben (oder einfach "todo" tippen)`);
                res.status(200).send('OK');
                return;
            }
            if (text === '/inbox') {
                const inboxSnap = await db.ref('claudeBridge/inbox').once('value');
                let unread = 0, total = 0;
                inboxSnap.forEach(c => { total++; if (!c.val()?.read) unread++; });
                await sendClaudeBotMessage(chatId, `📥 Posteingang: ${unread} ungelesen / ${total} gesamt.`);
                res.status(200).send('OK');
                return;
            }

            // 🆕 v6.62.208: /todo + 'todo' — listet offene Aufgaben aus /claudeBridge/tasks.
            // Patrick (03.05.): "Kannst du das mal bitte alles als To-Do, alles, was ich
            // so sage, aufschreiben". Tasks werden von Claude gepflegt — Bot zeigt sie nur an.
            const _txtLower = text.toLowerCase();
            if (text === '/todo' || _txtLower === 'todo' || _txtLower === 'aufgaben' || _txtLower === '/aufgaben') {
                if (!await isTelegramAdmin(chatId)) {
                    await sendClaudeBotMessage(chatId, '🤖 ToDo-Liste nur für Admins.');
                    res.status(200).send('OK');
                    return;
                }
                const tasksSnap = await db.ref('claudeBridge/tasks').once('value');
                const tasks = tasksSnap.val() || {};
                const arr = Object.entries(tasks)
                    .map(([id, t]) => ({ id, ...t }))
                    .filter(t => t && t.status !== 'completed' && t.status !== 'deleted')
                    .sort((a, b) => (a.priority || 99) - (b.priority || 99) || (a.createdAt || 0) - (b.createdAt || 0));
                if (arr.length === 0) {
                    await sendClaudeBotMessage(chatId, '✅ Keine offenen Aufgaben in der ToDo-Liste. Sage mir was — und es landet hier.');
                    res.status(200).send('OK');
                    return;
                }
                const lines = arr.slice(0, 30).map((t, i) => {
                    const icon = t.status === 'in_progress' ? '⏳' : '⬜';
                    const subj = (t.subject || '(ohne Titel)').slice(0, 100);
                    const since = t.createdAt ? `<i>seit ${new Date(t.createdAt).toLocaleDateString('de-DE')}</i>` : '';
                    return `${icon} <b>${i + 1}.</b> ${subj} ${since}`;
                });
                const more = arr.length > 30 ? `\n\n<i>… und ${arr.length - 30} weitere.</i>` : '';
                await sendClaudeBotMessage(chatId,
                    `📋 <b>Offene Aufgaben (${arr.length})</b>\n\n` + lines.join('\n') + more +
                    `\n\n<i>Stand: ${new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' })}</i>`);
                res.status(200).send('OK');
                return;
            }

            // Admin-Check — alles andere wird abgewiesen
            if (!await isTelegramAdmin(chatId)) {
                await sendClaudeBotMessage(chatId,
                    `🤖 Hallo ${fromName}! Dieser Bot ist nur für den Betreiber von Funk Taxi Heringsdorf.\n\n` +
                    `Für Buchungen wende dich bitte an den Buchungs-Bot oder ruf an: 038378/22022`);
                res.status(200).send('OK');
                return;
            }

            // Admin-Nachricht → direkt in den Posteingang
            const ts = Date.now();
            await db.ref(`claudeBridge/inbox/${ts}`).set({
                ts,
                fromChatId: chatId,
                fromName,
                message: text.slice(0, 4000),
                read: false,
                source: 'claudeBot'
            });
            // v6.62.60: Heartbeat-Drama raus — schlichte Bestätigung. Antworten kommen via Outbox-Trigger.
            await sendClaudeBotMessage(chatId, `📥 Notiz gespeichert (#${ts}).`);
            res.status(200).send('OK');
        } catch (err) {
            console.error('❌ claudeBotWebhook Fehler:', err.message);
            res.status(200).send('OK'); // Telegram nicht retry-en
        }
    }
);

// 🆕 v6.41.92: Setup-Endpoint — User legt Claude-Bot-Token + registriert Webhook in einem Schritt.
// Aufruf: GET https://...setupClaudeBot?token=BOTFATHER_TOKEN
// Speichert Token, generiert Webhook-Secret, ruft Telegram setWebhook auf.
exports.setupClaudeBot = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        const token = req.query.token || req.body?.token;
        if (!token || !/^\d+:[A-Za-z0-9_-]{30,}$/.test(token)) {
            res.status(400).send('❌ Token fehlt oder ist ungültig. Aufruf: setupClaudeBot?token=DEIN_BOT_TOKEN');
            return;
        }
        try {
            // 1. Token speichern
            await db.ref('settings/telegram/claudeBotToken').set(token);
            claudeBotToken = token; // Cache
            // 2. Webhook-Secret generieren
            const secret = await ensureClaudeBotWebhookSecret();
            // 3. Webhook bei Telegram registrieren
            const webhookUrl = `https://europe-west1-taxi-heringsdorf.cloudfunctions.net/claudeBotWebhook`;
            const resp = await fetch(`https://api.telegram.org/bot${token}/setWebhook`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    url: webhookUrl,
                    secret_token: secret,
                    drop_pending_updates: true,
                    allowed_updates: ['message']
                })
            });
            const data = await resp.json();
            if (!data.ok) {
                res.status(500).send(`❌ Telegram setWebhook fehlgeschlagen: ${data.description}`);
                return;
            }
            // 4. Bot-Commands setzen damit /start, /help, /inbox im Telegram-Menü erscheinen
            await fetch(`https://api.telegram.org/bot${token}/setMyCommands`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    commands: [
                        { command: 'start', description: '👋 Bot starten' },
                        { command: 'help', description: 'ℹ️ Hilfe' },
                        { command: 'inbox', description: '📥 Posteingang-Status' },
                        { command: 'todo', description: '📋 Offene Aufgaben' }
                    ]
                })
            }).catch(() => {});
            res.status(200).send(`✅ Claude-Bot eingerichtet!\n\nWebhook: ${webhookUrl}\n\nÖffne deinen neuen Bot in Telegram und schreibe /start.`);
        } catch (e) {
            res.status(500).send(`❌ Fehler: ${e.message}`);
        }
    }
);


// ═══════════════════════════════════════════════════════════════
// 🆕 v6.62.308: BUCHHALTUNGS-FOUNDATION — Belege → SKR03 → DATEV-CSV
// (Original-Idee aus PR #1098 v6.62.129 vom 29.04. — Branch zu alt
// fuer Merge, daher fresh in v6.62.308 portiert auf aktuelles main.)
//
// Workflow:
// 1. Patrick scannt Beleg (Foto/PDF) → POST /classifyReceipt
// 2. Anthropic Vision (claude-sonnet-4-6) extrahiert: lieferant, datum,
//    brutto/netto/ustSatz, skr03Konto-Vorschlag, confidence
// 3. Gespeichert in /belegImport/{batchId}/{belegId} mit bestaetigt:false
// 4. Patrick bestaetigt im DMS (UI in v6.62.309)
// 5. GET /datevExport?batchId=X liefert DATEV-CSV (nur bestaetigte Zeilen)
//
// Belegnr-Schema v6.62.308 (GoBD-konform, lueckenlos pro Typ+Monat):
//   JJJJ-MM-TYP-NNNN  z.B. 2026-05-EINR-0042
//   Typen: EINR (Eingangsrechnung), AUSR (Ausgangsrechnung), KAS, BANK,
//          LOHN, SONST, PRIV (privat). Counter atomar via DB-Transaction.
// ═══════════════════════════════════════════════════════════════

// 🆕 v6.62.337: Patrick (06.05. 09:25): "Kannst du die Kontenlisten nicht aus dem Internet
// laden... Das System muesste auch gleich die richtige Zuordnung machen."
// → Ausgelagert nach functions/skr03.js mit ~70 kuratierten Konten (statt 24 hardcoded).
const _skr03 = require('./skr03');
const SKR03_KONTEN_PROMPT = _skr03.SKR03_KONTEN_PROMPT;

exports.classifyReceipt = onRequest(
    { region: 'europe-west1', invoker: 'public', timeoutSeconds: 120, memory: '512MiB' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        if (req.method !== 'POST') { res.status(405).json({ error: 'POST required' }); return; }
        const key = req.query.key;
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const validKey = keySnap.val() || 'funk-taxi-heringsdorf-2026';
        if (!key || key !== validKey) { res.status(403).json({ error: 'Forbidden' }); return; }
        try {
            const body = (typeof req.body === 'object') ? req.body : JSON.parse(req.body || '{}');
            const { fileBase64, mediaType, filename, batchId } = body;
            if (!fileBase64) { res.status(400).json({ error: 'fileBase64 required' }); return; }
            const _media = mediaType || 'application/pdf';
            const anthropicKey = await getAnthropicApiKey();
            if (!anthropicKey) { res.status(500).json({ error: 'Kein Anthropic API Key' }); return; }

            const prompt = `Du analysierst einen deutschen Beleg/Rechnung/Quittung fuer die Buchhaltung von "Funk Taxi Heringsdorf" (Patrick Wydra, Kanalstr. 1, 17424 Heringsdorf).

Extrahiere als striktes JSON:
- lieferant: Firmenname (z.B. "Aral Tankstelle Heringsdorf", "Werkstatt Mueller GmbH", "Telekom Deutschland")
- datum: Belegdatum im Format "YYYY-MM-DD"
- brutto: Endbetrag inkl. USt (Number, Euro)
- netto: Nettobetrag (Number, Euro)
- ustBetrag: USt-Betrag (Number, Euro)
- ustSatz: 7 oder 19 (Number)
- belegNr: Beleg-/Rechnungsnummer wenn erkennbar (String oder null)
- zahlungsart: "bar"|"karte"|"ueberweisung"|"unbekannt"
- bereich: Vermutung wer den Beleg verbucht: "taxi" (Standardfall fuer Funk Taxi), "ferienwohnung" (wenn Wasser/Strom/Reinigung fuer eine private Ferienwohnung), "privat" (eindeutig privat)
- skr03Konto: 4-stelliges SKR03-Konto aus DIESER Liste:
${SKR03_KONTEN_PROMPT}
- skr03Bezeichnung: lesbarer Name des Kontos
- confidence: 0.0-1.0 wie sicher du bist mit der Konto-Zuordnung
- hint: 1 kurzer Satz Begruendung fuer die Zuordnung (Deutsch)
- lieferantEmail: Email-Adresse des Lieferanten wenn auf dem Beleg sichtbar (z.B. info@aral.de) oder null
- lieferantTelefon: Telefonnummer des Lieferanten im internationalen oder deutschen Format (z.B. +49 30 12345678 oder 030 12345678) oder null
- lieferantWebsite: Website des Lieferanten wenn sichtbar (z.B. www.aral.de) oder null
- hauptKategorie: Hauptkategorie aus DIESER Liste: "Fahrzeuge", "Verträge", "Krankenkasse", "Büro", "Steuer/Behörden", "Marketing/Werbung", "Telekommunikation", "Reisekosten", "Sonstiges"
- subKategorie: passende Unter-Kategorie z.B. "TÜV", "Werkstatt", "Tanken", "Versicherung", "Stromvertrag", "Mobilfunk", "Internet", "Software-Abo", "Berufsverband", "Bank", "Steuerberater", "Lohnsteuer", "USt-Voranmeldung", "Angestellten-KK", "Privat-KK", "Buero-Material", "Werbeflyer", "Hotel" (oder eine sinnvolle neue Kategorie wenn keiner passt)
- lieferantOrdner: Kurzname des Lieferanten als Ordnername (z.B. "TÜV Rheinland", "AOK Nordost", "Aral", "Telekom" — wie er im Filing-System gefuhrt wird)
- rawText: alle sichtbaren Texte des Belegs wortgenau

Gib NUR das JSON zurueck, kein Markdown, kein Pre/Post-Text. Bei fehlenden Feldern: null. Achte besonders darauf, ob der Beleg ueberhaupt eine Ausgabe ist — wenn es eine eingehende Zahlung/Erloes ist, nutze 8400/8401.`;

            const visionResp = await callAnthropicAPI(anthropicKey, 'claude-sonnet-4-6', 4000, [{
                role: 'user',
                content: [
                    { type: 'document', source: { type: 'base64', media_type: _media, data: fileBase64 } },
                    { type: 'text', text: prompt }
                ]
            }]);
            const text = (visionResp.content?.[0]?.text || '').trim();
            let jsonText = text;
            const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
            if (m) jsonText = m[1].trim();
            let parsed = null;
            try { parsed = JSON.parse(jsonText); }
            catch (parseErr) {
                console.error('classifyReceipt JSON-Parse:', parseErr.message);
                res.status(200).json({ ok: false, error: 'KI-Antwort kein valides JSON', rawText: text });
                return;
            }

            // v6.62.308: Belegnr-Schema JJJJ-MM-TYP-NNNN — lueckenlos pro Typ+Monat (GoBD)
            const _isErloes = parsed.skr03Konto && String(parsed.skr03Konto).startsWith('84');
            const _typForBelegNr = _isErloes ? 'AUSR' : 'EINR';
            const _belegDate = parsed.datum && /^\d{4}-\d{2}-\d{2}$/.test(parsed.datum)
                ? parsed.datum
                : new Date().toISOString().slice(0, 10);
            const _yyyymm = _belegDate.slice(0, 7); // YYYY-MM
            const _counterRef = db.ref(`belegCounter/${_yyyymm}/${_typForBelegNr}`);
            const _counterTx = await _counterRef.transaction(curr => (curr || 0) + 1);
            const _counterValue = _counterTx.snapshot.val() || 1;
            const _belegNrFormatted = `${_yyyymm}-${_typForBelegNr}-${String(_counterValue).padStart(4, '0')}`;
            const _physOrdner = `${_yyyymm}-${_typForBelegNr}`;

            const _batchId = batchId || ('batch_' + new Date().toISOString().slice(0, 10));

            // 🆕 v6.62.335: Patrick (06.05. 09:18): "Dubletten-Erkennung funktioniert?"
            // Vor dem Speichern pruefen ob Lieferant + Datum + Brutto schon existiert.
            let _isDuplicate = false;
            let _duplicateOf = null;
            if (parsed.lieferant && parsed.datum && parsed.brutto) {
                try {
                    const _allBatches = await db.ref('belegImport').once('value');
                    _allBatches.forEach(_batch => {
                        _batch.forEach(_b => {
                            const _bd = _b.val();
                            if (!_bd || !_bd.parsed) return;
                            if (_isDuplicate) return;
                            if (
                                _bd.parsed.lieferant && _bd.parsed.datum && _bd.parsed.brutto &&
                                _bd.parsed.lieferant.toLowerCase().trim() === parsed.lieferant.toLowerCase().trim() &&
                                _bd.parsed.datum === parsed.datum &&
                                Math.abs(parseFloat(_bd.parsed.brutto) - parseFloat(parsed.brutto)) < 0.01
                            ) {
                                _isDuplicate = true;
                                _duplicateOf = { batchId: _batch.key, id: _b.key, belegNr: _bd.belegNr };
                            }
                        });
                    });
                } catch (_dupErr) { console.warn('Dubletten-Check Fehler:', _dupErr.message); }
            }

            const belegRef = db.ref(`belegImport/${_batchId}`).push();
            await belegRef.set({
                t: Date.now(),
                filename: filename || 'unbekannt',
                mediaType: _media,
                parsed,
                bestaetigt: false,
                belegNr: _belegNrFormatted,
                typ: _typForBelegNr,
                physOrdner: _physOrdner,
                physPosition: _counterValue,
                eingangsDatum: new Date().toISOString().slice(0, 10),
                belegDatum: _belegDate,
                isDuplicate: _isDuplicate,
                duplicateOf: _duplicateOf
            });

            res.status(200).json({
                ok: true, parsed, belegId: belegRef.key, batchId: _batchId,
                belegNr: _belegNrFormatted, physOrdner: _physOrdner, physPosition: _counterValue,
                isDuplicate: _isDuplicate, duplicateOf: _duplicateOf
            });
        } catch (err) {
            console.error('classifyReceipt Fehler:', err.message);
            res.status(500).json({ error: err.message });
        }
    }
);

// 🆕 v6.62.335: Patrick (06.05. 09:17): "kannst du das so gestalten dass die KI das
// Dokument durchliest, weiss was drin steht und mir verschiedene Vorlagen gibt was man
// dem Empfaenger antworten kann oder fragen bezugnehmend auf dieses Dokument".
