// 🆕 v6.62.356 (06.05.): Telefonnummern aus Volltext nachziehen
// Patrick (06.05. 12:56): "Selbst wo Telefonnummern dabei waren, werden
// keine angezeigt — würde ich gerne kontrolliert haben". Befund: 4 von
// 10 Belegen haben Nummern im KI-Volltext aber lieferantPhone=null,
// weil die KI sie nicht ins JSON-Feld uebernommen hat.
//
// Diese Function durchsucht den Volltext aller /docs nach deutschen
// Telefonnummern und schreibt die erste gefundene in lieferantPhone
// wenn das Feld leer ist. Aufruf via /backfillDocPhones (Admin-Button
// in dms.html oder direkt URL aufrufen).
function extractGermanPhoneFromText(text) {
    if (!text) return null;
    const t = String(text);
    // Patterns nach Genauigkeit absteigend
    const patterns = [
        /(?:Tel(?:efon)?|Fon|T\.|☎)[\s.:]*\+?(\d[\d\s\-/()]{7,20}\d)/i,
        /\+49[\s\-/]?\d{2,4}[\s\-/]?\d{3,9}/,
        /\b0\d{2,4}[\s\-/]?\d{3,9}\b/
    ];
    for (const re of patterns) {
        const m = t.match(re);
        if (m) {
            // Erst bei Group 1 nehmen (Tel-Pattern), sonst Match[0]
            const raw = (m[1] || m[0]).replace(/[\s.\-/()]/g, '');
            // Nur wenn 6+ Ziffern und kein Datum/Betrag-Match (z.B. 4262 oder 12.05.2026)
            const digits = raw.replace(/\D/g, '');
            if (digits.length >= 7 && digits.length <= 14) {
                // Zurueckformatieren mit '/' nach Vorwahl wenn 0xx
                if (digits.startsWith('0')) return digits.slice(0, 5) + ' ' + digits.slice(5);
                if (digits.startsWith('49')) return '+' + digits.slice(0, 2) + ' ' + digits.slice(2);
                return digits;
            }
        }
    }
    return null;
}

// 🆕 v6.62.367: Belegnummern-Backfill fuer alte Belege ohne Nummer
// Patrick (06.05. 15:10): "Belegnummern-Backfill als 1. Punkt" — gelbe Warnungen
// 'keine Belegnummer' bei alten Belegen weg.
//
// Geht alle /docs ohne belegnummer durch, sortiert chronologisch nach datum
// (Fallback: uploadedAt), vergibt pro Quartal fortlaufend Nummern via atomic
// Firebase-Transaction. Format: YYYY-QN-NNNN — gleich wie Live-Vergabe.
exports.backfillBelegnummern = onRequest(
    { region: 'europe-west1', invoker: 'public', timeoutSeconds: 120, memory: '256MiB' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        try {
            const dryRun = req.query.dryRun === '1' || req.query.dry === '1';
            const docsSnap = await db.ref('docs').once('value');
            const docs = docsSnap.val() || {};
            const todo = Object.entries(docs)
                .filter(([_, d]) => d && !d.belegnummer)
                .map(([id, d]) => {
                    const ts = d.datum ? new Date(d.datum + 'T12:00:00').getTime() : (d.uploadedAt || Date.now());
                    return { id, doc: d, ts };
                })
                .sort((a, b) => a.ts - b.ts);

            const results = [];
            for (const item of todo) {
                const dt = new Date(item.ts);
                const jahr = dt.getFullYear();
                const monat = dt.getMonth() + 1;
                const quartal = Math.ceil(monat / 3);
                const counterKey = `${jahr}-Q${quartal}`;
                const belegEntry = { id: item.id, lieferant: item.doc.lieferant, datum: item.doc.datum, quartal: counterKey };
                if (dryRun) {
                    belegEntry.wouldAssign = `${jahr}-Q${quartal}-???? (dry-run)`;
                } else {
                    const counterRef = db.ref('settings/dms/belegCounter/' + counterKey);
                    const result = await counterRef.transaction(curr => (curr || 0) + 1);
                    const nr = result.snapshot.val();
                    const belegnummer = `${jahr}-Q${quartal}-${String(nr).padStart(4, '0')}`;
                    await db.ref(`docs/${item.id}`).update({
                        belegnummer,
                        belegQuartal: 'Q' + quartal,
                        belegJahr: jahr,
                        belegnummerSource: 'backfill_v6.62.367'
                    });
                    belegEntry.assigned = belegnummer;
                }
                results.push(belegEntry);
            }
            res.status(200).json({ ok: true, dryRun, totalDocs: Object.keys(docs).length, processed: results.length, results });
        } catch (e) {
            res.status(500).json({ ok: false, error: e.message });
        }
    }
);

exports.backfillDocPhones = onRequest(
    { region: 'europe-west1', invoker: 'public', timeoutSeconds: 60, memory: '256MiB' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        try {
            const dryRun = req.query.dryRun === '1' || req.query.dry === '1';
            const docsSnap = await db.ref('docs').once('value');
            const docs = docsSnap.val() || {};
            const results = [];
            const updates = {};
            for (const [id, doc] of Object.entries(docs)) {
                if (!doc) continue;
                if (doc.lieferantPhone) continue; // schon vorhanden
                const phone = extractGermanPhoneFromText(doc.volltext);
                if (phone) {
                    results.push({ id, lieferant: doc.lieferant, foundPhone: phone });
                    if (!dryRun) {
                        updates[`docs/${id}/lieferantPhone`] = phone;
                        updates[`docs/${id}/lieferantPhoneSource`] = 'volltext_regex_v6.62.356';
                    }
                }
            }
            if (!dryRun && Object.keys(updates).length) {
                await db.ref().update(updates);
            }
            res.status(200).json({ ok: true, dryRun, totalDocs: Object.keys(docs).length, found: results.length, results });
        } catch (e) {
            res.status(500).json({ ok: false, error: e.message });
        }
    }
);

exports.generateEmailTemplates = onRequest(
    { region: 'europe-west1', invoker: 'public', timeoutSeconds: 60, memory: '256MiB' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        const key = req.query.key;
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const validKey = keySnap.val() || 'funk-taxi-heringsdorf-2026';
        if (!key || key !== validKey) { res.status(403).json({ error: 'Forbidden' }); return; }
        const batchId = req.query.batchId;
        const id = req.query.id;
        if (!batchId || !id) { res.status(400).json({ error: 'batchId+id required' }); return; }
        try {
            const snap = await db.ref(`belegImport/${batchId}/${id}`).once('value');
            const b = snap.val();
            if (!b || !b.parsed) { res.status(404).json({ error: 'Beleg nicht gefunden' }); return; }
            const p = b.parsed;
            const anthropicKey = await getAnthropicApiKey();
            if (!anthropicKey) { res.status(500).json({ error: 'Kein Anthropic API Key' }); return; }
            const prompt = `Du bist Patrick Wydra, Inhaber von "Funk Taxi Heringsdorf" (Kanalstr. 1, 17424 Heringsdorf, Tel 038378/22022).

Analysiere folgenden Beleg und erstelle 4 verschiedene Email-Vorlagen, die ich dem Lieferanten/Aussteller schicken koennte. Jede Vorlage soll konkret auf den INHALT des Belegs Bezug nehmen.

BELEG-DATEN:
- Lieferant: ${p.lieferant || '?'}
- Datum: ${p.datum || '?'}
- Belegnr: ${p.belegNr || b.belegNr || '?'}
- Brutto: ${p.brutto || '?'} EUR
- USt-Satz: ${p.ustSatz || '?'}%
- Zahlungsart: ${p.zahlungsart || '?'}
- Kategorie: ${p.skr03Bezeichnung || '?'} (${p.skr03Konto || '?'})
- Volltext-Auszug: ${(p.rawText || '').slice(0, 1500)}

ERSTELLE genau 4 Email-Vorlagen mit unterschiedlicher Intention:
1. ZAHLUNGSBESTAETIGUNG (Patrick bestaetigt Zahlung oder fragt nach Eingang)
2. RUECKFRAGE (Frage zu einer Position/Detail im Beleg)
3. REKLAMATION (etwas stimmt nicht, Berichtigung anfordern)
4. INFORMATIONSANFRAGE (z.B. Angebot, Folgeauftrag, Vertragsdetails)

Gib als JSON-Array zurueck:
[
  { "intent": "Zahlungsbestaetigung", "subject": "...", "body": "..." },
  { "intent": "Rueckfrage", "subject": "...", "body": "..." },
  ...
]

REGELN:
- Body 4-8 Zeilen, hoeflich, sachlich, deutsch
- Bezug zum konkreten Beleg (Belegnr, Datum, Betrag)
- Beginne mit "Sehr geehrte Damen und Herren," wenn keine Person bekannt
- Schliesse mit "Mit freundlichen Gruessen, Patrick Wydra, Funk Taxi Heringsdorf"
- KEIN Markdown im Body — reiner Plain-Text fuer mailto:
- Subject 50-80 Zeichen

NUR das JSON-Array zurueckgeben, kein Markdown, kein Pre/Post-Text.`;

            const resp = await callAnthropicAPI(anthropicKey, 'claude-sonnet-4-6', 4000, [{
                role: 'user', content: [{ type: 'text', text: prompt }]
            }]);
            const text = (resp.content?.[0]?.text || '').trim();
            let jsonText = text;
            const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
            if (m) jsonText = m[1].trim();
            let templates;
            try { templates = JSON.parse(jsonText); } catch (parseErr) {
                console.error('generateEmailTemplates JSON-Parse:', parseErr.message);
                res.status(200).json({ ok: false, error: 'KI-Antwort kein valides JSON', rawText: text });
                return;
            }
            if (!Array.isArray(templates)) { res.status(200).json({ ok: false, error: 'KI-Antwort kein Array', got: typeof templates }); return; }
            res.status(200).json({ ok: true, templates });
        } catch (err) {
            console.error('generateEmailTemplates Fehler:', err.message);
            res.status(500).json({ error: err.message });
        }
    }
);

exports.datevExport = onRequest(
    { region: 'europe-west1', invoker: 'public', timeoutSeconds: 60, memory: '256MiB' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        const key = req.query.key;
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const validKey = keySnap.val() || 'funk-taxi-heringsdorf-2026';
        if (!key || key !== validKey) { res.status(403).json({ error: 'Forbidden' }); return; }
        const batchId = req.query.batchId;
        if (!batchId) { res.status(400).json({ error: 'batchId required' }); return; }
        try {
            const snap = await db.ref(`belegImport/${batchId}`).once('value');
            const data = snap.val() || {};
            const lines = ['Datum;Belegnr;Konto;Gegenkonto;Betrag;USt-Satz;Buchungstext;PhysOrdner'];
            for (const [id, b] of Object.entries(data)) {
                if (!b || !b.parsed || !b.bestaetigt) continue;
                const p = b.parsed;
                const datum = (p.datum || '').replace(/-/g, '');
                const beleg = b.belegNr || p.belegNr || id.slice(-8);
                const konto = p.skr03Konto || '4980';
                const isErloes = String(konto).startsWith('84');
                const gegen = isErloes
                    ? (p.zahlungsart === 'karte' ? '1361' : '1000')
                    : (p.zahlungsart === 'bar' ? '1000' : '1200');
                const betrag = (p.brutto || 0).toFixed(2).replace('.', ',');
                const ust = p.ustSatz || '';
                const txt = ((p.lieferant || '') + ' — ' + (p.skr03Bezeichnung || '')).slice(0, 60).replace(/[;\n\r]/g, ' ');
                const ordner = b.physOrdner || '';
                lines.push(`${datum};${beleg};${konto};${gegen};${betrag};${ust};${txt};${ordner}`);
            }
            const csv = lines.join('\n') + '\n';
            res.set('Content-Type', 'text/csv; charset=utf-8');
            res.set('Content-Disposition', `attachment; filename="datev-stapel-${batchId}.csv"`);
            res.status(200).send(csv);
        } catch (err) {
            console.error('datevExport Fehler:', err.message);
            res.status(500).json({ error: err.message });
        }
    }
);

// 🆕 v6.63.302 (Patrick 12.06. 07:04 Bridge: 'Kannst du automatisch die
//   Schichtverlaengerung machen. Und kriegt dann der Fahrer eine Nachricht'):
//   DB-Trigger auf /vehicleShifts/{vehicleId}/{dateStr} — wenn explicit
//   Date-Eintrag NEU geschrieben wird (Tages-Ausnahme), sende Telegram-Push
//   an den Fahrer.
exports.onShiftExceptionWritten = onValueWritten(
    {
        ref: '/vehicleShifts/{vehicleId}/{dateStr}',
        region: 'europe-west1',
        timeoutSeconds: 60
    },
    async (event) => {
        try {
            const dateStr = event.params.dateStr;
            // Nur Date-Pattern YYYY-MM-DD verarbeiten, NICHT 'defaults', 'defaultTimes', 'exceptions' etc.
            if (!/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) return;
            const after = event.data.after.val();
            const before = event.data.before.val();
            if (!after) return; // Geloescht — kein Push
            const vehicleId = event.params.vehicleId;

            // Nur reagieren wenn aktiv=true UND startTime/endTime gesetzt sind
            if (after.active !== true || !after.endTime) return;

            // Vergleiche mit defaults dieser Wochentag-Schicht: wenn endTime gleich
            // → keine Notification noetig
            const dt = new Date(dateStr + 'T12:00:00');
            const dow = dt.getDay(); // 0=So, 1=Mo, ...
            const shiftSnap = await db.ref(`vehicleShifts/${vehicleId}`).once('value');
            const fullShift = shiftSnap.val() || {};
            const defTimes = (fullShift.defaultTimes || [])[dow];
            const defStart = defTimes?.startTime || '00:00';
            const defEnd = defTimes?.endTime || '23:59';

            // Schon vorher gleicher Wert? Dann nichts neues
            if (before && before.active === true &&
                before.startTime === after.startTime && before.endTime === after.endTime) {
                return;
            }

            const vehicleName = (OFFICIAL_VEHICLES[vehicleId] || {}).name || vehicleId;
            const vehiclePlate = (OFFICIAL_VEHICLES[vehicleId] || {}).plate || '';

            // Format Datum DD.MM.YYYY
            const _dateDe = dateStr.split('-').reverse().join('.');

            const _isExtension = after.endTime > defEnd;
            const _isEarlierStart = after.startTime < defStart;
            const _isShortened = after.endTime < defEnd || after.startTime > defStart;

            let _emoji = '🕒';
            let _kindText = 'angepasst';
            if (_isExtension && !_isShortened) { _emoji = '⏰➕'; _kindText = 'verlaengert'; }
            else if (_isEarlierStart && !_isShortened) { _emoji = '⏰⬅️'; _kindText = 'frueher beginnend'; }
            else if (_isShortened) { _emoji = '⏰➖'; _kindText = 'verkuerzt'; }

            const _msg = `${_emoji} *Schicht-Hinweis ${vehicleName}*\n\n` +
                `Am ${_dateDe} wurde deine Schicht ${_kindText}:\n` +
                `  Wochenplan: ${defStart} – ${defEnd}\n` +
                `  Heute:      ${after.startTime} – ${after.endTime}\n` +
                (after.exceptionReason ? `\nGrund: ${after.exceptionReason}\n` : '') +
                `\nGilt nur fuer ${_dateDe}, keine Aenderung am Wochenplan.`;

            const driverChatId = await getDriverChatId(vehicleId);
            if (driverChatId) {
                try {
                    await sendTelegramMessage(driverChatId, _msg, { parse_mode: 'Markdown' });
                    console.log(`✅ v6.63.302 Schicht-Notif an Fahrer ${vehicleName} (${driverChatId}) gesendet`);
                } catch (e) {
                    console.error('v6.63.302 sendTelegram Fehler:', e.message);
                }
            } else {
                console.log(`⚠️ v6.63.302 Keine Fahrer-ChatId fuer ${vehicleId} — Schicht-Notif uebersprungen`);
            }

            // Audit log
            await db.ref('shiftExceptionLog').push({
                ts: Date.now(),
                vehicleId, vehicleName,
                dateStr,
                wochenplan: { startTime: defStart, endTime: defEnd },
                heute: { startTime: after.startTime, endTime: after.endTime },
                kind: _kindText,
                reason: after.exceptionReason || null,
                notifiedDriver: !!driverChatId
            }).catch(() => {});
        } catch (e) {
            console.error('onShiftExceptionWritten Fehler:', e);
            await logError('onShiftExceptionWritten', e, {
                vehicleId: event.params.vehicleId,
                dateStr: event.params.dateStr,
                severity: 'warning'
            }).catch(() => {});
        }
    }
);

// v6.63.337 (Patrick 14.06.2026 15:41 'ich hab vergessen Quast fertigzustellen,
//   deswegen wurde auch nicht weitergeleitet'): Auto-Complete wenn Fahrzeug an
//   Destination steht + 5 Min vergangen.
exports.scheduledAutoCompleteAtDestination = onSchedule(
    {
        schedule: 'every 2 minutes',
        region: 'europe-west1',
        timeoutSeconds: 60,
        memory: '256MiB'
    },
    async (event) => {
        try {
            const NOW = Date.now();
            const FIVE_MIN = 5 * 60 * 1000;
            const ridesSnap = await db.ref('rides')
                .orderByChild('pickupTimestamp')
                .startAt(NOW - 24 * 60 * 60 * 1000)
                .endAt(NOW + 60 * 1000)
                .once('value');
            if (!ridesSnap.val()) return;

            const vehSnap = await db.ref('vehicles').once('value');
            const vehs = vehSnap.val() || {};

            const completes = [];
            ridesSnap.forEach(child => {
                const ride = child.val();
                const rideId = child.key;
                if (!ride || !ride.status) return;
                const st = String(ride.status).toLowerCase();
                if (st !== 'on_way' && st !== 'arrived') return;
                if (!ride.assignedVehicle) return;
                if (!ride.destinationLat || !ride.destinationLon) return;
                const veh = vehs[ride.assignedVehicle];
                if (!veh || !veh.lat || !veh.lon || !veh.lastUpdate) return;
                if (veh.lastUpdate < NOW - FIVE_MIN) return;
                const dist = haversineMeters(
                    parseFloat(veh.lat), parseFloat(veh.lon),
                    parseFloat(ride.destinationLat), parseFloat(ride.destinationLon)
                );
                // v6.63.338 (Patrick 14.06. 15:51): Auto-Complete auch wenn Fahrer
                //   schon weitergefahren ist. Speichere atDestinationSince beim
                //   ersten Erkennen, completion wenn >5 Min vergangen — egal wo Vehicle jetzt ist.
                const nearNow = dist <= 200;
                if (nearNow && !ride.atDestinationSince) {
                    // erstmal nur markieren
                    db.ref('rides/' + rideId).update({ atDestinationSince: NOW }).catch(() => {});
                    return;
                }
                if (!ride.atDestinationSince) return;
                if (ride.atDestinationSince > NOW - FIVE_MIN) return;
                completes.push({ rideId, ride, dist });
            });

            for (const c of completes) {
                try {
                    await db.ref('rides/' + c.rideId).update({
                        status: 'completed',
                        completedAt: NOW,
                        completedBy: 'auto-complete-at-destination',
                        autoCompleted: true,
                        autoCompletedDistance: Math.round(c.dist),
                        updatedAt: NOW
                    });
                    const _name = c.ride.customerName || 'Fahrt';
                    const _veh = c.ride.assignedVehicle;
                    await sendToAllAdmins(
                        `✅ <b>Auto-Complete</b>\n${_name} (${_veh})\n` +
                        `📍 ${Math.round(c.dist)}m vom Ziel, Status auto auf 'completed' gesetzt.\n\n` +
                        `💰 Preis fuer diese Fahrt eintragen? Per Web Dispo Bearbeiten oder Native Card.`,
                        'auto-complete-at-destination',
                        { rideId: c.rideId }
                    ).catch(() => {});
                    console.log('[auto-complete] rideId', c.rideId, 'dist', Math.round(c.dist) + 'm');
                } catch (e) {
                    console.warn('[auto-complete] Fehler rideId ' + c.rideId, e.message);
                }
            }
        } catch (e) {
            console.error('scheduledAutoCompleteAtDestination Fehler:', e);
            await logError('scheduledAutoCompleteAtDestination', e, { severity: 'warning' }).catch(() => {});
        }
    }
);

// v6.63.337: Video-Handler im Telegram-Webhook — Patrick 14.06.2026 15:47:
//   'Videos von meinen Kollegen schicken... per Telegram, funktioniert nicht'.
//   Bisher: webhook ignorierte update.message.video → kein Inbox-Push.
async function handleVideo(message) {
    try {
        const chatId = message.from?.id || message.chat?.id;
        if (!(await isTelegramAdmin(chatId))) return;
        const video = message.video || message.video_note || {};
        const fileId = video.file_id || null;
        const caption = message.caption || '';
        const ts = Date.now();
        await db.ref('claudeBridge/inbox/' + ts).set({
            type: 'video',
            chatId,
            ts,
            fileId,
            duration: video.duration || null,
            width: video.width || null,
            height: video.height || null,
            caption,
            from: message.from?.first_name || null,
            messageId: message.message_id || null
        });
        await sendTelegramMessage(chatId,
            '🎬 Video an Claude weitergeleitet (' + (video.duration ? video.duration + 's' : 'unbekannte Dauer') + ').\n' +
            'Caption: ' + (caption || '—'),
            { via: 'claude' }
        ).catch(() => {});
    } catch (e) {
        console.warn('handleVideo Fehler:', e.message);
    }
}

// v6.63.343 (Patrick 15.06.2026 06:08 'Tagebuch was lief gut/schlecht'):
//   Daily-Report aggregiert taeglich 23:00 alle relevanten Logs:
//   - rideStatusAudit (Status-Wechsel pro Ride)
//   - conflictResolveLog (Phase 1 Vehicle-Replans/Time-Shifts)
//   - optimierungsLog (Phase 2 Optimierungen)
//   - Wartepool-Lifecycle (wann rein, wann raus)
//   - Anomalien (autoCompleted, stuck rides)
//
//   Speichert /dailyReports/{YYYY-MM-DD} + Bridge-Push der Zusammenfassung.
exports.scheduledDailyReport = onSchedule(
    {
        // 🆕 v6.63.449 (Patrick 20.06. 20:49 Bridge: "Tagesablauf wollte ich auch noch
        //   haben, was im Wartepool war, warum... wann kommt das, 22 Uhr"):
        //   Schedule von 23:00 → 22:00, Push via Claude-Bot Bridge statt sendToAllAdmins,
        //   erweiterter Inhalt mit Umsatz/Wartepool-Verlauf/morgige Vorbestellungen.
        schedule: '0 22 * * *',
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 300,
        memory: '512MiB'
    },
    async (event) => {
        try {
            const now = new Date();
            const dayStart = new Date(now);
            dayStart.setHours(0, 0, 0, 0);
            const dayEnd = new Date(dayStart.getTime() + 24 * 60 * 60 * 1000 - 1);
            const dateKey = dayStart.toISOString().slice(0, 10);
            const tomorrowStart = new Date(dayStart.getTime() + 24 * 60 * 60 * 1000);
            const tomorrowEnd = new Date(tomorrowStart.getTime() + 24 * 60 * 60 * 1000 - 1);

            // Rides heute (gesamt-Tag nach pickupTimestamp)
            const ridesSnap = await db.ref('rides')
                .orderByChild('pickupTimestamp')
                .startAt(dayStart.getTime())
                .endAt(dayEnd.getTime())
                .once('value');
            const rides = ridesSnap.val() || {};

            const stats = {
                total: 0, completed: 0, cancelled: 0, deleted: 0,
                wartepool: 0, vorbestellt: 0, autoCompleted: 0,
                byVehicle: {}, byVehicleEur: {}, bySource: {},
                conflicts: [], wartepoolHistory: [],
                umsatz: 0
            };
            for (const [rid, r] of Object.entries(rides)) {
                if (!r) continue;
                stats.total++;
                const st = (r.status || '').toLowerCase();
                if (st === 'completed') stats.completed++;
                else if (st === 'cancelled' || st === 'storniert') stats.cancelled++;
                else if (st === 'deleted') stats.deleted++;
                else if (st === 'wartepool') stats.wartepool++;
                else if (st === 'vorbestellt') stats.vorbestellt++;
                if (r.autoCompleted) stats.autoCompleted++;
                if (r.assignedVehicle) {
                    stats.byVehicle[r.assignedVehicle] = (stats.byVehicle[r.assignedVehicle] || 0) + 1;
                    if (st === 'completed') {
                        const _p = parseFloat(String(r.price || r.estimatedPrice || 0).replace(',', '.')) || 0;
                        stats.byVehicleEur[r.assignedVehicle] = (stats.byVehicleEur[r.assignedVehicle] || 0) + _p;
                        stats.umsatz += _p;
                    }
                }
                if (r.source) stats.bySource[r.source] = (stats.bySource[r.source] || 0) + 1;
                // Alle Rides die JE im Wartepool waren (auch wieder rauskamen)
                if (r.wartepoolAt || r.wartepoolReason) {
                    stats.wartepoolHistory.push({
                        customerName: r.customerName,
                        pickupTime: r.pickupTime,
                        reason: (r.wartepoolReason || r.autoAssignLastReason || '').slice(0, 140),
                        endStatus: st,
                        attempts: r.autoAssignAttempts || 0,
                        assignedVehicle: r.assignedVehicle || null
                    });
                }
                if (st === 'wartepool' && r.wartepoolReason) {
                    stats.conflicts.push({
                        rideId: rid, customerName: r.customerName, pickupTime: r.pickupTime,
                        reason: r.wartepoolReason, resolved: false
                    });
                }
            }

            // Morgen-Vorbestellungen
            const tomSnap = await db.ref('rides')
                .orderByChild('pickupTimestamp')
                .startAt(tomorrowStart.getTime())
                .endAt(tomorrowEnd.getTime())
                .once('value');
            const tomorrow = [];
            tomSnap.forEach(c => {
                const v = c.val();
                if (!v) return;
                if (['vorbestellt', 'assigned', 'accepted', 'wartepool', 'new'].includes((v.status || '').toLowerCase())) {
                    tomorrow.push({
                        pickupTimestamp: v.pickupTimestamp,
                        customerName: v.customerName,
                        status: v.status,
                        assignedVehicle: v.assignedVehicle,
                        pickup: v.pickup,
                        destination: v.destination
                    });
                }
            });
            tomorrow.sort((a, b) => (a.pickupTimestamp || 0) - (b.pickupTimestamp || 0));

            // Conflict-Resolve Log heute
            const crlSnap = await db.ref('conflictResolveLog')
                .orderByChild('ts').startAt(dayStart.getTime()).endAt(dayEnd.getTime()).once('value');
            const conflictResolveLog = [];
            crlSnap.forEach(c => conflictResolveLog.push(c.val()));

            // 🆕 v6.63.460 (Patrick 21.06. 09:27 Bridge: "vielleicht müssen wir auch
            //   Statistiken ausführen. Welche Anrufe hatten wir? Was hat funktioniert?
            //   Was hat nicht funktioniert?"): Anrufe heute zählen + Buchungs-Konversion.
            const _callStats = { total: 0, mitCrm: 0, ohneCrm: 0, mitRide: 0, callerNumbers: new Set() };
            try {
                const _callSnap = await db.ref('callHistory')
                    .orderByChild('timestamp').startAt(dayStart.getTime()).endAt(dayEnd.getTime()).once('value');
                _callSnap.forEach(c => {
                    const _v = c.val();
                    if (!_v) return;
                    _callStats.total++;
                    if (_v.customerFound) _callStats.mitCrm++; else _callStats.ohneCrm++;
                    if (_v.caller) _callStats.callerNumbers.add(String(_v.caller).slice(-10));
                });
                // Check: aus Anrufen Rides angelegt?
                for (const _rRide of Object.values(rides)) {
                    if (!_rRide || (!_rRide.customerPhone && !_rRide.customerMobile)) continue;
                    const _ridePhone = String(_rRide.customerPhone || _rRide.customerMobile).replace(/\D/g, '').slice(-10);
                    if (_callStats.callerNumbers.has(_ridePhone)) _callStats.mitRide++;
                }
            } catch (_cErr) {
                console.warn('callStats Fehler:', _cErr.message);
            }
            const _callConversion = _callStats.total > 0 ? Math.round(100 * _callStats.mitRide / _callStats.total) : 0;

            // Optimierungs-Log heute
            const optSnap = await db.ref('optimierungsLog')
                .orderByChild('timestamp').startAt(dayStart.getTime()).endAt(dayEnd.getTime()).once('value');
            const optimierungsLog = [];
            optSnap.forEach(o => optimierungsLog.push(o.val()));

            const report = {
                date: dateKey,
                generatedAt: Date.now(),
                stats,
                conflictResolveLog: conflictResolveLog.slice(-50),
                optimierungsLog: optimierungsLog.slice(-50),
                summary: {
                    abschlussQuote: stats.total > 0 ? Math.round(100 * stats.completed / stats.total) : 0,
                    konfliktQuote: stats.total > 0 ? Math.round(100 * stats.wartepool / stats.total) : 0,
                    cloudReplans: conflictResolveLog.length,
                    cloudOptimizes: optimierungsLog.length,
                    umsatz: stats.umsatz
                }
            };
            await db.ref('dailyReports/' + dateKey).set(report);

            // Bridge-Push: ausführlicher Tagesablauf an Patrick (Claude-Bot)
            const _vehLines = Object.entries(stats.byVehicleEur)
                .sort((a, b) => b[1] - a[1])
                .map(([v, eur]) => `• ${v}: ${stats.byVehicle[v]} F, ${eur.toFixed(2)} €`)
                .join('\n');
            const _wpHist = stats.wartepoolHistory.slice(0, 8).map(w => {
                const _resolved = w.endStatus === 'completed' ? '✅ gefahren' :
                    w.endStatus === 'assigned' || w.endStatus === 'accepted' ? '✅ zugewiesen ' + (w.assignedVehicle || '') :
                        w.endStatus === 'cancelled' ? '❌ abgesagt' : '⚠️ ' + w.endStatus;
                return `• ${w.pickupTime || '?'} ${w.customerName || '?'} (${w.attempts}×) → ${_resolved}\n  ↳ ${w.reason || '-'}`;
            }).join('\n');
            const _tomLines = tomorrow.slice(0, 12).map(r => {
                const _t = r.pickupTimestamp ? new Date(r.pickupTimestamp).toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' }) : '?';
                return `• ${_t} ${r.customerName || '?'} | ${r.status} | ${r.assignedVehicle || '-'}`;
            }).join('\n');

            const msg =
                `📋 TAGESABLAUF ${dateKey}\n\n` +
                `━━━ HEUTE ━━━\n` +
                `${stats.total} Buchungen | ${stats.completed} ✓ | ${stats.cancelled} ✗ | ${stats.wartepool} 🆘\n` +
                `💶 Umsatz: ${stats.umsatz.toFixed(2)} €\n` +
                `🤖 ${stats.autoCompleted} auto-complete | ${conflictResolveLog.length} cloud-replan | ${optimierungsLog.length} optimize\n\n` +
                `━━━ ANRUFE ━━━\n` +
                `📞 ${_callStats.total} eingehend (${_callStats.mitCrm} CRM ✓ / ${_callStats.ohneCrm} unbekannt) → ${_callStats.mitRide} Buchungen (Quote ${_callConversion}%)\n\n` +
                `━━━ FAHRZEUGE ━━━\n${_vehLines || 'keine'}\n\n` +
                (stats.wartepoolHistory.length > 0
                    ? `━━━ WARTEPOOL (${stats.wartepoolHistory.length}) ━━━\n${_wpHist}\n\n`
                    : `✅ KEIN Wartepool heute\n\n`) +
                (tomorrow.length > 0
                    ? `━━━ MORGEN (${tomorrow.length} Vorbestellungen) ━━━\n${_tomLines}\n\n`
                    : '') +
                `Abschluss-Quote: ${report.summary.abschlussQuote}% | Konflikt-Quote: ${report.summary.konfliktQuote}%`;

            const _bridgeTs = Date.now();
            await db.ref('claudeBridge/outbox/' + _bridgeTs).set({
                message: msg,
                targetChatId: 6229490043,
                via: 'claude',
                ts: _bridgeTs
            });
            console.log('📋 Daily Report ' + dateKey + ' an Bridge gepusht (' + stats.total + ' rides, ' + stats.umsatz.toFixed(2) + ' €)');
        } catch (e) {
            console.error('scheduledDailyReport Fehler:', e);
            await logError('scheduledDailyReport', e, { severity: 'warning' }).catch(() => {});
        }
    }
);

// 🆕 v6.63.449 (Patrick 20.06. 19:48 Bridge: "Sobald eine Fahrt im Wartepool landet,
//   musst du das überprüfen... auseinandernehmen und gucken warum/weshalb/wieso"):
//   Real-Time Wartepool-Detektiv. Triggert bei Status-Wechsel auf 'wartepool', liest
//   vehicleScores, kategorisiert das Problem und pusht strukturierten Befund an Patrick.
exports.onRideEnteredWartepool = onValueUpdated(
    {
        ref: '/rides/{rideId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        try {
            const before = event.data.before.val() || {};
            const after = event.data.after.val() || {};
            const rideId = event.params.rideId;

            // Nur beim Wechsel zu wartepool, nicht bei Folge-Updates
            if (after.status !== 'wartepool') return;
            if (before.status === 'wartepool') return;
            if (after.wartepoolDetectivePushed) return;

            const scores = after.vehicleScores || {};
            const reason = after.autoAssignLastReason || after.wartepoolReason || '';

            // Kategorisierung anhand vehicleScores
            let cShift = 0, cCapacity = 0, cConflict = 0, cLive = 0, cDriverRej = 0, cOther = 0;
            const conflictDetail = [];
            for (const [vid, sc] of Object.entries(scores)) {
                const check = String(sc.check || '').toLowerCase();
                const r = String(sc.reason || '').toLowerCase();
                if (/shift|wochenplan|außerhalb|ausserhalb|kein dienst/.test(check + ' ' + r)) cShift++;
                else if (/capacity|kapazität|kapazitaet/.test(check + ' ' + r)) cCapacity++;
                else if (/timeconflict|zeitkonflikt/.test(check + ' ' + r)) {
                    cConflict++;
                    if (sc.conflictMath) {
                        conflictDetail.push({
                            vehicle: vid,
                            blocking: sc.blockingRideCustomer,
                            blockingTime: sc.blockingRideTime,
                            overlapMin: sc.conflictMath.overlapMin
                        });
                    }
                }
                else if (/live-shift|sofortfahrt/.test(check + ' ' + r)) cLive++;
                else if (/driver_rejected|fahrer hat nicht/.test(check + ' ' + r)) cDriverRej++;
                else cOther++;
            }
            const total = cShift + cCapacity + cConflict + cLive + cDriverRej + cOther;

            let category, options = [];
            if (total === 0) {
                category = 'KEINE-SCORES';
                options.push('vehicleScores fehlen — Cron neu auslösen');
            } else if (cCapacity > 0 && cCapacity === total - cConflict - cShift) {
                category = 'KAPAZITÄT';
                options.push('Sammelfahrt mit 2 Fahrzeugen');
                options.push('Kunde nach Pax-Zahl rückfragen');
            } else if (cConflict > 0 && cShift === 0) {
                category = 'NUR-KONFLIKT';
                const knapp = conflictDetail.filter(c => c.overlapMin <= 10);
                if (knapp.length > 0) {
                    options.push(`Folgefahrt ${knapp[0].blocking} um ${knapp[0].overlapMin} Min verschieben (Karenz greift)`);
                } else {
                    options.push(`Folgefahrt ${conflictDetail[0]?.blocking || '?'} auf anderes Vehicle`);
                }
                options.push('Springer Tesla YM manuell freischalten');
            } else if (cShift === total) {
                category = 'SCHICHT-LOCH';
                options.push('Welches Vehicle am nächsten an Pickup-Zeit — Schicht verlängern');
                options.push('Springer Tesla YM manuell freischalten');
                options.push('Kunde verschieben (5-15 Min)');
            } else if (cConflict > 0 && cShift > 0) {
                category = 'SCHICHT+KONFLIKT';
                options.push('Springer YM oder Schicht verlängern');
                if (conflictDetail.length > 0) {
                    options.push(`Folgefahrt ${conflictDetail[0].blocking} verschieben`);
                }
            } else if (cLive > 0 && cLive === total) {
                category = 'SOFORT-NIEMAND-LIVE';
                options.push('Kunde anrufen — kein Fahrer aktuell online');
                options.push('Fahrer per Push aktivieren');
            } else if (cDriverRej > 0) {
                category = 'FAHRER-ABGELEHNT';
                options.push('Anderes Vehicle prüfen');
                options.push('Manuell zuweisen + Fahrer anrufen');
            } else {
                category = 'GEMISCHT';
                options.push('Manuelle Disposition prüfen');
            }
            options.push('Fahrt absagen');
            options.push('Manuell zuweisen (deine Entscheidung)');

            // Push bauen
            const _fmt = ts => ts ? new Date(ts).toLocaleString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : '?';
            const pickup = _fmt(after.pickupTimestamp);
            const _price = after.estimatedPrice || after.price || '?';

            let msg = `🚨 WARTEPOOL: ${after.customerName || '?'} ${pickup}\n`;
            msg += `${(after.pickup || '').slice(0, 50)} → ${(after.destination || '').slice(0, 50)}\n`;
            msg += `${after.passengers || 1} Pax | ${_price} €\n\n`;
            msg += `Kategorie: ${category}\n`;
            msg += `${reason.slice(0, 200)}\n\n`;
            msg += `Optionen:\n`;
            msg += options.map((o, i) => `[${String.fromCharCode(65 + i)}] ${o}`).join('\n');

            const _bridgeTs = Date.now();
            await db.ref('claudeBridge/outbox/' + _bridgeTs).set({
                message: msg,
                targetChatId: 6229490043,
                via: 'claude',
                ts: _bridgeTs
            });
            await db.ref(`rides/${rideId}/wartepoolDetectivePushed`).set(true);
            console.log(`🚨 WP-Detective Push (${category}): ${after.customerName} ${pickup}`);
        } catch (e) {
            console.error('onRideEnteredWartepool Fehler:', e);
        }
    }
);
